/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	42. Mortgage Issued Business Case by Case.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_042_MortgageIssuedBusinessCaseByCase]

as

IF OBJECT_ID('tempdb..#b') IS NOT NULL	
DROP TABLE #b

IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c

IF OBJECT_ID('tempdb..#D') IS NOT NULL	
DROP TABLE #D

declare @StartDate datetime,@EndDate datetime;
set @StartDate = CONVERT(DATETIME, '2017-01-12 00:00:00', 102)
set @EndDate = CONVERT(DATETIME, '2017-04-11 23:59:59', 102) ---- ACTUAL DATES NEEDED

select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
group by po.policyref, po.cont_num, co.productcode

-- create a table in order to calculate the first issued transaction number in a case
	
select min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #b
from		 
dbo.mstt_Commissions co INNER JOIN
dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID
where co.poltrantranstype <> 39
and co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
group by
po.policyref, po.cont_num, co.productcode

SELECT  
min(co.transactionid) as transactionid, 
min(po.PolicyRef) AS CaseID, 
case when min(pt.writtendate) < '1 May 2014' then 'PREOWS' else min(iv.valuename) end as MortgageCategory, 
case when min(pt.writtendate) < '1 May 2014' then 'PREOWS' else min(iv5.valuename) end as MortgageTransaction
INTO #D
FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  dbo.sa_ows_policies opol ON opol.PolicyID = po.policyref LEFT OUTER JOIN
			  Policy.sa_ows_MortgageProduct mo on mo.InternalProductID = opol.InternalProductID LEFT OUTER JOIN
			  dbo.vw_ows_MortgageProductSummary mop on mop.policyid = opol.PolicyID LEFT OUTER JOIN
			  dbo.vw_ows_MortgageRecommendedSolution mrs on mrs.policyid = opol.PolicyID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV on IV.inputid = mop.mortgagecategoryid LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV2 on IV2.inputid = mop.mortgagetypeID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV3 on IV3.inputid = mop.InterestRateTypeID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV4 on IV4.inputid = mop.InitialRatePeriodID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV5 on IV5.inputid = mrs.transactiontypeid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where  
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
AND ph.productgroupname = 'Mortgage'
group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate)

-- Swift transactions

select
case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end as agent_code,

Case 
when ag.agent_code in ('1011543','1011587') then 

(case 

when co3.firm = '1000941' then '1007791' when co3.firm = '1000976' then '2001655' when co3.firm = '1001619' then '2001460' when co3.firm = '1001747' then '1006123' when co3.firm = '1001860' then '2000914' when co3.firm = '1001931' then '2001142' when co3.firm = '1002683' then '2001252' when co3.firm = '1002866' then '2001140' when co3.firm = '1002958' then '1002961' when co3.firm = '1003038' then '2001543' when co3.firm = '1003450' then '2001454' when co3.firm = '1004284' then '1000392' when co3.firm = '1005445' then '2001002' when co3.firm = '1010723' then '1001338' when co3.firm = '1000746' then '1011544' when co3.firm = '1002578' then '2001476' when co3.firm = '1002580' then '1011548' when co3.firm = '2000508' then '1004215'
when co3.firm = '1001374' then '2001538' when co3.firm = '1000981' then '2000425' when co3.firm = '2000522' then '2001536' when co3.firm = '1009210' then '2001543' when co3.firm = '1001167' then '2001540' when co3.firm = '1001789' then '2001395' when co3.firm = '1002076' then '2001475' when co3.firm = '1001058' then '2001549' when co3.firm = '1011487' then '2001497' when co3.firm = '1000821' then '1011541' when co3.firm = '1000692' then '2001575' when co3.firm = '1007638' then '2001578' when co3.firm = '1001804' then '2001582' when co3.firm = '1000794' then '2001580' when co3.firm = '1001492' then '2001584' when co3.firm = '1011448' then '2001585' when co3.firm = '1011540' then '1001897' when co3.firm = '1002178' then '2001613'
when co3.firm = '1000967' then '2001653' when co3.firm = '2001040' then '2001655' when co3.firm = '1001891' then '2001714' when co3.firm = '1002112' then '2001807' when co3.firm = '1000867' then '1011604' when co3.firm = '1011608' then '1010815' when co3.firm = '1001049' then '2001995' when co3.firm = '1000724' then '1004141' when co3.firm = '1001346' then '1009425' when co3.firm = '1000678' then '2004388' when co3.firm = '1000704' then '1003010' when co3.firm = '1008026' then '1001546' when co3.firm = '1002702' then '2001504' when co3.firm = '2000988' then '1001249' when co3.firm = '2001397' then '2004449' when co3.firm = '1000995' then '2004732' when co3.firm = '2001518' then '2006569' when co3.firm = '2005389' then '2006353'
when co3.firm = '1002174' then '2006794' when co3.firm = '2004325' then '2007293' when co3.firm = '1009620' then '2010099' when co3.firm = '1007327' then '2011344'

else co3.firm end)

when (case when((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end) = '1006886' then 'NULL' 

when ag.firm = '1000941' then '1007791' when ag.firm = '1000976' then '2001655' when ag.firm = '1001619' then '2001460' when ag.firm = '1001747' then '1006123' when ag.firm = '1001860' then '2000914' when ag.firm = '1001931' then '2001142' when ag.firm = '1002683' then '2001252' when ag.firm = '1002866' then '2001140' when ag.firm = '1002958' then '1002961' when ag.firm = '1003038' then '2001543' when ag.firm = '1003450' then '2001454' when ag.firm = '1004284' then '1000392' when ag.firm = '1005445' then '2001002' when ag.firm = '1010723' then '1001338' when ag.firm = '1000746' then '1011544' when ag.firm = '1002578' then '2001476' when ag.firm = '1002580' then '1011548' when ag.firm = '2000508' then '1004215'
when ag.firm = '1001374' then '2001538' when ag.firm = '1000981' then '2000425' when ag.firm = '2000522' then '2001536' when ag.firm = '1009210' then '2001543' when ag.firm = '1001167' then '2001540' when ag.firm = '1001789' then '2001395' when ag.firm = '1002076' then '2001475' when ag.firm = '1001058' then '2001549' when ag.firm = '1011487' then '2001497' when ag.firm = '1000821' then '1011541' when ag.firm = '1000692' then '2001575' when ag.firm = '1007638' then '2001578' when ag.firm = '1001804' then '2001582' when ag.firm = '1000794' then '2001580' when ag.firm = '1001492' then '2001584' when ag.firm = '1011448' then '2001585' when ag.firm = '1011540' then '1001897' when ag.firm = '1002178' then '2001613'
when ag.firm = '1000967' then '2001653' when ag.firm = '2001040' then '2001655' when ag.firm = '1001891' then '2001714' when ag.firm = '1002112' then '2001807' when ag.firm = '1000867' then '1011604' when ag.firm = '1011608' then '1010815' when ag.firm = '1001049' then '2001995' when ag.firm = '1000724' then '1004141' when ag.firm = '1001346' then '1009425' when ag.firm = '1000678' then '2004388' when ag.firm = '1000704' then '1003010' when ag.firm = '1008026' then '1001546' when ag.firm = '1002702' then '2001504' when ag.firm = '2000988' then '1001249' when ag.firm = '2001397' then '2004449' when ag.firm = '1000995' then '2004732' when ag.firm = '2001518' then '2006569' when ag.firm = '2005389' then '2006353'
when ag.firm = '1002174' then '2006794' when ag.firm = '2004325' then '2007293' when ag.firm = '1009620' then '2010099' when ag.firm = '1007327' then '2011344'

else ag.firm End AS "Firm", ag.commissiontypedesc,
ag.transactionid, ag.createdatetime, coalesce(ex.cashreceiveddate,ex2.cashreceiveddate,ex3.cashreceiveddate) as cashreceiveddate,

-- PREMIUM FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM
Case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 else
(Case when (case when pt.frequencydescription = 'Single' Then 'Single' ELSE 'Regular' end) = 'Single' then ((case when (ag.commissiontype = 2 AND ph.productgroupname = 'Mortgage') then (coalesce(cs.ape,co2.turnover,0)*-1) when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) * (Case when ph.productgroupname = 'Mortgage' then 1 else 10 end)) else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end)
end) end as "Premium",

-- APE FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM / 10 FOR APE
CASE WHEN (ag.commissiontype = 2 AND ph.productgroupname = 'Mortgage') then coalesce(cs.ape,co2.turnover,0) ELSE
(case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then ((cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 / 10) else

-- ENSURE MORTGAGES APE IS THE SAME AS DA
(case when 
(case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuities' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end) = 'Mortgage'
then (case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end)
else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end) end)END as "APE", 


---DA INITAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) when (ph.ProductGroupName = 'Mortgage' AND ag.commissiontype = 2) then (round((cs.inissued/ag.amount),0) *ag.derivedmarginamount) else 0 end as DA,

-- COMM INITIAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then cs.inissued
-- COMM SERVICING
when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
-- COMM TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
else 0 end as Comm,

-- GROSS MARGIN INITIAL
(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
-- GROSS MARGIN TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
-- GROSS MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) when (ph.ProductGroupName = 'Mortgage' AND ag.commissiontype = 2) then (round((cs.inissued/ag.amount),0) *ag.derivedmarginamount) else 0 end) as 'Margin',


case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end as "NB Cases",
coalesce(case when ag.commissiontypedesc like '%claw%' then 0 when cs.ape < 0 then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 else ag.derivedagentsplit/100 end,0) as "Cases", case when pt.frequencydescription = 'Single' Then 'Single' ELSE 'Regular' END AS 'Frequency', ag.caseid, ag.providerref
, coalesce(co.businessreason,co2.businessreason,'NB') as "business reason", coalesce(co.adminmethoddescription,co2.adminmethoddescription) as adminmethod, isnull(co.productcode,ag.tranproduct) as "ProductCode", isnull(co.productprovidercode,ag.comp_code) as "Comp_code", rp.reportingproductname as reportingproductname, ph.productsubgroupname as productsubgroupname, 

case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end as ProductGroupName,
ccs.calculationcode, case when cs.paybasisdesc in ('Accr') then 'Accrual' else 'Indemnity' end as paybasisdesc, cs.oastatus, rtrim(ah.asdname), (replace(ccs.description,'do not use - ','')) as description,
#D.MortgageCategory,
#D.MortgageTransaction

from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_Commissions co3 on co3.transactionid = ag.transactionid 
and co3.agent_code = pt.agentcode
and co3.commissiontype = ag.commissiontype 
and co3.firm <> '1011543' LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
mstt_expectation ex ON ex.id = cs.expectationid LEFT OUTER JOIN
(select max(cashreceiveddate) as cashreceiveddate, amount_rec, transactionid from mstt_expectation group by transactionid, amount_rec) ex2 ON ex2.transactionid = ag.transactionid and ag.amount = ex2.amount_rec LEFT OUTER JOIN
(select max(cashreceiveddate) as cashreceiveddate, transactionid from mstt_expectation group by transactionid) ex3 ON ex3.transactionid = ag.transactionid LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid  
LEFT OUTER JOIN #D on (#D.CaseID = ag.CaseID AND #D.transactionID = ag.transactionID)

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate
and ag.agent_code <> '10002'
and ag.amount <> 0
and (ag.commissiontype in ('1','4','10','17','18','19') OR (ph.productgroupname = 'Mortgage' AND ag.commissiontype = 2))
and (co2.id not in ('17797514','17797515') or co2.id is NULL)
and (co3.id not in ('17797514','17797515') or co3.id is NULL)
and (cs.oastatus = 'valid' or cs.oastatus is null)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
and ---DA INITAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
 --DA SERVICING
when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
 --DA TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
 --DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end <> 0
and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 
--and case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end IN('4006770', '4006738')
and case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end in ('Mortgage')



UNION ALL

---INSERT ZERO UPFRONT APE

select co.agent_code,

case
when co.firm = '1000941' then '1007791' when co.firm = '1000976' then '2001655' when co.firm = '1001619' then '2001460' when co.firm = '1001747' then '1006123' when co.firm = '1001860' then '2000914' when co.firm = '1001931' then '2001142' when co.firm = '1002683' then '2001252' when co.firm = '1002866' then '2001140' when co.firm = '1002958' then '1002961' when co.firm = '1003038' then '2001543' when co.firm = '1003450' then '2001454' when co.firm = '1004284' then '1000392' when co.firm = '1005445' then '2001002' when co.firm = '1010723' then '1001338' when co.firm = '1000746' then '1011544' when co.firm = '1002578' then '2001476' when co.firm = '1002580' then '1011548' when co.firm = '2000508' then '1004215'
when co.firm = '1001374' then '2001538' when co.firm = '1000981' then '2000425' when co.firm = '2000522' then '2001536' when co.firm = '1009210' then '2001543' when co.firm = '1001167' then '2001540' when co.firm = '1001789' then '2001395' when co.firm = '1002076' then '2001475' when co.firm = '1001058' then '2001549' when co.firm = '1011487' then '2001497' when co.firm = '1000821' then '1011541' when co.firm = '1000692' then '2001575' when co.firm = '1007638' then '2001578' when co.firm = '1001804' then '2001582' when co.firm = '1000794' then '2001580' when co.firm = '1001492' then '2001584' when co.firm = '1011448' then '2001585' when co.firm = '1011540' then '1001897' when co.firm = '1002178' then '2001613'
when co.firm = '1000967' then '2001653' when co.firm = '2001040' then '2001655' when co.firm = '1001891' then '2001714' when co.firm = '1002112' then '2001807' when co.firm = '1000867' then '1011604' when co.firm = '1011608' then '1010815' when co.firm = '1001049' then '2001995' when co.firm = '1000724' then '1004141' when co.firm = '1001346' then '1009425' when co.firm = '1000678' then '2004388' when co.firm = '1000704' then '1003010' when co.firm = '1008026' then '1001546' when co.firm = '1002702' then '2001504' when co.firm = '2000988' then '1001249' when co.firm = '2001397' then '2004449' when co.firm = '1000995' then '2004732' when co.firm = '1002174' then '2006794' when co.firm = '2004325' then '2007293'
when co.firm = '1009620' then '2010099' when co.firm = '1007327' then '2011344'

else co.firm end as "Firm",
commissiontypedesc = 'Zero Fee', co.transactionid, pt.createdatetime, pt.createdatetime,
case when pt.frequencydescription = 'Single' Then (co.ape * 10) ELSE (co.ape) end as "Premium",
co.ape,
DA = 0,
Comm = 0,
Margin = 0,
case when b.transactionid is null then 0 when (co.businessreason = 'I' and co.adminmethoddescription <> 'Not Sold By This Office' and co.adminmethoddescription <> 'Execution Only Increase') then 0 when co.ape = 0 then 0 when co.ape > 0 and co.transactionid = b.transactionid then co.agent_perc/100 else 0 end as "NB Cases",
agent_perc/100 as Cases,
pt.frequencydescription,
po.policyref as CaseID,
po.cont_num as Provideref,
co.businessreason,
co.adminmethoddescription,
co.productcode,
co.productprovidercode as Comp_Code,
rp.reportingproductname,
ph.productsubgroupname,
case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ((left(co.productcode,2) in ('OW','OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else ph.productgroupname end as 'ProductGroupName', ccs.description,
pt.commissiontypedesc,
oastatus = 'NULL',
rtrim(ah.asdname), (replace(ccs.description,'do not use - ','')) as description,
#D.MortgageCategory,
#D.MortgageTransaction

from 
mstt_Commissions co LEFT OUTER JOIN
mstt_Policytransactions pt on co.transactionid = pt.id LEFT OUTER JOIN
mstt_Policies po on pt.policyid = po.pol_num LEFT OUTER JOIN
mstt_ProductHierarchy ph ON co.ProductCode = ph.productcode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = co.transactionid LEFT OUTER JOIN
#D on #D.CaseID = po.policyref


where
co.agent_code <> '10002'
and pt.createdatetime >= @StartDate
and pt.createdatetime <= @EndDate
and co.commissiontype = 1
and ph.rdrtype is not null
and pt.comminitialamount <= 0 and pt.amount > 0
and co.poltrantranstype = 17
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
and case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ((left(co.productcode,2) in ('OW','OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else ph.productgroupname end IN ('Mortgage')


UNION ALL

Select Distinct MBF.AdviserUID, MBF.FirmUID, 'Mortgage Broker Fee' as commissiontypedesc, MBF.TransactionID, MBF.ApplicationDate as createdatetime, MBF.PaymentMatchedDate as cashreceiveddate, MBF.AdviceFeeAmount as Premium, 
       MBF.APE, MBF.APE as DA, MBF.AdviceFeeAmount+MBF.DeductionAmount as comm, MBF.DeductionAmount*-1 as Margin, '' as NBCases, '' as cases, 'Single' as Frequency, MBF.PolicyID as caseid, MBF.MortgageNumber as providerref, 'NB' as "business Reason", '' as adminmethod,
	   ag.tranproduct as ProductCode, ag.comp_code as Comp_code, rp.reportingproductname as reportingproductname, ph.productsubgroupname as productsubgroupname, ph.productgroupname, '' as calculationcode,
	   '' as paybasisdesc,'' as oastatus, '', 'Mortgage Broker Fee' as description,
	   #D.MortgageCategory,
       #D.MortgageTransaction
FROM dbo.owt_MortgageBrokerFees MBF left outer join
     mstt_paymentspending ag ON ag.transactionid = MBF.transactionid LEFT OUTER JOIN
	 mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
     msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
     #D on #D.CaseID = MBF.PolicyID
where (MBF.PaymentMatchedDate) >= DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0) 
AND MBF.AdviceFeeCharged = 'Yes' 
order by ag.createdatetime desc

drop table #b
drop table #C
drop table #D

GO
