/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	43. Mortgage Proposition BTL Data Extension.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_043_MortgagePropositionBTLDataExtension]

as

Declare @StartDate datetime,@EndDate datetime;
set @StartDate = CONVERT(DATETIME, '2018-01-01 00:00:00', 102)
set @EndDate = CONVERT(DATETIME, '2019-01-31 23:59:59', 102) ---- ACTUAL DATES NEEDED -- Data need to cover R12


select

FFP1.SaleID, SA.AdviserUID, SA.BusinessUID, FFP1.DateCreated, FFP2.ExistingPropertyID, IV.ValueName as 'Has Other Properties', IV3.Valuename as 'Self Funded' , FFP1.NUmberofProperties, IV2.ValueName as 'To be Held with Litd Company'
into #a

from 

sa_ows_FactFindProperties FFP1 inner Join
sa_ows_FactFindPropertiesExistingProperties FFP2 on FFP2.SaleID = FFP1.SaleID inner Join
StaticData.sa_ows_InputValues IV on IV.InputID = FFP1.HavePropertiesID left outer join
StaticData.sa_ows_InputValues IV3 on IV3.InputID = FFP1.SelfFundingID left outer join
StaticData.sa_ows_InputValues IV2 on IV2.InputID = FFP2.HeldToBeHeldWithinALimitedCompanyID left Join
SA_OWS_Sale SA on SA.SaleID = FFP1.SaleID

order by FFP1.DateCreated desc


select pol.PolicyRef,
IV4.ValueName as 'Type',
IV5.ValueName as 'Transation Type',
pol.CreateDate,
#a.AdviserUID,
#a.BusinessUID,
pH.ProductName as 'Mortgage Provider',
#a.[To be Held with Litd Company],
#a.[Self Funded],
#a.NumberOfProperties, 
case when #a.NumberOfProperties > 3 then 'Yes' else 'No' end as 'Portfolio Landlord'

from 
dbo.mstt_Policies Pol join
mstt_ProductHierarchy PH on PH.ProductGroupcode = POL.ProductGroupCode and POL.ProductCode = PH.Productcode left join
PolicyOneLink.sa_ows_MortgageProductSummary  MPS on MPS.PolicyID = POL.PolicyRef left Join
StaticData.sa_ows_InputValues IV4 on IV4.InputID = MPS.MortgageCategoryId right Join
StaticData.sa_ows_InputValues IV5 on IV5.InputID = MPS.TransactionTypeId right Join
#a on #a.ExistingPropertyID = MPS.RelatedpropertyID



where pol.ProductGroupCode = '3'
and pol.createdate >= @StartDate
and pol.createdate <= @EndDate
and IV4.ValueName in ('BTL','CBTL')
--and pol.StatusDescription in ('Active')
and IV5.ValueName in ('First time purchase','Second or subsequent purchase')

drop table #a


GO
/****** Object:  StoredProcedure [BI].[pr_044_MortgagePropositionReportMaster]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	44. Mortgage Proposition Report Master.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_044_MortgagePropositionReportMaster]

as

----WRITTEN MORTGAGE DATA
----ISSUED MORTGAGE DATA
----WRITTEN MORTGAGE CLIENT DATA
----ISSUED MORTGAGE CLIENT DATA

IF OBJECT_ID('tempdb..#b') IS NOT NULL
DROP TABLE #b

IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c

declare @StartDate datetime,@EndDate datetime;
set @StartDate = CONVERT(DATETIME, '2018-01-01 00:00:00', 102)
set @EndDate = CONVERT(DATETIME, '2019-12-31 23:59:59', 102) ---- ACTUAL DATES NEEDED

select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
group by po.policyref, po.cont_num, co.productcode


select
cast((year(wr.writtendate)) as nvarchar(max)) + (case when month(wr.writtendate) > month(@enddate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end as "R12",
wr.adviser,
Case 

when WR.firm = '1000941' then '1007791' when wr.firm = '1000976' then '2001655' when wr.firm = '1001619' then '2001460' when wr.firm = '1001747' then '1006123' when wr.firm = '1001860' then '2000914' when wr.firm = '1001931' then '2001142' when wr.firm = '1002683' then '2001252' when wr.firm = '1002866' then '2001140' when wr.firm = '1002958' then '1002961' when wr.firm = '1003038' then '2001543' when wr.firm = '1003450' then '2001454' when wr.firm = '1004284' then '1000392' when wr.firm = '1005445' then '2001002' when wr.firm = '1010723' then '1001338' when wr.firm = '1000746' then '1011544' when wr.firm = '1002578' then '2001476' when wr.firm = '1002580' then '1011548' when wr.firm = '2000508' then '1004215'
when wr.firm = '1001374' then '2001538' when wr.firm = '1000981' then '2000425' when wr.firm = '2000522' then '2001536' when wr.firm = '1009210' then '2001543' when wr.firm = '1001167' then '2001540' when wr.firm = '1001789' then '2001395' when wr.firm = '1002076' then '2001475' when wr.firm = '1001058' then '2001549' when wr.firm = '1011487' then '2001497' when wr.firm = '1000821' then '1011541' when wr.firm = '1000692' then '2001575' when wr.firm = '1007638' then '2001578' when wr.firm = '1001804' then '2001582' when wr.firm = '1000794' then '2001580' when wr.firm = '1001492' then '2001584' when wr.firm = '1011448' then '2001585' when wr.firm = '1011540' then '1001897' when wr.firm = '1002178' then '2001613'
when wr.firm = '1000967' then '2001653' when wr.firm = '2001040' then '2001655' when wr.firm = '1001891' then '2001714' when wr.firm = '1002112' then '2001807' when wr.firm = '1000867' then '1011604' when wr.firm = '1011608' then '1010815' when wr.firm = '1001049' then '2001995' when wr.firm = '1000724' then '1004141' when wr.firm = '1001346' then '1009425' when wr.firm = '1000678' then '2004388' when wr.firm = '1000704' then '1003010' when wr.firm = '1008026' then '1001546' when wr.firm = '1002702' then '2001504' when wr.firm = '2000988' then '1001249' when wr.firm = '2001397' then '2004449' when wr.firm = '2001518' then '2006569' when wr.firm = '2005389' then '2006353' when wr.firm = '1002174' then '2006794'
when wr.firm = '1009620' then '2010099' when wr.firm = '1007327' then '2011344'

else wr.firm End as "Firm",
case when wr.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when wr.reportingproductname like '%Platform%' then 'Platform Mortgages' when wr.reportingproductname like '%Scottish Widows%' then 'Scottish Widows Bank' when wr.reportingproductname like '%Fleet%' then 'Fleet Mortgages' when wr.reportingproductname like '%Kent Reliance%' then 'Kent Reliance' when wr.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when wr.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when wr.reportingproductname like '%Progressive Mortgages%' THEN 'Progressive Building Society' WHEN wr.reportingproductname like '%Abbey Mortgages%' THEN 'Santander for Intermediaries' WHEN wr.reportingproductname like '%Santander%' THEN 'Santander for Intermediaries' WHEN wr.reportingproductname like '%Skipton Mortgages%' THEN 'Skipton Building Society' WHEN wr.reportingproductname like '%Skipton (Buildstore)%' THEN 'Skipton Building Society'  WHEN wr.reportingproductname like '%Northern Rock%' THEN 'Virgin Money' WHEN wr.reportingproductname like '%Platform%' THEN 'Platform (Co-op Bank)' WHEN wr.reportingproductname like '%BM Solutions%' THEN 'BM Solutions (LBG)' WHEN wr.reportingproductname like '%The Mortgage Works%' THEN 'The Mortgage Works (NBS)' WHEN wr.reportingproductname like '%Godiva%' THEN 'Coventry' WHEN wr.reportingproductname like '%Principality%' THEN 'Principality' WHEN wr.reportingproductname like '%lloyds TSB%' THEN 'TSB' WHEN wr.reportingproductname like '%Precise%' THEN 'Precise' WHEN wr.reportingproductname like '%Newcastle%' THEN 'Newcastle Building Society' WHEN wr.reportingproductname = 'BOI' THEN 'Bank of Ireland' WHEN wr.reportingproductname like '%Woolwich%' THEN 'Barclays' ELSE REPLACE(REPLACE(wr.reportingproductname,' Mortgages',''),' (TBMC)','') END AS 'Provider',
(cast((month(wr.writtendate)) as nvarchar(max)) + cast((year(wr.writtendate)) as varchar(max))) as Date,
wr.caseid,
wr.MortgageCategory, wr.mortgagetype, wr.InterestType, 
Case When wr.MortgageCategory in('Buy to Let', 'BTL') THEN (case when wr.LVRatio is null THEN 'PREOWS' WHEN wr.LVRatio = '5.5' THEN 'PREOWS' WHEN wr.LVRatio < '61' THEN '0-60%' WHEN wr.LVRatio < '71' THEN '61-70%' WHEN wr.LVRatio < '76' THEN '71-75%' WHEN wr.LVRatio < '81' THEN '76-80%' WHEN wr.LVRatio < '91' THEN '81-90%' WHEN wr.LVRatio  >= '91' THEN '91+%' ELSE 'PREOWS' END) ELSE  (CASE WHEN wr.LVRatio is null THEN 'PREOWS' WHEN wr.LVRatio = '5.5' THEN 'PREOWS' WHEN wr.LVRatio < '61' THEN '0-60%' WHEN wr.LVRatio < '71' THEN '61-70%' WHEN wr.LVRatio < '81' THEN '71-80%' WHEN wr.LVRatio < '91' THEN '81-90%' WHEN wr.LVRatio  >= '91' THEN '91+%' ELSE 'PREOWS' END) END AS 'LTV%',
CASE WHEN wr.dealperiod = 5.5 THEN 'PREOWS' WHEN wr.dealperiod < 24 THEN '12m-23m' WHEN wr.dealperiod < 36 THEN '24m-35m' WHEN wr.dealperiod < 60 THEN '36m-59m' WHEN wr.dealperiod >= 60 THEN '60m+' ELSE 'PREOWS' END AS dealperiod,
CASE WHEN wr.MortgageTransaction = 'First time purchase' THEN 'First Time Buyer' WHEN wr.MortgageTransaction = 'Second or subsequent purchase' THEN 'Purchase' WHEN wr.MortgageTransaction = 'Unencumbered property' THEN 'Remortgage' ELSE wr.MortgageTransaction END AS MortgageTransaction,
wr.NBCases

from


(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate, min(pt.issueddate) as issueddate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) as distributionallowance, 

round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2) as NBI, 


round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) as Margin, 
max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases", 
max((co.agent_perc/100)) as "AllCases", min(pt.FrequencyDescription) as frequency, min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD,
case when min(pt.writtendate) < '1 May 2014' then 'PREOWS' else min(iv.valuename) end as MortgageCategory, case when min(pt.writtendate) < '1 May 2014' then 'PREOWS' else min(iv2.valuename) end as MortgageType, case when min(pt.writtendate) < '1 May 2014' then 'PREOWS' else min(iv3.valuename) end as InterestType, case when min(pt.writtendate) < '1 May 2014' then '5.5' else  min(mop.MortgageLVratio) end as LVRatio, case when min(pt.writtendate) < '1 May 2014' then 5.5 else min(replace(replace(replace(iv4.valuename,' years',''),'under 2',''), 'Lifetime', 100))*12 end as dealperiod, case when min(pt.writtendate) < '1 May 2014' then 'PREOWS' else min(iv5.valuename) end as MortgageTransaction

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  dbo.sa_ows_policies opol ON opol.PolicyID = po.policyref LEFT OUTER JOIN
			  Policy.sa_ows_MortgageProduct mo on mo.InternalProductID = opol.InternalProductID LEFT OUTER JOIN
			  --Policy.sa_ows_MortgageProductSummary mop on mop.policyid = opol.PolicyID LEFT OUTER JOIN
			  dbo.vw_ows_MortgageProductSummary mop on mop.policyid = opol.PolicyID LEFT OUTER JOIN
			  --Policy.sa_ows_MortgageRecommendedSolution mrs on mrs.policyid = opol.PolicyID LEFT OUTER JOIN
			  dbo.vw_ows_MortgageRecommendedSolution mrs on mrs.policyid = opol.PolicyID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV on IV.inputid = mop.mortgagecategoryid LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV2 on IV2.inputid = mop.mortgagetypeID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV3 on IV3.inputid = mop.InterestRateTypeID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV4 on IV4.inputid = mop.InitialRatePeriodID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV5 on IV5.inputid = mrs.transactiontypeid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where  
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate)) wr

where
wr.writtendate >= @StartDate
and wr.writtendate <= @EndDate	
--and wr.adviser = '1003198'
--and wr.originatingsource = '5'
and (wr.caseid not in ('500020430','500020431') or wr.caseid is null)
and case when wr.productsubgroupname like '%Annuity' then 'Annuities' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end in ('Mortgage')

group by
cast((year(wr.writtendate)) as nvarchar(max)) + (case when month(wr.writtendate) > month(@enddate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end,
wr.adviser, wr.firm,
case when wr.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when wr.reportingproductname like '%Platform%' then 'Platform Mortgages' when wr.reportingproductname like '%Scottish Widows%' then 'Scottish Widows Bank' when wr.reportingproductname like '%Fleet%' then 'Fleet Mortgages' when wr.reportingproductname like '%Kent Reliance%' then 'Kent Reliance' when wr.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when wr.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when wr.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when wr.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when wr.reportingproductname like '%Santander%' then 'Santander for Intermediaries' when wr.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when wr.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society' when wr.reportingproductname like '%Northern Rock%' then 'Virgin Money' when wr.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when wr.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when wr.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when wr.reportingproductname like '%Godiva%' then 'Coventry' when wr.reportingproductname like '%Principality%' then 'Principality' when wr.reportingproductname like '%lloyds TSB%' then 'TSB' when wr.reportingproductname like '%Precise%' then 'Precise' when wr.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when wr.reportingproductname = 'BOI' THEN 'Bank of Ireland' when wr.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(wr.reportingproductname,' Mortgages',''),' (TBMC)','') end,
(cast((month(wr.writtendate)) as nvarchar(max)) + cast((year(wr.writtendate)) as varchar(max))),
year(wr.writtendate), month(wr.writtendate),
wr.NBCases,
wr.caseid,
wr.MortgageCategory, wr.mortgagetype, wr.InterestType,
Case When wr.MortgageCategory in('Buy to Let', 'BTL') THEN (case when wr.LVRatio is null then 'PREOWS' when wr.LVRatio = '5.5' then 'PREOWS' when wr.LVRatio < '61' then '0-60%' when wr.LVRatio < '71' then '61-70%' when wr.LVRatio < '76' then '71-75%' when wr.LVRatio < '81' then '76-80%' when wr.LVRatio < '91' then '81-90%' when wr.LVRatio  >= '91' then '91+%' else 'PREOWS' end) ELSE  (case when wr.LVRatio is null then 'PREOWS' when wr.LVRatio = '5.5' then 'PREOWS' when wr.LVRatio < '61' then '0-60%' when wr.LVRatio < '71' then '61-70%' when wr.LVRatio < '81' then '71-80%' when wr.LVRatio < '91' then '81-90%' when wr.LVRatio  >= '91' then '91+%' else 'PREOWS' end) END,
case when wr.dealperiod = 5.5 then 'PREOWS' when wr.dealperiod < 24 then '12m-23m' when wr.dealperiod < 36 then '24m-35m' when wr.dealperiod < 60 then '36m-59m' when wr.dealperiod >= 60 then '60m+' else 'PREOWS' end,
wr.MortgageTransaction

order by year(wr.writtendate), month(wr.writtendate)

