and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_ProductHierarchy ph ON cs.ProductCode = ph.ProductCode LEFT OUTER JOIN
mstt_ProductHierarchy ph2 ON ag.tranproduct = ph2.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp2 ON rp2.Code = ph2.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = cs.commshapeid LEFT OUTER JOIN
msit_CodeCommissionShape ccc ON ccc.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid LEFT OUTER JOIN
dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN
dbo.sa_ows_policies opol ON opol.PolicyID = po.policyref LEFT OUTER JOIN
--Policy.sa_ows_MortgageProductSummary mop on mop.policyid = opol.PolicyID LEFT OUTER JOIN
dbo.vw_ows_MortgageProductSummary mop on mop.policyid = opol.PolicyID LEFT OUTER JOIN
StaticData.sa_ows_InputValues IV on IV.inputid = mop.mortgagecategoryid
 
where 
oa.createdate >= @StartDate
and oa.createdate <= @EndDate
and cs.oastatus = 'valid'
and (oa.remarks <> 'claw' or oa.remarks is null)
and oa.source = 'openwork 2006'
and cs.inissued <> 0
and ag.derivedmarginamount is NOT NULL
and ph.productgroupname = 'Mortgage'
--and ag.caseid = '1367714'
--and ag.comp_code in ('Sterling', 'SIML', 'ZLA')

group by
ag.agent_code, iv.valuename, --ag.commissiontypedesc, b.transactionid, co.businessreason,co2.businessreason, co.adminmethoddescription,co2.adminmethoddescription,ag.transactionid, ag.derivedagentsplit,cs.ape,pt.mortgageamount,
Case 

when ag.firm = '1000941' then '1007791' when ag.firm = '1000976' then '2001655' when ag.firm = '1001619' then '2001460' when ag.firm = '1001747' then '1006123' when ag.firm = '1001860' then '2000914' when ag.firm = '1001931' then '2001142' when ag.firm = '1002683' then '2001252' when ag.firm = '1002866' then '2001140' when ag.firm = '1002958' then '1002961' when ag.firm = '1003038' then '2001543' when ag.firm = '1003450' then '2001454' when ag.firm = '1004284' then '1000392' when ag.firm = '1005445' then '2001002' when ag.firm = '1010723' then '1001338' when ag.firm = '1000746' then '1011544' when ag.firm = '1002578' then '2001476' when ag.firm = '1002580' then '1011548' when ag.firm = '2000508' then '1004215'
when ag.firm = '1001374' then '2001538' when ag.firm = '1000981' then '2000425' when ag.firm = '2000522' then '2001536' when ag.firm = '1009210' then '2001543' when ag.firm = '1001167' then '2001540' when ag.firm = '1001789' then '2001395' when ag.firm = '1002076' then '2001475' when ag.firm = '1001058' then '2001549' when ag.firm = '1011487' then '2001497' when ag.firm = '1000821' then '1011541' when ag.firm = '1000692' then '2001575' when ag.firm = '1007638' then '2001578' when ag.firm = '1001804' then '2001582' when ag.firm = '1000794' then '2001580' when ag.firm = '1001492' then '2001584' when ag.firm = '1011448' then '2001585' when ag.firm = '1011540' then '1001897' when ag.firm = '1002178' then '2001613'
when ag.firm = '1000967' then '2001653' when ag.firm = '2001040' then '2001655' when ag.firm = '1001891' then '2001714' when ag.firm = '1002112' then '2001807' when ag.firm = '1000867' then '1011604' when ag.firm = '1011608' then '1010815' when ag.firm = '1001049' then '2001995' when ag.firm = '1000724' then '1004141' when ag.firm = '1001346' then '1009425' when ag.firm = '1000678' then '2004388' when ag.firm = '1000704' then '1003010' when ag.firm = '1008026' then '1001546' when ag.firm = '1002702' then '2001504' when ag.firm = '2000988' then '1001249' when ag.firm = '2001397' then '2004449' when ag.firm = '2001518' then '2006569' when ag.firm = '2005389' then '2006353' when ag.firm = '1002174' then '2006794'
when ag.firm = '1009620' then '2010099' when ag.firm = '1007327' then '2011344'

else ag.firm End,

cast((year(oa.createdate)) as nvarchar(max)) + (case when month(oa.createdate) > month(@enddate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,oa.createdate),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,oa.createdate),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end,

case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Platform%' then 'Platform Mortgages' when rp.reportingproductname like '%Scottish Widows%' then 'Scottish Widows Bank' when rp.reportingproductname like '%Fleet%' then 'Fleet Mortgages' when rp.reportingproductname like '%Kent Reliance%' then 'Kent Reliance' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Santander%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society' when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Principality%' then 'Principality' when rp.reportingproductname like '%lloyds TSB%' then 'TSB' when rp.reportingproductname like '%Precise%' then 'Precise' when rp.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when rp.reportingproductname = 'BOI' THEN 'Bank of Ireland' when rp.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end,
(cast((month(oa.createdate)) as nvarchar(max)) + cast((year(oa.createdate)) as varchar(max)))


--- WRITTEN CLIENT DATA

select
Stat = 'Written',
year(wr.Writtendate) as year,
month(wr.Writtendate) as month,
sum(wr.NBcases), 
MortgageLoanAmount = '',
wr.Postcode,
wr.ProductName as ProviderName

from


(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate, min(po.prop_date) as PropDate, min(co.issuedDate) as IssuedDate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
min((pt.mortgageamount) * (co.Agent_Perc/100)) as MortgageAmount,
round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) as distributionallowance, min(co.baseamount + co.upliftamount) AS NBI, min(co.salesmargin) as margin, 
max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases", 
max((co.agent_perc/100)) as "AllCases", min(pt.FrequencyDescription) as frequency, min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD,
min(Cl.Title) as Title, min(cl.Firstnames) as FirstName, min(cl.Name) as Name, min(cl.Address1) as Address1, min(cl.Address2) as Address2, min(cl.Address3) as Address3, min(cl.Address4) as Address4, min(cl.Address5) as Address5, min(cl.Postcode) as Postcode, min(cl.birthdate) as Birthdate,
case when ph.ProductName like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when ph.ProductName like '%Platform%' then 'Platform Mortgages' when ph.ProductName like '%Scottish Widows%' then 'Scottish Widows Bank' when ph.ProductName like '%Fleet%' then 'Fleet Mortgages' when ph.ProductName like '%Kent Reliance%' then 'Kent Reliance' when ph.ProductName like '%Nationwide Mortgages%' then 'Nationwide Building Society' when ph.ProductName like '%Natwest Mortgages%' then 'Natwest' when ph.ProductName like '%Progressive Mortgages%' then 'Progressive Building Society' when ph.ProductName like '%Abbey Mortgages%' then 'Santander for Intermediaries' when ph.ProductName like '%Santander%' then 'Santander for Intermediaries' when ph.ProductName like '%Skipton Mortgages%' then 'Skipton Building Society' when ph.ProductName like '%Skipton (Buildstore)%' then 'Skipton Building Society' when ph.ProductName like '%Northern Rock%' then 'Virgin Money' when ph.ProductName like '%Platform%' then 'Platform (Co-op Bank)' when ph.ProductName like '%BM Solutions%' then 'BM Solutions (LBG)' when ph.ProductName like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when ph.ProductName like '%Godiva%' then 'Coventry' when ph.ProductName like '%Principality%' then 'Principality' when ph.ProductName like '%lloyds TSB%' then 'TSB' when ph.ProductName like '%Precise%' then 'Precise' when ph.ProductName like '%Newcastle%' then 'Newcastle Building Society' when ph.ProductName = 'BOI' THEN 'Bank of Ireland' when ph.ProductName like '%Woolwich%' then 'Barclays' else replace(replace(ph.ProductName,' Mortgages',''),' (TBMC)','') end as ProductName

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where  
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), case when ph.ProductName like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when ph.ProductName like '%Platform%' then 'Platform Mortgages' when ph.ProductName like '%Scottish Widows%' then 'Scottish Widows Bank' when ph.ProductName like '%Fleet%' then 'Fleet Mortgages' when ph.ProductName like '%Kent Reliance%' then 'Kent Reliance' when ph.ProductName like '%Nationwide Mortgages%' then 'Nationwide Building Society' when ph.ProductName like '%Natwest Mortgages%' then 'Natwest' when ph.ProductName like '%Progressive Mortgages%' then 'Progressive Building Society' when ph.ProductName like '%Abbey Mortgages%' then 'Santander for Intermediaries' when ph.ProductName like '%Santander%' then 'Santander for Intermediaries' when ph.ProductName like '%Skipton Mortgages%' then 'Skipton Building Society' when ph.ProductName like '%Skipton (Buildstore)%' then 'Skipton Building Society' when ph.ProductName like '%Northern Rock%' then 'Virgin Money' when ph.ProductName like '%Platform%' then 'Platform (Co-op Bank)' when ph.ProductName like '%BM Solutions%' then 'BM Solutions (LBG)' when ph.ProductName like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when ph.ProductName like '%Godiva%' then 'Coventry' when ph.ProductName like '%Principality%' then 'Principality' when ph.ProductName like '%lloyds TSB%' then 'TSB' when ph.ProductName like '%Precise%' then 'Precise' when ph.ProductName like '%Newcastle%' then 'Newcastle Building Society' when ph.ProductName = 'BOI' THEN 'Bank of Ireland' when ph.ProductName like '%Woolwich%' then 'Barclays' else replace(replace(ph.ProductName,' Mortgages',''),' (TBMC)','') end) wr

where
wr.writtendate >= @StartDate
and wr.writtendate <= @EndDate	
--and wr.firm = '1001602'
--and wr.adviser = '1000000'
and wr.productgroupname = 'Mortgage'

group by year(wr.Writtendate),
month(wr.Writtendate),
wr.Postcode,
wr.ProductName

order by year(wr.Writtendate), month(wr.Writtendate)


--- ISSUED CLIENT DATA

select
Stat = 'Issued',
year(ag.createdatetime) as year,
month(ag.createdatetime) as month,
sum(case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end) as "NB Cases",
sum(pt.mortgageamount * (ag.derivedagentsplit/100)) as MortgageLoanAmount,
cl.Postcode,
case when ph.ProductName like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when ph.ProductName like '%Platform%' then 'Platform Mortgages' when ph.ProductName like '%Scottish Widows%' then 'Scottish Widows Bank' when ph.ProductName like '%Fleet%' then 'Fleet Mortgages' when ph.ProductName like '%Kent Reliance%' then 'Kent Reliance' when ph.ProductName like '%Nationwide Mortgages%' then 'Nationwide Building Society' when ph.ProductName like '%Natwest Mortgages%' then 'Natwest' when ph.ProductName like '%Progressive Mortgages%' then 'Progressive Building Society' when ph.ProductName like '%Abbey Mortgages%' then 'Santander for Intermediaries' when ph.ProductName like '%Santander%' then 'Santander for Intermediaries' when ph.ProductName like '%Skipton Mortgages%' then 'Skipton Building Society' when ph.ProductName like '%Skipton (Buildstore)%' then 'Skipton Building Society' when ph.ProductName like '%Northern Rock%' then 'Virgin Money' when ph.ProductName like '%Platform%' then 'Platform (Co-op Bank)' when ph.ProductName like '%BM Solutions%' then 'BM Solutions (LBG)' when ph.ProductName like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when ph.ProductName like '%Godiva%' then 'Coventry' when ph.ProductName like '%Principality%' then 'Principality' when ph.ProductName like '%lloyds TSB%' then 'TSB' when ph.ProductName like '%Precise%' then 'Precise' when ph.ProductName like '%Newcastle%' then 'Newcastle Building Society' when ph.ProductName = 'BOI' THEN 'Bank of Ireland' when ph.ProductName like '%Woolwich%' then 'Barclays' else replace(replace(ph.ProductName,' Mortgages',''),' (TBMC)','') end as ProviderName



from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM LEFT OUTER JOIN
mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate
and ag.amount <> 0
--and ag.commissiontype in ('1','4','10','17','18','19')
and (cs.oastatus = 'valid' or cs.oastatus is null)
and ---DA INITAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
-- DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end <> 0

and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 
--and ag.providerref in ('D-508867','62104292','62104514','769673Z','D-512291')

and case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end = 'Mortgage'



group by
year(ag.createdatetime),
month(ag.createdatetime),
cl.Postcode,
case when ph.ProductName like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when ph.ProductName like '%Platform%' then 'Platform Mortgages' when ph.ProductName like '%Scottish Widows%' then 'Scottish Widows Bank' when ph.ProductName like '%Fleet%' then 'Fleet Mortgages' when ph.ProductName like '%Kent Reliance%' then 'Kent Reliance' when ph.ProductName like '%Nationwide Mortgages%' then 'Nationwide Building Society' when ph.ProductName like '%Natwest Mortgages%' then 'Natwest' when ph.ProductName like '%Progressive Mortgages%' then 'Progressive Building Society' when ph.ProductName like '%Abbey Mortgages%' then 'Santander for Intermediaries' when ph.ProductName like '%Santander%' then 'Santander for Intermediaries' when ph.ProductName like '%Skipton Mortgages%' then 'Skipton Building Society' when ph.ProductName like '%Skipton (Buildstore)%' then 'Skipton Building Society' when ph.ProductName like '%Northern Rock%' then 'Virgin Money' when ph.ProductName like '%Platform%' then 'Platform (Co-op Bank)' when ph.ProductName like '%BM Solutions%' then 'BM Solutions (LBG)' when ph.ProductName like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when ph.ProductName like '%Godiva%' then 'Coventry' when ph.ProductName like '%Principality%' then 'Principality' when ph.ProductName like '%lloyds TSB%' then 'TSB' when ph.ProductName like '%Precise%' then 'Precise' when ph.ProductName like '%Newcastle%' then 'Newcastle Building Society' when ph.ProductName = 'BOI' THEN 'Bank of Ireland' when ph.ProductName like '%Woolwich%' then 'Barclays' else replace(replace(ph.ProductName,' Mortgages',''),' (TBMC)','') end

drop table #b

GO
