when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) in ('IFDL')) then 'Plt: IFDL Platform' when co.productcode = 'OFHBSIPP' then 'Plt: IFDL Platform' when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Plt: Zurich Platform' when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife') then 'Off: Metlife' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(tranproduct,2) = 'OF')) then 'Off: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Off: Other Comm' 

-- Annuities
when isnull(co.productprovidercode,ag.comp_code) = 'PTSP' then 'Ann: Partnership' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'Pru')) then 'Ann: Pru' when isnull(co.productprovidercode,ag.comp_code) = 'MGMA' then 'Ann: MGMA' when ph.productsubgroupname like '%Annuity%' then 'Ann: Other' 

-- Investments
when (ph.productgroupname = 'Investment' and (isnull(co.productprovidercode,ag.comp_code) = 'IFDL' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') ) then 'Plt: IFDL Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Plt: Zurich Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Off: PruFund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Off: Structured' when (ph.productgroupname = 'Investment' and (left(tranproduct,2) = 'OF')) then 'Off: Other Fee' when ph.productgroupname = 'Investment' then 'Off: Other Comm'

when ph.productgroupname = 'Mortgage' then 'Mortgages' else ph.productsubgroupname end


UNION ALL

