min(coalesce(po.originatingsource,0)) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname = 'Guaranteed Account' or rp.reportingproductname = 'Zurich Bank Structured Product') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(coalesce(ccs.calculationcode,'')) as calculationcode, min(coalesce(ccs.description,'')) as description

