---ADVISER ISSUED-----------------------------------------------------------------------------------------------

select
"Type" = 'Issued',

case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end as agent_code,

month(ag.createdatetime)as month, year(ag.createdatetime) as year,
case when ag.agent_code = '1011587' then 'BSC'  when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end,

case when ag.agent_code = '1011587' then 'BSC' when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' when ag.commissiontype in ('4','15','18') then 'Legacy Recurring'

-- Protection
when (left((replace(ccs.description,'do not use - ','')),3) = '005' and ag.firm <> '1000311') then 'Pro: Openwork Select' when left((replace(ccs.description,'do not use - ','')),3) = '002' then 'Pro: IFA Panel' when Left(co.productcode,3) = 'PNL' then 'Pro: IFA Panel' when (isnull(co.productprovidercode,ag.comp_code) = 'L&G' and ph.productgroupname = 'Protection') then 'Pro: NASP L&G' when ph.productgroupname = 'Protection' then 'Pro: Zurich Plus' 

-- Pensions
when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) in ('IFDL')) then 'Plt: IFDL Platform' when co.productcode = 'OFHBSIPP' then 'Plt: IFDL Platform' when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Plt: Zurich Platform' when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife') then 'Off: Metlife' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(tranproduct,2) = 'OF')) then 'Off: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Off: Other Comm' 

-- Annuities
when isnull(co.productprovidercode,ag.comp_code) = 'PTSP' then 'Ann: Partnership' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'Pru')) then 'Ann: Pru' when isnull(co.productprovidercode,ag.comp_code) = 'MGMA' then 'Ann: MGMA' when ph.productsubgroupname like '%Annuity%' then 'Ann: Other' 

-- Investments
when (ph.productgroupname = 'Investment' and (isnull(co.productprovidercode,ag.comp_code) = 'IFDL' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT')) then 'Plt: IFDL Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Plt: Zurich Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Off: PruFund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Off: Structured' when (ph.productgroupname = 'Investment' and (left(tranproduct,2) = 'OF')) then 'Off: Other Fee' when ph.productgroupname = 'Investment' then 'Off: Other Comm'

when ph.productgroupname = 'Mortgage' then 'Mortgages' else ph.productsubgroupname end as 'productsubgroup',

sum(case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) when (ph.ProductGroupName = 'Mortgage' AND ag.commissiontype = 2) then (round((cs.inissued/ag.amount),0) *ag.derivedmarginamount) else 0 end) as 'Gross DA',

-- GROSS MARGIN INITIAL
sum(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
-- GROSS MARGIN TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
-- GROSS MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) when (ph.ProductGroupName = 'Mortgage' AND ag.commissiontype = 2) then (round((cs.inissued/ag.amount),0) *ag.derivedmarginamount) else 0 end) as 'Gross Margin (Pre Claw)',

sum(case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end) as "NB Cases"

from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_Commissions co3 on co3.transactionid = ag.transactionid 
and co3.agent_code = pt.agentcode
and co3.commissiontype = ag.commissiontype 
and co3.firm <> '1011543' LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate		
and (ag.agent_code <> '10002' or ag.agent_code <> '1011623')
and ag.amount <> 0
and (co2.id not in ('17797514','17797515') or co2.id is NULL)
and (co3.id not in ('17797514','17797515') or co3.id is NULL)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
and ag.commissiontype in ('1','4','10','17','18','19')
and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 
and (case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT like '%Group Pension%' then 1 when (ph.productsubgroupname like '%Group Pension%'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by

case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end,
month(ag.createdatetime), year(ag.createdatetime),
case when ag.agent_code = '1011587' then 'BSC'  when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end,

case when ag.agent_code = '1011587' then 'BSC' when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' when ag.commissiontype in ('4','15','18') then 'Legacy Recurring'

-- Protection
when (left((replace(ccs.description,'do not use - ','')),3) = '005' and ag.firm <> '1000311') then 'Pro: Openwork Select' when left((replace(ccs.description,'do not use - ','')),3) = '002' then 'Pro: IFA Panel' when Left(co.productcode,3) = 'PNL' then 'Pro: IFA Panel' when (isnull(co.productprovidercode,ag.comp_code) = 'L&G' and ph.productgroupname = 'Protection') then 'Pro: NASP L&G' when ph.productgroupname = 'Protection' then 'Pro: Zurich Plus' 

-- Pensions
when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) in ('IFDL')) then 'Plt: IFDL Platform' when co.productcode = 'OFHBSIPP' then 'Plt: IFDL Platform' when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Plt: Zurich Platform' when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife') then 'Off: Metlife' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(tranproduct,2) = 'OF')) then 'Off: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Off: Other Comm' 

-- Annuities
when isnull(co.productprovidercode,ag.comp_code) = 'PTSP' then 'Ann: Partnership' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'Pru')) then 'Ann: Pru' when isnull(co.productprovidercode,ag.comp_code) = 'MGMA' then 'Ann: MGMA' when ph.productsubgroupname like '%Annuity%' then 'Ann: Other' 

-- Investments
when (ph.productgroupname = 'Investment' and (isnull(co.productprovidercode,ag.comp_code) = 'IFDL' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') ) then 'Plt: IFDL Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Plt: Zurich Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Off: PruFund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Off: Structured' when (ph.productgroupname = 'Investment' and (left(tranproduct,2) = 'OF')) then 'Off: Other Fee' when ph.productgroupname = 'Investment' then 'Off: Other Comm'

when ph.productgroupname = 'Mortgage' then 'Mortgages' else ph.productsubgroupname end

UNION ALL

---INSERT ZERO UPFRONT APE

select 
"Type" = 'Issued',
co.agent_code,

month(pt.createdatetime)as month, year(pt.createdatetime) as year,
case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(co.productcode,2) in ('OW','OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else ph.productgroupname end as 'ProductGroupName',

case
-- Pensions
when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'IFDL') then 'Plt: IFDL Platform' when co.productcode = 'OFHBSIPP' then 'Plt: IFDL Platform' when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'Zurich PLT') then 'Plt: Zurich Platform' when (co.productprovidercode = 'MetLife') then 'Off: Metlife' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Off: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Off: Other Comm' 

-- Annuities
when co.productprovidercode = 'PTSP' then 'Ann: Partnership' when (ph.productsubgroupname like '%Annuity%' and co.productprovidercode = 'Pru') then 'Ann: Pru' when co.productprovidercode = 'MGMA' then 'Ann: MGMA' when ph.productsubgroupname like '%Annuity%' then 'Ann: Other' 

-- Investments
when (ph.productgroupname = 'Investment' and (co.productprovidercode = 'IFDL' or co.productprovidercode = 'Pru PLT')) then 'Plt: IFDL Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Zurich PLT') then 'Plt: Zurich Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Pru') then 'Off: PruFund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Off: Structured' when (ph.productgroupname = 'Investment' and (left(co.productcode,2) = 'OF')) then 'Off: Other Fee' when ph.productgroupname = 'Investment' then 'Off: Other Comm'

when ph.productgroupname = 'Mortgage' then 'Mortgages' when ph.productgroupname = 'Protection' then 'Protection' else ph.productsubgroupname end as 'productsubgroup',

"Gross DA" = 0, "Gross Margin" = 0,
sum(case when b.transactionid is null then 0 when (co.businessreason = 'I' and co.adminmethoddescription <> 'Not Sold By This Office' and co.adminmethoddescription <> 'Execution Only Increase') then 0 when co.ape = 0 then 0 when co.ape > 0 and co.transactionid = b.transactionid then co.agent_perc/100 else 0 end) as "NB Cases"

from 
mstt_Commissions co LEFT OUTER JOIN
mstt_Policytransactions pt on co.transactionid = pt.id LEFT OUTER JOIN
mstt_Policies po on pt.policyid = po.pol_num LEFT OUTER JOIN
mstt_ProductHierarchy ph ON co.ProductCode = ph.productcode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = co.transactionid


where
co.agent_code <> '10002'
and pt.createdatetime >= @StartDate
and pt.createdatetime <= @EndDate
and co.commissiontype = 1
and ph.rdrtype is not null
and pt.comminitialamount <= 0 and pt.amount > 0
and co.poltrantranstype = 17
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT like '%Group Pension%' then 1 when (ph.productsubgroupname like '%Group Pension%'and year(pt.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by 
co.agent_code,
month(pt.createdatetime), year(pt.createdatetime),
case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(co.productcode,2) in ('OW','OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else ph.productgroupname end,
case
-- Pensions
when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'IFDL') then 'Plt: IFDL Platform' when co.productcode = 'OFHBSIPP' then 'Plt: IFDL Platform' when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'Zurich PLT') then 'Plt: Zurich Platform' when (co.productprovidercode = 'MetLife') then 'Off: Metlife' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Off: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Off: Other Comm' 

-- Annuities
when co.productprovidercode = 'PTSP' then 'Ann: Partnership' when (ph.productsubgroupname like '%Annuity%' and co.productprovidercode = 'Pru') then 'Ann: Pru' when co.productprovidercode = 'MGMA' then 'Ann: MGMA' when ph.productsubgroupname like '%Annuity%' then 'Ann: Other' 

-- Investments
when (ph.productgroupname = 'Investment' and (co.productprovidercode = 'IFDL' or co.productprovidercode = 'Pru PLT')) then 'Plt: IFDL Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Zurich PLT') then 'Plt: Zurich Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Pru') then 'Off: PruFund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Off: Structured' when (ph.productgroupname = 'Investment' and (left(co.productcode,2) = 'OF')) then 'Off: Other Fee' when ph.productgroupname = 'Investment' then 'Off: Other Comm'

when ph.productgroupname = 'Mortgage' then 'Mortgages' when ph.productgroupname = 'Protection' then 'Protection' else ph.productsubgroupname end

UNION ALL

---LEGACY

select
"Type" = 'Issued', 
oa.sellercode,
month(oa.month) as "month", year(oa.month) as "year", 

case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off-Platform' when oa.provider='Sterling' then 'COB Off-Platform' when oa.provider='Scottish Equitable' then 'COB Off-Platform' when oa.prodtype = 'PE' then 'COB Off-Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else isNull(ph.productgroupname,'Protection') end as productgroupname,
case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'Legacy Off' when oa.provider='Sterling' then 'Legacy Off' when oa.provider='Scottish Equitable' then 'Legacy Off' when oa.prodtype = 'PE' then 'Legacy Annuity' else (case when ph.productgroupname = 'Pensions' then 'Legacy Off' when ph.productgroupname = 'Investment' then 'Legacy Off' else 'Legacy Protection' end) end 
as "productsubgroupname",

sum(case when ph.productgroupname = 'Mortgage' then oa.ape else oa.totdue_enhd/0.8163 end) as "Gross DA",
sum(case when ph.productgroupname = 'Mortgage' then oa.ape - oa.totdue_enhd else ((oa.totdue_enhd/0.8163) - oa.totdue_enhd) end) as "Gross Margin (Pre Claw)",
"Issued Cases" = 0

from msit_openworkadviserlisting oa left outer join 
msit_feesNonSwiftFeeListing fnsfl on fnsfl.ID = oa.sourceID left outer join
mstt_producthierarchy ph on 'NBI_'+ fnsfl.productCode = ph.productCode left outer join
cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode left outer join
cscv_AgentsHierarchy ah1 ON oa.sellercode = ah1.agentcode

where
(oa.month
BETWEEN @StartDate
AND @EndDate)
and oa.feetype <> 'RC'
and oa.feetype <> 'Trail'
and oa.feetype <> 'TF'
and oa.source = 'openwork 2005'
and oa.providercode <> 'GI'
and ((ape + totdue_enhd) <> 0)
and (fnsfl.id <> '27617494' or fnsfl.id is NULL)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT like '%Group Pension%' then 1 when (ph.productsubgroupname like '%Group Pension%'and year(oa.month) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------
group by 
oa.sellercode,
month(oa.month), year(oa.month),
case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off-Platform' when oa.provider='Sterling' then 'COB Off-Platform' when oa.provider='Scottish Equitable' then 'COB Off-Platform' when oa.prodtype = 'PE' then 'COB Off-Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else isNull(ph.productgroupname,'Protection') end,
case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'Legacy Off' when oa.provider='Sterling' then 'Legacy Off' when oa.provider='Scottish Equitable' then 'Legacy Off' when oa.prodtype = 'PE' then 'Legacy Annuity' else (case when ph.productgroupname = 'Pensions' then 'Legacy Off' when ph.productgroupname = 'Investment' then 'Legacy Off' else 'Legacy Protection' end) end 


UNION ALL

---GI

select
"Type" = 'Issued', 
oa.sellercode,
month(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end) as 'month', year(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end) as 'year',
"ProductGroupName" = 'GI',
"ProductSubGroupName" = 'GI',
sum(case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else ape end) as "Gross DA",
sum(case when (businesscode <> '1010904' AND rtrim(ah.asdname) = 'GHL') then (case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end- (totdue_enhd))-((case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end - (totdue_enhd)) *0.7) when rtrim(ah.asdname) = 'First Affinity' then (case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end - (totdue_enhd)) -((totdue_enhd)*(10.0/9) - (totdue_enhd)) else case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end - (totdue_enhd) end) as "Gross Margin (Pre Claw)", 
sum((case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end)/121) as "NB Cases"
from msit_openworkadviserlisting oa LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode

where
(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end
BETWEEN @StartDate
AND @EndDate)
and oa.providercode in ('GI', 'Payment shield', 'PYMTSHLD')
and feetype <> 'RC'
and feetype <> 'Trail'
and feetype <> 'TF'
and APE <> 0
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)

group by 
oa.sellercode,
month(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end), year(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end)

UNION ALL

-------Issued Mortgage Broker Fee ---------------------------------

Select Distinct 
"Type" = 'Issued',
--cast((month(MBF.PaymentMatchedDate)) as nvarchar(max)) + cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + 'Mortgage Broker Fee' AS Concat,
--cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + (case when month(MBF.PaymentMatchedDate) > month(@enddate) then 'NOT YTD' else 'YTD' end) as "YTD",
--case when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end as "Rolling",
MBF.AdviserUID, 
--ah.AgentDesc as AgentName,
--MBF.FirmUID,
--ah2.agentDesc as FirmName, 
Month(MBF.PaymentMatchedDate) as "Month", 
Year(MBF.PaymentMatchedDate) as "Year",
'Mortgage Broker Fee' as productgroupname,
'Mortgage Broker Fee' as productgroupname2,
SUM(MBF.APE) as 'Gross DA',
SUM(MBF.DeductionAmount*-1) as 'Gross Margin (Pre Claw)', 
--0 as 'Written NB APE',
--0 as 'Written NB Cases',
--SUM(MBF.APE) as 'Issued APE', 
SUM(MBF.AgentSplit)/100 as 'NB Cases'
--SUM(MBF.AgentSplit)/100 as 'Cases',

--0 as 'DA Claw',
--SUM(MBF.APE) as 'Net DA', 
--SUM(MBF.AdviceFeeAmount+MBF.DeductionAmount) as 'Gross Comm',
--0 as 'Comm Claw',
--SUM(MBF.AdviceFeeAmount+MBF.DeductionAmount) as 'Net Comm',
--SUM(MBF.DeductionAmount*-1) as 'Gross Margin (Pre Claw)',
--0 as 'Margin Claw',
--0 as 'Comm Adj',
--SUM(MBF.DeductionAmount*-1) as 'Gross Margin',
--0 as 'Net Charges',
--SUM(MBF.DeductionAmount*-1) as 'Contribution',
--case when sum(oa.totalpayment) is null then 0 else sum(oa.totalpayment) end as 'Paid'

FROM dbo.owt_MortgageBrokerFees MBF left outer join
     mstt_paymentspending ag ON ag.transactionid = MBF.transactionid AND ag.AGENT_CODE = 10002  LEFT OUTER JOIN
	 mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
	 msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
	 cscv_AgentsHierarchy ah ON MBF.AdviserUID = ah.agentcode LEFT OUTER JOIN
	 cscv_AgentsHierarchy ah2 ON MBF.FirmUID = ah2.agentcode  LEFT OUTER JOIN
	 msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
	 msit_openworkadviserlisting oa ON oa.sourceid = cs.id

where
(MBF.PaymentMatchedDate) >= @StartDate
and (MBF.PaymentMatchedDate) <= @EndDate
and MBF.AdviceFeeCharged = 'Yes'

GROUP BY MBF.AdviserUID, 
--MBF.FirmUID, 
Month(MBF.PaymentMatchedDate), 
Year(MBF.PaymentMatchedDate)
--ph.productsubgroupname, ph.productgroupname,
--cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + (case when month(MBF.PaymentMatchedDate) > month(@enddate) then 'NOT YTD' else 'YTD' end),
--case when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end,
--ah.agentdesc,ah2.agentdesc


/*UNION ALL


---ADVISER WRITTEN

SELECT
"TYPE" = 'Written',
wr.adviser,

month(wr.writtendate) as month,
year(wr.writtendate) as year,

wr.productgroupname,

case
-- Protection
when (left((replace(wr.description,'do not use - ','')),3) = '005' and wr.firm <> '1000311') then 'Pro: Openwork Select' when left((replace(wr.description,'do not use - ','')),3) = '002' then 'Pro: IFA Panel' when Left(wr.productcode,3) = 'PNL' then 'Pro: IFA Panel' when (wr.provider = 'L&G' and wr.productgroupname = 'Protection') then 'Pro: NASP L&G' when wr.productgroupname = 'Protection' then 'Pro: Zurich Plus' 

-- Pensions
when (wr.productgroupname in ('Pensions','Other') and wr.provider = 'IFDL') then 'Pen: IFDL Platform' when wr.productcode = 'OFHBSIPP' then 'Pen: IFDL Platform' when (wr.productgroupname in ('Pensions','Other') and wr.provider = 'Zurich PLT') then 'Pen: Zurich Platform' when (wr.provider = 'MetLife') then 'Pen: Metlife' when (wr.productgroupname in ('Pensions','Other') and wr.productsubgroupname not like '%Annuity%') then 'Pen: Other'

-- Annuities
when (wr.provider = 'PTSP') then 'Ann: Partnership' when (wr.provider = 'Pru' and wr.productsubgroupname like '%Annuity%') then 'Ann: Pru' when (wr.productsubgroupname like '%Annuity%') then 'Ann: Other'

-- Investments
when (wr.productgroupname = 'Investment' and wr.provider = 'IFDL') then 'Inv: IFDL Platform' when (wr.productgroupname = 'Investment' and wr.provider = 'Zurich PLT') then 'Inv: Zurich Platform' when (wr.productgroupname = 'Investment' and wr.provider = 'Pru') then 'Inv: PruFund' when (wr.productgroupname = 'Investment' and wr.productsubgroupname like 'Guaranteed Account') then 'Inv: Structured' when (wr.productgroupname = 'Investment') then 'Inv: Other'

when wr.productgroupname = 'Mortgage' then 'Mortgages' else 'PLEASE ALLOCATE' end as 'productsubgroup',


sum(wr.WrittenAPE) as "APE", 
"Gross DA" = 0,
"Gross Margin" = 0,

sum(wr.WrittenCases) as Cases 

from

(SELECT 
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm, 
min(co.transactionid) as transactionid, min(pt.writtendate) as "writtendate", 
round(co.Turnover,2) as writtenape,
min(co.distributionallowance) as distributionallowance, min(co.baseamount + co.upliftamount) AS NBI, min(co.salesmargin) as margin, min(co.Agent_Perc/100) as "Old Cases", max(case when pt.transactionnumber = 1 then (co.agent_perc/100) else 0 end) as "writtencases", min(pt.FrequencyDescription) as frequency, 
po.PolicyRef AS CaseID,
po.CONT_NUM AS Policy,
min(co.BusinessReason) as businessreason, min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(CASE WHEN ph.productsubgroupname like '%Annuity' THEN 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' ELSE ph.ProductGroupName END) as "productgroupname",
min(coalesce(po.originatingsource,0)) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname = 'Guaranteed Account' or rp.reportingproductname = 'Zurich Bank Structured Product') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(coalesce(ccs.calculationcode,'')) as calculationcode, min(coalesce(ccs.description,'')) as description

FROM         dbo.mstt_Commissions co INNER JOIN
			 dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			 dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			 dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		     dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			 dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			 dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			 cscv_AgentsHierarchy ah ON co.firm = ah.agentcode


where  
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39	
and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)

group by cast(co.AGENT_CODE as int), round(co.turnover,2), po.policyref, po.cont_num) wr

where
wr.writtendate >= @StartDate
and wr.writtendate < @EndDate	

Group by
wr.adviser,

month(wr.writtendate),
year(wr.writtendate),

wr.productgroupname,


case
-- Protection
when (left((replace(wr.description,'do not use - ','')),3) = '005' and wr.firm <> '1000311') then 'Pro: Openwork Select' when left((replace(wr.description,'do not use - ','')),3) = '002' then 'Pro: IFA Panel' when Left(wr.productcode,3) = 'PNL' then 'Pro: IFA Panel' when (wr.provider = 'L&G' and wr.productgroupname = 'Protection') then 'Pro: NASP L&G' when wr.productgroupname = 'Protection' then 'Pro: Zurich Plus' 

-- Pensions
when (wr.productgroupname in ('Pensions','Other') and wr.provider = 'IFDL') then 'Pen: IFDL Platform' when wr.productcode = 'OFHBSIPP' then 'Pen: IFDL Platform' when (wr.productgroupname in ('Pensions','Other') and wr.provider = 'Zurich PLT') then 'Pen: Zurich Platform' when (wr.provider = 'MetLife') then 'Pen: Metlife' when (wr.productgroupname in ('Pensions','Other') and wr.productsubgroupname not like '%Annuity%') then 'Pen: Other'

-- Annuities
when (wr.provider = 'PTSP') then 'Ann: Partnership' when (wr.provider = 'Pru' and wr.productsubgroupname like '%Annuity%') then 'Ann: Pru' when (wr.productsubgroupname like '%Annuity%') then 'Ann: Other'

-- Investments
when (wr.productgroupname = 'Investment' and wr.provider = 'IFDL') then 'Inv: IFDL Platform' when (wr.productgroupname = 'Investment' and wr.provider = 'Zurich PLT') then 'Inv: Zurich Platform' when (wr.productgroupname = 'Investment' and wr.provider = 'Pru') then 'Inv: PruFund' when (wr.productgroupname = 'Investment' and wr.productsubgroupname like 'Guaranteed Account') then 'Inv: Structured' when (wr.productgroupname = 'Investment') then 'Inv: Other'

when wr.productgroupname = 'Mortgage' then 'Mortgages' else 'PLEASE ALLOCATE' end
*/

drop table #b

GO
/****** Object:  StoredProcedure [BI].[pr_047_OWSPlatformPruMetLife]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	47. OWS Platform Pru MetLife.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_047_OWSPlatformPruMetLife]

as

IF OBJECT_ID('tempdb..#fee') IS NOT NULL
DROP TABLE #fee

IF OBJECT_ID('tempdb..#r') IS NOT NULL
DROP TABLE #r

set nocount on

declare @StartDate datetime,@EndDate datetime;
set @StartDate = CONVERT(DATETIME, '2013-01-01 00:00:00', 102) 
set @EndDate = CONVERT(DATETIME, '2019-01-31 23:59:59', 102)

Select s.SaleId,X.*,qr3.qrid as FeeQRID,qr3.questionid as FeeQuestionId,qr3.answertext as FeeRate
into #FEE
FROM sa_ows_Sale s
inner join sa_ows_Policies pol on pol.Saleid = s.SaleId
inner join (Select qr.PolicyID,qr.QuestionID,qr.qrid,
                  qr.QuestionRepeatNumber,qr.ParentQuestionID,qr.RepeatableQuestionGroup,
                  case when qr.QuestionID in (70,72,300,496,507,646,647,713,904,1204,1205,1504,1705) 
                  then isnull(qr.AnswerText,'') end as TransferAnswerText,
                  case when qr.QuestionID in (34,81,86,101,362,401,497,503,528,627,641,701,905,1501) 
                  then isnull(qr.AnswerText,'') end as OneOffAnswerText,
                  case when qr.QuestionID in (2,378,508) 
                  then isnull(qr.AnswerText,'') end as RegularAnswerText,
                  min(qr2.qrid) as NearestRateId
                  from dbo.sa_ows_HDRUI_QuestionnaireResponses qr
                  inner join StaticData.sa_ows_HDRUI_QuestionBank qb on qb.QuestionId = qr.QuestionID
                  inner join ( select policyid,QRID from sa_ows_HDRUI_QuestionnaireResponses
                                    where QuestionID in (505,506,511,522,524,525,529,706,715,1206,1502,1505,1706)) qr2 on qr2.policyid = qr.policyid and qr2.qrid > qr.qrid
                  where qb.QuestionTypeID in (6) --and qb.questiontext not like '%regular%' 
                  and qb.validationaction like '%maxlen=12%' 
                  and isnull(qr.AnswerText,'') <> '' and isnumeric(qr.AnswerText) = 1
                  group by qr.PolicyID,qr.QuestionID,qr.qrid,
                  qr.QuestionRepeatNumber,qr.ParentQuestionID,qr.RepeatableQuestionGroup,
                  case when qr.QuestionID in (70,72,300,496,507,646,647,713,904,1204,1205,1504,1705) 
                  then isnull(qr.AnswerText,'') end,
                  case when qr.QuestionID in (34,81,86,101,362,401,497,503,528,627,641,701,905,1501) 
                  then isnull(qr.AnswerText,'') end,
                  case when qr.QuestionID in (2,378,508) 
                  then isnull(qr.AnswerText,'') end) X on X.Policyid = pol.policyid
                  left join ( select policyid,qrid,questionid,answertext 
                                    from sa_ows_HDRUI_QuestionnaireResponses
                                    where QuestionID in (505,506,511,522,524,525,529,706,715,1206,1502,1505,1706)
                                    ) qr3 on qr3.policyid = X.policyid and qr3.qrid = X.NearestRateid
where S.SaleStatusId = 2
order by s.SaleId,x.PolicyId

select DISTINCT s.SaleId,pol.PolicyID,
case when ud.usr_externalid = '4001674' then '1011586' when ud.usr_externalid = '0072' then '1008203' when ud.usr_externalid = '1010321' then '1010897' when ud.usr_externalid = '1003604' then '1005181' else s.AdviserUID end as adviseruid,
ud.USR_Name as AdviserName,ag.Code as BusinessUID,rtrim(ltrim(coalesce(ag.tradingname,ag.descn))) as BusinessName
,case pol.PolicyOwnerType when 1 then 'Client' when 2 then 'Partner' when 3 then 'Joint' end as ClientType
,case when pol.PolicyOwnerType in (1,3) then ltrim(rtrim(p1.firstname)) + ' ' + ltrim(rtrim(p1.lastname)) end as ClientName
,case when pol.PolicyOwnerType in (2,3) then ltrim(rtrim(p2.firstname)) + ' ' + ltrim(rtrim(p2.lastname)) end as PartnerName
,prod.DisplayName as ProductSold,prov.ProviderCodeSwift as Provider,convert(date,s.DateSubmitted) DateSubmitted,LAT.LATType
,convert(float,isnull(replace(f.OneOffAnswerText, ',', ''),0.00)) as OneOffInvestment
,convert(float,isnull(replace(f.TransferAnswerText, ',', ''),0.00)) as TransferValue
,convert(float,isnull(replace(f.RegularAnswerText, ',', ''),0.00)) as RegularPremium
,case when ab6.AnswerId > 0 then ab6.AnswerText end as RegularPremiumFrequency
,convert(float,isnull(replace(f.FeeRate, ',', ''),0.00)) as FeeRate
,case when ua.FeeType = 65 and sl.UnderstandingAnalysisFlatFee > 0 then 'Flat Fee' when ua.FeeType = 66 and ua.Hours > 0 then 'Hourly' end as UAType
,

case when ua.FeeType = 65 and sl.UnderstandingAnalysisFlatFee > 0 then sl.UnderstandingAnalysisFlatFee when ua.FeeType = 66 and ua.Hours > 0 then sl.UnderstandingAnalysisHourlyFee end as UACharge
--,ua.Discount as UADiscount
--,case ua.FeeType when 65 then sl.UnderstandingAnalysisFlatFee when 66 then sl.UnderstandingAnalysisHourlyFee*ua.Hours end - ua.Discount as NetUAFee

,case when prod.ProductCodeSwift in ('OWADVICE','OWADHOC') then 'No' else 'Yes' end as FeeFromFunds
,case when prod.OnPlatform = 1 then 'Yes' else 'No' end as OnPlatform
,case when ab8.AnswerId > 0 then ab8.AnswerText else 'No' end as TopUp
,od.Firm as OngoingRate,od.OngoingFeeType, prod.productcodeswift as productcodeswift, prov.providercodeswift as providercodeswift
into #R
from dbo.sa_ows_sale s 
inner join dbo.sa_ows_SCRTY_UserBusinessRoleHierarchy uh on uh.useruid = s.adviseruid
inner join dbo.SA_INSIGHT_UserDetails ud on ud.USR_ID = uh.		UserGUID
left join mstt_Agents a1 on a1.code = s.AdviserUID
left join mstt_Agents ag on ag.code = a1.Firm
left join dbo.sa_ows_Policies pol on pol.SaleID = s.SaleID --and pol.[Status] = 2 --Submitted
left join #FEE f on f.saleid = s.SaleId and f.Policyid = pol.policyid
left join dbo.sa_ows_Person p1 on p1.PersonId = s.PersonId
left join dbo.sa_ows_Person p2 on p2.PersonId = p1.PartnerPersonId  
left join StaticData.sa_ows_Product prod on prod.InternalProductID = pol.InternalProductID
left join StaticData.sa_ows_ProviderProducts PP on PP.InternalProductID = prod.InternalProductID
left join StaticData.sa_ows_Provider Prov on prov.InternalProviderID = pp.InternalProviderID
left join ( Select dcr.SaleID,max(IV.ValueName) as LATType
                  from sa_ows_HDRUI_DocumentCheckListResponses DCR 
                  left join StaticData.sa_ows_InputValues IV on IV.InputId = DCR.LATTransferType
                  group by dcr.SaleId ) LAT on LAT.SaleId = s.SaleID
left join dbo.sa_ows_HDRUI_QuestionnaireResponses qr5 on qr5.PolicyID = pol.PolicyID and qr5.QuestionID in (505,506,511,522,524,525,529,1206,1502,1505) and isnull(qr5.AnswerText,'') <> '' and isnumeric(qr5.AnswerText) = 1
left join dbo.sa_ows_HDRUI_QuestionnaireResponses qr6 on qr6.PolicyID = pol.PolicyID and qr6.QuestionID in (5,458,509) and isnull(qr6.AnswerText,'') <> ''
left join StaticData.sa_ows_HDRUI_AnswerBank ab6 on ab6.AnswerID = ISNULL(qr6.AnswerText,0)
left join dbo.sa_ows_HDRUI_QuestionnaireResponses qr8 on qr8.PolicyID = pol.PolicyID and qr8.QuestionID in (32,106,350,368,369,370,376,377,382,383,406,407,408,409,454,462,499,504,633,645,1701,1910) and isnull(qr8.AnswerText,'') <> ''
left join StaticData.sa_ows_HDRUI_AnswerBank ab8 on ab8.AnswerID = ISNULL(qr8.AnswerText,0)
left join (select ua1.saleid,ua2.EffDate,ua1.Feepolicyid,ua1.FeeType,
--ua1.Discount,
ua1.Hours
               from dbo.sa_ows_HDRUI_SubmissionFeeUnderstandingDetails ua1
               inner join ( select saleid,MAX(dateupdated) as EffDate
                                    from dbo.sa_ows_HDRUI_SubmissionFeeUnderstandingDetails
                                    group by SaleID) ua2 on ua2.SaleID = ua1.SaleID and ua1.DateUpdated = ua2.EffDate
                  ) ua on ua.SaleID = s.SaleID
left join ( select od1.saleid,'Unknown' as OngoingFeeType,od1.PaymentType,isnull(od1.Firm,0) - isnull(od1.Discount,0) as Firm,od2.EffDate,od1.currententerpriseservicelevel
                from dbo.sa_ows_HDRUI_SubmissionFeeOngoingDetails od1
                  inner join Proposition.sa_ows_ServiceLevel sl on sl.ServiceLevelID = od1.currententerpriseservicelevel
                   --left join dbo.sa_ows_ServiceLevelFeeTypes slft on slft.TypeID = sl.OngoingServiceTypeID  ---<CHANGE
                inner join (select saleid,MAX(dateupdated) as EffDate
                                    from dbo.sa_ows_HDRUI_SubmissionFeeOngoingDetails
                                    group by SaleID) od2 on od2.SaleID = od1.SaleID and od1.DateUpdated = od2.EffDate
                where isnull(od1.Firm,0) - isnull(od1.Discount,0) > 0
                  ) od on od.SaleID = s.SaleID
left join Proposition.sa_ows_ServiceLevel psl on psl.servicelevelid = od.currententerpriseservicelevel
left join Proposition.sa_ows_Proposition sl on sl.PropositionId = psl.PropositionId
where s.SaleStatusID in (2)  --Submitted
and ( prod.ProductCodeSwift in ('OWADHOC','OWADVICE') 
            or prod.OnPlatform = 1 or prod.IsGapFill = 1
            or qr5.policyid is not null or od.FIRM is not null or prod.FeeApplies = 1
      )

order by s.SaleId,pol.PolicyID
-- select * from sa_ows_ServiceLevels
select 
SaleId,AdviserUID,AdviserName,BusinessUID,BusinessName,DateSubmitted,
productcodeswift, case when providercodeswift = 'Pru Plt' then 'IFDL' else providercodeswift end as providercodeswift, case when providercodeswift = 'PTSP' then 'No' else onplatform end as OnPlatform,
LATType as LATType,
REPLACE(ClientName, ',',' ') as ClientName, REPLACE(PartnerName,',',' ') as PartnerName, 
PolicyId as PolicyID,
(OneOffInvestment + TransferValue + (coalesce((case when RegularPremiumFrequency = 'Annually' then 1 when RegularPremiumFrequency = 'Quarterly' then 4 when RegularPremiumFrequency = 'Monthly' then 12 end * RegularPremium),0))) as TotalAnnualInvestment,
(OneOffInvestment*FeeRate/100) + (TransferValue*FeeRate/100) + coalesce((((case when RegularPremiumFrequency = 'Annually' then 1 when RegularPremiumFrequency = 'Quarterly' then 4 when RegularPremiumFrequency = 'Monthly' then 12 end) * RegularPremium) * (FeeRate/100)),0)	as TotalAnnualInitialFees,
OneOffInvestment as OneOffInvestment,OneOffInvestment*FeeRate/100 as OneOffFees,
case when (OneOffInvestment) > 0 then (OneOffInvestment*FeeRate)/(OneOffInvestment) end as OneOffEffRate,
(TransferValue) as TransferValue,(TransferValue*FeeRate/100) as TransferValueFees,
case when (TransferValue) > 0 then (TransferValue*FeeRate)/(TransferValue) end as TransferValueEffRate,
RegularPremium as RegularPremium,
(RegularPremium * (FeeRate/100)) as RegularFee,
case when RegularPremium > 0
then (	(RegularPremium * FeeRate)/RegularPremium) end as RegFeeEffRate,
RegularPremiumFrequency,
UAType as UAType,UACharge as UACharge,
0 as UADiscount,
--UADiscount as UADiscount,
--Case when NetUAFee >= 0 then NetUAFee end as NetUAFee,
0 as NetUAFee,
(OngoingFeeType) as OngoingFeeType
,case when ongoingfeetype = 'Cash' then 0 else coalesce(ongoingrate,0) end as NetOngoingRate
,((OneOffInvestment + TransferValue + coalesce((case when RegularPremiumFrequency = 'Annually' then 1	when RegularPremiumFrequency = 'Quarterly' then 4 when RegularPremiumFrequency = 'Monthly' then 12 end * RegularPremium),0))
 * ((case when ongoingfeetype = 'Cash' then 0 else coalesce(ongoingrate,0) end)/100)) as AnnualServiceFee
from #R
where 
datesubmitted >= @StartDate
and datesubmitted <= @EndDate
and providercodeswift in ('IFDL','Pru','Metlife','Zurich PLT', 'Pru Plt')
--and PolicyID = 550196854
order by datesubmitted desc

drop table #FEE
drop table #R

GO
/****** Object:  StoredProcedure [BI].[pr_048_PanelSellers]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	48. Panel Sellers Query.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_048_PanelSellers]

as

-- Simple Join to give latest Panel for Agent (replace getdate() by relevant date required)
-- Note the use of the Function as a Table (can use as LEFT join as well)

SET NOCOUNT ON

Select AG.CODE, rtrim(ag.descn) as Name, Ag.AgentTypeDescription,AG.CompetentStatusDescription,
INS.InsightAgentUID,INS.Section,INS.Panel,INS.EffFrom,isnull(INS.EffTo,'31 dec 2999') as EffTo
from mstt_Agents AG
inner join (select InsightAgentUID,Section,Panel,EffFrom,isnull(EffTo,'31 dec 2999') as EffTo 
            from dbo.f_Insight_ListPanelHistoryOfAllSellersLUKETEST()
			) INS on INS.InsightAgentUID = AG.CODE and dateadd(dd,0,datediff(dd,0,getdate() )) between INS.EffFrom and INS.EffTo
order by AG.CODE            


