Create Procedure [BI].[pr_049_ProfitabilityDataV4]

as


SET NOCOUNT ON

IF OBJECT_ID('tempdb..#b') IS NOT NULL
DROP TABLE #b
IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c
IF OBJECT_ID('tempdb..#d') IS NOT NULL
DROP TABLE #d
IF OBJECT_ID('tempdb..#e') IS NOT NULL
DROP TABLE #e

SET DATEFIRST 1

--CALENDER DATES
declare @StartDate varchar(30), @EndDate varchar(30);
set @StartDate = CONVERT(DATETIME, '2017-01-01 00:00:00', 102) 
set @EndDate = CONVERT(DATETIME, '2019-01-31 23:59:59', 102) ---ENSURE END DATE IS LAST DAY OF REPORTING MONTH

--DEDUCE ISSUED NEW POLICIES (I.E IF TRANSACTIONID IS 1ST ACTIVE POLICY THEN IT IS A NEW POLICY)
select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #b

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where co.poltrantranstype <> 39
and co.agent_code not in ('10002','1011542','10004')	
and co.commissiontype = 1
and(po.comp_code <> 'L&G'  or (po.comp_code = 'L&G' and (left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null)))

group by po.policyref, po.cont_num, co.productcode

union all

select
min(transactionid) as transactionid, '', '','L&G' provider

FROM				  dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (po.comp_code = 'L&G' and po.policyref like '8000%')
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end

--DEDUCE WRITTEN NEW POLICIES (I.E IF TRANSACTIONID IS 1ST PROPOSED POLICY THEN IT IS A NEW POLICY)
select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)

and(po.comp_code <> 'L&G'  or (po.comp_code = 'L&G' and (left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null)))

group by po.policyref, po.cont_num, co.productcode

union all
select
min(transactionid) as transactionid, '', '','L&G' provider

FROM          dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (po.comp_code = 'L&G' and po.policyref like '8000%')
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end

-------------------------CORRECT APE LV

Select distinct 
edic.PolicyNumber, 
edic.PremiumAmount, 
edic.AmountReceived,  
edic.CommissionType, 
edih.LifeOfficeCode, 
edih.DateReceived,
potr.Amount, 
potr.CommInitialPeriod, 
potr.Amount/potr.CommInitialPeriod as CorrectPremium,
(potr.Amount/potr.CommInitialPeriod)*12 as CorrectAPE,
potr.Amount*12 as IncorrectAPE,
pp.AGENT_CODE,
pp.AGENT_PERC,
pp.BACSDate,
pp.FranchiseAgentCode,
agt.DESCN,
pp.TransactionID AS TransID
--pacc.UnallocatedReasonCode
into #d
from sa_swift_EDIFACTCommissionStatementContents edic
join sa_swift_EDIFACTCommissionStatementHeader edih on edih.ID = edic.StatementHeaderID
join sa_swift_S_PACC pacc on pacc.ID = edic.Pacc_ID
join sa_swift_PolicyTransactions potr on potr.ID = pacc.TransactionID
join mstt_PaymentsPending pp on pp.PACC_ID = pacc.ID
join sa_swift_S_AGENTS agt on agt.code = pp.FranchiseAgentCode
where edih.LifeOfficeCode = '24225G' and edih.DateReceived <= '10-Apr-2017' --dateadd(year,-1,getdate())
and pp.BACSDate > '11-Jan-2016' --and pp.BACSDate < '12-Jan-2017'
and edic.CommissionType = 'Y'
and edic.PremiumAmount = potr.Amount
and pp.AGENT_CODE != '10002'
--and pacc.UnallocatedReasonCode is not null
order by Amount desc



--- SELECT ALL SWIFT MATCHED TRANSACTIONS EXCLUDING PAID VALUES FROM OPEN ACCESS
select
cast((month(ag.createdatetime)) as nvarchar(max)) + cast((year(ag.createdatetime)) as nvarchar(max)) + case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end as Concat,
cast((year(ag.createdatetime)) as nvarchar(max)) + (case when month(ag.createdatetime) > month(@enddate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end as "Rolling",

case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end as agent_code,

rtrim(ah.agentdesc) as "AgentDesc", 
Case 
when ag.agent_code in ('1011543','1011587') then 

(case 

when co3.firm = '1000941' then '1007791' when co3.firm = '1000976' then '2001655' when co3.firm = '1001619' then '2001460' when co3.firm = '1001747' then '1006123' when co3.firm = '1001860' then '2000914' when co3.firm = '1001931' then '2001142' when co3.firm = '1002683' then '2001252' when co3.firm = '1002866' then '2001140' when co3.firm = '1002958' then '1002961' when co3.firm = '1003038' then '2001543' when co3.firm = '1003450' then '2001454' when co3.firm = '1004284' then '1000392' when co3.firm = '1005445' then '2001002' when co3.firm = '1010723' then '1001338' when co3.firm = '1000746' then '1011544' when co3.firm = '1002578' then '2001476' when co3.firm = '1002580' then '1011548' when co3.firm = '2000508' then '1004215'
when co3.firm = '1001374' then '2001538' when co3.firm = '1000981' then '2000425' when co3.firm = '2000522' then '2001536' when co3.firm = '1009210' then '2001543' when co3.firm = '1001167' then '2001540' when co3.firm = '1001789' then '2001395' when co3.firm = '1002076' then '2001475' when co3.firm = '1001058' then '2001549' when co3.firm = '1011487' then '2001497' when co3.firm = '1000821' then '1011541' when co3.firm = '1000692' then '2001575' when co3.firm = '1007638' then '2001578' when co3.firm = '1001804' then '2001582' when co3.firm = '1000794' then '2001580' when co3.firm = '1001492' then '2001584' when co3.firm = '1011448' then '2001585' when co3.firm = '1011540' then '1001897' when co3.firm = '1002178' then '2001613'
when co3.firm = '1000967' then '2001653' when co3.firm = '2001040' then '2001655' when co3.firm = '1001891' then '2001714' when co3.firm = '1002112' then '2001807' when co3.firm = '1000867' then '1011604' when co3.firm = '1011608' then '1010815' when co3.firm = '1001049' then '2001995' when co3.firm = '1000724' then '1004141' when co3.firm = '1001346' then '1009425' when co3.firm = '1000678' then '2004388' when co3.firm = '1000704' then '1003010' when co3.firm = '1008026' then '1001546' when co3.firm = '1002702' then '2001504' when co3.firm = '2000988' then '1001249' when co3.firm = '2001397' then '2004449' when co3.firm = '1000995' then '2004732' when co3.firm = '2001518' then '2006569' when co3.firm = '2005389' then '2006353'
when co3.firm = '1002174' then '2006794' when co3.firm = '1009620' then '2010099' when co3.firm = '1007327' then '2011344'

else co3.firm end)

when (case when((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end) = '1006886' then 'NULL' 

when ag.firm = '1000941' then '1007791' when ag.firm = '1000976' then '2001655' when ag.firm = '1001619' then '2001460' when ag.firm = '1001747' then '1006123' when ag.firm = '1001860' then '2000914' when ag.firm = '1001931' then '2001142' when ag.firm = '1002683' then '2001252' when ag.firm = '1002866' then '2001140' when ag.firm = '1002958' then '1002961' when ag.firm = '1003038' then '2001543' when ag.firm = '1003450' then '2001454' when ag.firm = '1004284' then '1000392' when ag.firm = '1005445' then '2001002' when ag.firm = '1010723' then '1001338' when ag.firm = '1000746' then '1011544' when ag.firm = '1002578' then '2001476' when ag.firm = '1002580' then '1011548' when ag.firm = '2000508' then '1004215'
when ag.firm = '1001374' then '2001538' when ag.firm = '1000981' then '2000425' when ag.firm = '2000522' then '2001536' when ag.firm = '1009210' then '2001543' when ag.firm = '1001167' then '2001540' when ag.firm = '1001789' then '2001395' when ag.firm = '1002076' then '2001475' when ag.firm = '1001058' then '2001549' when ag.firm = '1011487' then '2001497' when ag.firm = '1000821' then '1011541' when ag.firm = '1000692' then '2001575' when ag.firm = '1007638' then '2001578' when ag.firm = '1001804' then '2001582' when ag.firm = '1000794' then '2001580' when ag.firm = '1001492' then '2001584' when ag.firm = '1011448' then '2001585' when ag.firm = '1011540' then '1001897' when ag.firm = '1002178' then '2001613'
when ag.firm = '1000967' then '2001653' when ag.firm = '2001040' then '2001655' when ag.firm = '1001891' then '2001714' when ag.firm = '1002112' then '2001807' when ag.firm = '1000867' then '1011604' when ag.firm = '1011608' then '1010815' when ag.firm = '1001049' then '2001995' when ag.firm = '1000724' then '1004141' when ag.firm = '1001346' then '1009425' when ag.firm = '1000678' then '2004388' when ag.firm = '1000704' then '1003010' when ag.firm = '1008026' then '1001546' when ag.firm = '1002702' then '2001504' when ag.firm = '2000988' then '1001249' when ag.firm = '2001397' then '2004449' when ag.firm = '1000995' then '2004732' when ag.firm = '2001518' then '2006569' when ag.firm = '2005389' then '2006353'
when ag.firm = '1002174' then '2006794' when ag.firm = '1009620' then '2010099' when ag.firm = '1007327' then '2011344'

else ag.firm End as "Firm",
rtrim(ah.agentdesc) as "FirmDesc",
month(ag.createdatetime)as month, year(ag.createdatetime) as year,
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity%' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT'  or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end as ProductGroupName,
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity%' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end as ProductGroupName2,


-----------------------------ISSUED APE------------------------------------------------------------------------------------------------------------------

-- APE FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM / 10 FOR APE
sum(Case when (d.PolicyNumber = ag.providerRef AND ag.createdatetime < '10-Jul-2017') then d.CorrectAPE else((case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then ((cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 / 10) else
	
-- ENSURE MORTGAGES APE IS THE SAME AS DA
(case when 
(case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity%' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end) = 'Mortgage'
then (case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end)
else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end) end))END) as "IssuedAPE",

-----------------------------GROSS DA------------------------------------------------------------------------------------------------------------------

sum(case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'GrossDA',

-----------------------------DA CLAW------------------------------------------------------------------------------------------------------------------

sum(case when (ag.commissiontype in ('2') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- DA CLAW SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('15','16')) then (ag.amount + isnull(derivedmarginamount,0))
-- DA CLAW TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('16')) then (ag.amount / (8.0/10))
-- DA CLAW POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontypedesc like '%claw%') then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'DAClaw',

-----------------------------GROSS COMMISSION------------------------------------------------------------------------------------------------------------------

-- GROSS COMM INITIAL
sum(CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.INIssued)
-- GROSS COMM SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then ag.amount
-- GROSS COMM TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ag.amount
else 0 end) as 'GrossComm',

-----------------------------COMMISSION CLAW------------------------------------------------------------------------------------------------------------------

-- COMM CLAW INITIAL
sum(CASE  when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('2') and cs.oastatus = 'valid')) and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN (cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN ((cs.INIssued) * 10.0)/ 9 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) when ((ag.commissiontype in ('2') and cs.oastatus = 'valid')) then (cs.INIssued)
-- COMM CLAW SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('15','16')) then ag.amount
-- COMM CLAW TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('16')) then ag.amount
else 0 end) as 'CommClaw',

-----------------------------NET COMMISSION------------------------------------------------------------------------------------------------------------------

-- NET COMM INITIAL
sum(CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.INIssued)
-- NET COMM SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
-- NET COMM TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
else 0 end) as 'NetComm',

-----------------------------GROSS MARGIN------------------------------------------------------------------------------------------------------------------

 -- NET MARGIN INITIAL
sum(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) when ((ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid')) then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
-- NET MARGIN TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
-- NET MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'GrossMargin',

-----------------------------Net Charges------------------------------------------------------------------------------------------------------------------

"NetCharges" = 0,

-----------------------------New Policies------------------------------------------------------------------------------------------------------------------

sum(case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end) as "NBCases",

-----------------------------Written APE------------------------------------------------------------------------------------------------------------------

"WrittenNBAPE" = 0, 

-----------------------------Written Cases------------------------------------------------------------------------------------------------------------------

"WrittenNBCases" = 0,

-----------------------------Paid------------------------------------------------------------------------------------------------------------------

--sum(oa.totalpayment) as 'Paid'
"Paid" = 0


into #e


from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_Commissions co3 on co3.transactionid = ag.transactionid 
and co3.agent_code = pt.agentcode
and co3.commissiontype = ag.commissiontype 
and co3.firm <> '1011543' LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid
LEFT OUTER JOIN #d d on (d.PolicyNumber = ag.providerref) AND (d.TransID = ag.TransactionID)

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate		
and (ag.agent_code <> '10002' or ag.agent_code <> '1011623')
and ag.amount <> 0
and (co2.id not in ('17797514','17797515') or co2.id is NULL)
and (co3.id not in ('17797514','17797515') or co3.id is NULL)
and (cs.oastatus = 'valid' or cs.oastatus is NULL)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null )
--ENSURE NO TRAIL WHERE OPENWORK DO NOT TAKE A MARGIN IS INCLUDED
and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 

--ENSURE NO ZERO DA TRANSACTIONS ARE INCLUDED AS UNNEEDED
and (case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- NET DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- NET DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
-- NET DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by
cast((month(ag.createdatetime)) as nvarchar(max)) + cast((year(ag.createdatetime)) as nvarchar(max)) + case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end,
cast((year(ag.createdatetime)) as nvarchar(max)) + (case when month(ag.createdatetime) > month(@enddate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end,
case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end,

rtrim(ah.agentdesc), 
Case 
when ag.agent_code in ('1011543','1011587') then 

(case 

when co3.firm = '1000941' then '1007791' when co3.firm = '1000976' then '2001655' when co3.firm = '1001619' then '2001460' when co3.firm = '1001747' then '1006123' when co3.firm = '1001860' then '2000914' when co3.firm = '1001931' then '2001142' when co3.firm = '1002683' then '2001252' when co3.firm = '1002866' then '2001140' when co3.firm = '1002958' then '1002961' when co3.firm = '1003038' then '2001543' when co3.firm = '1003450' then '2001454' when co3.firm = '1004284' then '1000392' when co3.firm = '1005445' then '2001002' when co3.firm = '1010723' then '1001338' when co3.firm = '1000746' then '1011544' when co3.firm = '1002578' then '2001476' when co3.firm = '1002580' then '1011548' when co3.firm = '2000508' then '1004215'
