when wr.firm = '1000967' then '2001653' when wr.firm = '2001040' then '2001655' when wr.firm = '1001891' then '2001714' when wr.firm = '1002112' then '2001807' when wr.firm = '1000867' then '1011604' when wr.firm = '1011608' then '1010815' when wr.firm = '1001049' then '2001995' when wr.firm = '1000724' then '1004141' when wr.firm = '1001346' then '1009425' when wr.firm = '1000678' then '2004388' when wr.firm = '1000704' then '1003010' when wr.firm = '1008026' then '1001546' when wr.firm = '1002702' then '2001504' when wr.firm = '2000988' then '1001249' when wr.firm = '2001397' then '2004449' when wr.firm = '1000995' then '2004732' when wr.firm = '2001518' then '2006569' when wr.firm = '2005389' then '2006353'
when wr.firm = '1002174' then '2006794' when wr.firm = '1009620' then '2010099' when wr.firm= '1007327' then '2011344'

Else wr.firm End as "Firm Code", 
rtrim(wr.agentdesc) as "FirmDesc",

month(wr.writtendate),
year(wr.writtendate),
case when wr.adminmethod <> 'Advised' then 'NonWri' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end) else 'Advised' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end) end as productgroupname,
case when wr.adminmethod <> 'Advised' then 'NonWri' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end) else 'Advised' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end) end as productgroupname2,


