sum(wr.writtencases),
-----------------------------Paid------------------------------------------------------------------------------------------------------------------
"Paid" = 0

--"Cases" = 0, 

--"Net DA" = 0, 

--"Gross Margin (Pre Claw)" = 0, 
--"Margin Claw" = 0, 
--"Comm Adj" = 0, 

--"Contribution" = 0
--"Elite_Points" = 0,




from

-- IN ORDER TO REMOVE DUPLICATES OF SAME ADVISERCODE/POLICY/CASEID/APE/WRITTEN DATE IN SAME WEEK

(SELECT 
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm, 
min(co.transactionid) as transactionid, 
min(pt.writtendate) as "writtendate",
datepart(week,(pt.writtendate)) as writtenweek, 
year(pt.writtendate) as writtenyear,
Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) END as WrittenAPE,
Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2)End AS NBI, 
Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2)End as margin, 
Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max((co.agent_perc/100))End as "Old Cases", 
Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)End as "WrittenCases", 
min(pt.FrequencyDescription) as frequency, 
po.PolicyRef AS CaseID,
po.CONT_NUM AS Policy,
min(co.BusinessReason) as businessreason, min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(CASE WHEN ph.productsubgroupname like '%Annuity' THEN 'COB Off-Platform' when ph.productgroupname = 'Other' then 'Pensions' ELSE ph.ProductGroupName END) as "productgroupname",

min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD
, min(ah.agentdesc) as agentdesc

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and po.COMP_CODE NOT LIKE '%Owl%'
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.writtendate) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), ph.productgroupname,ph.productgroupname,co.agent_code) wr

where 
wr.writtendate >= @StartDate
and wr.writtendate <= @EndDate	
and (wr.caseid not in ('500020430','500020431') or wr.caseid is null)

group by
cast((month(wr.writtendate)) as nvarchar) + cast((year(wr.writtendate)) as nvarchar)  + (case when wr.adminmethod <> 'Advised' then 'NonWri' + wr.productgroupname else 'Advised' + wr.productgroupname end),
cast((year(wr.writtendate)) as nvarchar(max)) + (case when month(wr.writtendate) > month(@enddate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end,
wr.adviser, rtrim(wr.agentdesc), 
case when wr.firm = '1000941' then '1007791' when wr.firm = '1000976' then '2001040' when wr.firm = '1001619' then '2001460' when wr.firm = '1001747' then '1006123' when wr.firm = '1001860' then '2000914' when wr.firm = '1001931' then '2001142' when wr.firm = '1002683' then '2001252' when wr.firm = '1002866' then '2001140' when wr.firm = '1002958' then '1002961' when wr.firm = '1003038' then '2001543' when wr.firm = '1003450' then '2001454' when wr.firm = '1004284' then '1000392' when wr.firm = '1005445' then '2001002' when wr.firm = '1010723' then '1001338' when wr.firm = '1000746' then '1011544' when wr.firm = '1002578' then '2001476' when wr.firm = '1002580' then '1011548' when wr.firm = '2000508' then '1004215'
when wr.firm = '1001374' then '2001538' when wr.firm = '1000981' then '2000425' when wr.firm = '2000522' then '2001536' when wr.firm = '1009210' then '2001543' when wr.firm = '1001167' then '2001540' when wr.firm = '1001789' then '2001395' when wr.firm = '1002076' then '2001475' when wr.firm = '1001058' then '2001549' when wr.firm = '1011487' then '2001497' when wr.firm = '1000821' then '1011541' when wr.firm = '1000692' then '2001575' when wr.firm = '1007638' then '2001578' when wr.firm = '1001804' then '2001582' when wr.firm = '1000794' then '2001580' when wr.firm = '1001492' then '2001584' when wr.firm = '1011448' then '2001585' when wr.firm = '1011540' then '1001897' when wr.firm = '1002178' then '2001613'
when wr.firm = '1000967' then '2001653' when wr.firm = '2001040' then '2001655' when wr.firm = '1001891' then '2001714' when wr.firm = '1002112' then '2001807' when wr.firm = '1000867' then '1011604' when wr.firm = '1011608' then '1010815' when wr.firm = '1001049' then '2001995' when wr.firm = '1000724' then '1004141' when wr.firm = '1001346' then '1009425' when wr.firm = '1000678' then '2004388' when wr.firm = '1000704' then '1003010' when wr.firm = '1008026' then '1001546' when wr.firm = '1002702' then '2001504' when wr.firm = '2000988' then '1001249' when wr.firm = '2001397' then '2004449' when wr.firm = '1000995' then '2004732' when wr.firm = '2001518' then '2006569' when wr.firm = '2005389' then '2006353'
when wr.firm = '1002174' then '2006794' when wr.firm = '1009620' then '2010099' when wr.firm = '1007327' then '2011344'

Else wr.firm End, 
rtrim(wr.agentdesc),
case when wr.adminmethod <> 'Advised' then 'NonWri' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end) else 'Advised' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end) end,
month(wr.writtendate),
year(wr.writtendate),
wr.productgroupname

UNION ALL

-------Issued Mortgage Broker Fee ---------------------------------

Select Distinct 
cast((month(MBF.PaymentMatchedDate)) as nvarchar(max)) + cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + 'Mortgage Broker Fee' AS Concat,
cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + (case when month(MBF.PaymentMatchedDate) > month(@enddate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end as "Rolling",
MBF.AdviserUID, 
mbf.AdviserName as AgentName,
case when MBF.FirmUID = '1000941' then '1007791' when MBF.FirmUID = '1000976' then '2001040' when MBF.FirmUID = '1001619' then '2001460' when MBF.FirmUID = '1001747' then '1006123' when MBF.FirmUID = '1001860' then '2000914' when MBF.FirmUID = '1001931' then '2001142' when MBF.FirmUID = '1002683' then '2001252' when MBF.FirmUID = '1002866' then '2001140' when MBF.FirmUID = '1002958' then '1002961' when MBF.FirmUID = '1003038' then '2001543' when MBF.FirmUID = '1003450' then '2001454' when MBF.FirmUID = '1004284' then '1000392' when MBF.FirmUID = '1005445' then '2001002' when MBF.FirmUID = '1010723' then '1001338' when MBF.FirmUID = '1000746' then '1011544' when MBF.FirmUID = '1002578' then '2001476' when MBF.FirmUID = '1002580' then '1011548' when MBF.FirmUID = '2000508' then '1004215'
when MBF.FirmUID = '1001374' then '2001538' when MBF.FirmUID = '1000981' then '2000425' when MBF.FirmUID = '2000522' then '2001536' when MBF.FirmUID = '1009210' then '2001543' when MBF.FirmUID = '1001167' then '2001540' when MBF.FirmUID = '1001789' then '2001395' when MBF.FirmUID = '1002076' then '2001475' when MBF.FirmUID = '1001058' then '2001549' when MBF.FirmUID = '1011487' then '2001497' when MBF.FirmUID = '1000821' then '1011541' when MBF.FirmUID = '1000692' then '2001575' when MBF.FirmUID = '1007638' then '2001578' when MBF.FirmUID = '1001804' then '2001582' when MBF.FirmUID = '1000794' then '2001580' when MBF.FirmUID = '1001492' then '2001584' when MBF.FirmUID = '1011448' then '2001585' when MBF.FirmUID = '1011540' then '1001897' when MBF.FirmUID = '1002178' then '2001613'
when MBF.FirmUID = '1000967' then '2001653' when MBF.FirmUID = '2001040' then '2001655' when MBF.FirmUID = '1001891' then '2001714' when MBF.FirmUID = '1002112' then '2001807' when MBF.FirmUID = '1000867' then '1011604' when MBF.FirmUID = '1011608' then '1010815' when MBF.FirmUID = '1001049' then '2001995' when MBF.FirmUID = '1000724' then '1004141' when MBF.FirmUID = '1001346' then '1009425' when MBF.FirmUID = '1000678' then '2004388' when MBF.FirmUID = '1000704' then '1003010' when MBF.FirmUID = '1008026' then '1001546' when MBF.FirmUID = '1002702' then '2001504' when MBF.FirmUID = '2000988' then '1001249' when MBF.FirmUID = '2001397' then '2004449' when MBF.FirmUID = '1000995' then '2004732' when MBF.FirmUID = '2001518' then '2006569' when MBF.FirmUID = '2005389' then '2006353'
when MBF.FirmUID = '1002174' then '2006794' when MBF.FirmUID = '1009620' then '2010099' when MBF.FirmUID = '1007327' then '2011344'

Else MBF.FirmUID End as 'Firm Code',
mbf.FirmName as FirmName, 
Month(MBF.PaymentMatchedDate) as "Month", 
Year(MBF.PaymentMatchedDate) as "Year",
'Mortgage Broker Fee' as productgroupname,
'Mortgage Broker Fee' as productgroupname2,



SUM(MBF.APE) as 'Issued APE', 

SUM(MBF.APE) as 'Gross DA', 

0 as 'DA Claw',

SUM((MBF.AdviceFeeAmount*(MBF.AgentSplit/100))+MBF.DeductionAmount)  as 'Gross Comm',

0 as 'Comm Claw',

SUM((MBF.AdviceFeeAmount*(MBF.AgentSplit/100))+MBF.AdviceFeeAmount+MBF.DeductionAmount) as 'Net Comm',

SUM(MBF.DeductionAmount*-1) as 'Gross Margin',

0 as 'Net Charges',

SUM(MBF.AgentSplit)/100 as 'NB Cases',

0 as 'Written NB APE',

0 as 'Written NB Cases',

case when sum(mbf.AdviceFeeAmount) is null then 0 else sum(mbf.AdviceFeeAmount) end as 'Paid'

FROM dbo.owt_MortgageBrokerFees MBF 
where
(MBF.PaymentMatchedDate) >= @StartDate
and (MBF.PaymentMatchedDate) <= @EndDate
and MBF.AdviceFeeCharged = 'Yes'
and transactionID = (select max(TransactionID)
								from dbo.owt_MortgageBrokerFees MBF2
								where MBF2.policyID = MBF.PolicyID)
GROUP BY MBF.AdviserUID, MBF.FirmUID, Month(MBF.PaymentMatchedDate), 
Year(MBF.PaymentMatchedDate),
cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + (case when month(MBF.PaymentMatchedDate) > month(@enddate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end,
mbf.AdviserName,mbf.FirmName  


