when ah.FirmCode = '1001374' then '2001538' when ah.FirmCode = '1000981' then '2000425' when ah.FirmCode = '2000522' then '2001536' when ah.FirmCode = '1009210' then '2001543' when ah.FirmCode = '1001167' then '2001540' when ah.FirmCode = '1001789' then '2001395' when ah.FirmCode = '1002076' then '2001475' when ah.FirmCode = '1001058' then '2001549' when ah.FirmCode = '1011487' then '2001497' when ah.FirmCode = '1000821' then '1011541' when ah.FirmCode = '1000692' then '2001575' when ah.FirmCode = '1007638' then '2001578' when ah.FirmCode = '1001804' then '2001582' when ah.FirmCode = '1000794' then '2001580' when ah.FirmCode = '1001492' then '2001584' when ah.FirmCode = '1011448' then '2001585' when ah.FirmCode = '1011540' then '1001897' when ah.FirmCode = '1002178' then '2001613'
when ah.FirmCode = '1000967' then '2001653' when ah.FirmCode = '2001040' then '2001655' when ah.FirmCode = '1001891' then '2001714' when ah.FirmCode = '1002112' then '2001807' when ah.FirmCode = '1000867' then '1011604' when ah.FirmCode = '1011608' then '1010815' when ah.FirmCode = '1001049' then '2001995' when ah.FirmCode = '1000724' then '1004141' when ah.FirmCode = '1001346' then '1009425' when ah.FirmCode = '1000678' then '2004388' when ah.FirmCode = '1000704' then '1003010' when ah.FirmCode = '1008026' then '1001546' when ah.FirmCode = '1002702' then '2001504' when ah.FirmCode = '2000988' then '1001249' when ah.FirmCode = '2001397' then '2004449' when ah.FirmCode = '1000995' then '2004732' when ah.FirmCode = '2001518' then '2006569' when ah.FirmCode = '2005389' then '2006353'
when ah.FirmCode = '1002174' then '2006794' when ah.FirmCode = '1009620' then '2010099' when ah.FirmCode = '1007327' then '2011344'
