Source:			Sarah Inglis (MI Team)

Script Name:	50. Profitability Historical Tab Data Query.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_050_ProfitabilityHistoricalTabData]

as

SET NOCOUNT ON

IF OBJECT_ID('tempdb..#b') IS NOT NULL
DROP TABLE #b
IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c
IF OBJECT_ID('tempdb..#d') IS NOT NULL
DROP TABLE #d
IF OBJECT_ID('tempdb..#e') IS NOT NULL
DROP TABLE #e

SET DATEFIRST 1

--CALENDER DATES
declare @StartDate varchar(30), @EndDate varchar(30);
set @StartDate = CONVERT(DATETIME, '2017-01-01 00:00:00', 102) 
set @EndDate = CONVERT(DATETIME, '2019-02-28 23:59:59', 102) ---ENSURE END DATE IS LAST DAY OF REPORTING MONTH

--DEDUCE ISSUED NEW POLICIES (I.E IF TRANSACTIONID IS 1ST ACTIVE POLICY THEN IT IS A NEW POLICY)
select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #bb

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where co.poltrantranstype <> 39
and co.agent_code not in ('10002','1011542','10004')	
and co.commissiontype = 1
and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by po.policyref, po.cont_num, co.productcode

union all

select
min(transactionid) as transactionid, '', '','L&G' provider

FROM				  dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end

select transactionid,policyref,cont_num into #b from #bb where left(cont_num,2) <> 'ZR' or cont_num is null
union all
select case when left(cont_num,2) = 'ZR' then min(transactionid) end transactionid, policyref, cont_num
from #bb where left(cont_num,2) = 'ZR'group by  policyref, cont_num

drop table #bb

--DEDUCE WRITTEN NEW POLICIES (I.E IF TRANSACTIONID IS 1ST PROPOSED POLICY THEN IT IS A NEW POLICY)
select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode,ph.productgroupname,COMP_CODE
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')

group by po.policyref, po.cont_num, co.productcode, ph.productgroupname,COMP_CODE

union all



select
min(transactionid) as transactionid, '' t1, '' t2,'' t3,ph.productgroupname,COMP_CODE

FROM          dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
--and ph.productgroupname like 'Protection'
and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')

group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end,ph.productgroupname,COMP_CODE


-------------------------CORRECT APE LV

Select distinct 
edic.PolicyNumber, 
edic.PremiumAmount, 
edic.AmountReceived,  
edic.CommissionType, 
edih.LifeOfficeCode, 
edih.DateReceived,
potr.Amount, 
potr.CommInitialPeriod, 
potr.Amount/potr.CommInitialPeriod as CorrectPremium,
(potr.Amount/potr.CommInitialPeriod)*12 as CorrectAPE,
potr.Amount*12 as IncorrectAPE,
pp.AGENT_CODE,
pp.AGENT_PERC,
pp.BACSDate,
pp.FranchiseAgentCode,
agt.DESCN,
pp.TransactionID AS TransID
--pacc.UnallocatedReasonCode
into #d
from sa_swift_EDIFACTCommissionStatementContents edic
join sa_swift_EDIFACTCommissionStatementHeader edih on edih.ID = edic.StatementHeaderID
join sa_swift_S_PACC pacc on pacc.ID = edic.Pacc_ID
join sa_swift_PolicyTransactions potr on potr.ID = pacc.TransactionID
join mstt_PaymentsPending pp on pp.PACC_ID = pacc.ID
join sa_swift_S_AGENTS agt on agt.code = pp.FranchiseAgentCode
where edih.LifeOfficeCode = '24225G' and edih.DateReceived <= '10-Apr-2017' --dateadd(year,-1,getdate())
and pp.BACSDate > '11-Jan-2016' --and pp.BACSDate < '12-Jan-2017'
and edic.CommissionType = 'Y'
and edic.PremiumAmount = potr.Amount
and pp.AGENT_CODE != '10002'
--and pacc.UnallocatedReasonCode is not null
order by Amount desc



--- SELECT ALL SWIFT MATCHED TRANSACTIONS
select
cast((month(ag.createdatetime)) as nvarchar(max)) + cast((year(ag.createdatetime)) as nvarchar(max)) + case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end as Concat,
cast((year(ag.createdatetime)) as nvarchar(max)) + (case when month(ag.createdatetime) > month(@enddate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end as "Rolling",

case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end as agent_code,

rtrim(ah.agentdesc) as "AgentDesc", 
Case 
when ag.agent_code in ('1011543','1011587') then 

(case 

when co3.firm = '1000941' then '1007791' when co3.firm = '1000976' then '2001655' when co3.firm = '1001619' then '2001460' when co3.firm = '1001747' then '1006123' when co3.firm = '1001860' then '2000914' when co3.firm = '1001931' then '2001142' when co3.firm = '1002683' then '2001252' when co3.firm = '1002866' then '2001140' when co3.firm = '1002958' then '1002961' when co3.firm = '1003038' then '2001543' when co3.firm = '1003450' then '2001454' when co3.firm = '1004284' then '1000392' when co3.firm = '1005445' then '2001002' when co3.firm = '1010723' then '1001338' when co3.firm = '1000746' then '1011544' when co3.firm = '1002578' then '2001476' when co3.firm = '1002580' then '1011548' when co3.firm = '2000508' then '1004215'
when co3.firm = '1001374' then '2001538' when co3.firm = '1000981' then '2000425' when co3.firm = '2000522' then '2001536' when co3.firm = '1009210' then '2001543' when co3.firm = '1001167' then '2001540' when co3.firm = '1001789' then '2001395' when co3.firm = '1002076' then '2001475' when co3.firm = '1001058' then '2001549' when co3.firm = '1011487' then '2001497' when co3.firm = '1000821' then '1011541' when co3.firm = '1000692' then '2001575' when co3.firm = '1007638' then '2001578' when co3.firm = '1001804' then '2001582' when co3.firm = '1000794' then '2001580' when co3.firm = '1001492' then '2001584' when co3.firm = '1011448' then '2001585' when co3.firm = '1011540' then '1001897' when co3.firm = '1002178' then '2001613'
when co3.firm = '1000967' then '2001653' when co3.firm = '2001040' then '2001655' when co3.firm = '1001891' then '2001714' when co3.firm = '1002112' then '2001807' when co3.firm = '1000867' then '1011604' when co3.firm = '1011608' then '1010815' when co3.firm = '1001049' then '2001995' when co3.firm = '1000724' then '1004141' when co3.firm = '1001346' then '1009425' when co3.firm = '1000678' then '2004388' when co3.firm = '1000704' then '1003010' when co3.firm = '1008026' then '1001546' when co3.firm = '1002702' then '2001504' when co3.firm = '2000988' then '1001249' when co3.firm = '2001397' then '2004449' when co3.firm = '1000995' then '2004732' when co3.firm = '2001518' then '2006569' when co3.firm = '2005389' then '2006353'
when co3.firm = '1002174' then '2006794' when co3.firm = '1009620' then '2010099' when co3.firm = '1007327' then '2011344'

