--sum(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
--WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) when ((ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid')) then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
---- NET MARGIN TRAIL
--when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
---- NET MARGIN POT ACCOUNT/SERVICING
--when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'GrossMargin',

---- CONTRIBUTION MARGIN INITIAL
--sum(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
--WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) when ((ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid')) then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
---- CONTRIBUTION TRAIL
--when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
---- CONTRIBUTION POT ACCOUNT/SERVICING
--when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'Contribution'

--, sum(oa.elite_points) as elitepoints


into #e


from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_Commissions co3 on co3.transactionid = ag.transactionid 
and co3.agent_code = pt.agentcode
and co3.commissiontype = ag.commissiontype 
and co3.firm <> '1011543' LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid
LEFT OUTER JOIN #d d on (d.PolicyNumber = ag.providerref) AND (d.TransID = ag.TransactionID)

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate		
and (ag.agent_code <> '10002' or ag.agent_code <> '1011623')
and ag.amount <> 0
and (co2.id not in ('17797514','17797515') or co2.id is NULL)
and (co3.id not in ('17797514','17797515') or co3.id is NULL)
and (cs.oastatus = 'valid' or cs.oastatus is NULL)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null )
--ENSURE NO TRAIL WHERE OPENWORK DO NOT TAKE A MARGIN IS INCLUDED
and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 

--ENSURE NO ZERO DA TRANSACTIONS ARE INCLUDED AS UNNEEDED
and (case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- NET DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- NET DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
-- NET DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by
cast((month(ag.createdatetime)) as nvarchar(max)) + cast((year(ag.createdatetime)) as nvarchar(max)) + case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end,
cast((year(ag.createdatetime)) as nvarchar(max)) + (case when month(ag.createdatetime) > month(@enddate) then 'NOT YTD' else 'YTD' end),
