case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end,

rtrim(ah.agentdesc), 
