msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = co.transactionid


where
co.agent_code <> '10002'
and pt.createdatetime >= @StartDate
and pt.createdatetime <= @EndDate
and co.commissiontype = 1
and ph.rdrtype is not null
and pt.comminitialamount <= 0 and pt.amount > 0
and co.poltrantranstype = 17
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or co.agent_code <> '1011623' or ah.ASDName is Null )
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------


group by 
cast((month(pt.createdatetime)) as nvarchar(max)) + cast((year(pt.createdatetime)) as nvarchar(max)) + (case when ph.productsubgroupname like '%Annuity%' then 'COB Off-Platform' when ((left(co.productcode,2) in ('OW','OZ')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else ph.productgroupname end),
