case when convert(datetime, dateadd(month,datediff(Month,0,pt.createdatetime),0), 102) >= dateadd(month,-12,@enddate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,pt.createdatetime),0), 102) >= dateadd(month,-24,@enddate) then 'PrevR' else 'NOR12' end,

co.agent_code, rtrim(ah.agentdesc), 

case
