'NB' as businessreason,
'' as Adminmethoddescription,
'L&GASU OWL' as Productcode,
'L&G OWL' as Provider,
'' as reportingproductname,
'ASU' as ProductSubGroup,
'Protection' as ProductGroupName,
'' as originatingsource,
