-------------------NEW ISSUED TABLE--------------------

Select


Agent_code,
Firm,
convert(varchar(2),month(createdatetime))+convert(varchar(4),year(createdatetime)) as Date,
SUM (Premium) as Premium,
SUM (APE) as APE,
SUM (DA) as DA,
SUM (Comm) as Commision,
SUM (Margin) as Margin,
SUM (Cases) as Cases,
SUM ([NB Cases]) as [NB Cases],
Comp_code,
reportingproductname,
productsubgroupname,
calculationcode,
paybasisdesc,
description,
Catagory



from #OWLIssued


where Catagory = 'ST'


Group by 
Agent_code,
Firm,
convert(varchar(2),month(createdatetime))+convert(varchar(4),year(createdatetime)), 
Comp_code,
reportingproductname,
productsubgroupname,
calculationcode,
paybasisdesc,
description,
Catagory

Select sum(APE), catagory from #OWLIssued group by catagory

-------------- end of Issued Scan------------------


select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
group by po.policyref, po.cont_num, co.productcode




select
wr.Adviser,
wr.Firm,
wr.transactionid,
wr.Writtendate,
wr.Ape,
wr.Distributionallowance, wr.NBI, wr.Margin, wr.NBcases, wr.Allcases, wr.frequency, wr.CaseID, 
wr.Policy, wr.Businessreason,
wr.Adminmethoddescription, wr.Productcode, wr.Provider, wr.Reportingproductname, 
case when wr.productsubgroupname in ('Critical Illness','TALA') then 'Term Assurance' when wr.productcode = 'MLP' then 'MLP' else wr.productsubgroupname end as "productsubgroupname",
wr.Productgroupname,
wr.Originatingsource, wr.Adminmethod, wr.Calculationcode, REPLACE(wr.Description, ',',' ' ) AS Description, wr.ASD,
case when wr.Provider like '%OWL%' then 'ST' else 'Panel' end as 'Catagory' 

Into #OWLWritten

from


(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
round(co.Turnover,2) as APE,
min(co.distributionallowance) as distributionallowance, min(co.baseamount + co.upliftamount) AS NBI, min(co.salesmargin) as margin, 
max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases", 
max((co.agent_perc/100)) as "AllCases", min(pt.FrequencyDescription) as frequency, min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD


FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) = 'Pat Mckenna') -- or ah.ASDName is Null)
group by cast(co.AGENT_CODE as int), round(co.Turnover,2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate)) wr

where
wr.writtendate >= @StartDate
and wr.writtendate <= @EndDate
and wr.productgroupname = 'Protection'
--and wr.firm = '1002222'
--and wr.originatingsource = '5'






------------------Adding L&G data Written
---- add L&G union here
Union All

select 
--'Written' as Type,
uh.UserUID as Adviser,
uh.businessuid as Firm,
null as transactionid,
convert(Date,pol.ApplicationDate,103) as writtendate,
pps.PremiumAmount*12*((20.00/25.00)) as APE,
pps.PremiumAmount*12*((20.00/25.00)) as DA,
'' as NBI,
((pps.PremiumAmount*12*(0.35*(20.00/25.00))) - (pps.PremiumAmount*12*0.2)) as Margin,
20.00/25.00 as NBCases,
20.00/25.00 as AllCases,
'' as Frequency,
pol.policyID as caseid,
pps.policynumber as policy,
'NB' as businessreason,
'' as Adminmethoddescription,
'L&GASU OWL' as Productcode,
'L&G OWL' as Provider,
'' as reportingproductname,
'ASU' as ProductSubGroup,
'Protection' as ProductGroupName,
'' as originatingsource,
'Advised' as adminmethod,
'' as calculationcode,
'' as 'description',
'Pat McKenna' as ASD,
'ST' as Catagory

from sa_ows_Policies  pol
join policy.sa_ows_ProtectionProductSummary pps on pps.PolicyID = pol.PolicyID
join sa_ows_sale sale on sale.SaleID = pol.SaleID
join mi_insight_UserHierarchy uh on uh.UserUID = sale.AdviserUID
join sa_ows_person pers on pers.PersonID = sale.personID

where pol.InternalProductID = 10000063
and SaleStatusID = 2 and pol.Status = 2
and sale.adviserUID <> '4006226' -- Excluding the test UID
and convert(Date,pol.ApplicationDate,103) >= @Startdate
and convert(Date,pol.ApplicationDate,103) <= @Enddate
	


UNION all

select distinct
--'Written',
uh1.UserUID as Adviser,

uh1.businessuid as Firm,

null as transactionid,
convert(date,pol.ApplicationDate,103) as writtendate,

pps.PremiumAmount*12*((4.00/25.00)) as APE,
pps.PremiumAmount*12*((4.00/25.00)) as DistributionAllowance,
'' as NBI,
((pps.PremiumAmount*12*(0.35*(4.00/25.00))) - (pps.PremiumAmount*12*0.04)) as Margin,
4.00/25.00 AS NBCases,
4.00/25.00 AS AllCases,
'' as frequency,
pol.policyID as caseid,
pps.policynumber as policy,
'NB' as businessreason,
'' as Adminmethoddescription,
'L&GASU OWL' as Productcode,
'L&G OWL' as Provider,
'' as reportingproductname,
'ASU' as ProductSubGroup,
'Protection' as ProductGroupName,
'' as originatingsource,
'Advised' as adminmethod,
'' as calculationcode,
'' as 'description',
'Pat McKenna' as ASD,
'ST' as Catagory

from sa_ows_Policies  pol
join policy.sa_ows_ProtectionProductSummary pps on pps.PolicyID = pol.PolicyID
join sa_ows_sale sale on sale.SaleID = pol.SaleID
join mi_insight_UserHierarchy uh on uh.UserUID = sale.AdviserUID
left join mi_insight_UserHierarchy uh1 on uh.OwlASMUID1 = uh1.UserUID
join sa_ows_person pers on pers.PersonID = sale.personID

where pol.InternalProductID = 10000063
and SaleStatusID = 2 and pol.Status = 2
--and uh.OwlASMUID1 is not null
and sale.adviserUID <> '4006226' -- Excluding the test UID
and convert(Date,pol.ApplicationDate,103) >= @Startdate
and convert(Date,pol.ApplicationDate,103) <= @Enddate

UNION all

select 
--'Written',
uh2.UserUID as Adviser,

uh2.businessuid as Firm,

null as transactionid,
convert(date,pol.ApplicationDate,103) as writtendate,

pps.PremiumAmount*12*((1.00/25.00)) as APE,
pps.PremiumAmount*12*((1.00/25.00)) as DistributionAllowance,
'' as NBI,
((pps.PremiumAmount*12*(0.35*(1.00/25.00))) - (pps.PremiumAmount*12*0.01)) as Margin,
1.00/25.00 as NBCases,
1.00/25.00 as AllCases,
'' as frequency,
pol.policyID as caseid,
pps.policynumber as policy,
'NB' as businessreason,
'' as Adminmethoddescription,
'L&GASU OWL' as Productcode,
'L&G OWL' as Provider,
'' as reportingproductname,
'ASU' as ProductSubGroup,
'Protection' as ProductGroupName,
'' as originatingsource,
'Advised' as adminmethod,
'' as calculationcode,
'' as 'description',
'Pat McKenna' as ASD,
'ST' as Catagory


from sa_ows_Policies  pol
join policy.sa_ows_ProtectionProductSummary pps on pps.PolicyID = pol.PolicyID
join sa_ows_sale sale on sale.SaleID = pol.SaleID
join mi_insight_UserHierarchy uh on uh.UserUID = sale.AdviserUID
left join  mi_insight_UserHierarchy uh2 on uh.OwlASMUID2 = uh2.UserUID
join sa_ows_person pers on pers.PersonID = sale.personID

where pol.InternalProductID = 10000063
and SaleStatusID = 2 and pol.Status = 2
and sale.adviserUID <> '4006226' -- Excluding the test UID
and convert(Date,pol.ApplicationDate,103) >= @Startdate
and convert(Date,pol.ApplicationDate,103) <= @Enddate
--and uh.OwlASMUID2 is not null

order by wr.writtendate desc
--drop table #c


---------------New Written Table------------------------


Select


Adviser,
Firm,
convert(varchar(2),month(WrittenDate))+convert(varchar(4),year(WrittenDate)) as WrittenDate, 
SUM (APE) as APE,
SUM (DistributionAllowance) as DA,
SUM (NBI) as Comm,
SUM (Margin) as Margin,
SUM (NBCases) as NBCases,
SUM (Allcases) as AllCases,
Businessreason,
Provider,
productsubgroupname,
Calculationcode,
Description,
Catagory

from #OWLWritten

where catagory = 'ST'

Group by 
Adviser,
Firm,
convert(varchar(2),month(WrittenDate))+convert(varchar(4),year(WrittenDate)),
Businessreason,
Provider,
productsubgroupname,
Calculationcode,
Description,
Catagory



Select sum(APE),catagory from #OWLWritten group by catagory

GO
/****** Object:  StoredProcedure [BI].[pr_055_ProtectionDataRebuildOwlTotal]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	55. Protection Data Rebuild OWL Total.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_055_ProtectionDataRebuildOwlTotal]

as

--ISSUED DATA
--WRITTEN DATA

IF OBJECT_ID('tempdb..#b') IS NOT NULL
DROP TABLE #b

IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c

IF OBJECT_ID('tempdb..#d') IS NOT NULL
DROP TABLE #d

declare @StartDate datetime,@EndDate datetime;
set @StartDate = CONVERT(DATETIME, '2018-01-01 00:00:00', 102) 
set @EndDate = CONVERT(DATETIME, '2019-02-28 23:59:59', 102)

IF OBJECT_ID('tempdb..#e') IS NOT NULL
DROP TABLE #e

select min(id) as transactionid, policyreference, Commissionmonth, count(policyreference) as lines
into #e
from dbo.owt_OwlDirectPayments	 
where
Grosspremium >=0 
group by
policyreference, Commissionmonth

-- create a table in order to calculate the first issued transaction number in a case
	
select min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #b
from		 
dbo.mstt_Commissions co INNER JOIN
dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID
where co.poltrantranstype <> 39
and co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
group by
po.policyref, po.cont_num, co.productcode

-------------------------CORRECT APE LV

Select distinct 
edic.PolicyNumber, 
edic.PremiumAmount, 
edic.AmountReceived,  
edic.CommissionType, 
edih.LifeOfficeCode, 
edih.DateReceived,
potr.Amount, 
potr.CommInitialPeriod, 
potr.Amount/potr.CommInitialPeriod as CorrectPremium,
(potr.Amount/potr.CommInitialPeriod)*12 as CorrectAPE,
potr.Amount*12 as IncorrectAPE,
pp.AGENT_CODE,
pp.AGENT_PERC,
pp.BACSDate,
pp.FranchiseAgentCode,
agt.DESCN,
pp.TransactionID AS TransID
--pacc.UnallocatedReasonCode
into #d
from sa_swift_EDIFACTCommissionStatementContents edic
join sa_swift_EDIFACTCommissionStatementHeader edih on edih.ID = edic.StatementHeaderID
join sa_swift_S_PACC pacc on pacc.ID = edic.Pacc_ID
join sa_swift_PolicyTransactions potr on potr.ID = pacc.TransactionID
join mstt_PaymentsPending pp on pp.PACC_ID = pacc.ID
join sa_swift_S_AGENTS agt on agt.code = pp.FranchiseAgentCode
where edih.LifeOfficeCode = '24225G' and edih.DateReceived >= dateadd(year,-1,getdate())
and pp.BACSDate > '11-Jan-2016' --and pp.BACSDate < '12-Jan-2017'
and edic.CommissionType = 'Y'
and edic.PremiumAmount = potr.Amount
and pp.AGENT_CODE != '10002'
--and pacc.UnallocatedReasonCode is not null
order by Amount desc

-- Swift transactions

select
case when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end as agent_code,

Case 
when (case when((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end) = '1006886' then 'NULL'

when ag.firm = '1000941' then '1007791' when ag.firm = '1000976' then '2001655' when ag.firm = '1001619' then '2001460' when ag.firm = '1001747' then '1006123' when ag.firm = '1001860' then '2000914' when ag.firm = '1001931' then '2001142' when ag.firm = '1002683' then '2001252' when ag.firm = '1002866' then '2001140' when ag.firm = '1002958' then '1002961' when ag.firm = '1003038' then '2001543' when ag.firm = '1003450' then '2001454' when ag.firm = '1004284' then '1000392' when ag.firm = '1005445' then '2001002' when ag.firm = '1010723' then '1001338' when ag.firm = '1000746' then '1011544' when ag.firm = '1002578' then '2001476' when ag.firm = '1002580' then '1011548' when ag.firm = '2000508' then '1004215'
when ag.firm = '1001374' then '2001538' when ag.firm = '1000981' then '2000425' when ag.firm = '2000522' then '2001536' when ag.firm = '1009210' then '2001543' when ag.firm = '1001167' then '2001540' when ag.firm = '1001789' then '2001395' when ag.firm = '1002076' then '2001475' when ag.firm = '1001058' then '2001549' when ag.firm = '1011487' then '2001497' when ag.firm = '1000821' then '1011541' when ag.firm = '1000692' then '2001575' when ag.firm = '1007638' then '2001578' when ag.firm = '1001804' then '2001582' when ag.firm = '1000794' then '2001580' when ag.firm = '1001492' then '2001584' when ag.firm = '1011448' then '2001585' when ag.firm = '1011540' then '1001897' when ag.firm = '1002178' then '2001613'
when ag.firm = '1000967' then '2001653' when ag.firm = '2001040' then '2001655' when ag.firm = '1001891' then '2001714' when ag.firm = '1002112' then '2001807' when ag.firm = '1000867' then '1011604' when ag.firm = '1011608' then '1010815' when ag.firm = '1001049' then '2001995' when ag.firm = '1000724' then '1004141' when ag.firm = '1001346' then '1009425' when ag.firm = '1000678' then '2004388' when ag.firm = '1000704' then '1003010' when ag.firm = '1008026' then '1001546' when ag.firm = '1002702' then '2001504' when ag.firm = '2000988' then '1001249' when ag.firm = '2001397' then '2004449' when ag.firm = '1002174' then '2006794' when ag.firm = '1009620' then '2010099' when ag.firm = '1007327' then '2011344'

else ag.firm End as "Firm", ag.commissiontypedesc,
ag.transactionid, ag.createdatetime, 
Case when (case when cs.frequencydesc = 'Single' Then 'Single' ELSE 'Regular' end) = 'Single' then ((case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) *10) else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end as "Premium",
Case when d.PolicyNumber = ag.providerRef then d.CorrectAPE else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end)end as "APE", 

---DA INITAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
-- DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end as DA,

-- COMM INITIAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then cs.inissued
-- COMM SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
-- COMM TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
else 0 end as Comm,

-- MARGIN INITIAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- MARGIN TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
-- MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end as Margin
,

coalesce(case when ag.commissiontypedesc like '%claw%' then 0 when cs.ape < 0 then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 else ag.derivedagentsplit/100 end,0) as "Cases", 
case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end as "NB Cases",
case when pt.frequencydescription = 'Single' Then 'Single' ELSE 'Regular' END AS 'Frequency', ag.caseid, ag.providerref
, isnull((case when co.BusinessReason in ('NB') then 'NB' else co.businessreason end),'NB') as "business reason", isnull(co.productcode,ag.tranproduct) as "ProductCode", isnull(co.productprovidercode,ag.comp_code) as "Comp_code", rp.reportingproductname as reportingproductname, 
case when ph.productsubgroupname in ('Critical Illness','TALA') then 'Term Assurance' when cs.productcode = 'MLP' then 'MLP' else ph.productsubgroupname end as "productsubgroupname",
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','19') and (left(tranproduct,2) in ('OW','OF'))) then 'Servicing Fee' when ag.commissiontype in ('10','19') then 'Trail Income' else 'Renewal Income' end as "ProductGroupName",
ccs.calculationcode, case when cs.paybasisdesc in ('Accr') then 'Accrual' else 'Indemnity' end as paybasisdesc, cs.oastatus, rtrim(ah.asdname), Replace(ccs.description, ',', ' ') AS description,
case when ag.COMP_CODE like '%OWL%' then 'ST' else 'Panel' end as 'Catagory' 



from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid
LEFT OUTER JOIN #d d on (d.PolicyNumber = ag.providerref) AND (d.TransID = ag.TransactionID)

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate
and (ag.agent_code <> '10002' or ag.agent_code <> '1011623')
and ag.amount <> 0
and ag.commissiontype in ('1','4','10','17','18','19')
and (cs.oastatus = 'valid' or cs.oastatus is null)
and (rtrim(ah.ASDName) = 'Pat Mckenna') --or ah.ASDName is Null)
and ---DA INITAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
-- DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end <> 0

and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 

and case when (ag.firm in ('1006698','1009681','1000311','1004454','1009681','1009681','2001020','1011141') and isnull(co.productprovidercode,ag.comp_code) = 'Zurich New') then 'NASP ZURICH' else 'OTHER' end <> 'NASP ZURICH'
and ph.productgroupname = 'Protection'

and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Indexation'



and case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','19') and (left(tranproduct,2) in ('OW','OF'))) then 'Servicing Fee' when ag.commissiontype in ('10','19') then 'Trail Income' else 'Renewal Income' end = 'Protection'

union all

