-------------- end of Issued Scan------------------


select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
group by po.policyref, po.cont_num, co.productcode




select
wr.Adviser,
wr.Firm,
wr.transactionid,
wr.Writtendate,
wr.Ape,
wr.Distributionallowance, wr.NBI, wr.Margin, wr.NBcases, wr.Allcases, wr.frequency, wr.CaseID, 
wr.Policy, wr.Businessreason,
wr.Adminmethoddescription, wr.Productcode, wr.Provider, wr.Reportingproductname, 
case when wr.productsubgroupname in ('Critical Illness','TALA') then 'Term Assurance' when wr.productcode = 'MLP' then 'MLP' else wr.productsubgroupname end as "productsubgroupname",
wr.Productgroupname,
wr.Originatingsource, wr.Adminmethod, wr.Calculationcode, REPLACE(wr.Description, ',',' ' ) AS Description, wr.ASD,
case when wr.Provider like '%OWL%' then 'ST' else 'Panel' end as 'Catagory' 


from


(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
round(co.Turnover,2) as APE,
min(co.distributionallowance) as distributionallowance, min(co.baseamount + co.upliftamount) AS NBI, min(co.salesmargin) as margin, 
max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases", 
max((co.agent_perc/100)) as "AllCases", min(pt.FrequencyDescription) as frequency, min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD


FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) = 'Pat Mckenna') -- or ah.ASDName is Null)
group by cast(co.AGENT_CODE as int), round(co.Turnover,2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate)) wr

where
wr.writtendate >= @StartDate
and wr.writtendate <= @EndDate
and wr.productgroupname = 'Protection'
--and wr.firm = '1002222'
--and wr.originatingsource = '5'






