'NB' as businessreason,
'' as Adminmethoddescription,
'L&GASU OWL' as Productcode,
'L&G OWL' as Provider,
'' as reportingproductname,
'ASU' as ProductSubGroup,
'Protection' as ProductGroupName,
'' as originatingsource,
'Advised' as adminmethod,
'' as calculationcode,
'' as 'description',
'Pat McKenna' as ASD,
'ST' as Catagory


from sa_ows_Policies  pol
join policy.sa_ows_ProtectionProductSummary pps on pps.PolicyID = pol.PolicyID
join sa_ows_sale sale on sale.SaleID = pol.SaleID
join mi_insight_UserHierarchy uh on uh.UserUID = sale.AdviserUID
left join  mi_insight_UserHierarchy uh2 on uh.OwlASMUID2 = uh2.UserUID
join sa_ows_person pers on pers.PersonID = sale.personID

where pol.InternalProductID = 10000063
and SaleStatusID = 2 and pol.Status = 2
and sale.adviserUID <> '4006226' -- Excluding the test UID
and convert(Date,pol.ApplicationDate,103) >= @Startdate
and convert(Date,pol.ApplicationDate,103) <= @Enddate
--and uh.OwlASMUID2 is not null

order by wr.writtendate desc
drop table #c



GO
/****** Object:  StoredProcedure [BI].[pr_056_ProtectionDataRebuildOwl]    Script Date: 7/3/2026 3:34:42 PM ******/
