CAST(ROUND(sum((dp.GrossPremium*(ASMCommissionPct/(SellerCommissionPct + ASMCommissionPct + ESMCommissionPct))))*0.35,2) as Decimal (15,2))-dp.ASMCommissionAmt as Margin,
CAST(ROUND(ASMCommissionPct/(SellerCommissionPct + ASMCommissionPct + ESMCommissionPct),2) as Decimal(15,2)) as Cases,
