dp.Product,
dp.policyreference,
dp.SellerCommissionAmt,
GrossPremium,
TransactionType,
SellerCommissionPct,
ASMCommissionPct,
ESMCommissionPct,
ASMCommissionAmt


union all

select
--'Issued' As Type,
dp.ASMUID as agent_Code,
' ' as Firm,
' ' as Commissiontypedesc,
' ' as TransactionID,
dp.Commissionmonth as date,
CAST(Round(sum((dp.GrossPremium*(ASMCommissionPct/(SellerCommissionPct + ASMCommissionPct + ESMCommissionPct)))),2) as Decimal(15,2)) as premium,
CAST(ROUND(sum((dp.GrossPremium*(ASMCommissionPct/(SellerCommissionPct + ASMCommissionPct + ESMCommissionPct)))),2) as Decimal(15,2)) as APE,
CAST(ROUND(sum((dp.GrossPremium*(ASMCommissionPct/(SellerCommissionPct + ASMCommissionPct + ESMCommissionPct))))*0.35,2) as Decimal(15,2)) as DA,
dp.ASMCommissionAmt as Comm,
CAST(ROUND(sum((dp.GrossPremium*(ASMCommissionPct/(SellerCommissionPct + ASMCommissionPct + ESMCommissionPct))))*0.35,2) as Decimal (15,2))-dp.ASMCommissionAmt as Margin,
CAST(ROUND(ASMCommissionPct/(SellerCommissionPct + ASMCommissionPct + ESMCommissionPct),2) as Decimal(15,2)) as Cases,
case when (dp.TransactionType in ('New Business')) then CAST(ROUND(ASMCommissionPct/(SellerCommissionPct + ASMCommissionPct + ESMCommissionPct),2) as Decimal(15,2)) end as NBCases,
' ' as Frequency,
' ' as CaseID,
dp.policyreference as Provideref,
'NB' as Businessreason,
'L&GASU OWL' as Productcode,
'L&G OWL' as Compcode,
' ' as ReportingProductName,
dp.Product as Productsubgroupname,
'Protection' as productgroupname,
'ATP1' as Calculationcode,
' ' as Paybasisdescription,
' ' as oastatus,
'Pat McKenna' as ASDName,
'033 - Adviser ASM ESM (Annually / Indemnity)' as Description,
'ST' as Catagory




from dbo.owt_OwlDirectPayments dp
	 left join #e e on e.transactionID = dp.ID
	 left join cscv_AgentsHierarchy ah on ah.Agentcode = dp.adviserUID

where
