/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	59. Protection Proposition Master.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_059_ProtectionPropositionMaster]

as

--ISSUED DATA
--WRITTEN DATA

IF OBJECT_ID('tempdb..#b') IS NOT NULL
DROP TABLE #b

IF OBJECT_ID('tempdb..#bb') IS NOT NULL
DROP TABLE #bb

IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c

IF OBJECT_ID('tempdb..#d') IS NOT NULL
DROP TABLE #d

IF OBJECT_ID('tempdb..#IssProtect') IS NOT NULL
DROP TABLE #IssProtect

IF OBJECT_ID('tempdb..#WriProtect') IS NOT NULL
DROP TABLE #WriProtect


declare @StartDate datetime,@EndDate datetime;
set @StartDate = CONVERT(DATETIME, '2018-01-01 00:00:00', 102) 
set @EndDate = CONVERT(DATETIME, '2019-02-28 23:59:59', 102)

-- create a table in order to calculate the first issued transaction number in a case
	
select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #bb

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where co.poltrantranstype <> 39
and co.agent_code not in ('10002','1011542','10004')	
and co.commissiontype = 1
and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by po.policyref, po.cont_num, co.productcode

union all

select
min(transactionid) as transactionid, '', '','L&G' provider

FROM				  dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end

select transactionid,policyref,cont_num into #b from #bb where left(cont_num,2) <> 'ZR' or cont_num is null
union all
select case when left(cont_num,2) = 'ZR' then min(transactionid) end transactionid, policyref, cont_num
from #bb where left(cont_num,2) = 'ZR'group by  policyref, cont_num

drop table #bb

-------------------------CORRECT APE LV

Select distinct 
edic.PolicyNumber, 
edic.PremiumAmount, 
edic.AmountReceived,  
edic.CommissionType, 
edih.LifeOfficeCode, 
edih.DateReceived,
potr.Amount, 
potr.CommInitialPeriod, 
potr.Amount/potr.CommInitialPeriod as CorrectPremium,
(potr.Amount/potr.CommInitialPeriod)*12 as CorrectAPE,
potr.Amount*12 as IncorrectAPE,
pp.AGENT_CODE,
pp.AGENT_PERC,
pp.BACSDate,
pp.FranchiseAgentCode,
agt.DESCN,
pp.TransactionID AS TransID
--pacc.UnallocatedReasonCode
into #d
from sa_swift_EDIFACTCommissionStatementContents edic
join sa_swift_EDIFACTCommissionStatementHeader edih on edih.ID = edic.StatementHeaderID
join sa_swift_S_PACC pacc on pacc.ID = edic.Pacc_ID
join sa_swift_PolicyTransactions potr on potr.ID = pacc.TransactionID
join mstt_PaymentsPending pp on pp.PACC_ID = pacc.ID
join sa_swift_S_AGENTS agt on agt.code = pp.FranchiseAgentCode
where edih.LifeOfficeCode = '24225G' and edih.DateReceived <= '10-Apr-2017' --dateadd(year,-1,getdate())
and pp.BACSDate > '11-Jan-2016' --and pp.BACSDate < '12-Jan-2017'
and edic.CommissionType = 'Y'
and edic.PremiumAmount = potr.Amount
and pp.AGENT_CODE != '10002'
--and pacc.UnallocatedReasonCode is not null
order by Amount desc


-- Swift transactions

select
case when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end as agent_code,

Case 
when (case when((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end) = '1006886' then 'NULL'

when ag.firm = '1000941' then '1007791' when ag.firm = '1000976' then '2001655' when ag.firm = '1001619' then '2001460' when ag.firm = '1001747' then '1006123' when ag.firm = '1001860' then '2000914' when ag.firm = '1001931' then '2001142' when ag.firm = '1002683' then '2001252' when ag.firm = '1002866' then '2001140' when ag.firm = '1002958' then '1002961' when ag.firm = '1003038' then '2001543' when ag.firm = '1003450' then '2001454' when ag.firm = '1004284' then '1000392' when ag.firm = '1005445' then '2001002' when ag.firm = '1010723' then '1001338' when ag.firm = '1000746' then '1011544' when ag.firm = '1002578' then '2001476' when ag.firm = '1002580' then '1011548' when ag.firm = '2000508' then '1004215'
when ag.firm = '1001374' then '2001538' when ag.firm = '1000981' then '2000425' when ag.firm = '2000522' then '2001536' when ag.firm = '1009210' then '2001543' when ag.firm = '1001167' then '2001540' when ag.firm = '1001789' then '2001395' when ag.firm = '1002076' then '2001475' when ag.firm = '1001058' then '2001549' when ag.firm = '1011487' then '2001497' when ag.firm = '1000821' then '1011541' when ag.firm = '1000692' then '2001575' when ag.firm = '1007638' then '2001578' when ag.firm = '1001804' then '2001582' when ag.firm = '1000794' then '2001580' when ag.firm = '1001492' then '2001584' when ag.firm = '1011448' then '2001585' when ag.firm = '1011540' then '1001897' when ag.firm = '1002178' then '2001613'
when ag.firm = '1000967' then '2001653' when ag.firm = '2001040' then '2001655' when ag.firm = '1001891' then '2001714' when ag.firm = '1002112' then '2001807' when ag.firm = '1000867' then '1011604' when ag.firm = '1011608' then '1010815' when ag.firm = '1001049' then '2001995' when ag.firm = '1000724' then '1004141' when ag.firm = '1001346' then '1009425' when ag.firm = '1000678' then '2004388' when ag.firm = '1000704' then '1003010' when ag.firm = '1008026' then '1001546' when ag.firm = '1002702' then '2001504' when ag.firm = '2000988' then '1001249' when ag.firm = '2001397' then '2004449' when ag.firm = '2001518' then '2006569' when ag.firm = '2005389' then '2006353' when ag.firm = '1002174' then '2006794'
when ag.firm = '1009620' then '2010099' when ag.firm = '1007327' then '2011344'

else ag.firm End as "Firm", ag.commissiontypedesc,
ag.transactionid, ag.createdatetime, 
Case when (case when cs.frequencydesc = 'Single' Then 'Single' ELSE 'Regular' end) = 'Single' then ((case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) *10) else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end as "Premium",
Case when (d.PolicyNumber = ag.providerRef AND ag.createdatetime < '10-Jul-2017') then d.CorrectAPE else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end)END as "APE", 

---DA INITAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
-- DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end as DA,
  
-- COMM INITIAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then cs.inissued
-- COMM SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
-- COMM TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
else 0 end as Comm,

-- MARGIN INITIAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- MARGIN TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
-- MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end as Margin
,

coalesce(case when ag.commissiontypedesc like '%claw%' then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when cs.ape < 0 then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 else ag.derivedagentsplit/100 end,0) as "Cases", 

case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end as "NB Cases",

case when pt.frequencydescription = 'Single' Then 'Single' ELSE 'Regular' END AS 'Frequency', ag.caseid, ag.providerref
, isnull((case when co.BusinessReason in ('NB') then 'NB' else co.businessreason end),'NB') as "business reason", isnull(co.productcode,ag.tranproduct) as "ProductCode", isnull(co.productprovidercode,ag.comp_code) as "Comp_code", rp.reportingproductname as reportingproductname, 
case when ph.productsubgroupname in ('Critical Illness','TALA') then 'Term Assurance' when cs.productcode = 'MLP' then 'MLP' else ph.productsubgroupname end as "productsubgroupname",
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','19') and (left(tranproduct,2) in ('OW','OF'))) then 'Servicing Fee' when ag.commissiontype in ('10','19') then 'Trail Income' else 'Renewal Income' end as "ProductGroupName",
ccs.calculationcode, case when cs.paybasisdesc in ('Accr') then 'Accrual' else 'Indemnity' end as paybasisdesc, cs.oastatus, rtrim(ah.asdname) AS ASD, ccs.description,
case when ag.firm in ('1006698','1009681','1000311','1004454','1009681','1009681','2001020','1011141') then 'NASP'
when (left(cs.productcode,3) = 'PNL' or left((replace(ccs.description,'do not use - ','')),3) = '002' or isnull(co.productprovidercode,ag.comp_code) in ('Zurich PNL','NU','SCOT EQ')) then 'Legacy Providers' when (left((replace(ccs.description,'do not use - ','')),3) = '005' or left(ccs.description,16) = 'DO NOT USE - 005') or left(ccs.description,6) = 'Exeter' or left(ccs.description,8) = 'Guardian' then 'Panel' when (ag.firm not in ('1006698','1009681','1000311','1004454','1009681','1009681','2001020','1011141', '2005309') and isnull(co.productprovidercode,ag.comp_code) = 'L&G') then 'Panel' when ag.firm = '2005309' then 'JM' else 'ST' end as 'Category',
pt.termYears, pt.termMonths, pt.Comminitialperiod, case when left(ltrim(ag.caseid),3) like '500' then 'BP' else ' ' end as "BP Marker"

Into #IssProtect

from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid
LEFT OUTER JOIN #d d on (d.PolicyNumber = ag.providerref) AND (d.TransID = ag.TransactionID)

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate
and (ag.agent_code <> '10002' or ag.agent_code <> '1011623')
and ag.amount <> 0
and ag.commissiontype in ('1','4','10','17','18','19')
and (cs.oastatus = 'valid' or cs.oastatus is null)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
and ---DA INITAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
-- DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end <> 0

and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 

and case when (ag.firm in ('1006698','1009681','1000311','1004454','1009681','1009681','2001020','1011141') and isnull(co.productprovidercode,ag.comp_code) = 'Zurich New') then 'NASP ZURICH' else 'OTHER' end <> 'NASP ZURICH'
and ph.productgroupname = 'Protection'

and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Indexation'



and case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','19') and (left(tranproduct,2) in ('OW','OF'))) then 'Servicing Fee' when ag.commissiontype in ('10','19') then 'Trail Income' else 'Renewal Income' end = 'Protection'
and isnull(co.productprovidercode,ag.comp_code) NOT LIKE '%Owl%'

order by ag.agent_code, ag.firm  desc
drop table #b



---------------- New Issued Table------------------


Select distinct


Agent_code,
Firm,
convert(varchar(2),month(createdatetime))+convert(varchar(4),year(createdatetime)) as Date,
SUM (Premium) as Premium,
SUM (APE) as APE,
SUM (DA) as DA,
SUM (Comm) as Commision,
SUM (Margin) as Margin,
SUM (Cases) as Cases,
SUM ([NB Cases]) as [NB Cases],
Comp_code,
reportingproductname,
productsubgroupname,
calculationcode,
paybasisdesc,
description,
Category,
[BP Marker]


from #IssProtect


Group by 
Agent_code,
Firm,
convert(varchar(2),month(createdatetime))+convert(varchar(4),year(createdatetime)), 
Comp_code,
reportingproductname,
productsubgroupname,
calculationcode,
paybasisdesc,
description,
Category,
[BP Marker]


---------------------- Written ---------------------------------------

select
min(transactionid) as transactionid, po.PolicyRef, po.cont_num, co.productcode,ph.productgroupname,COMP_CODE --case when po.policyref IS NULL then convert(VARCHAR,replace(po.cont_num,'-','')) else convert(VARCHAR, po.policyref) end AS caseid
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')

group by po.policyref, po.cont_num, co.productcode, ph.productgroupname,COMP_CODE

union all



select
min(transactionid) as transactionid, '' t1, '' t2,'' t3,ph.productgroupname,COMP_CODE

FROM          dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
--and ph.productgroupname like 'Protection'
and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')

group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end,ph.productgroupname,COMP_CODE


select
wr.Adviser,

case when wr.firm = '1000941' then '1007791' when wr.firm = '1000976' then '2001655' when wr.firm = '1001619' then '2001460' when wr.firm = '1001747' then '1006123' when wr.firm = '1001860' then '2000914' when wr.firm = '1001931' then '2001142' when wr.firm = '1002683' then '2001252' when wr.firm = '1002866' then '2001140' when wr.firm = '1002958' then '1002961' when wr.firm = '1003038' then '2001543' when wr.firm = '1003450' then '2001454' when wr.firm = '1004284' then '1000392' when wr.firm = '1005445' then '2001002' when wr.firm = '1010723' then '1001338' when wr.firm = '1000746' then '1011544' when wr.firm = '1002578' then '2001476' when wr.firm = '1002580' then '1011548' when wr.firm = '2000508' then '1004215'
when wr.firm = '1001374' then '2001538' when wr.firm = '1000981' then '2000425' when wr.firm = '2000522' then '2001536' when wr.firm = '1009210' then '2001543' when wr.firm = '1001167' then '2001540' when wr.firm = '1001789' then '2001395' when wr.firm = '1002076' then '2001475' when wr.firm = '1001058' then '2001549' when wr.firm = '1011487' then '2001497' when wr.firm = '1000821' then '1011541' when wr.firm = '1000692' then '2001575' when wr.firm = '1007638' then '2001578' when wr.firm = '1001804' then '2001582' when wr.firm = '1000794' then '2001580' when wr.firm = '1001492' then '2001584' when wr.firm = '1011448' then '2001585' when wr.firm = '1011540' then '1001897' when wr.firm = '1002178' then '2001613'
when wr.firm = '1000967' then '2001653' when wr.firm = '2001040' then '2001655' when wr.firm = '1001891' then '2001714' when wr.firm = '1002112' then '2001807' when wr.firm = '1000867' then '1011604' when wr.firm = '1011608' then '1010815' when wr.firm = '1001049' then '2001995' when wr.firm = '1000724' then '1004141' when wr.firm = '1001346' then '1009425' when wr.firm = '1000678' then '2004388' when wr.firm = '1000704' then '1003010' when wr.firm = '1008026' then '1001546' when wr.firm = '1002702' then '2001504' when wr.firm = '2000988' then '1001249' when wr.firm = '2001397' then '2004449' when wr.firm = '2001518' then '2006569' when wr.firm = '2005389' then '2006353' when wr.firm = '1002174' then '2006794'
when wr.firm = '1009620' then '2010099' when wr.firm = '1007327' then '2011344'

else wr.firm End as "Firm",
wr.transactionid,
wr.Writtendate,
wr.Ape,
wr.Distributionallowance, wr.NBI, wr.Margin, wr.NBcases, wr.Allcases, wr.frequency, wr.CaseID, 
wr.Policy, wr.Businessreason,
wr.Adminmethoddescription, wr.Productcode, wr.Provider, wr.Reportingproductname, 
case when wr.productsubgroupname in ('Critical Illness','TALA') then 'Term Assurance' when wr.productcode = 'MLP' then 'MLP' else wr.productsubgroupname end as "productsubgroupname",
wr.Productgroupname,
wr.Originatingsource, wr.Adminmethod, wr.Calculationcode, wr.Description, wr.ASD,
case when wr.firm in ('1006698','1009681','1000311','1004454','1009681','1009681','2001020','1011141') then 'NASP'
when (left(wr.productcode,3) = 'PNL' or left((replace(wr.description,'do not use - ','')),3) = '002' or wr.productcode in ('Zurich PNL','NU','SCOT EQ'))then 'Legacy Providers' when (left((replace(wr.description,'do not use - ','')),3) = '005' or left(wr.description,16) = 'DO NOT USE - 005') or left(wr.description,6) = 'Exeter' or left(wr.description,8) = 'Guardian' then 'Panel' when (wr.firm not in ('1006698','1009681','1000311','1004454','1009681','1009681','2001020','1011141', '2005309') and wr.provider = 'L&G') then 'Panel' when (wr.description is null and wr.provider in ('L&G','Scot Eq') and wr.firm <> '2005309') then 'Panel' when wr.provider in ('Scot Prov','NU') then 'IFA' when wr.firm = '2005309' then 'JM' else 'ST' end as 'Category'

Into #WriProtect
from


(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,
Case when (min(po.PolicyRef) is null AND co.agent_code <> '1000312') then 0 else min(co.distributionallowance)End as distributionallowance, 
Case when (min(po.PolicyRef) is null AND co.agent_code <> '1000312') then 0 else min(co.baseamount + co.upliftamount)END AS NBI, 
Case when (min(po.PolicyRef) is null AND co.agent_code <> '1000312') then 0 else min(co.salesmargin)END as margin, 
CASE WHEN min(c.policyref) = 0 then 0 else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)End)End as "NBCases", 
CASE WHEN min(c.policyref) = 0 then 0 else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312' OR (((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection'))) then 0 else max((co.agent_perc/100))END)END as "AllCases",
min(pt.FrequencyDescription) as frequency, min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD


FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
			  dbo.sa_ows_Policies P ON P.PolicyID = po.PolicyRef LEFT OUTER JOIN
			  dbo.sa_ows_Sale S ON S.SaleID = P.SaleID LEFT OUTER JOIN
			  --sa_ows_FactFindIncomeDetail FFI on FFI.SaleID = P.SaleID LEFT OUTER JOIN
			  dbo.sa_ows_Person Per ON Per.PersonID = S.PersonID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV on IV.InputID = Per.TitleID AND IV.InputType = 'Title'
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
and po.COMP_CODE NOT LIKE '%Owl%'
group by cast(co.AGENT_CODE as int), round(co.Turnover,2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate),co.AGENT_CODE, ph.productgroupname, ccs.description, pt.mortgageamount, co.agent_perc, co.Turnover) wr

where
wr.writtendate >= @StartDate
and wr.writtendate <= @EndDate
and wr.productgroupname = 'Protection'
--and wr.firm = '1002222'
--and wr.originatingsource = '5'

order by wr.writtendate desc
drop table #c


-------------------- New Written Table---------------

Select distinct


Adviser,
Firm,
convert(varchar(2),month(WrittenDate))+convert(varchar(4),year(WrittenDate)) as WrittenDate, 
SUM (APE) as APE,
SUM (DistributionAllowance) as DA,
SUM (NBI) as Comm,
SUM (Margin) as Margin,
SUM (NBCases) as NBCases,
SUM (Allcases) as AllCases,
Businessreason,
Provider,
productsubgroupname,
Calculationcode,
Description,
Category

from #WriProtect

Group by 
Adviser,
Firm,
convert(varchar(2),month(WrittenDate))+convert(varchar(4),year(WrittenDate)),
Businessreason,
Provider,
productsubgroupname,
Calculationcode,
Description,
Category


GO
/****** Object:  StoredProcedure [BI].[pr_060_PruMetReports]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	60. PruMet Reports.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_060_PruMetReports]

as

IF OBJECT_ID('tempdb..#b') IS NOT NULL
DROP TABLE #b

declare @StartDate datetime,@EndDate datetime;
set @StartDate = CONVERT(DATETIME, '2016-01-01 00:00:00', 102) 
set @EndDate = CONVERT(DATETIME, '2017-12-31 23:59:59', 102) ---ENSURE END DATE IS LAST DAY OF REPORTING MONTH

---PRU MET REPORT -----------------------------------------------------------------------------------------------------------------------------------------------------------------------------

-- create a table in order to calculate the first issued transaction number in a case
select min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #b
from		 
dbo.mstt_Commissions co INNER JOIN
dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID
where co.poltrantranstype <> 39
and co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
group by
po.policyref, po.cont_num, co.productcode

select
ag.agent_code,

month(ag.createdatetime)as month, year(ag.createdatetime) as year,
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end as "ProductGroupName",

case when (ag.commissiontype in ('4','10','19') and (left(tranproduct,2) in ('OW','OF'))) then 'Servicing Fee' when ag.commissiontype in ('10','19') then 'Trail Income' when ag.commissiontype in ('4','18') then 'Renewal Income'

-- Protection
when (left((replace(ccs.description,'do not use - ','')),3) = '005' and ag.firm <> '1000311') then 'Pro: Openwork Select' when left((replace(ccs.description,'do not use - ','')),3) = '002' then 'Pro: IFA Panel' when Left(co.productcode,3) = 'PNL' then 'Pro: IFA Panel' when (isnull(co.productprovidercode,ag.comp_code) = 'L&G' and ph.productgroupname = 'Protection') then 'Pro: NASP L&G' when ph.productgroupname = 'Protection' then 'Pro: Zurich Plus' 

-- Pensions
when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) in ('IFDL','Zurich PLT','Openwork')) then 'Pen: Platform' when co.productcode = 'OFHBSIPP' then 'Pen: Platform' when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife') then 'Pen: Metlife' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Pru Tip' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Pen: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Pen: Other Comm'

-- Annuities
when isnull(co.productprovidercode,ag.comp_code) = 'PTSP' then 'PTSP Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'Pru')) then 'Pru Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) like '%Zurich%')) then 'Zurich Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'MGMA')) then 'MGMA Annuity' when ph.productsubgroupname like '%Annuity%' then 'Other Annuity'

-- Investments
when (ph.productgroupname = 'Investment' and (isnull(co.productprovidercode,ag.comp_code) = 'IFDL' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT')) then 'Inv: IFDL Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Inv: Zurich Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Pru Fund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Inv: Structured' when ph.productgroupname = 'Investment' then 'Inv: Other'

when ph.productgroupname = 'Mortgage' then 'Mortgages' else ph.productsubgroupname end as 'productsubgroup',

-- APE FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM / 10 FOR APE
sum((case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then ((cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 / 10) else
	
-- ENSURE MORTGAGES APE IS THE SAME AS DA
(case when 
(case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuities' when ((left(ag.tranproduct,2) in ('OW','OZ')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end) = 'Mortgage'
then (case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end)
else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end) end)) as "APE", 

sum(case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'Gross DA',

-- GROSS MARGIN INITIAL
sum(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
-- GROSS MARGIN TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
-- GROSS MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'Gross Margin (Pre Claw)',

sum(case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end) as "NB Cases"

from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate		
and ag.agent_code <> '10002'
and ag.amount <> 0
and ag.commissiontype in ('1','4','10','17','18','19')
and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 
and (case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0

and case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end in ('Pensions','Investment','Annuity')

and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Indexation'
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT like '%Group Pension%' then 1 when (ph.productsubgroupname like '%Group Pension%'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by

ag.agent_code,
month(ag.createdatetime), year(ag.createdatetime),
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end,

case when (ag.commissiontype in ('4','10','19') and (left(tranproduct,2) in ('OW','OF'))) then 'Servicing Fee' when ag.commissiontype in ('10','19') then 'Trail Income' when ag.commissiontype in ('4','18') then 'Renewal Income'

-- Protection
when (left((replace(ccs.description,'do not use - ','')),3) = '005' and ag.firm <> '1000311') then 'Pro: Openwork Select' when left((replace(ccs.description,'do not use - ','')),3) = '002' then 'Pro: IFA Panel' when Left(co.productcode,3) = 'PNL' then 'Pro: IFA Panel' when (isnull(co.productprovidercode,ag.comp_code) = 'L&G' and ph.productgroupname = 'Protection') then 'Pro: NASP L&G' when ph.productgroupname = 'Protection' then 'Pro: Zurich Plus' 

-- Pensions
when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) in ('IFDL','Zurich PLT','Openwork')) then 'Pen: Platform' when co.productcode = 'OFHBSIPP' then 'Pen: Platform' when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife') then 'Pen: Metlife' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Pru Tip' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Pen: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Pen: Other Comm'

-- Annuities
when isnull(co.productprovidercode,ag.comp_code) = 'PTSP' then 'PTSP Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'Pru')) then 'Pru Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) like '%Zurich%')) then 'Zurich Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'MGMA')) then 'MGMA Annuity' when ph.productsubgroupname like '%Annuity%' then 'Other Annuity'

-- Investments
when (ph.productgroupname = 'Investment' and (isnull(co.productprovidercode,ag.comp_code) = 'IFDL' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT')) then 'Inv: IFDL Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Inv: Zurich Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Pru Fund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Inv: Structured' when ph.productgroupname = 'Investment' then 'Inv: Other'

when ph.productgroupname = 'Mortgage' then 'Mortgages' else ph.productsubgroupname end

UNION ALL

---INSERT ZERO UPFRONT APE

select 
co.agent_code,
month(pt.createdatetime)as month, year(pt.createdatetime) as year,
case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end as ProductGroupName,

case
-- Pensions
when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'IFDL') then 'Pen: Platform' when co.productcode = 'OFHBSIPP' then 'Pen: Platform' when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'Zurich PLT') then 'Pen: Platform' when (co.productprovidercode = 'MetLife') then 'Pen: Metlife' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%' and co.productprovidercode = 'Pru') then 'Pru Tip' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Pen: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Pen: Other Comm' 

-- Annuities
when co.productprovidercode = 'PTSP' then 'Ann: Partnership' when (ph.productsubgroupname like '%Annuity%' and co.productprovidercode = 'Pru') then 'Ann: Pru' when co.productprovidercode = 'MGMA' then 'Ann: MGMA' when ph.productsubgroupname like '%Annuity%' then 'Ann: Other' 

-- Investments
when (ph.productgroupname = 'Investment' and (co.productprovidercode = 'IFDL' or co.productprovidercode = 'Pru PLT')) then 'Inv: IFDL Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Zurich PLT') then 'Inv: Zurich Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Pru') then 'Inv: PruFund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Inv: Structured' when (ph.productgroupname = 'Investment' and (left(co.productcode,2) = 'OF')) then 'Inv: Other Fee' when ph.productgroupname = 'Investment' then 'Inv: Other Comm'

when ph.productgroupname = 'Mortgage' then 'Mortgages' when ph.productgroupname = 'Protection' then 'Protection' else ph.productsubgroupname end as 'productsubgroup',

sum(co.ape),
"Gross DA" = 0, "Gross Margin" = 0,
sum(case when b.transactionid is null then 0 when (co.businessreason = 'I' and co.adminmethoddescription <> 'Not Sold By This Office' and co.adminmethoddescription <> 'Execution Only Increase') then 0 when co.ape = 0 then 0 when co.ape > 0 and co.transactionid = b.transactionid then co.agent_perc/100 else 0 end) as "NB Cases"

from 
mstt_Commissions co LEFT OUTER JOIN
mstt_Policytransactions pt on co.transactionid = pt.id LEFT OUTER JOIN
mstt_Policies po on pt.policyid = po.pol_num LEFT OUTER JOIN
mstt_ProductHierarchy ph ON co.ProductCode = ph.productcode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = co.transactionid


where
co.agent_code <> '10002'
and pt.createdatetime >= @StartDate
and pt.createdatetime <= @EndDate
and co.commissiontype = 1
and ph.rdrtype is not null
and pt.comminitialamount <= 0 and pt.amount > 0
and co.poltrantranstype = 17
and co.adminmethoddescription <> 'Indexation'
and case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end in ('Pensions','Investment','Annuity')
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT like '%Group Pension%' then 1 when (ph.productsubgroupname like '%Group Pension%'and year(pt.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by 
co.agent_code,
month(pt.createdatetime), year(pt.createdatetime),
case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end,
case
-- Pensions
when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'IFDL') then 'Pen: Platform' when co.productcode = 'OFHBSIPP' then 'Pen: Platform' when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'Zurich PLT') then 'Pen: Platform' when (co.productprovidercode = 'MetLife') then 'Pen: Metlife' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%' and co.productprovidercode = 'Pru') then 'Pru Tip' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Pen: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Pen: Other Comm' 

-- Annuities
when co.productprovidercode = 'PTSP' then 'Ann: Partnership' when (ph.productsubgroupname like '%Annuity%' and co.productprovidercode = 'Pru') then 'Ann: Pru' when co.productprovidercode = 'MGMA' then 'Ann: MGMA' when ph.productsubgroupname like '%Annuity%' then 'Ann: Other' 

-- Investments
when (ph.productgroupname = 'Investment' and (co.productprovidercode = 'IFDL' or co.productprovidercode = 'Pru PLT')) then 'Inv: IFDL Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Zurich PLT') then 'Inv: Zurich Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Pru') then 'Inv: PruFund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Inv: Structured' when (ph.productgroupname = 'Investment' and (left(co.productcode,2) = 'OF')) then 'Inv: Other Fee' when ph.productgroupname = 'Investment' then 'Inv: Other Comm'

when ph.productgroupname = 'Mortgage' then 'Mortgages' when ph.productgroupname = 'Protection' then 'Protection' else ph.productsubgroupname end


order by year(ag.createdatetime), month(ag.createdatetime) desc


--- CLIENT POSTCODE---------------------------------------------------------------------------------------------------------------------------------------------


select


month(ag.createdatetime)as month, year(ag.createdatetime) as year,
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end as "ProductGroupName",

case when (ag.commissiontype in ('4','10','19') and (left(tranproduct,2) in ('OW','OF'))) then 'Servicing Fee' when ag.commissiontype in ('10','19') then 'Trail Income' when ag.commissiontype in ('4','18') then 'Renewal Income'

-- Protection
when (left((replace(ccs.description,'do not use - ','')),3) = '005' and ag.firm <> '1000311') then 'Pro: Openwork Select' when left((replace(ccs.description,'do not use - ','')),3) = '002' then 'Pro: IFA Panel' when Left(co.productcode,3) = 'PNL' then 'Pro: IFA Panel' when (isnull(co.productprovidercode,ag.comp_code) = 'L&G' and ph.productgroupname = 'Protection') then 'Pro: NASP L&G' when ph.productgroupname = 'Protection' then 'Pro: Zurich Plus' 

-- Pensions
when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) in ('IFDL','Zurich PLT','Openwork')) then 'Pen: Platform' when co.productcode = 'OFHBSIPP' then 'Pen: Platform' when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife') then 'Pen: Metlife' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Pru Tip' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Pen: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Pen: Other Comm'

-- Annuities
when isnull(co.productprovidercode,ag.comp_code) = 'PTSP' then 'PTSP Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'Pru')) then 'Pru Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) like '%Zurich%')) then 'Zurich Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'MGMA')) then 'MGMA Annuity' when ph.productsubgroupname like '%Annuity%' then 'Other Annuity'

-- Investments
when (ph.productgroupname = 'Investment' and (isnull(co.productprovidercode,ag.comp_code) = 'IFDL' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT')) then 'Inv: IFDL Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Inv: Zurich Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Pru Fund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Inv: Structured' when ph.productgroupname = 'Investment' then 'Inv: Other'

when ph.productgroupname = 'Mortgage' then 'Mortgages' else ph.productsubgroupname end as 'productsubgroup',

sum(case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) as "Issued APE",
sum(case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end) as "NB Cases", cl.postcode

from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid

where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate		
and ag.agent_code <> '10002'
and ag.amount <> 0
and ag.commissiontype in ('1','4','10','17','18','19')
and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 
and (case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0

and case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end in ('Pensions','Investment','Annuity')

and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Indexation'
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT like '%Group Pension%' then 1 when (ph.productsubgroupname like '%Group Pension%'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by

month(ag.createdatetime), year(ag.createdatetime),
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end,

case when (ag.commissiontype in ('4','10','19') and (left(tranproduct,2) in ('OW','OF'))) then 'Servicing Fee' when ag.commissiontype in ('10','19') then 'Trail Income' when ag.commissiontype in ('4','18') then 'Renewal Income'

-- Protection
when (left((replace(ccs.description,'do not use - ','')),3) = '005' and ag.firm <> '1000311') then 'Pro: Openwork Select' when left((replace(ccs.description,'do not use - ','')),3) = '002' then 'Pro: IFA Panel' when Left(co.productcode,3) = 'PNL' then 'Pro: IFA Panel' when (isnull(co.productprovidercode,ag.comp_code) = 'L&G' and ph.productgroupname = 'Protection') then 'Pro: NASP L&G' when ph.productgroupname = 'Protection' then 'Pro: Zurich Plus' 

-- Pensions
when (ph.productgroupname in ('Pensions','Other') and isnull(co.productprovidercode,ag.comp_code) in ('IFDL','Zurich PLT','Openwork')) then 'Pen: Platform' when co.productcode = 'OFHBSIPP' then 'Pen: Platform' when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife') then 'Pen: Metlife' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Pru Tip' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Pen: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Pen: Other Comm'

-- Annuities
when isnull(co.productprovidercode,ag.comp_code) = 'PTSP' then 'PTSP Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'Pru')) then 'Pru Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) like '%Zurich%')) then 'Zurich Annuity' when (ph.productsubgroupname like '%Annuity%' and (isnull(co.productprovidercode,ag.comp_code) = 'MGMA')) then 'MGMA Annuity' when ph.productsubgroupname like '%Annuity%' then 'Other Annuity'

-- Investments
when (ph.productgroupname = 'Investment' and (isnull(co.productprovidercode,ag.comp_code) = 'IFDL' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT')) then 'Inv: IFDL Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'Inv: Zurich Platform' when (ph.productgroupname = 'Investment' and isnull(co.productprovidercode,ag.comp_code) = 'Pru') then 'Pru Fund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Inv: Structured' when ph.productgroupname = 'Investment' then 'Inv: Other'

when ph.productgroupname = 'Mortgage' then 'Mortgages' else ph.productsubgroupname end, cl.postcode

UNION ALL

