when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'IFDL') then 'Pen: Platform' when co.productcode = 'OFHBSIPP' then 'Pen: Platform' when (ph.productgroupname in ('Pensions','Other') and co.productprovidercode = 'Zurich PLT') then 'Pen: Platform' when (co.productprovidercode = 'MetLife') then 'Pen: Metlife' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%' and co.productprovidercode = 'Pru') then 'Pru Tip' when ((ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') and (left(co.productcode,2) = 'OF')) then 'Pen: Other Fee' when (ph.productgroupname in ('Pensions','Other') and ph.productsubgroupname not like '%Annuity%') then 'Pen: Other Comm' 

-- Annuities
when co.productprovidercode = 'PTSP' then 'Ann: Partnership' when (ph.productsubgroupname like '%Annuity%' and co.productprovidercode = 'Pru') then 'Ann: Pru' when co.productprovidercode = 'MGMA' then 'Ann: MGMA' when ph.productsubgroupname like '%Annuity%' then 'Ann: Other' 

-- Investments
when (ph.productgroupname = 'Investment' and (co.productprovidercode = 'IFDL' or co.productprovidercode = 'Pru PLT')) then 'Inv: IFDL Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Zurich PLT') then 'Inv: Zurich Platform' when (ph.productgroupname = 'Investment' and co.productprovidercode = 'Pru') then 'Inv: PruFund' when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Inv: Structured' when (ph.productgroupname = 'Investment' and (left(co.productcode,2) = 'OF')) then 'Inv: Other Fee' when ph.productgroupname = 'Investment' then 'Inv: Other Comm'

when ph.productgroupname = 'Mortgage' then 'Mortgages' when ph.productgroupname = 'Protection' then 'Protection' else ph.productsubgroupname end, cl.postcode


order by year(ag.createdatetime), month(ag.createdatetime) desc
drop table #b
GO
/****** Object:  StoredProcedure [BI].[pr_061_RDRQualified]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	61. RDR Qualified.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_061_RDRQualified]

as

select DISTINCT 
case when USR_ExternalID = '1010364' then '1010744' when USR_ExternalID = '4001519' then '1011554' when USR_ExternalID = '1003604' then '1005181' when USR_ExternalID = '1009352' then '1010487' else USR_ExternalID end as 'UID', 
ltrim(rtrim(USR_Name)) as InsightName,competentstatusdescription,
cd1.code_description as UserType,cd2.code_description as UserStatus,
case when isnumeric(STAF_reasonforleaving) <> 1 then STAF_reasonforleaving else cd3.code_description end as LeaveReason,
qual_Description as Qualification,cd0.code_Description as QualStatus,
case when qual_Description like '%AIFA - Diploma Qualified%' then 'AIFAQualified'
      when qual_Description like '%AIFA Diploma Route%' then 'AIFATraining'
      when qual_Description like '%Calibrand - Diploma Qualified%' then 'CalibrandQualified'  
       when qual_Description like '%Calibrand Diploma Route%' then 'CalibrandTraining'
      when qual_Description like '%CII - Diploma Qualified%' then 'CIIQualified'
      when qual_Description like '%CII Diploma Route%' then 'CIITraining'
      when qual_Description like '%IFS - Diploma Qualified%' then 'IFSQualified'
      when qual_Description like '%IFS Diploma Route%' then 'IFSTraining'
      when qual_Description like '%Other Diploma Route%' then 'OtherTraining'
      when qual_Description like '%Not Taking Diploma%' then 'NotTakingStatus'
end as DiplomaType,
t1.SupervisorUID as Supervisor,t1.SupervisorName as SupervisorName,
t1.BQM_UID,t1.BQM_Name,t1.AQM_UID,t1.AQM_Name,t1.AD_UID,t1.AD_Name, UQUAL_UpdatedDate
from sa_insight_UserDetails
inner join sa_insight_UserPosition on USR_ID = UPS_UserID
inner join sa_insight_userqualification on UPS_UserId = UQUAL_UserID
inner join sa_insight_qualification on uqual_QualificationId = QUAL_ID
left join sa_insight_CodeDescription cd0 on cd0.code_codetype = 508 and cd0.code_code = UQUAL_Status
left join (
SELECT DISTINCT ud.USR_ExternalID AS [AdviserUID],ud.USR_Name AS [AdviserName],
cd6.Code_Description AS [UserType],CASE WHEN up5.ups_id IS NULL THEN 'No' ELSE 'Yes' END AS Seller,
cd5.Code_Description AS [AdviserEmploymentStatus], cd7.Code_Description AS [ContractStatus], 
max(CASE WHEN up1.UPS_JobTitle = '8' THEN ud1.USR_ExternalID END) AS [SupervisorUID],
max(CASE WHEN up1.UPS_JobTitle = '8' THEN ud1.USR_Name END) AS [SupervisorName], 
max(COALESCE (CASE WHEN up1.UPS_JobTitle = '7' THEN ud1.USR_ExternalID ELSE NULL END, 
              CASE WHEN up2.UPS_JobTitle = '7' THEN ud2.USR_ExternalID ELSE NULL END)) AS [BQM_UID], 
max(COALESCE (CASE WHEN up1.UPS_JobTitle = '7' THEN ud1.USR_Name ELSE NULL END, 
              CASE WHEN up2.UPS_JobTitle = '7' THEN ud2.USR_Name ELSE NULL END)) AS [BQM_Name], 
max(COALESCE (CASE WHEN up1.UPS_JobTitle = '9' THEN ud1.USR_ExternalID ELSE NULL END, 
              CASE WHEN up2.UPS_JobTitle = '9' THEN ud2.USR_ExternalID ELSE NULL END, 
              CASE WHEN up3.UPS_JobTitle = '9' THEN ud3.USR_ExternalID ELSE NULL END)) AS [AQM_UID], 
max(COALESCE (CASE WHEN up1.UPS_JobTitle = '9' THEN ud1.USR_Name ELSE NULL END, 
              CASE WHEN up2.UPS_JobTitle = '9' THEN ud2.USR_Name ELSE NULL END,
              CASE WHEN up3.UPS_JobTitle = '9' THEN ud3.USR_Name ELSE NULL END)) AS [AQM_Name], 
max(COALESCE (CASE WHEN up1.UPS_JobTitle = '14' THEN ud1.USR_ExternalID ELSE NULL END, 
              CASE WHEN up2.UPS_JobTitle = '14' THEN ud2.USR_ExternalID ELSE NULL END,
              CASE WHEN up3.UPS_JobTitle = '14' THEN ud3.USR_ExternalID ELSE NULL END, 
              CASE WHEN up4.UPS_JobTitle = '14' THEN ud4.USR_ExternalID ELSE NULL END, 
              CASE WHEN up6.UPS_JobTitle = '14' THEN ud6.USR_ExternalID ELSE NULL END)) AS [AD_UID], 
max(COALESCE (CASE WHEN up1.UPS_JobTitle = '14' THEN ud1.USR_Name ELSE NULL END,
              CASE WHEN up2.UPS_JobTitle = '14' THEN ud2.USR_Name ELSE NULL END,
              CASE WHEN up3.UPS_JobTitle = '14' THEN ud3.USR_Name ELSE NULL END, 
              CASE WHEN up4.UPS_JobTitle = '14' THEN ud4.USR_Name ELSE NULL END,
              CASE WHEN up6.UPS_JobTitle = '14' THEN ud6.USR_Name ELSE NULL END)) AS [AD_Name]

FROM dbo.sa_insight_UserDetails as UD
INNER JOIN dbo.sa_insight_Staff as S ON ud.USR_ID = s.STAF_UserID 
INNER JOIN dbo.sa_insight_UserPosition as UP ON ud.USR_ID = up.UPS_UserID 
INNER JOIN dbo.sa_insight_UserPositionLink as UPL ON up.UPS_ID = upl.UPSL_ChildUserPositionID 
INNER JOIN dbo.sa_insight_UserPosition AS up1 ON upl.UPSL_ParentUserPositionID = up1.UPS_ID 
INNER JOIN dbo.sa_insight_UserDetails AS ud1 ON up1.UPS_UserID = ud1.USR_ID 
INNER JOIN dbo.sa_insight_UserPositionLink AS upl1 ON up1.UPS_ID = upl1.UPSL_ChildUserPositionID 
INNER JOIN dbo.sa_insight_UserPosition AS up2 ON upl1.UPSL_ParentUserPositionID = up2.UPS_ID 
INNER JOIN dbo.sa_insight_UserDetails AS ud2 ON up2.UPS_UserID = ud2.USR_ID 
INNER JOIN dbo.sa_insight_UserPositionLink AS upl2 ON up2.UPS_ID = upl2.UPSL_ChildUserPositionID 
INNER JOIN dbo.sa_insight_UserPosition AS up3 ON upl2.UPSL_ParentUserPositionID = up3.UPS_ID 
INNER JOIN dbo.sa_insight_UserDetails AS ud3 ON up3.UPS_UserID = ud3.USR_ID 
INNER JOIN dbo.sa_insight_UserPositionLink AS upl3 ON up3.UPS_ID = upl3.UPSL_ChildUserPositionID 
INNER JOIN dbo.sa_insight_UserPosition AS up4 ON upl3.UPSL_ParentUserPositionID = up4.UPS_ID 
INNER JOIN dbo.sa_insight_UserDetails AS ud4 ON up4.UPS_UserID = ud4.USR_ID
INNER JOIN dbo.sa_insight_UserPositionLink AS upl4 ON up4.UPS_ID = upl4.UPSL_ChildUserPositionID 
INNER JOIN dbo.sa_insight_UserPosition AS up6 ON upl4.UPSL_ParentUserPositionID = up6.UPS_ID
LEFT JOIN dbo.sa_insight_UserPosition AS up5 ON ud.USR_ID = up5.UPS_UserID AND dateadd(dd,0,datediff(dd,0,GETDATE())) BETWEEN up5.UPS_DateFrom AND ISNULL(up5.UPS_DateTo, 'Dec 31, 9999') AND up5.UPS_JobTitle IN (4, 42) 
INNER JOIN dbo.sa_insight_UserDetails AS ud6 ON up6.UPS_UserID = ud6.USR_ID 
LEFT JOIN dbo.sa_insight_CodeDescription ON up.UPS_JobTitle = dbo.sa_insight_CodeDescription.Code_Code AND sa_insight_CodeDescription.Code_CodeType = 54
LEFT JOIN dbo.sa_insight_CodeDescription AS cd1 ON up1.UPS_JobTitle = cd1.Code_Code AND cd1.Code_CodeType = 54 
LEFT JOIN dbo.sa_insight_CodeDescription AS cd2 ON up2.UPS_JobTitle = cd2.Code_Code AND cd2.Code_CodeType = 54 
LEFT JOIN dbo.sa_insight_CodeDescription AS cd3 ON up3.UPS_JobTitle = cd3.Code_Code AND cd3.Code_CodeType = 54 
LEFT JOIN dbo.sa_insight_CodeDescription AS cd4 ON up4.UPS_JobTitle = cd4.Code_Code AND cd4.Code_CodeType = 54 
LEFT JOIN dbo.sa_insight_CodeDescription AS cd5 ON s.STAF_EmploymentStatus = cd5.Code_Code AND cd5.Code_CodeType = 125 
LEFT JOIN dbo.sa_insight_CodeDescription AS cd6 ON ud.USR_Type = cd6.Code_Code AND cd6.Code_CodeType = 11 
LEFT JOIN dbo.sa_insight_CodeDescription AS cd7 ON s.STAF_ContractStatus = cd7.Code_Code AND cd7.Code_CodeType = 527 
LEFT JOIN dbo.sa_insight_CodeDescription AS cd8 ON up6.UPS_JobTitle = cd8.Code_Code AND cd8.Code_CodeType = 54
WHERE upl.UPSL_DateTo IS NULL
AND upl1.UPSL_DateTo IS NULL
AND upl2.UPSL_DateTo IS NULL
AND upl3.UPSL_DateTo IS NULL
AND up.UPS_JobTitle NOT IN (28, 29, 30) --Admin 1/2/3
AND s.STAF_ContractStatus <> '3'          --Pre-Contract
AND up.UPS_UserType NOT IN (5, 10)        --SQST Assessor/Manager
AND upl4.UPSL_DateTo IS NULL
group by ud.USR_ExternalID ,ud.USR_Name,
cd6.Code_Description ,CASE WHEN up5.ups_id IS NULL THEN 'No' ELSE 'Yes' END ,
cd5.Code_Description , cd7.Code_Description
) t1 on t1.adviseruid = USR_ExternalID
left join dbo.sa_insight_Staff on staf_userid = USR_ID
left join sa_insight_Codedescription cd1 on cd1.code_codetype = 11 and cd1.code_code = usr_type
left join sa_insight_Codedescription cd2 on cd2.code_codetype = 527 and cd2.code_code = STAF_contractstatus
left join sa_insight_Codedescription cd3 on case when isnumeric(STAF_reasonforleaving) = 1 then STAF_reasonforleaving end = cd3.code_code and cd3.code_codetype = 555
left join mstt_Agents on code = USR_ExternalID

where len(USR_ExternalID) = 7
and cd0.code_Description = 'Open'
and qual_Description = 'RDR Compliant'
and competentstatusdescription not in ('NULL','NPW','Left','Deceased')
order by 
case when USR_ExternalID = '1010364' then '1010744' when USR_ExternalID = '4001519' then '1011554' when USR_ExternalID = '1003604' then '1005181' when USR_ExternalID = '1009352' then '1010487' else USR_ExternalID end, 
qual_Description desc

GO
/****** Object:  StoredProcedure [BI].[pr_063_StandingOrdersCaseByCase]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	63. Standing Orders Case by Case.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_063_StandingOrdersCaseByCase]

as

select --sum(ag.amount), ag.standingordercodedesc
ag.firm, month(ag.createddate) as month, year(ag.createddate) as year, sum(ag.amount) as amount, ag.standingordercode, ag.standingordercodedesc
from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id

where 
ag.createdatetime
BETWEEN CONVERT(DATETIME, '2013-01-01 00:00:00', 102) 
AND CONVERT(DATETIME, '2014-11-30 23:59:59', 102)
and ag.commissiontype = 8
and ag.standingordercode in (2,4,66,52,67,53,32,49,6,7,17)
and cs.oastatus = 'valid'
and (ag.firm <> 1010904 or ag.standingordercode <> 49) --GHL Amendment
and (ag.firm <> 1011323 or ag.standingordercode not in (7,49)) -- First Affinity Amendment
and ag.id not in ('15598178')
group by ag.id, ag.firm, month(ag.createddate), year(ag.createddate), ag.standingordercode, ag.standingordercodedesc
order by year(ag.createddate), month(ag.createddate), ag.standingordercode
--group by ag.standingordercode, ag.standingordercodedesc
--order by ag.standingordercodedesc


--test
select sum(ag.amount)
from mstt_paymentspending ag
where 
ag.createdatetime
BETWEEN CONVERT(DATETIME, '2010-01-01 00:00:00', 102) 
AND CONVERT(DATETIME, '2010-11-30 23:59:59', 102)
and ag.commissiontype = 8
and ag.standingordercode in (2,4,66,52,67,53,32,49,6,7,17,78)
GO
/****** Object:  StoredProcedure [BI].[pr_064_WrittenProductionCaseByCaseMasterV2]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************************************

Date Created:	31/05/2019

Source:			Sarah Inglis (MI Team)

Script Name:	64. Written Production Case by Case Master v2.sql

*******************************************************************************************************************/

Create Procedure [BI].[pr_064_WrittenProductionCaseByCaseMasterV2]

as

IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c

declare @StartDate datetime,@EndDate datetime;
set @StartDate = '1 October 2018'
set @EndDate = '01 November 2018' -- Enter Monday's date (or if last day of month, the current date)


select
min(transactionid) as transactionid, po.PolicyRef, po.cont_num, co.productcode,ph.productgroupname,COMP_CODE --case when po.policyref IS NULL then convert(VARCHAR,replace(po.cont_num,'-','')) else convert(VARCHAR, po.policyref) end AS caseid
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')
group by po.PolicyRef, po.cont_num, co.productcode,ph.productgroupname,COMP_CODE


union all



select
min(transactionid) as transactionid, '' t1, '' t2,'' t3,ph.productgroupname,COMP_CODE

FROM          dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
--and ph.productgroupname like 'Protection'
and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')

group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end,ph.productgroupname,COMP_CODE


select
wr.Adviser,
wr.Firm,
wr.transactionid,
CONVERT(DATE,wr.Writtendate,103) AS Writtendate, CONVERT(DATE,wr.issueddate,103) AS issuedate,
wr.Ape,
wr.Distributionallowance, 
wr.NBI, wr.Margin, 
--wr.NBcases, 
wr.NBCases, 
wr.Allcases, 
wr.frequency, 
wr.CaseID, 
wr.Policy, 
wr.MortgageAmount,
wr.Businessreason,
wr.Adminmethoddescription, 
wr.Productcode, 
wr.Provider, 
wr.Reportingproductname, 
wr.Productsubgroupname, 
case when wr.productsubgroupname like '%Annuity' then 'Annuities' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end as 'ProductGroupName',
wr.Originatingsource, wr.Adminmethod, wr.Calculationcode, wr.Description, wr.ASD,
--wr.Client_Num, wr.REFER, wr.Title, wr.FIRSTNAME, wr.LastNAME, wr.DOB, datediff(year,wr.DOB,dateadd(month,2,getdate())) 'Age' 
--Added SI 25.2.19:
case when ((wr.ProductGroupName = 'Protection' and wr.calculationcode in ('LV2','PRT2','ZALP1','AXA2','AIP1','TALA2','ALP3','IPPE1','ALP1','IPPP1','ATP4')) or 
		 (wr.ProductGroupName = 'Protection' and wr.calculationcode = 'ATP1' and (wr.description like '2 Yr' or wr.description like '2Yr'))) then '2Yr' 
		 when wr.ProductGroupName != 'Protection' then 'Unknown'
		 else '4yr' end as ProtectionInitialPeriod
--wr.GrossIncome

from


(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate, min(pt.issueddate) as issueddate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
min((pt.mortgageamount) * (co.Agent_Perc/100)) as MortgageAmount,
round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) as distributionallowance, 

round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2) as NBI, 


round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) as Margin, 
--max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases",

CASE WHEN min(c.policyref) = 0 then 0 
	else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else 
	max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) 
	then (co.agent_perc/100) else 0 end)End)End as "NBCases", 




CASE WHEN min(c.policyref) = 0 then 0 
	else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312' 
	OR (((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection'))) 
	then 0 else max((co.agent_perc/100))END)END as "AllCases",




min(pt.FrequencyDescription) as frequency, 
min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD
--cl.Client_Num, cl.REFER, 
--ISNULL(IV.ValueName, Cl.Title) AS Title, 
--ISNULL(Per.FirstName + CASE WHEN Per.MiddleName = NULL THEN '' ELSE ' ' + Per.MiddleName END,  Replace(cl.FIRSTNAMES,',',' ')) AS FirstName, 
--ISNULL(Per.Lastname, REPLACE(cl.NAME, ',',' ')) AS LastName, 
--ISNULL(CAST(CONVERT(Date,per.DateOfBirth,103)AS Date), cl.birthdate) AS DOB
--FFI.GrossIncome



FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
			  dbo.sa_ows_Policies P ON P.PolicyID = po.PolicyRef LEFT OUTER JOIN
			  dbo.sa_ows_Sale S ON S.SaleID = P.SaleID LEFT OUTER JOIN
			  --sa_ows_FactFindIncomeDetail FFI on FFI.SaleID = P.SaleID LEFT OUTER JOIN
			  dbo.sa_ows_Person Per ON Per.PersonID = S.PersonID LEFT OUTER JOIN
			  StaticData.sa_ows_InputValues IV on IV.InputID = Per.TitleID AND IV.InputType = 'Title'
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), cl.Client_Num, cl.REFER, Replace(cl.FIRSTNAMES,',',' '), REPLACE(cl.NAME, ',',' ') , CONVERT(varchar, cl.birthdate, 103), ISNULL(IV.ValueName, Cl.Title), ISNULL(Per.FirstName + CASE WHEN Per.MiddleName = NULL THEN '' ELSE ' ' + Per.MiddleName END,  Replace(cl.FIRSTNAMES,',',' ')), ISNULL(Per.Lastname, REPLACE(cl.NAME, ',',' ')), ISNULL(CAST(CONVERT(Date,per.DateOfBirth,103)AS Date), cl.birthdate), ph.productgroupname, co.AGENT_CODE
having min(pt.writtendate) >= @StartDate
	   and min(pt.writtendate) < @EndDate

) wr

where
--wr.writtendate >= @StartDate
--and wr.writtendate < @EndDate	
--and wr.adviser = '1003198'
--and wr.originatingsource = '5'
 (wr.caseid not in ('500020430','500020431') or wr.caseid is null)
--and case when wr.productsubgroupname like '%Annuity' then 'Annuities' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end in ('Protection')
--and wr.Firm = '1005170'
--and wr.provider in ('L&G')
--and wr.ProductGroupName = 'Mortgage'
--and wr.policy = '0140406919'
--and wr.caseID in ('800003086','800003085', '551299911','551299523')

order by wr.writtendate desc

drop table #c

GO
/****** Object:  StoredProcedure [BI].[pr_065_WrittenProductionCaseByCaseMaster]    Script Date: 7/3/2026 3:34:42 PM ******/
