/**********************************************************************************************
Name	: [BI].[pr_066_InvalidHierarchy]  
Author	: A Yavuz
Date	: 27/05/2021

Purpose	: This report is used by the Payments team to show all payments	that have been matched
		  to an incorrect hierarchy

		  Execute as follows:
		  exec [BI].[pr_066_InvalidHierarchy] 'ptl92264', 'Browser', 'View All', 'Zurich New'

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_066_InvalidHierarchy]
		@StartDate	datetime,
		@EndDate	datetime

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'Invalid Hierarchy'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select
ProductGroupName,
AGENT_CODE,
agt.DESCN,
COMP_CODE,
ProviderRef,
CaseID,
CommissionTypeDesc,
Amount,
CreateDateTime
from mstt_PaymentsPending pp
join mstt_ProductHierarchy ph on ph.ProductCode = TranProduct
join mstt_Agents agt on agt.CODE = pp.AGENT_CODE
where ValidTASHH != 'Valid' and year(CreateDateTime) >= 2020
and (CreateDateTime between @StartDate and @EndDate) --Selects data based on users date range
Order by ProductGroupName, COMP_CODE, AGENT_CODE

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH


/****************************************************************************

			E N D															

****************************************************************************/
GO
