		  adviser details. The user can search by either the agency code or company code.

		  Execute as follows:
		  exec [logi].[pr_logi_PSD_AllAgentCodes] 'ptl92264', 'Browser', 'View All', 'Zurich New'

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_068_AllAgentCodes]
 @AgencyNo varchar(max),
 @Company varchar(max)

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'All Agent Codes'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select distinct
AgentCode,
DESCN as AdviserName,
can.CompanyCode,
can.AgencyNo
from sa_swift_CodeAgencyNumberAgents cana
join sa_swift_CodeAgencyNumbers can on can.ID = cana.AgencyNumberID
join mstt_Agents agt on agt.CODE = AgentCode
join mstt_ProductHierarchy ph on ph.ProductProviderCode = can.CompanyCode
where ph.ProductCategoryCode = 4

AND can.CompanyCode IN (@Company)

--OR (can.CompanyCode IN  (@Company) OR @Company ='')
--     OR(can.AgencyNo =  @AgencyNo OR @AgencyNo ='')

order by AgentCode

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH


