/**********************************************************************************************
Name	: [BI].[pr_070_MortgageSuspenseList]  
Author	: A Yavuz
Date	: 18/08/2021

Purpose	: This report is used by PSD to check mortgage suspense payments. The report owner 
		  is Debbie Beattie, PSD Manager.

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_070_MortgageSuspenseList]
	@ReportDate				date,
	@StateDate				date 

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@DateFrom				date,
			@DateTo					date

set	@ReportName			= 'Mortgage Suspense List'
set @StoredProcName		= object_name(@@procid)

/****************************************************************************

	Select the report date range					
												
	Note: @StateDate is always the first of the month. Where the date represents
			a whole month rather than just that day, 1000 years is added to the 
			date. When we know the year > 3000, we can subtract the 1000 years 
			to get the date back to what it should be.
																	
****************************************************************************/

if YEAR(@StateDate) > 3000
begin
	set @DateFrom	= dateadd(yy,-1000,@StateDate)				--Take off 1000 years 
	set @DateTo		= dateadd(dd,-1,dateadd(mm,1,@DateFrom))	--The last day of the month
end
else
begin
	set @DateFrom	= @StateDate
	set @DateTo		= @StateDate
end


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select	EDIContentsID as ID,
		DupPol,
		EDIFullName,
		EDIPolicy,
		EDIPremium,
		EDIAmount,
		EDIAgent,
		EDICaseID,
		Statement,
		StateDate,
		Process,
		Provider,
		Unalloc,
		CaseID,
		ExtPolNo,
		Invalid,
		Product,
		case 
			when CaseID >= 550000000 then 'OWS'		
			when CaseID >= 500000000 then 'ABS' 
			when CaseID >= 100000000 then 'OWS' 
			when CaseID >= 3000000 then 'OBP' 
			else 'Manual' 
		end as Source,
		AgentUID,
		AgentName,
		AgentRole,
		AgentBusUID,
		AgentBusName,
		RSMUID,
		RSMName,
		ASDUID,
		ASDName,
		SuspenseCompletionFile,
		PolicyState,
		ActiveStatement,
		ActiveDate,
		ActiveCompletionFile,
		PropCreateDate
from	dbo.owhot_MTG_SuspenseEDIList_History
where	ReportDate = @ReportDate
and		StateDate between @DateFrom and @DateTo
order	by StateDate desc, ID desc

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH


