SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_071_MortgageSuspenseList_UIStateDateSelector]  
Author	: A Yavuz
Date	: 18/08/2021

			The added 1000 years is used by the report data selection proc so it knows whether
			to select data for just the one day or for the whole month.

			Before this proc is called, another dropdown list will have been used in the report 
			to select @ReportDate which is then passed into this proc.
			
			Note: When Logi is in its initial state i.e. the report runs as it is loaded before
			the user has the chance to select any inputs, the @ReportDate passed into this proc 
			is empty. In this scenario, it knows the default @ReportDate is the maximum and so 
			it finds its maximum value and then uses that to return the results. This ensures 
			that the two date dropdowns on the report start off consistent with each other.
			
			This is a PSD Report and the owner is Debbie Beattie. 
			
			This stored proc is run as follows:
			
				exec logi.pr_logi_PSD_MortgageSuspenseList_UIStateDateSelector '2017-06-12'

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_072_MortgageSuspenseList_UIStateDateSelector]

		@ReportDate date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'Mortgage Suspense List'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

if isnull(@ReportDate,'') = ''
begin 
	select @ReportDate = MAX(ReportDate)
	from dbo.owhot_MTG_SuspenseEDIList_History
end

select	StateDateTxt,
		StateDateDte
from
		(
		select	distinct 1 as SortOrder,	--List months first
				datename(mm,StateDate) + ' ' + convert(varchar(4),year(StateDate)) as StateDateTxt,
				convert(datetime,'01/' + right('00' + convert(varchar(2),month(StateDate)),2) + '/' + convert(varchar(4),year(StateDate)+1000),103) as StateDateDte
		from	dbo.owhot_MTG_SuspenseEDIList_History
		where	ReportDate = @ReportDate
		union all
		select	distinct 2 as SortOrder,	--Individual dates after months
				convert(varchar(10),StateDate,103) as StateDateTxt,
				StateDate as StateDateDte
		from	dbo.owhot_MTG_SuspenseEDIList_History
		where	ReportDate = @ReportDate
		) a 
order	by	SortOrder asc,
			StateDateDte desc


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH


