/****** Object:  StoredProcedure [BI].[pr_073_WeeklyTopWrittenReport]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_073_WeeklyTopWrittenReport]  
Author	: A Yavuz
Date	: 23/08/2021

			This weekly written report is run on a weekly basis to find the top 10 written cases
			accross Protection, Mortgage and Wealth. More info on this report is found here:
			G:\Finance and MI\MI & Reporting (NEW STRUCTURE)\Openwork Reporting\Weekly Top Written Report
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_073_WeeklyTopWrittenReport]

with recompile

AS 

set nocount on;

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'Weekly Top Written Report'
set @StoredProcName		= object_name(@@procid);


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

WITH APE_CHECK AS (
SELECT
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
WHERE
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
GROUP BY
po.policyref, po.cont_num, co.productcode
),

All_Cases_CTE AS (

SELECT
wr.AdviserName,
wr.FirmName,
wr.Adviser,
wr.Firm,
wr.Transactionid as [Transaction ID],
CONVERT(DATE,wr.Writtendate,103) AS Writtendate, CONVERT(DATE,wr.issueddate,103) AS [Issued Date],
wr.APE,
wr.Distributionallowance as [Distribution Allowance],  
wr.Margin, 
wr.NBcases, 
wr.Allcases AS [All Cases], 
wr.Frequency, 
wr.CaseID as [Case ID], 
wr.Policy as [Policy], 
wr.Productsubgroupname as [Product Sub Group Name], 
case when wr.productsubgroupname like '%Annuity' then 'Wealth' when ((left(wr.productcode,2) in ('OW','OZ') AND wr.productcode NOT IN ('OWADHOC','OWADVICE')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'Wealth' when wr.productgroupname in ('Pensions','Investment') then 'Wealth' else wr.productgroupname end as [Product Group Name],
wr.Provider,
wr.[Client Surname],
wr.[Mortgage Size],
wr.[SinglePremiumAmount],
wr.[ProductType]

FROM
(SELECT  
ah.AgentDesc as AdviserName,
ah.FirmDescn as FirmName,
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate, min(pt.issueddate) as issueddate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
min((pt.mortgageamount) * (co.Agent_Perc/100)) as MortgageAmount,
round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) as distributionallowance, 
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2) as NBI, 
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) as Margin, 
max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases", 
max((co.agent_perc/100)) as "AllCases", min(pt.FrequencyDescription) as frequency, min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD,
cl.NAME [Client Surname],
CASE WHEN ph.productgroupname = 'Mortgage' THEN sum(pt.MortgageAmount) else null END as [Mortgage Size],
CASE WHEN pt.FrequencyDescription = 'Single' THEN sum(pt.Amount) else null END as [SinglePremiumAmount],
ph.ProductSubGroupName as [ProductType]

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  APE_CHECK c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.AGENT_CODE = ah.agentcode

WHERE 
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)

GROUP BY
cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2)
,po.policyref,
po.cont_num,
datepart(week,(pt.writtendate)),
year(pt.writtendate),
ah.FirmDescn,
ah.AgentDesc,
cl.NAME,
ph.ProductGroupName,
pt.FrequencyDescription,
ph.ProductSubGroupName
) wr

WHERE
wr.writtendate >= CONVERT(date,DATEADD(DD,-7,DATEADD(wk, DATEDIFF(wk,0,GETDATE()), 0)))
and wr.writtendate < DATEADD(wk, DATEDIFF(wk,0,GETDATE()), 0)



and (wr.caseid not in ('500020430','500020431') or wr.caseid is null)
and wr.ProductGroupName is not null
),


Protection_Cases_CTE AS(
SELECT TOP 5  * FROM All_Cases_CTE
WHERE [Product Group Name] = 'Protection'
ORDER BY APE Desc),

Mortgage_Cases_CTE AS(
SELECT TOP 5 * FROM All_Cases_CTE
WHERE [Product Group Name] = 'Mortgage'
ORDER BY APE Desc),

Wealth_Cases_CTE AS(
SELECT TOP 5  * FROM All_Cases_CTE
WHERE [Product Group Name] = 'Wealth'
ORDER BY APE Desc)

SELECT * FROM Protection_Cases_CTE
UNION ALL
SELECT * FROM Mortgage_Cases_CTE
UNION ALL
SELECT * FROM Wealth_Cases_CTE


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH


/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_074_BSClookup]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_074_BSClookup] 
Author	: A Yavuz
Date	: 24/08/2021

			The report shows where an adviser has changed a clients servicing from a BSC service
			level to a non BSC service level and reduced the ongoing fee.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_074_BSClookup]

@Name varchar(max)

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'BSC Lookup'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


Select
ROW_Number() over (Partition By TransactionID order by case when Agent_Code = '1011543' then '9999999'
															when agent_code = '1011587' then '8888888'
															else FranchiseAgentCode end) as Row_Num,
TransactionID,
AGENT_CODE,
AGENT_PERC,
FranchiseAgentCode
into #Splits
from mstt_Commissions cs
where CommissionType = 10
and TransactionID = (Select max(cs2.transactionid)
					 from mstt_Commissions cs2
					 where cs.PolicyID = cs2.PolicyID)
and ProductCode in (Select ProductCode from mstt_ProductHierarchy where RDRType is not null)

Select distinct
tid.TransactionID,
bsc.AGENT_CODE as BSC,
bsc.AGENT_PERC as BSCPct,
owm.AGENT_CODE as Margin,
owm.AGENT_PERC as MarginPct,
sp1.AGENT_CODE as Code1,
sp1.AGENT_PERC as Code1Pct, 
sp1.FranchiseAgentCode as Code1Firm,
sp2.AGENT_CODE as Code2,
sp2.AGENT_PERC as Code2Pct,
sp2.FranchiseAgentCode as Code2Firm,
sp3.AGENT_CODE as Code3,
sp3.AGENT_PERC as Code3Pct,
sp3.FranchiseAgentCode as Code3Firm
into #CurrentSplits
from #Splits tid
left join #Splits bsc on bsc.TransactionID = tid.TransactionID and bsc.agent_code = '1011587'
left join #Splits owm on owm.TransactionID = tid.TransactionID and owm.AGENT_CODE = '1011543'
left join #Splits sp1 on sp1.TransactionID = tid.TransactionID and sp1.AGENT_CODE not in ('1011543','1011587') and sp1.Row_Num = 1
left join #Splits sp2 on sp2.TransactionID = tid.TransactionID and sp2.AGENT_CODE not in ('1011543','1011587') and sp2.Row_Num = 2
left join #Splits sp3 on sp3.TransactionID = tid.TransactionID and sp3.AGENT_CODE not in ('1011543','1011587') and sp3.Row_Num = 3

--Create Uplift Rate Table

Select 
ROW_NUMBER() over(partition by au.agentcode, au.productcode order by au.dateinforce) as RowNum,
au.AgentCode,
au.DateInForce,
au.ProductCode,
au.UpliftRate,
au.Status,
au.PolicyType
into #AgentUpliftTable
from sa_swift_AgentUplifts au
join mstt_ProductHierarchy ph on ph.ProductCode = au.ProductCode and ph.ProductCategoryCode = 1
where status = 0

--Create to and from date for rates 
Select
aut.RowNum,
aut.AgentCode,
aut.DateInForce,
aut.UpliftRate,
aut.ProductCode,
isnull(dateadd(day,-1,aut2.dateinforce),'31-Dec-3099')  as EndDate,
aut2.RowNum as NewRow
into #FranchiseUpliftRate
from #AgentUpliftTable aut
left join #AgentUpliftTable aut2 on aut2.AgentCode = aut.AgentCode 
								and aut2.ProductCode = aut.ProductCode
								and aut2.RowNum = aut.RowNum +1

Select
pers.FirstName,
pers.LastName,
pers.DateOfBirth,
sl.BscApplies as NewSL,
csl.Fee as NewOngoing,
sl2.BscApplies as PrevSL,
csla.Fee as PreviousOngoing,
poli.COMP_CODE,
poli.ProductCode,
poli.PolicyRef,
poli.CONT_NUM,
pt.ProposalDate,
cs.BSC,
cs.BSCPct,
cs.Margin,
cs.MarginPct,
cs.Code1,
cs.Code1Pct,
cs.Code1Firm,
cs.Code2,
cs.Code2Pct,
cs.Code2Firm,
cs.Code3,
cs.Code3Pct,
cs.Code3Firm,
ROUND(case when cs.Code2Firm is null then fur2.upliftrate - 20
	 when cs.Code3Firm is null and cs.Code1Firm = cs.Code2Firm then cs.Code1Pct/(cs.Code1Pct+cs.Code2Pct)* (fur2.upliftrate - 20)
	 when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then cs.Code1Pct/(cs.Code1Pct+cs.Code2Pct+cs.Code3Pct)* (fur2.upliftrate - 20) 
	 when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then (Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur2.UpliftRate - 20)
	 else (Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur2.UpliftRate - 20)
	 end,2) as Code1NewRate,
ROUND(case when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then (Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur4.UpliftRate - 20)
	 when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then cs.Code2Pct/(cs.Code1Pct+cs.Code2Pct+cs.Code3Pct)* (fur4.upliftrate - 20) 
	 else (Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur4.UpliftRate - 20)
	 end,2) as Code2NewRate,
ROUND((Code3Pct/fur6.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur5.UpliftRate - 20)
	 ,2) as Code3NewRate,
case when cs.Code2Firm is null then 100-(fur2.upliftrate - 20) 
	 when cs.Code3Firm is null and cs.Code1Firm = cs.Code2Firm then 100-(fur2.upliftrate - 20)
	 when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then 100-(fur2.upliftrate - 20)
	 when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then
	 100 - (Round((Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur2.UpliftRate - 20),2)+ROUND((Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur4.UpliftRate - 20),2)) end as MarginNewRate,
--com.AGENT_CODE,
--com.AGENT_PERC,
--com.Firm as OrginalFirm,
--fur.UpliftRate as OriginalCOBRate,
--agt.Firm as CurrentFirm,
--fur2.UpliftRate as CurrentCOBRate,
csl.ServiceLevelSigningDate,
pt.AgentCode
into #NewSplits
from sa_ows_ClientServiceLevel csl
join proposition.sa_ows_ServiceLevel sl on sl.ServiceLevelId = csl.ServiceLevelId
left join sa_ows_ClientServiceLevelAudit csla on csla.PersonID = csl.PersonID and csla.ClientServiceLevelAuditID = 
																						(Select max(csla2.ClientServiceLevelAuditID)
																						 from sa_ows_ClientServiceLevelAudit csla2
																						 where csla2.PersonID = csl.PersonID)
left join Proposition.sa_ows_ServiceLevel sl2 on sl2.ServiceLevelId = csla.ServiceLevelId
left join sa_ows_Person pers on pers.PersonID = csl.PersonID
left join sa_ows_Sale sale on sale.PersonID = pers.PersonID
left join sa_ows_Policies pol on pol.SaleID = sale.SaleID
left join mstt_Policies poli on poli.PolicyRef = pol.PolicyID
left join mstt_ProductHierarchy ph on ph.ProductCode = poli.ProductCode
left join mstt_PolicyTransactions pt on pt.PolicyID = poli.POL_NUM and pt.TransactionNumber = 
																						(Select max(pt2.transactionnumber)
																						 from mstt_PolicyTransactions pt2
																						 where poli.POL_NUM = pt2.PolicyID)
Left join #CurrentSplits cs on cs.TransactionID = pt.ID
left join #FranchiseUpliftRate fur on fur.ProductCode = poli.ProductCode and pt.ProposalDate between fur.DateInForce and fur.EndDate and fur.AgentCode = cs.Code1Firm
left join mstt_agents agt on agt.CODE = cs.Code1
left join mstt_Agents agt2 on agt2.CODE = cs.Code2
left join mstt_Agents agt3 on agt3.CODE = cs.Code3
left join #FranchiseUpliftRate fur2 on fur2.AgentCode = agt.Firm and fur2.ProductCode = poli.ProductCode and csl.ServiceLevelSigningDate between fur2.DateInForce and fur2.EndDate
left join #FranchiseUpliftRate fur3 on fur3.ProductCode = poli.ProductCode and pt.ProposalDate between fur3.DateInForce and fur3.EndDate and fur3.AgentCode = cs.Code2Firm
left join #FranchiseUpliftRate fur4 on fur4.AgentCode = agt2.Firm and fur4.ProductCode = poli.ProductCode and csl.ServiceLevelSigningDate between fur4.DateInForce and fur4.EndDate
left join #FranchiseUpliftRate fur5 on fur5.AgentCode = agt3.Firm and fur5.ProductCode = poli.ProductCode and csl.ServiceLevelSigningDate between fur5.DateInForce and fur5.EndDate
left join #FranchiseUpliftRate fur6 on fur6.ProductCode = poli.ProductCode and pt.ProposalDate between fur6.DateInForce and fur6.EndDate and fur6.AgentCode = cs.Code3Firm
where 
ph.RDRType is not null  
Order by poli.CLIENT_NUM, poli.CONT_NUM

Select
FirstName,
LastName,
DateOfBirth,
agt.DESCN as AdviserName,
frm.MIName as FirmName,
PolicyRef,
ServiceLevelSigningDate,
Code1,
Code1NewRate,
Code2,
Code2NewRate,
Code3,
Code3NewRate,
100-(Code1NewRate+isnull(Code2NewRate,0)+isnull(Code3NewRate,0)) as Margin,
CONCAT(Firstname, ' ', Lastname) AS Fullname

from #NewSplits
left join mstt_agents agt on agt.CODE = AgentCode
left join mstt_Agents frm on frm.CODE = agt.Firm
where 
NewOngoing < PreviousOngoing
and (CONCAT(Firstname, ' ', Lastname) IN (@Name) OR @Name = '')

drop table #AgentUpliftTable,#FranchiseUpliftRate,#CurrentSplits,#Splits,#NewSplits

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_075_BSCchanges]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_075_BSCchanges] 
Author	: A Yavuz
Date	: 24/08/2021

			The report shows where an adviser has changed a clients servicing from a BSC service
			level to a non BSC service level and reduced the ongoing fee.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
23/12/21	J Homer		Amended code for New Splits to include "left join mstt_Policies poli2 on poli2.Client_Num = poli.Client_Num"
						to bring thorugh manual cases as well as OWS Cases
24/12/21	J Homer		Amended SELECT statements to SELECT DISTINCT to remove duplication of results
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_075_BSCchanges]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'BSC Changes'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/
Select DISTINCT
ROW_Number() over (Partition By PersonID order by clientservicelevelauditID) AS roW_nUM, 
csla.PersonID, 
sl.BscApplies as NewSL,
csla.Fee as NewOngoing,
csla.ServiceLevelId,
csla.ServiceLevelSigningDate, 
csla.DateUpdated
into #ServiceLevelAudit
from sa_ows_ClientServiceLevelAudit csla
join proposition.sa_ows_ServiceLevel sl on sl.ServiceLevelId = csla.ServiceLevelId
 
 
Select DISTINCT
ROW_Number() over (Partition By TransactionID order by case when Agent_Code = '1011543' then '9999999'
                                                            when agent_code = '1011587' then '8888888'
                                                            else FranchiseAgentCode end) as Row_Num,
TransactionID,
AGENT_CODE,
AGENT_PERC,
FranchiseAgentCode
into #Splits
from mstt_Commissions cs
where CommissionType = 10
and TransactionID = (Select max(cs2.transactionid)
                     from mstt_Commissions cs2
                     where cs.PolicyID = cs2.PolicyID
                     and cs2.PolTranTransType not in (39,117))
and ProductCode in (Select ProductCode from mstt_ProductHierarchy where RDRType is not null) 
 
Select distinct
tid.TransactionID,
bsc.AGENT_CODE as BSC,
bsc.AGENT_PERC as BSCPct,
owm.AGENT_CODE as Margin,
owm.AGENT_PERC as MarginPct,
sp1.AGENT_CODE as Code1,
sp1.AGENT_PERC as Code1Pct, 
sp1.FranchiseAgentCode as Code1Firm,
sp2.AGENT_CODE as Code2,
sp2.AGENT_PERC as Code2Pct,
sp2.FranchiseAgentCode as Code2Firm,
sp3.AGENT_CODE as Code3,
sp3.AGENT_PERC as Code3Pct,
sp3.FranchiseAgentCode as Code3Firm
into #CurrentSplits
from #Splits tid
left join #Splits bsc on bsc.TransactionID = tid.TransactionID and bsc.agent_code = '1011587'
left join #Splits owm on owm.TransactionID = tid.TransactionID and owm.AGENT_CODE = '1011543'
left join #Splits sp1 on sp1.TransactionID = tid.TransactionID and sp1.AGENT_CODE not in ('1011543','1011587') and sp1.Row_Num = 1
left join #Splits sp2 on sp2.TransactionID = tid.TransactionID and sp2.AGENT_CODE not in ('1011543','1011587') and sp2.Row_Num = 2
left join #Splits sp3 on sp3.TransactionID = tid.TransactionID and sp3.AGENT_CODE not in ('1011543','1011587') and sp3.Row_Num = 3
 
 
--Create Uplift Rate Table
 
Select DISTINCT
ROW_NUMBER() over(partition by au.agentcode, au.productcode order by au.dateinforce) as RowNum,
au.AgentCode,
au.DateInForce,
au.ProductCode,
au.UpliftRate,
au.Status,
au.PolicyType
into #AgentUpliftTable
from sa_swift_AgentUplifts au
join mstt_ProductHierarchy ph on ph.ProductCode = au.ProductCode and ph.ProductCategoryCode = 1
where status = 0
 
--Create to and from date for rates 
Select DISTINCT
aut.RowNum,
aut.AgentCode,
aut.DateInForce,
aut.UpliftRate,
aut.ProductCode,
isnull(dateadd(day,-1,aut2.dateinforce),'31-Dec-3099')  as EndDate,
aut2.RowNum as NewRow
into #FranchiseUpliftRate
from #AgentUpliftTable aut
left join #AgentUpliftTable aut2 on aut2.AgentCode = aut.AgentCode 
                                 and aut2.ProductCode = aut.ProductCode
                                 and aut2.RowNum = aut.RowNum +1
 
Select DISTINCT
pers.FirstName,
pers.LastName,
pers.DateOfBirth,
sl.BscApplies as NewSL,
csl.Fee as NewOngoing,
csl.DateUpdated,
sl2.BscApplies as PrevSL,
csla.Fee as PreviousOngoing,
poli2.COMP_CODE,
poli2.ProductCode,
poli2.PolicyRef,
poli2.CONT_NUM,
pt.ProposalDate,
cs.BSC,
cs.BSCPct,
cs.Margin,
cs.MarginPct,
cs.Code1,
cs.Code1Pct,
cs.Code1Firm,
cs.Code2,
cs.Code2Pct,
cs.Code2Firm,
cs.Code3,
cs.Code3Pct,
cs.Code3Firm,
ROUND(case when cs.Code2Firm is null then fur2.upliftrate - 20
       when cs.Code3Firm is null and cs.Code1Firm = cs.Code2Firm then cs.Code1Pct/(cs.Code1Pct+cs.Code2Pct)* (fur2.upliftrate - 20)
       when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then cs.Code1Pct/(cs.Code1Pct+cs.Code2Pct+cs.Code3Pct)* (fur2.upliftrate - 20) 
       when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then (Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur2.UpliftRate - 20)
       else (Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur2.UpliftRate - 20)
       end,2) as Code1NewRate,
ROUND(case when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then (Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur4.UpliftRate - 20)
       when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then cs.Code2Pct/(cs.Code1Pct+cs.Code2Pct+cs.Code3Pct)* (fur4.upliftrate - 20) 
       else (Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur4.UpliftRate - 20)
       end,2) as Code2NewRate,
ROUND((Code3Pct/fur6.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur5.UpliftRate - 20)
       ,2) as Code3NewRate,
case when cs.Code2Firm is null then 100-(fur2.upliftrate - 20) 
       when cs.Code3Firm is null and cs.Code1Firm = cs.Code2Firm then 100-(fur2.upliftrate - 20)
       when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then 100-(fur2.upliftrate - 20)
       when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then
       100 - (Round((Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur2.UpliftRate - 20),2)+ROUND((Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur4.UpliftRate - 20),2)) end as MarginNewRate,
--com.AGENT_CODE,
--com.AGENT_PERC,
--com.Firm as OrginalFirm,
--fur.UpliftRate as OriginalCOBRate,
--agt.Firm as CurrentFirm,
--fur2.UpliftRate as CurrentCOBRate,
csl.ServiceLevelSigningDate,
pt.AgentCode,
case when cs.BSCPct is null then 'No' else 'Yes' end as BSCOnLatestSlice
into #NewSplits
from sa_ows_ClientServiceLevel csl
join proposition.sa_ows_ServiceLevel sl on sl.ServiceLevelId = csl.ServiceLevelId
left join sa_ows_ClientServiceLevelAudit csla on csla.PersonID = csl.PersonID and csla.ClientServiceLevelAuditID = (Select max(csla2.ClientServiceLevelAuditID)
                                                                                                                    from sa_ows_ClientServiceLevelAudit csla2
                                                                                                                    where csla2.PersonID = csl.PersonID)
left join Proposition.sa_ows_ServiceLevel sl2 on sl2.ServiceLevelId = csla.ServiceLevelId
left join sa_ows_Person pers on pers.PersonID = csl.PersonID
left join sa_ows_Sale sale on sale.PersonID = pers.PersonID
left join sa_ows_Policies pol on pol.SaleID = sale.SaleID
left join mstt_Policies poli on poli.PolicyRef = pol.PolicyID
left join mstt_Policies poli2 on poli2.Client_Num = poli.Client_Num
left join mstt_ProductHierarchy ph on ph.ProductCode = poli2.ProductCode
left join mstt_PolicyTransactions pt on pt.PolicyID = poli2.POL_NUM and pt.TransactionNumber = (Select max(pt2.transactionnumber)
                                                                                                from mstt_PolicyTransactions pt2
                                                                                                where poli2.POL_NUM = pt2.PolicyID)
Left join #CurrentSplits cs on cs.TransactionID = pt.ID
left join #FranchiseUpliftRate fur on fur.ProductCode = poli2.ProductCode and pt.ProposalDate between fur.DateInForce and fur.EndDate and fur.AgentCode = cs.Code1Firm
left join mstt_agents agt on agt.CODE = cs.Code1
left join mstt_Agents agt2 on agt2.CODE = cs.Code2
left join mstt_Agents agt3 on agt3.CODE = cs.Code3
left join #FranchiseUpliftRate fur2 on fur2.AgentCode = agt.Firm and fur2.ProductCode = poli2.ProductCode and csl.DateUpdated between fur2.DateInForce and fur2.EndDate
left join #FranchiseUpliftRate fur3 on fur3.ProductCode = poli2.ProductCode and pt.ProposalDate between fur3.DateInForce and fur3.EndDate and fur3.AgentCode = cs.Code2Firm
left join #FranchiseUpliftRate fur4 on fur4.AgentCode = agt2.Firm and fur4.ProductCode = poli2.ProductCode and csl.DateUpdated between fur4.DateInForce and fur4.EndDate
left join #FranchiseUpliftRate fur5 on fur5.AgentCode = agt3.Firm and fur5.ProductCode = poli2.ProductCode and csl.DateUpdated between fur5.DateInForce and fur5.EndDate
left join #FranchiseUpliftRate fur6 on fur6.ProductCode = poli2.ProductCode and pt.ProposalDate between fur6.DateInForce and fur6.EndDate and fur6.AgentCode = cs.Code3Firm
where 
ph.RDRType is not null  
and (sl.DateUpdated > '01-Aug-2021' or sl.DateUpdated IS NULL)
--and csl.fee < csla.Fee
--and sl.BscApplies <> sl2.BscApplies
--and sl.BscApplies = 0
UNION ALL
Select DISTINCT
pers.FirstName,
pers.LastName,
pers.DateOfBirth,
sla.NewSL as NewSL,
sla.NewOngoing as NewOngoing,
sla.DateUpdated,
slapre.NewSL as PrevSL,
slapre.NewOngoing as PreviousOngoing,
poli2.COMP_CODE,
poli2.ProductCode,
poli2.PolicyRef,
poli2.CONT_NUM,
pt.ProposalDate,
cs.BSC,
cs.BSCPct,
cs.Margin,
cs.MarginPct,
cs.Code1,
cs.Code1Pct,
cs.Code1Firm,
cs.Code2,
cs.Code2Pct,
cs.Code2Firm,
cs.Code3,
cs.Code3Pct,
cs.Code3Firm,
ROUND(case when cs.Code2Firm is null then fur2.upliftrate - 20
       when cs.Code3Firm is null and cs.Code1Firm = cs.Code2Firm then cs.Code1Pct/(cs.Code1Pct+cs.Code2Pct)* (fur2.upliftrate - 20)
       when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then cs.Code1Pct/(cs.Code1Pct+cs.Code2Pct+cs.Code3Pct)* (fur2.upliftrate - 20) 
       when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then (Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur2.UpliftRate - 20)
       else (Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur2.UpliftRate - 20)
       end,2) as Code1NewRate,
ROUND(case when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then (Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur4.UpliftRate - 20)
       when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then cs.Code2Pct/(cs.Code1Pct+cs.Code2Pct+cs.Code3Pct)* (fur4.upliftrate - 20) 
       else (Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+isnull((Code3Pct/Fur6.UpliftRate*100),0))*(fur4.UpliftRate - 20)
       end,2) as Code2NewRate,
ROUND((Code3Pct/fur6.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur5.UpliftRate - 20)
       ,2) as Code3NewRate,
case when cs.Code2Firm is null then 100-(fur2.upliftrate - 20) 
       when cs.Code3Firm is null and cs.Code1Firm = cs.Code2Firm then 100-(fur2.upliftrate - 20)
       when cs.Code1Firm = cs.Code2Firm and cs.Code1Firm = cs.Code3Firm then 100-(fur2.upliftrate - 20)
       when cs.Code3Firm is null and cs.Code1Firm != cs.Code2Firm then
       100 - (Round((Code1Pct/fur.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100))*(fur2.UpliftRate - 20),2)+ROUND((Code2Pct/fur3.UpliftRate*100)/((Code1Pct/fur.UpliftRate*100)+(Code2Pct/Fur3.UpliftRate*100)+(Code3Pct/Fur6.UpliftRate*100))*(fur4.UpliftRate - 20),2)) end as MarginNewRate,
sla.ServiceLevelSigningDate,
pt.AgentCode,
case when cs.BSCPct is null then 'No' else 'Yes' end as BSCOnLatestSlice
from #ServiceLevelAudit sla
join #ServiceLevelAudit slapre on sla.PersonID = slapre.PersonID and slapre.roW_nUM = sla.roW_nUM-1
left join sa_ows_Person pers on pers.PersonID = sla.PersonID
left join sa_ows_Sale sale on sale.PersonID = pers.PersonID
left join sa_ows_Policies pol on pol.SaleID = sale.SaleID
left join mstt_Policies poli on poli.PolicyRef = pol.PolicyID
left join mstt_Policies poli2 on poli2.Client_Num = poli.Client_Num
left join mstt_ProductHierarchy ph on ph.ProductCode = poli2.ProductCode
left join mstt_PolicyTransactions pt on pt.PolicyID = poli2.POL_NUM and pt.TransactionNumber = (Select max(pt2.transactionnumber)
                                                                                                from mstt_PolicyTransactions pt2
                                                                                                where poli2.POL_NUM = pt2.PolicyID)
Left join #CurrentSplits cs on cs.TransactionID = pt.ID
left join #FranchiseUpliftRate fur on fur.ProductCode = poli2.ProductCode and pt.ProposalDate between fur.DateInForce and fur.EndDate and fur.AgentCode = cs.Code1Firm
left join mstt_agents agt on agt.CODE = cs.Code1
left join mstt_Agents agt2 on agt2.CODE = cs.Code2
left join mstt_Agents agt3 on agt3.CODE = cs.Code3
left join #FranchiseUpliftRate fur2 on fur2.AgentCode = agt.Firm and fur2.ProductCode = poli2.ProductCode and sla.DateUpdated between fur2.DateInForce and fur2.EndDate
left join #FranchiseUpliftRate fur3 on fur3.ProductCode = poli2.ProductCode and pt.ProposalDate between fur3.DateInForce and fur3.EndDate and fur3.AgentCode = cs.Code2Firm
left join #FranchiseUpliftRate fur4 on fur4.AgentCode = agt2.Firm and fur4.ProductCode = poli2.ProductCode and sla.DateUpdated between fur4.DateInForce and fur4.EndDate
left join #FranchiseUpliftRate fur5 on fur5.AgentCode = agt3.Firm and fur5.ProductCode = poli2.ProductCode and sla.DateUpdated between fur5.DateInForce and fur5.EndDate
left join #FranchiseUpliftRate fur6 on fur6.ProductCode = poli2.ProductCode and pt.ProposalDate between fur6.DateInForce and fur6.EndDate and fur6.AgentCode = cs.Code3Firm
where 
ph.RDRType is not null AND
(sla.DateUpdated > '01-Aug-2021' or sla.DateUpdated IS NULL) --and sla.NewSL = 0 and slapre.NewSL = 1 
--Order by poli.CLIENT_NUM, poli.CONT_NUM
 
Select DISTINCT
FirstName,
LastName,
DateOfBirth,
agt.DESCN as AdviserName,
frm.MIName as FirmName,
PolicyRef,
DateUpdated,
Code1,
Code1NewRate,
Code2,
Code2NewRate,
Code3,
Code3NewRate,
'1011543' as MarginCode,
100-(Code1NewRate+isnull(Code2NewRate,0)+isnull(Code3NewRate,0)) as Margin,
BSCOnLatestSlice
from #NewSplits
left join mstt_agents agt on agt.CODE = AgentCode
left join mstt_Agents frm on frm.CODE = agt.Firm
where 
NewSL <> PrevSL
and NewSL = 0
--and PolicyRef = 550040645
/*
Select
FirstName,
LastName,
DateOfBirth,
agt.DESCN as AdviserName,
frm.MIName as FirmName,
PolicyRef,
DateUpdated,
Code1,
Code1NewRate,
Code2,
Code2NewRate,
Code3,
Code3NewRate,
100-(Code1NewRate+isnull(Code2NewRate,0)+isnull(Code3NewRate,0)) as Margin
from #NewSplits
left join mstt_agents agt on agt.CODE = AgentCode
left join mstt_Agents frm on frm.CODE = agt.Firm
where 
NewOngoing < PreviousOngoing
*/
 
 
drop table #AgentUpliftTable,#FranchiseUpliftRate,#CurrentSplits,#Splits,#NewSplits,#ServiceLevelAudit

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



