/**********************************************************************************************
Name	: [BI].[pr_077_BACS_Summary] 
Author	: John Homer
Date	: 09/09/2021

This report gives a summary of the BACS process for PSD
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_077_BACS_Summary]


with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'BACS'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SELECT 
		  Agt.Code AS AgentCode,
		  bac.BACSPayment,
		  agt.descn,
		  CASE 
			WHEN agt.PaymentFrequency=0 THEN 'Unknown' 
			WHEN agt.PaymentFrequency=1 THEN 'Weekly'			
			WHEN agt.PaymentFrequency=3 THEN 'Quarterly'
			WHEN agt.PaymentFrequency=4 THEN 'HalfYearly'
			WHEN agt.PaymentFrequency=5 THEN 'Annually'
			WHEN agt.PaymentFrequency=6 THEN 'Single'
			WHEN agt.PaymentFrequency=7 THEN 'Daily'
			WHEN agt.PaymentFrequency=8 THEN 'Fortnightly'
			WHEN agt.PaymentFrequency = 2 AND ISNULL(Agt.Code,'')!='1011504' THEN 'Monthly'
			WHEN agt.PaymentFrequency = 2 AND ISNULL(Agt.Code,'')='1011504' THEN 'Daily'
		END AS 'Payment Frequency',
		BusinessStatus
	FROM owhot_BACSTotalsAllDates as bac
			inner join sa_swift_S_AGENTS as agt on agt.code = bac.businessuid  
	WHERE BACSDate >
		-- Last working day 
		DATEADD(DAY, CASE (DATEPART(WEEKDAY, GETDATE()) + @@DATEFIRST) % 7 
				WHEN 1 THEN -2 
				WHEN 2 THEN -3 
				ELSE -1 
		END, DATEDIFF(DAY, 0, GETDATE()))
		order by bac.BACSPayment desc 


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



