/**********************************************************************************************
Name	: [BI].[pr_079_ClientPortfolioLargeFees] 
Author	: R FOXMAN
Date	: 09/09/2021

Purpose	: This report is used by Debbie Burchell in PSD to identify any client portfolios
			by year i.e. sum of all fees in any given year that exceeds £25,000 as these
			require a concession from a Director.

		  The security groups associated with is report are:
		  1) GLS_Logi_OpenworkPortalAudience - for the user to get the "Logi" link on the portal
		  2) GLS_Logi_PSD - to give visibility of the report on the Logi Main Menu 

	

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_079_ClientPortfolioLargeFees]


with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Client Portfolio Large Fees'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


IF OBJECT_ID('tempdb..#Policies') IS NOT NULL
  drop table #Policies
  

select	distinct
		s.SaleId,
		pol.PolicyID,
		prod.DisplayName as ProductSold,
		prov.ProviderCodeSwift as Provider,
		s.DateSubmitted,
		s.AdviserUID,
		ltrim(rtrim(a1.Descn)) as AdviserName,
		ag.Code as BusinessUID,
		rtrim(ltrim(coalesce(ag.tradingname,ag.descn))) as BusinessName,
		case pol.PolicyOwnerType 
			when 1 then 'Client' 
			when 2 then 'Partner' 
			when 3 then 'Joint' 
		end as PolicyOwnerType,
		case when pol.PolicyOwnerType in (1,3) 
			then p1.PersonID
			else p2.PersonID
		end as PersonID,
		case when pol.PolicyOwnerType in (1,3) 
			then ltrim(rtrim(p1.firstname)) + ' ' + ltrim(rtrim(p1.lastname))
			else ltrim(rtrim(p2.firstname)) + ' ' + ltrim(rtrim(p2.lastname))
		end as ClientName,
		case when pol.PolicyOwnerType in (1,3) 
			then datediff(yy,p1.DateOfBirth,s.DateSubmitted)
			else datediff(yy,p2.DateOfBirth,s.DateSubmitted)
		end as ClientAgeAtSubmission,
		case when pol.PolicyOwnerType in (1,3) 
			then p1.DateOfBirth 
			else p2.DateOfBirth
		end as ClientDoB,
		case when pol.PolicyOwnerType in (1,3) 
			then p1.GenderID
			else p2.GenderID
		end as GenderID,
		case when pol.PolicyOwnerType in (1,3) 
			then soundex(ltrim(rtrim(p1.FirstName)))
			else soundex(ltrim(rtrim(p2.FirstName))) 
		end as SoundexFirstName,
		case when pol.PolicyOwnerType in (1,3) 
			then soundex(ltrim(rtrim(p1.LastName)))
			else soundex(ltrim(rtrim(p2.LastName))) 
		end as SoundexLastName,
		case when pol.PolicyOwnerType in (1,3) 
			then left(replace(p1.PostCode,' ',''),10) 
			else left(replace(p2.PostCode,' ',''),10) 
		end as PostCodeCompressed,
		isnull(LAT.LATType,'N/A') as LATType,
		convert(float,isnull(qr4.AnswerText,0.00)) as OrigAmountInvested,
		convert(float,isnull(qr5.AnswerText,0.00)) as OrigAmountFeeRate,
		convert(float,isnull(qr3.AnswerText,0.00)) as RegularPremiumAmount,
		convert(float,isnull(qr9.AnswerText,0.00)) as RegularFeeRate,
		case when ab6.AnswerId > 0 
			then ab6.AnswerText 
		end as RegularPremiumFrequency,
		convert(float,isnull(qr11.AnswerText,0.00)) as LATAmountInvested,
		convert(float,isnull(qr10.AnswerText,0.00)) as LATFeeRate,
		case	when ua.FeeType = 65 then 'Flat Fee' 
				when ua.FeeType = 66 then 'Hourly' 
				else '(No Fee)'
		end as UAType,
		convert(float,case ua.FeeType 
			when 65 then ua.FeeAmount 
			when 66 then ua.FeeAmount * ua.Hours 
			else 0.00
		end) as UAFeeAmount, 
		case when prod.ProductCodeSwift in ('OWADVICE','OWADHOC') 
				then 'No' 
				else 'Yes' 
		end as FeeFromFunds,
		case when prod.OnPlatform = 1 
			then 'Yes' 
			else 'No' 
		end as OnPlatform
into	#Policies
from	dbo.sa_ows_sale s 
		left join dbo.sa_ows_Person p1 on p1.PersonId = s.PersonId
		left join dbo.sa_ows_Person p2 on p2.PersonId = p1.PartnerPersonId  
		left join mstt_Agents a1 on a1.code = p1.AdviserUID
		left join mstt_Agents ag on ag.code = a1.Firm
		left join dbo.sa_ows_Policies pol on pol.SaleID = s.SaleID 
		left join StaticData.sa_ows_Product prod on prod.InternalProductID = pol.InternalProductID
		left join StaticData.sa_ows_ProviderProducts PP on PP.InternalProductID = prod.InternalProductID
		left join StaticData.sa_ows_Provider Prov on prov.InternalProviderID = pp.InternalProviderID
		left join ( Select	dcr.SaleID,max(IV.ValueName) as LATType
					from	sa_ows_HDRUI_DocumentCheckListResponses DCR 
							left join StaticData.sa_ows_InputValues IV on IV.InputId = DCR.LATTransferType
					group	by dcr.SaleId ) LAT on LAT.SaleId = s.SaleID
		left join dbo.sa_ows_HDRUI_QuestionnaireResponses qr6 on qr6.PolicyID = pol.PolicyID and qr6.QuestionID in (5,458,509) and isnull(qr6.AnswerText,'') <> ''
		left join StaticData.sa_ows_HDRUI_AnswerBank ab6 on ab6.AnswerID = ISNULL(qr6.AnswerText,0)
		left join (select	s.SaleID, ud.FeeType, ud.FeeAmount, ud.[Hours], prop.UnderstandingAnalysisFlatFee, prop.UnderstandingAnalysisHourlyFee
					from	dbo.sa_ows_sale  s with (nolock)
							inner join dbo.sa_ows_ClientServiceLevel csl with (nolock) on csl.PersonID = s.PersonId
							inner join Proposition.sa_ows_ServiceLevel SL with (nolock) on SL.ServiceLevelId = csl.ServiceLevelId
							inner join Proposition.sa_ows_Proposition prop with (nolock) on prop.PropositionId = sl.PropositionId
							inner join (select UD.saleId, MAX(UD.DateUpdated) as DateUpdated
										 from dbo.sa_ows_HDRUI_SubmissionFeeUnderstandingDetails UD
										 where UD.HaveYouChargedUnderstandingAnalysisFee = 19 -- Yes
										 group by UD.SaleId) as LatestUD on LatestUD.SaleID = s.SaleID
							inner join (select ud.SaleID, ud.DateUpdated, ud.FeeType, ud.FeeAmount, ud.[Hours]
										 from dbo.sa_ows_HDRUI_SubmissionFeeUnderstandingDetails ud with (NOLOCK)
										 where ud.HaveYouChargedUnderstandingAnalysisFee = 19 -- Yes
										) as ud on  ud.SaleId = LatestUD.SaleID
												and ud.DateUpdated = LatestUD.DateUpdated 
					) ua on ua.SaleID = s.SaleID
--RegularPremiumAmount
left join (select	qr3.PolicyID, qr3.QuestionID, cast(isnull(replace(qr3.AnswerText, ',', ''),0.00) as float) as AnswerText
			from	dbo.sa_ows_HDRUI_QuestionnaireResponses qr3  
					inner join StaticData.sa_ows_HDRUI_QuestionBank qb3 on qb3.QuestionID = qr3.QuestionID 
					left join owt_SelectionControl sc -- Handles multi-purpose ObjectModelProperties such as 'TransactionAmount' and 'SinglePremiumTransactionAmount'
									on  sc.Process = 'OWSSubmissionHeader'
									and sc.keyType = qb3.ObjectModelProperty
									and convert(int,sc.KeyValue) = qb3.QuestionID
			where	isnull(qr3.AnswerText,'') <> '' 
			and		isnumeric(qr3.AnswerText) = 1
			and		qr3.AnswerText not in ('.','-')
			and		(qb3.ObjectModelProperty in ('RegularContributionClientContribution','RegularPremiumTransactionAmount')
					or
					sc.SelectionType = 'Regular')	
			) qr3 on qr3.PolicyID = pol.PolicyID
--OrigAmountInvested/OneOff
left join (	select	qr4.PolicyID, sum(cast(isnull(replace(qr4.AnswerText, ',', ''),0.00) as float)) as AnswerText
			from	dbo.sa_ows_HDRUI_QuestionnaireResponses qr4  
					inner join StaticData.sa_ows_HDRUI_QuestionBank qb4 on qb4.QuestionID = qr4.QuestionID 
					left join owt_SelectionControl sc -- Handles multi-purpose ObjectModelProperties such as 'TransactionAmount' and 'SinglePremiumTransactionAmount'
									on  sc.Process = 'OWSSubmissionHeader'
									and sc.keyType = qb4.ObjectModelProperty
									and convert(int,sc.KeyValue) = qb4.QuestionID
			where	isnull(qr4.AnswerText,'') <> '' 
			and		isnumeric(qr4.AnswerText) = 1
			and		qr4.AnswerText not in ('.','-')
			and		(qb4.ObjectModelProperty in ('DrawdownTransferAmount','ProtDrawdownTransferAmount',
												 'ProtTransferAmount','TransferAmount',
												 'SingleContributionClientContribution','SingleContributionEmployerContribution')
					or 
					sc.SelectionType in ('OneOff','Transfer'))	-- AG 25/03/2014
			group	by qr4.PolicyID
			) qr4 on qr4.PolicyID = pol.PolicyID
--Legacy Asset Transfer
left join (select	qr11.PolicyID, sum(cast(isnull(replace(qr11.AnswerText, ',', ''),0.00) as float)) as AnswerText
			from	dbo.sa_ows_HDRUI_QuestionnaireResponses qr11
					inner join StaticData.sa_ows_HDRUI_QuestionBank qb11 on qb11.QuestionID = qr11.QuestionID 
			where	isnull(qr11.AnswerText,'') <> '' 
			and		isnumeric(qr11.AnswerText) = 1
			and		qr11.AnswerText not in ('.','-')
			and		qb11.ObjectModelProperty in ('LegacyAssetTransactionAmount')
			group	by qr11.PolicyID
			) qr11 on qr11.PolicyID = pol.PolicyID
--SinglePremiumFeeRate
left join (select	qr5.PolicyID, qr5.QuestionID, cast(isnull(replace(qr5.AnswerText, ',', ''),0.00) as float) as AnswerText
			from	dbo.sa_ows_HDRUI_QuestionnaireResponses qr5 
					inner join StaticData.sa_ows_HDRUI_QuestionBank qb5 on qb5.QuestionID = qr5.QuestionID 
			where	isnull(qr5.AnswerText,'') <> '' 
			and		isnumeric(qr5.AnswerText) = 1
			and		qb5.ObjectModelProperty in ('SinglePremiumFee')
			) qr5 on qr5.PolicyID = pol.PolicyID
--RegularPremiumFeeRate
left join (select	qr9.PolicyID, qr9.QuestionID, cast(isnull(replace(qr9.AnswerText, ',', ''),0.00) as float) as AnswerText
			from	dbo.sa_ows_HDRUI_QuestionnaireResponses qr9 
					inner join StaticData.sa_ows_HDRUI_QuestionBank qb9 on qb9.QuestionID = qr9.QuestionID 
			where	isnull(qr9.AnswerText,'') <> '' 
			and		isnumeric(qr9.AnswerText) = 1
			and		qb9.ObjectModelProperty in ('RegularPremiumFee')
			) qr9 on qr9.PolicyID = pol.PolicyID
--LegacyAssetFeeRate
left join (select	qr10.PolicyID, qr10.QuestionID, cast(isnull(replace(qr10.AnswerText, ',', ''),0.00) as float) as AnswerText
			from	dbo.sa_ows_HDRUI_QuestionnaireResponses qr10 
					inner join StaticData.sa_ows_HDRUI_QuestionBank qb10 on qb10.QuestionID = qr10.QuestionID 
			where	isnull(qr10.AnswerText,'') <> '' 
			and		isnumeric(qr10.AnswerText) = 1
			and		qb10.ObjectModelProperty in ('LegacyAssetFee')
			) qr10 on qr10.PolicyID = pol.PolicyID
where	s.SaleStatusID in (2)	--Submitted
and		pol.Status = 2			--Submitted
--and	s.SaleID in (261778,246851)
--and	s.SaleID in (109514,109515)
--and	s.SaleID in (109514)
and		(	prod.ProductCodeSwift in ('OWADHOC','OWADVICE') 
			or prod.OnPlatform = 1 or prod.IsGapFill = 1
			or prod.FeeApplies = 1
		)

/*********************

select top 10 *
from #Policies

**********************/

/****************************************************************************

	Populate a new temp table #PoliciesMatchedToClients. This is at case 
	level, fuzzy matched to client and all amount columns fully calculated. 
	Must include BusinessUID, AdviserUID and PersonID (and client name 
	details as not joining back to Person again).
																	
****************************************************************************/

IF OBJECT_ID('tempdb..#PoliciesMatchedToClients') IS NOT NULL
  drop table #PoliciesMatchedToClients
  			
select	a.SaleID,
		a.PolicyID,
		a.ProductSold,
		a.Provider,
		a.BusinessUID,
		a.BusinessName,
		a.AdviserUID,
		a.AdviserName,
		c.PersonID,
		c.FirstName,
		c.LastName,
		c.DateOfBirth,
		a.DateSubmitted,
		YEAR(a.DateSubmitted) as BusinessSubmittedYear,
		a.OrigAmountInvested,
		a.OrigAmountInvested * (a.OrigAmountFeeRate/100) as OrigAmountFee,
		case	when a.RegularPremiumFrequency = 'Quarterly' 
				then 4 
				when a.RegularPremiumFrequency = 'Monthly' 
				then 12 
				else 0 
		end * a.RegularPremiumAmount * (a.RegularFeeRate/100) as RegAmountFee,
		a.LATAmountInvested,
		a.LATAmountInvested * (a.LATFeeRate/100) as LATAmountFee,
		a.UAFeeAmount
into	#PoliciesMatchedToClients
from	#Policies a
		inner join (select	GenderID, SOUNDEX(FirstName) as SoundexFirstName, SOUNDEX(LastName) as SoundexLastName,
							left(replace(PostCode,' ',''),10) as PostCodeCompressed, MAX(PersonID) as MaxPersonID 
					from	dbo.sa_ows_Person
					group	by GenderID, SOUNDEX(FirstName), SOUNDEX(LastName), left(replace(PostCode,' ',''),10)
					) b on  a.GenderID = b.GenderID
						and a.SoundexFirstName = b.SoundexFirstName
						and a.SoundexLastName = b.SoundexLastName
						and a.PostCodeCompressed = b.PostCodeCompressed 
		inner join 	dbo.sa_ows_Person c on c.PersonID = b.maxPersonID

/*********************

select top 10 *
from #PoliciesMatchedToClients

sp_help '#PoliciesMatchedToClients'

sp_help '#Policies'

**********************/
/****************************************************************************

	Populate #LargePortfolioSummary from #PoliciesMatchedToClients,  group 
	by business, adviser, client where sum of amounts >= 25,000. Total Fee 
	will be sum of parts. Include most recent submitted date. Create a 
	SummaryID number for each summary line.
																	
****************************************************************************/

IF OBJECT_ID('tempdb..#LargePortfolioSummary') IS NOT NULL
  drop table #LargePortfolioSummary
  
select	row_number() over (order by a.BusinessName,a.AdviserName) as SummaryID,
		a.BusinessUID,
		a.BusinessName,
		a.AdviserUID,
		a.AdviserName,
		a.PersonID,
		a.FirstName,
		a.LastName,
		a.DateOfBirth,
		a.MaxDateSubmitted,
		a.BusinessSubmittedYear,
		TotalFees = a.SumOrigAmountFee + a.SumRegAmountFee + a.SumLATAmountFee + a.SumUAFeeAmount
into	#LargePortfolioSummary
from
		(
		select	BusinessUID,
				BusinessName,
				AdviserUID,
				AdviserName,
				PersonID,
				FirstName,
				LastName,
				DateOfBirth,
				BusinessSubmittedYear,
				max(DateSubmitted) as MaxDateSubmitted,
				sum(OrigAmountInvested) as SumOrigAmountInvested,
				sum(OrigAmountFee) as SumOrigAmountFee,
				sum(RegAmountFee) as SumRegAmountFee,
				sum(LATAmountInvested) as SumLATAmountInvested,
				sum(LATAmountFee) as SumLATAmountFee,
				sum(UAFeeAmount) as SumUAFeeAmount
		from	#PoliciesMatchedToClients
		group	by	BusinessUID,
					BusinessName,
					AdviserUID,
					AdviserName,
					PersonID,
					FirstName,
					LastName,
					DateOfBirth,
					BusinessSubmittedYear
		) a
where (a.SumOrigAmountFee + a.SumRegAmountFee + a.SumLATAmountFee + a.SumUAFeeAmount) > 25000


/*********************

select *
from #LargePortfolioSummary

**********************/


/****************************************************************************

	Populate #LargePortfolioDetail from #LargePortfolioSummary joined back 
	to #PoliciesMatchedToClients with case level information from the 
	latter. Note Total Fee = zero. Store submitted date and the SummaryID. 
	This gives all the detail rows for each summary row.
																	
****************************************************************************/

select	lps.SummaryID,
		lps.BusinessUID,
		lps.BusinessName,
		lps.AdviserUID,
		lps.AdviserName,
		lps.PersonID,
		lps.FirstName,
		lps.LastName,
		lps.DateOfBirth,
		lps.BusinessSubmittedYear,
		0 as TotalFees,
		pmtc.PolicyID,
		pmtc.DateSubmitted,
		pmtc.ProductSold,
		pmtc.Provider,
		pmtc.OrigAmountInvested,
		pmtc.OrigAmountFee,
		pmtc.RegAmountFee,
		pmtc.LATAmountInvested,
		pmtc.LATAmountFee,
		pmtc.UAFeeAmount
into	#LargePortfolioDetail
from	#LargePortfolioSummary lps
		inner join #PoliciesMatchedToClients pmtc
						on	pmtc.BusinessUID = lps.BusinessUID
						and	pmtc.AdviserUID = lps.AdviserUID
						and	pmtc.PersonID = lps.PersonID
						and	pmtc.BusinessSubmittedYear = lps.BusinessSubmittedYear

/****************************************************************************

	Finally, create a consolidated output comprising select all from 
	#LargePortfolioSummary union all select all from #LargePortfolioDetail. 
	Ensure SummaryID is included.
																	
****************************************************************************/

select	lps.SummaryID,
		lps.BusinessUID,
		lps.BusinessName,
		lps.AdviserUID,
		lps.AdviserName,
		ltrim(rtrim(lps.FirstName)) + ' ' + ltrim(rtrim(lps.LastName)) as ClientName,
		lps.DateOfBirth as ClientDoB,
		lps.BusinessSubmittedYear,
		lps.MaxDateSubmitted as DateSubmitted,
		lps.TotalFees,
		NULL as PolicyID,
		NULL as ProductSold,
		NULL as Provider,
		NULL as OrigAmountInvested,
		NULL as OrigAmountFee,
		NULL as RegAmountFee,
		NULL as LATAmountInvested,
		NULL as LATAmountFee,
		NULL as UAFeeAmount
from	#LargePortfolioSummary lps

union all

select	lpd.SummaryID,
		lpd.BusinessUID,
		lpd.BusinessName,
		lpd.AdviserUID,
		lpd.AdviserName,
		ltrim(rtrim(lpd.FirstName)) + ' ' + ltrim(rtrim(lpd.LastName)) as ClientName,
		lpd.DateOfBirth as ClientDoB,
		lpd.BusinessSubmittedYear,
		lpd.DateSubmitted,
		0 as TotalFees,
		lpd.PolicyID,
		lpd.ProductSold,
		lpd.Provider,
		lpd.OrigAmountInvested,
		lpd.OrigAmountFee,
		lpd.RegAmountFee,
		lpd.LATAmountInvested,
		lpd.LATAmountFee,
		lpd.UAFeeAmount
from	#LargePortfolioDetail lpd
--order	by 1,2,3,4,5,6,7,8,10 desc,11
order	by 9 desc,2,4,6,11



/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



