/****** Object:  StoredProcedure [BI].[pr_081_Delegations]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_081_Delegations] 
Author	: John Homer
Date	: 09/09/2021

This report shows the relationship between delegator and delegate. This functionality is used in 
OpenAccess to grant access to someone who would not automatically have access.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_081_Delegations]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


Select	distinct	-- Needed because a UID can be on IntUsers, the ISL, etc. multiple times 
		a.DelegatorPTL,
		a.DelegatorUID,
		a.DelegatorName,
		a.DelegatePTL,
		a.DelegateUID,
		a.DelegateName,
		convert(nvarchar(4000),
		reverse(substring(reverse(
		case when a.Problem01 <> '' then a.Problem01 + '; ' else '' end + 
		case when a.Problem02 <> '' then a.Problem02 + '; ' else '' end + 
		case when a.Problem03 <> '' then a.Problem03 + '; ' else '' end + 
		case when a.Problem04 <> '' then a.Problem04 + '; ' else '' end + 
		case when a.Problem05 <> '' then a.Problem05 + '; ' else '' end + 
		case when a.Problem06 <> '' then a.Problem06 + '; ' else '' end + 
		case when a.Problem07 <> '' then a.Problem07 + '; ' else '' end + 
		case when a.Problem08 <> '' then a.Problem08 + '; ' else '' end + 
		case when a.Problem09 <> '' then a.Problem09 + '; ' else '' end + 
		case when a.Problem10 <> '' then a.Problem10 + '; ' else '' end + 
		case when a.Problem11 <> '' then a.Problem11 + '; ' else '' end +
		case when a.Problem12 <> '' then a.Problem12 + '; ' else '' end + 
		case when a.Problem13 <> '' then a.Problem13 + '; ' else '' end + 
		case when a.Problem14 <> '' then a.Problem14 + '; ' else '' end 
		),3,8000))) as ReportingReason
from
(
select	surro.SurrogateOf as DelegatorPTL,
		DelegatorID.Field1Value as DelegatorUID,
		DelegatorAg.DESCN as DelegatorName,
		surro.DomainLogin as DelegatePTL,
		DelegateID.Field1Value as DelegateUID,
		DelegateAg.DESCN as DelegateName,
		case
			when DelegatorID.Field1Value IS null then 'Delegator not on the ISL'
			else ''
		end as Problem01,
		case
			when DelegatorAg.CODE is null then 'Delegator not on the Swift Agents table'
			else ''
		end as Problem02,
		case 
			when DelegateID.Field1Value IS null then 'Delegate not on the ISL'
			else ''
		end as Problem03,
		case
			when DelegateAg.CODE is null then 'Delegate not on the Swift Agents table'
			else ''
		end as Problem04,
		case
			when DelegatorAg.AgentType = 53 then 'Delegator is a Manager 2'
			else ''
		end as Problem05,
		case
			when DelegatorAg.AgentType = 55 then 'Delegator is a Manager 4'
			else ''
		end as Problem06,
		case
			when Delegatoruh.UserUID is null or Delegatoruh.UserEmploymentStatusCode = 2 or Delegatoruh.UserContractStatusCode = 2 then 'Delegator is Left Status on Insight'
			else ''
		end as Problem07,
		case
			when Delegateuh.UserUID is null or Delegateuh.UserEmploymentStatusCode = 2 or Delegateuh.UserContractStatusCode = 2 then 'Delegate is Left Status on Insight'
			else ''
		end as Problem08,
		case
			when DelegatoriuUID.AssociatedAgent is null then 'Delegator''s UID not on Swift IntUsers table'
			else ''
		end as Problem09,
		case
			when DelegatoriuPTL.Name is null then 'Delegator''s PTL not on Swift IntUsers table'
			else ''
		end as Problem10,
		case 
			when DelegateiuUID.AssociatedAgent is null then 'Delegate''s UID not on Swift IntUsers table'
			else ''
		end as problem11,
		case
			when DelegateiuPTL.Name is null then 'Delegate''s PTL not on Swift IntUsers table'
			else ''
		end as Problem12,
		case
			when DelegatorAg.Firm <> DelegateAg.Firm then 'Cross firm delegation'
			else ''
		end as Problem13,
		case
			when exists (select 1 from msit_UserSurrogates surro2 where surro2.SurrogateOf = surro.DomainLogin) then 'Delegate is also a delegator'
			else ''
		end as problem14
from	msit_UserSurrogates surro
		left join sa_ISL_SingleSignOnApplicationProfile DelegatorPTL 
						on  DelegatorPTL.Field1Value = replace(surro.SurrogateOf,'OPENWORK\','')
						and DelegatorPTL.SingleSignOnApplicationID = 1
		left join sa_ISL_SingleSignOnApplicationProfile DelegatorID
						on  DelegatorID.SingleSignOnUserId = DelegatorPTL.SingleSignOnUserId
						and	DelegatorID.SingleSignOnApplicationID = 3
		left join mstt_Agents DelegatorAg on DelegatorAg.CODE = DelegatorID.Field1Value
		left join mi_insight_UserHierarchy Delegatoruh on Delegatoruh.UserUID = DelegatorID.Field1Value
		left join sa_swift_IntUsers DelegatoriuUID on DelegatoriuUID.AssociatedAgent = DelegatorID.Field1Value
		left join sa_swift_IntUsers DelegatoriuPTL on DelegatoriuPTL.Name = DelegatorPTL.Field1Value
		--
		left join sa_ISL_SingleSignOnApplicationProfile DelegatePTL 
						on  DelegatePTL.Field1Value = replace(surro.DomainLogin,'OPENWORK\','')
						and DelegatePTL.SingleSignOnApplicationID = 1
		left join sa_ISL_SingleSignOnApplicationProfile DelegateID
						on  DelegateID.SingleSignOnUserId = DelegatePTL.SingleSignOnUserId
						and	DelegateID.SingleSignOnApplicationID = 3
		left join mstt_Agents DelegateAg on DelegateAg.CODE = DelegateID.Field1Value
		left join mi_insight_UserHierarchy Delegateuh on Delegateuh.UserUID = DelegateID.Field1Value
		left join sa_swift_IntUsers DelegateiuUID on DelegateiuUID.AssociatedAgent = DelegateID.Field1Value
		left join sa_swift_IntUsers DelegateiuPTL on DelegateiuPTL.Name = DelegatePTL.Field1Value
) a


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



