/**********************************************************************************************
Name   : [BI].[pr_082_UPV08ext] 
Author : R Foxman
Date   : 09/09/2021

       Purpose       :      This report is an extension of the ITSecurity.UPV08 report
                      5 additional columns are being selected

AMENDMENT HISTORY
=================
Date          Author        Description
----          ------        -----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_082_UPV08ext]

with recompile
AS 
set nocount on

/****************************************************************************
       Initialisation                                                                                                                   
****************************************************************************/
       
BEGIN TRY

declare
                      @ReportName                        varchar(200),
                      @StoredProcName                    varchar(200),
                      @StoredProcParams           varchar(4000),
                      @ErrMsg                                    nvarchar(4000),
                      @LastAuditID                int,
                      @ErrNum                                    int,
                      @ErrSev                                    int,
                      @ErrLine                            int

                      --Change the @Reportname param here to the name of your report
set    @ReportName                 = 'Portal Codes Report (UPV08) Extended'
set @StoredProcName         = object_name(@@procid)
/****************************************************************************
       Select the data for the report                                                                                                                
****************************************************************************/
SELECT     
                      IntUsers.Name AS PortalCode, 
                      IntUsers.Description AS Name, 
                      IntUsers.AssociatedAgent AS UniqueId, 
                      Agents.AgentTypeDescription AS Role, 
                      Agents.AgentCategory AS Category, 
                      IntUsersT.Name AS Template,
                      IntUsers.AgentPaymentRange ,
                      IntUsers.PolicyTransactionRange ,
                      CASE WHEN IntUsers.Principal = 1 THEN 'Yes' ELSE 'No' END AS 'Principal',
                      CASE WHEN IntUsers.Supervisor = 1 THEN 'Yes' ELSE 'No' END AS 'Supervisor',
                      CASE WHEN ISNULL(IntUsers.OSLoginUserName,'') = '' THEN 'Use Swift' ELSE 'Use OS' END AS LogonType                 
       FROM    msit_IntUsers AS IntUsers 
                      LEFT OUTER JOIN mstt_AGENTS AS Agents ON Agents.CODE = IntUsers.AssociatedAgent 
                      LEFT OUTER JOIN msit_IntUserTemplates AS Template ON IntUsers.ID = Template.UserID 
                      LEFT OUTER JOIN msit_IntUsers AS IntUsersT ON Template.TemplateUserID = IntUsersT.ID
       WHERE   (IntUsers.Name LIKE 'ptl%')
       ORDER BY PortalCode
/****************************************************************************
       End Of Report
****************************************************************************/
END TRY

BEGIN CATCH 
       select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
       set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
END CATCH
