/**********************************************************************************************
Name	: [BI].[pr_083_PaymentMatchedTimes] 
Author	: John Homer
Date	: 10/09/2021

This report is used by Payment Services after payment ut-off each month as part of their monthly reporting
it details the numbers of days spent matching payments
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_083_PaymentMatchedTimes]

	@Year as Integer, @Month as VarChar(20)

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Payment Matched Times'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select
pp.commissiontypedesc,
avg(datediff(day,edc.commissionreceiveddate,pp.createdatetime))
from sa_swift_edifactcommissionstatementcontents edc
join sa_swift_s_paccsu su on su.susp_id = edc.pacc_id
join mstt_paymentspending pp on pp.pacc_id = su.init_id
where year(commissionreceiveddate) = @Year and month(commissionreceiveddate) = @Month --charindex(LEFT(@Month,3),'JAN FEB MAR APR MAY JUN JUL AUG SEP OCT NOV DEC')/4+1
Group by
pp.commissiontypedesc

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



