/**********************************************************************************************
Name	: [BI].[pr_088_AQT_Stats_Submitted_by_Product] 
Author	: John Homer
Date	: 22/09/2021

AQT Report to show number of submissions by Product Type
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_088_AQT_Stats_Submitted_by_Product]

@StartDate as Date, @EndDate as Date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'AQT Submitted by Product'
set @StoredProcName		= object_name(@@procid);


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


WITH Sub_Table AS (

SELECT distinct
	SaCa.CASE_CaseReference AS Advice
	, BP.BPOL_BackOfficeID AS [Case ID]
	, PT.PROD_ShortName AS ProdShortName
	, AASS.LOB  as LOB  
	, CONVERT(varchar(10), SaCa.CASE_SubmitDate, 120) AS subdate
	, AASS.LOBSort as LOBSort
FROM  dbo.sa_insight_BasicPolicy BP INNER JOIN
      dbo.sa_insight_ProductType PT ON BP.BPOL_ProductType = PT.PROD_Code INNER JOIN
      dbo.sa_insight_SalesCase SaCa ON BP.BPOL_ParentID = SaCa.CASE_ID INNER JOIN
      dbo.sa_insight_UserDetails UD ON SaCa.CASE_AdviserID = UD.USR_ID INNER JOIN
	  logi.AQT_AQTStats_Submitted AASS on AASS.ProdShortName = PT.PROD_ShortName
			   
WHERE 	(CONVERT(varchar(10), SaCa.CASE_SubmitDate, 120) >= '2013-12-01') 
		AND (SaCa.CASE_CaseReference <> '0') 
		AND (PT.PROD_ShortName is not NULL)
		AND (PT.PROD_ShortName not like 'x%')
		AND (PT.PROD_ShortName not in ('GI','DUP','GPP','DRDW','OGS'))
		AND (BP.BPOL_BackOfficeID <> '0') 
		AND (BP.BPOL_BackOfficeID <> ' ') 
		AND (BP.BPOL_BackOfficeID is not NULL) 
		and SaCa.CASE_SubmitDate >= AASS.EffectiveStartDate
		and SaCa.CASE_SubmitDate <= AASS.EffectiveEndDate
		and SaCa.Case_SubmitDate Between @StartDate AND @EndDate
)

Select LOB as Line_Of_Business, ProdShortName as Product_Type, Count(Advice) AS Advice
from Sub_Table
Group By LOB, ProdShortName
Order by LOB asc, Product_Type asc


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



