/**********************************************************************************************
Name	: [BI].[pr_090_AQTStats_QualityResultsRFC] 
Author	: N Williams
Date	: 22/09/2021

RFC Quality Results
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_090_AQTStats_QualityResultsRFC]

	 @Startdate  date,
	 @Enddate	date 

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Quality Results RFC '
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


Begin

IF OBJECT_ID('tempdb..#AQT_HEATMAP') IS NOT NULL
DROP TABLE #AQT_HEATMAP;


CREATE TABLE #AQT_HEATMAP 
      (
            Advice                    VARCHAR(50),
            RFC                       VARCHAR(100),
            CaseOutcome               VARCHAR(50),
            ProdCode                  int,
            ProdShortName             VARCHAR(50),
            InitialStatus             VARCHAR(50),
            InitialStatusCode         VARCHAR(3),
            FinalStatus               VARCHAR(50),
            FinalStatusCode           VARCHAR(3),
            InitialWorkFlowStatus     VARCHAR(50),
            InitialWorkFlowStatusCode VARCHAR(1),
            FinalWorkFlowStatus       VARCHAR(50),
            FinalWorkFlowStatusCode   VARCHAR(1),
            InitialCheckDate          DATETIME,
            FinalCheckDate            DATETIME
      );


insert into #AQT_HEATMAP (Advice,RFC,CaseOutcome,ProdCode,ProdShortName,InitialStatus,InitialStatusCode,
                                       InitialWorkFlowStatus,InitialWorkFlowStatusCode,InitialCheckDate)
select saca.CASE_CaseReference
      ,rfc.RFC_Description
      ,cofs.CFS_Description
      ,prty.PROD_Code      
      ,prty.PROD_ShortName
      ,bqco.BQC_Description as outcome
      ,bqco.bqc_code
      ,CaseStatus.Code_Description as WorkFlowStatus
      ,CaseStatus.Code_Code
      ,buqu.BQ_CompletedDate
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCaseRFC] scrfc on scrfc.SCRFC_SalesCaseID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_RFC] rfc on rfc.RFC_ID = scrfc.SCRFC_RFCID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 9 and CaseStatus.Code_Code = buqu.BQ_Status 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
WHERE 
saca.CASE_SubmitDate >= '01-JUL-2013'
AND   saca.CASE_CaseReference != '0'
and   scrfc.SCRFC_DateTo is null
and   CaseStatus.code_code in (3,4,5,6,7,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757)
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select min(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) ;                            

create index CTE_OUTCOME1 on #AQT_HEATMAP (Advice,CaseOutcome,ProdShortName);


WITH CTE_OUTCOME
AS (select saca.CASE_CaseReference as Advice
      ,cofs.CFS_Description as CaseOutcome
      ,prty.PROD_ShortName  as ProdShortName    
      ,bqco.BQC_Description as FinalStatus
      ,bqco.bqc_code as FinalStatusCode
      ,CaseStatus.Code_Description as FinalWorkFlowStatus
      ,CaseStatus.Code_Code as FinalWorkFlowStatusCode
      ,buqu.BQ_CompletedDate FinalCheckDate
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 9 and CaseStatus.Code_Code = buqu.BQ_Status 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID --and cofs.CFS_Description like 'Case Outcome%' 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
WHERE 
saca.CASE_SubmitDate >= '01-JUL-2013'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757)
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,14)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) )
UPDATE #AQT_HEATMAP                             
 set    FinalStatus             = CTE_OUTCOME.FinalStatus,
        FinalStatusCode         = CTE_OUTCOME.FinalStatusCode,
        FinalWorkFlowStatus     = CTE_OUTCOME.FinalWorkFlowStatus,
        FinalWorkFlowStatusCode = CTE_OUTCOME.FinalWorkFlowStatusCode,
        FinalCheckDate          = CTE_OUTCOME.FinalCheckDate
FROM   #AQT_HEATMAP aqou1
JOIN   CTE_OUTCOME on CTE_OUTCOME.Advice        = aqou1.Advice
                           and CTE_OUTCOME.CaseOutcome   = aqou1.CaseOutCome
                           and CTE_OUTCOME.ProdShortName = aqou1.ProdShortName;

select HEAT.RFC
		,RFC_DISPLAY_NAME
		,Category
        --,InitialCheckDate as checkdate
        ,count(*) TotalChecked
      ,sum(case InitialStatus when 'A1 Suitable and Complete' then 1 
								when 'A2 Suitable and Acceptable' then 1
                                      else 0 end) as Pass
    ,sum(case InitialStatus when 'A3 Suitable but Defective' then 1 
								when 'B Clarify' then 1
								when 'C Potentially Unsuitable' then 1
                                      else 0 end) as Queried 
    ,sum(case InitialStatus when 'C Potentially Unsuitable' then 1 
                                                        else 0 end) as PotUnsuit 
	,sum(case FinalWorkFlowStatus when 'Reject' THEN 
								(case  FinalStatus when 'A3 Suitable but Defective' then 1
															when 'B Clarify' then 1
															when 'C Potentially Unsuitable' then 1
										          else 0 end)
                                     ELSE 0 END) as Reject
                
from #AQT_HEATMAP HEAT
join [logi].[AQT_Heatmap_RFC] HERF  on HERF.RFC      = HEAT.RFC
                          and case HERF.ProdCode when 0 then HEAT.ProdCode else HERF.ProdCode end = HEAT.ProdCode
						  and HEAT.InitialCheckDate between HERF.EffectiveStartDate and HERF.EffectiveEndDate
WHERE (Category = 'Case Based Risks' and RFC_Display_Name LIKE '%mortgage%') and InitialCheckDate between @Startdate and @Enddate

group by HEAT.RFC, RFC_DISPLAY_NAME, Category

--ORDER BY InitialCheckDate desc  

/****************************************************************************

	End Of Report
																	
****************************************************************************/

End

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH




/****************************************************************************

			E N D															

****************************************************************************/
GO
