/**********************************************************************************************
Name	: [BI].[pr_091_Assessor_Count] 
Author	: H Macarthur
Date	: 22/09/2021

		Insert report description here.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
31.05.2024  K Garcia    Included new case references for OAS and OAW product types
13/06/2024	S Hale		Further updates for missing products (OAS, OAW, OFIR, IHT, TIP, PNRP, WOLR)

***********************************************************************************************/

CREATE PROCEDURE [BI].[pr_091_Assessor_Count]

@startdate date,
@enddate date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'Assessor Count'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/



IF OBJECT_ID('tempdb..#AQT_OUTCOMES') IS NOT NULL
DROP TABLE #AQT_OUTCOMES;

CREATE TABLE #AQT_OUTCOMES  -- STIN and KWOL added 29/7/20 SH
      (
            Advice                    VARCHAR(30),
            CaseOutcome               VARCHAR(100),
            ProdShortName             VARCHAR(20),
			LOB						 VARCHAR(10),
            InitialStatus             VARCHAR(200),
           FinalStatus               VARCHAR(200),
            InitialWorkFlowStatus     VARCHAR(100),
            FinalWorkFlowStatus       VARCHAR(100),
			compfdate             VARCHAR(10),
            InitialCheckDate          DATETIME,
            FinalCheckDate            DATETIME,
		AssessorUID           VARCHAR(50),
		Assessor              VARCHAR(50),
		KAP              VARCHAR(10),
		KICO              VARCHAR(10),
		KWOL              VARCHAR(10),
		MORT              VARCHAR(10),
		BTL              VARCHAR(10),
		ICOB              VARCHAR(10),
		GI              VARCHAR(10),
		WOL              VARCHAR(10),
		WOLR              VARCHAR(10),
		ONIV              VARCHAR(10),
		OIRP              VARCHAR(10),
		OFIN              VARCHAR(10),
		OFIR              VARCHAR(10),
		IHT              VARCHAR(10),
		CINV              VARCHAR(10),
		TIP              VARCHAR(10),
		STIN              VARCHAR(10),
		EIS              VARCHAR(10),
		VCT              VARCHAR(10),
		BPRL              VARCHAR(10),
		PENS              VARCHAR(10),
		PNRP              VARCHAR(10),
		PNSW              VARCHAR(10),
		METG              VARCHAR(10),
		SIPP              VARCHAR(10),
		ANNC              VARCHAR(10),
		ANNS              VARCHAR(10),
		DRAW              VARCHAR(10),
		DTOD              VARCHAR(10),
		OGS				VARCHAR(10),
		OAS				VARCHAR(10),
		OAW				VARCHAR(10)
		--Total			INT
      );


insert into #AQT_OUTCOMES (Advice,CaseOutcome,ProdShortName,LOB,InitialStatus
						,InitialWorkFlowStatus,compfdate,InitialCheckDate,AssessorUID,Assessor
			,KAP,KICO,KWOL,MORT,BTL,ICOB,GI,WOL,WOLR,ONIV,OIRP,OFIN,OFIR,IHT,CINV,STIN,TIP,EIS,VCT,BPRL,PENS,PNRP,PNSW,METG,SIPP,ANNC,ANNS,DRAW,DTOD,OGS,OAS,OAW)
select saca.CASE_CaseReference
      ,cofs.CFS_Description
      ,prty.PROD_ShortName as ProdShortName
	,CASE prty.PROD_ShortName 
            WHEN 'KAP' THEN 'Owl'
	        WHEN 'KICO' THEN 'Owl'
	        WHEN 'KWOL' THEN 'Owl'


            WHEN 'MORT' THEN 'MORT'
			WHEN 'BTL' THEN 'MORT'

            WHEN 'ICOB' THEN 'ICOB'

			WHEN 'GI' THEN 'GI'

            WHEN 'ONIV' THEN 'COBi'
            WHEN 'OIRP' THEN 'COBi'
            WHEN 'OFIN' THEN 'COBi'
            WHEN 'OFIR' THEN 'COBi'
            WHEN 'WOL' THEN 'COBi'
            WHEN 'WOLR' THEN 'COBi'
            WHEN 'IHT' THEN 'COBi'
            WHEN 'CINV' THEN 'COBi'
            WHEN 'STIN' THEN 'COBi'
            WHEN 'TIP' THEN 'COBi'
            WHEN 'TIPR' THEN 'COBi'

            WHEN 'EIS' THEN 'SpInv'
            WHEN 'EISR' THEN 'SpInv'
            WHEN 'VCT' THEN 'SpInv'
            WHEN 'VCTR' THEN 'SpInv'
            WHEN 'BPRL' THEN 'SpInv'
            WHEN 'BPRR' THEN 'SpInv'

            WHEN 'PENS' THEN 'COBp'
            WHEN 'PNRP' THEN 'COBp'
            WHEN 'PNSW' THEN 'COBp'
            WHEN 'METG' THEN 'COBp'
            WHEN 'SIPP' THEN 'COBp'

            WHEN 'ANNC' THEN 'RPB'
            WHEN 'ANNS' THEN 'RPB'
            WHEN 'DRAW' THEN 'RPB'
			WHEN 'DTOD' THEN 'RPB'

			WHEN 'OGS' THEN 'OGS'
			WHEN 'OAW' THEN 'OGS'
			WHEN 'OAS' THEN 'OGS'

            ELSE 'Other' end as LOB          
      ,bqco.BQC_Description as outcome
      ,CaseStatus.Code_Description as WorkFlowStatus
		,convert (varchar(10),buqu.BQ_CompletedDate,120) as compfdate
      ,buqu.BQ_CompletedDate
	  ,miuh.UserUID AS AssessorUID
      ,miuh.UserName AS Assessor
	,(case  prty.PROD_ShortName when 'KAP' then 1 else 0 end) as KAP
	,(case  prty.PROD_ShortName when 'KICO' then 1 else 0 end) as KICO
	,(case  prty.PROD_ShortName when 'KWOL' then 1 else 0 end) as KWOL
	,(case  prty.PROD_ShortName when 'MORT' then 1 else 0 end) as MORT
	,(case  prty.PROD_ShortName when 'BTL' then 1 else 0 end) as BTL
	,(case  prty.PROD_ShortName when 'ICOB' then 1 else 0 end) as ICOB
	,(case  prty.PROD_ShortName when 'GI' then 1 else 0 end) as GI
	,(case  prty.PROD_ShortName when 'WOL' then 1 else 0 end) as WOL
	,(case  prty.PROD_ShortName when 'WOLR' then 1 else 0 end) as WOLR
	,(case  prty.PROD_ShortName when 'ONIV' then 1 else 0 end) as ONIV
	,(case  prty.PROD_ShortName when 'OIRP' then 1 else 0 end) as OIRP
	,(case  prty.PROD_ShortName when 'OFIN' then 1 else 0 end) as OFIN
	,(case  prty.PROD_ShortName when 'OFIR' then 1 else 0 end) as OFIR
	,(case  prty.PROD_ShortName when 'IHT' then 1 else 0 end) as IHT
	,(case  prty.PROD_ShortName when 'CINV' then 1 else 0 end) as CINV
	,(case  prty.PROD_ShortName when 'STIN' then 1 else 0 end) as STIN
	,(case  prty.PROD_ShortName when 'TIP' then 1 when 'TIPR' then 1 else 0 end) as TIP
	,(case  prty.PROD_ShortName when 'EIS' then 1 when 'EISR' then 1 else 0 end) as EIS
	,(case  prty.PROD_ShortName when 'VCT' then 1 when 'VCTR' then 1 else 0 end) as VCT
	,(case  prty.PROD_ShortName when 'BPRL' then 1 when 'BPRR' then 1 else 0 end) as BPRL
	,(case  prty.PROD_ShortName when 'PENS' then 1 else 0 end) as PENS
	,(case  prty.PROD_ShortName when 'PNRP' then 1 else 0 end) as PNRP
	,(case  prty.PROD_ShortName when 'PNSW' then 1 else 0 end) as PNSW
	,(case  prty.PROD_ShortName when 'METG' then 1 else 0 end) as METG
	,(case  prty.PROD_ShortName when 'SIPP' then 1 else 0 end) as SIPP
	,(case  prty.PROD_ShortName when 'ANNC' then 1 else 0 end) as ANNC
	,(case  prty.PROD_ShortName when 'ANNS' then 1 else 0 end) as ANNS
	,(case  prty.PROD_ShortName when 'DRAW' then 1 else 0 end) as DRAW
	,(case  prty.PROD_ShortName when 'DTOD' then 1 else 0 end) as DTOD
	,(case  prty.PROD_ShortName when 'OGS' then 1 else 0 end) as OGS
	,(case  prty.PROD_ShortName when 'OAS' then 1 else 0 end) as OAS
	,(case  prty.PROD_ShortName when 'OAW' then 1 else 0 end) as OAW
	

	--,count(saca.CASE_CaseReference) AS Total

FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --updated 29/7/20 SH

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[mi_insight_UserHierarchy] miuh on miuh.UserGUID = buqu.BQ_CheckedBy
WHERE 
  
saca.CASE_SubmitDate >= '01-JAN-2013'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)  --updated 30/7/20
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --updated 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select min(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) ;                            

create index CTE_OUTCOME1 on #AQT_OUTCOMES (Advice,CaseOutcome,ProdShortName);


WITH CTE_OUTCOME
AS (select saca.CASE_CaseReference as Advice
      ,cofs.CFS_Description as CaseOutcome
      ,prty.PROD_ShortName  as ProdShortName    
      ,bqco.BQC_Description as FinalStatus
      ,CaseStatus.Code_Description as FinalWorkFlowStatus
      ,buqu.BQ_CompletedDate FinalCheckDate
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --updated 29/7/20 SH
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
WHERE 
saca.CASE_SubmitDate >= '01-JAN-2013'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)  --updated 30/7/20
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --updated 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10,14)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) )
UPDATE #AQT_OUTCOMES                             
 set    FinalStatus             = CTE_OUTCOME.FinalStatus,
        FinalWorkFlowStatus     = CTE_OUTCOME.FinalWorkFlowStatus,
        FinalCheckDate          = CTE_OUTCOME.FinalCheckDate
FROM   #AQT_OUTCOMES aqou1
JOIN   CTE_OUTCOME on CTE_OUTCOME.Advice        = aqou1.Advice
                           and CTE_OUTCOME.CaseOutcome   = aqou1.CaseOutCome
                           and CTE_OUTCOME.ProdShortName = aqou1.ProdShortName;

select Assessor,
sum(cast (ANNS as int))[ANNS],  
sum(cast (BPRL as int))[BPRL], 
sum(cast (BTL as int))[BTL],
sum(cast (CINV as int))[CINV],
sum(cast (DRAW as int))[DRAW],
sum(cast (DTOD as int))[DTOD],
sum(cast (EIS as int))[EIS],
sum(cast (ICOB as int))[ICOB],
sum(cast (GI as int))[GI],
sum(cast (KICO as int))[KICO],
sum(cast (KWOL as int))[KWOL],
sum(cast (MORT as int))[MORT],
sum(cast (OFIN as int))[OFIN],
sum(cast (OFIR as int))[OFIR],
sum(cast (OGS as int))[OGS],
sum(cast (OAS as int))[OAS],
sum(cast (OAW as int))[OAW],
sum(cast (OIRP as int))[OIRP],
sum(cast (ONIV as int))[ONIV],
sum(cast (IHT as int))[IHT],
sum(cast (TIP as int))[TIP],
sum(cast (PENS as int))[PENS],
sum(cast (PNRP as int))[PNRP],
sum(cast (PNSW as int))[PNSW],
sum(cast (VCT as int))[VCT],
sum(cast (WOL as int))[WOL],
sum(cast (WOLR as int))[WOLR],
count(Advice) as TOTAL
from #AQT_OUTCOMES
WHERE compfdate between @startdate and @enddate
group by Assessor


--END




/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



