/**********************************************************************************************
Name	: [BI].[pr_091_MortgageNoInForce] 
Author	: A Yavuz
Date	: 24/08/2021

Proc for Logi Report to identify any new transactions where the Mortgage has no in force date.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_091_MortgageNoInForce] 

@DateFrom	Date 

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'Mortgage No In force'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select CreateDateTime as 'Date'
  , pt.AgentCode as 'AgentCode'
  , commcompanycode as 'Provider'
  , p.cont_num as 'Policy'
  , policyref as 'CaseId'
  , firstnames as 'FirstName'
  , name as 'Surname'
  , StartDate
  , FinishDate
  , Amount
from dbo.msit_policytransactions pt 
  inner join dbo.msit_s_polmai p on pt.policyid = p.pol_num
  inner join dbo.msit_s_client c on c.client_num = p.client_num
where   p.plan_code = 'MRTG'  
and   pt.transtype = 39
and   policyid not in
    (select policyid
    from dbo.msit_policytransactions pt 
    where  pt.transtype in (17,23))
and   dateadd(dd,0,datediff(dd,0,pt.CreateDateTime)) >= @DateFrom --updated to use a parameter for backdated viewing
order by cont_num

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



