SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/**********************************************************************************************
Name	: [BI].[pr_092_BSC] 
Author	: A Yavuz
Date	: 28/09/2021

		Insert report description here.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_092_BSC]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

--declare @ReportStartDate	datetime
--declare @ReportEndDate		datetime

--set @ReportStartDate = dbo.owf_CalcDateNWorkingDaysEarlierthanDate(getdate(),1);
--set @ReportEndDate = dateadd(dd,0,datediff(dd,0,getdate()));

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'Bsc Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

declare @ReportStartDate	datetime
declare @ReportEndDate		datetime

set @ReportStartDate = dbo.owf_CalcDateNWorkingDaysEarlierthanDate(getdate(),1);
set @ReportEndDate = dateadd(dd,0,datediff(dd,0,getdate()));

IF OBJECT_ID('tempdb..#BSCTABLE') IS NOT NULL
DROP TABLE #BSCTABLE;

CREATE TABLE #BSCTABLE 
      (BscSubmissionID   INT,
       PolicyID          INT,
       PolicyNumber      VARCHAR(100),
       DateSubmitted     DATETIME,
       ProviderName      VARCHAR(100),
       ProviderCodeSwift VARCHAR(100),
       OnGoingServiceFee DECIMAL(5,2),
       AdviserUID        VARCHAR(7),
       PersonID          INT,
       PolicyOwnerType   INT); 

IF OBJECT_ID('tempdb..#BSCTABLE_REPORT') IS NOT NULL
DROP TABLE #BSCTABLE_REPORT;       
CREATE TABLE #BSCTABLE_REPORT 
      (PolicyID          INT,
       PolicyNumber      VARCHAR(100),
       ApplicationDate   DATETIME,
       SubmissionDate    DATETIME,
       ProviderName      VARCHAR(100),
       ProviderCodeSwift VARCHAR(100),
       ClientName        VARCHAR(100),
       BusinessUID       VARCHAR(7),
       FirmName          VARCHAR(100),
       AdviserUID        VARCHAR(7),
       AdviserName       VARCHAR(100),
       AdviserPct        DECIMAL(7,2),
       OpenworkPct       DECIMAL(7,2),
       BscPct            DECIMAL(7,2),
       DateCreated       DATETIME);       
      

                            
with cte_non_submitted_policies as
(select bcsu.BscSubmissionID
        ,bcsu.ClientID as PersonID1
        ,sale2.AdviserUID
        ,sale1.SaleID SaleID1
        ,sale2.DateSubmitted as DateSubmittedNew -- Changed to use original submission date
       ,sale2.SaleID as SaleID2
       ,sale2.PersonID as PersonID2
       ,poli.PolicyID
       ,poli.InternalProductID
       ,poli.InternalProviderID
       ,prod.OnPlatform
       ,prov.DisplayName as ProviderName
       ,prov.ProviderCodeSwift
       ,case prod.OnPlatform when 0 then isnull(subm.OngoingServiceFee,0)
                                    else (999) end  as OngoingServiceFee
       ,poli.PolicyOwnerType                             
 FROM  [prod_zurich_openwork_datawarehouse].[BSC].[sa_ows_BscSubmission] bcsu
 JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Sale] sale1 on sale1.SaleID = bcsu.SaleID
 JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Sale] sale2 on sale2.PersonID = bcsu.ClientID
 JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Policies] poli on poli.SaleID = sale2.SaleID
 JOIN  [prod_zurich_openwork_datawarehouse].[StaticData].[sa_ows_Product] prod on prod.InternalProductID = poli.InternalProductID
 JOIN [prod_zurich_openwork_datawarehouse].[StaticData].[sa_ows_Provider] prov   on prov.InternalProviderID = poli.InternalProviderID
 LEFT JOIN  [prod_zurich_openwork_datawarehouse].[Submission].[sa_ows_SubmittedProductCurrentOngoingServiceFee_SubmissionSnapshot] subm on subm.SaleID = sale1.SaleID
                                                                                                                                 and subm.InternalProductID = poli.InternalProductID 
 WHERE sale1.DateSubmitted between @ReportStartDate and @ReportEndDate
 and   prod.FeeApplies = 1
 AND   exists (select 1 
                from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] polm
                where  polm.PolicyRef = poli.PolicyID )
 and   Poli.PolicyID not in (select subm1.PolicyID
                            from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_BscSubmission] bcsu1
                            JOIN   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Sale] sale3 on sale3.SaleID = bcsu1.SaleID
                            JOIN   [prod_zurich_openwork_datawarehouse].[Submission].[sa_ows_SubmittedProductCurrentOngoingServiceFee_SubmissionSnapshot] subm1 on subm1.SaleID = bcsu1.SaleID
                            where  sale3.DateSubmitted between @ReportStartDate and @ReportEndDate
                            and    PolicyID is not null)
 )
 insert into #BSCTABLE (BscSubmissionID,
              PolicyID,
              PolicyNumber,
              DateSubmitted,
              ProviderName,
              ProviderCodeSwift,
              OnGoingServiceFee,
              AdviserUID,
              PersonID
             ,PolicyOwnerType
              )
 select MAX(cnsp.BscSubmissionID) 
        ,cnsp.PolicyID 
        ,(select max(resp.AnswerText) RespPolNum
        from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_QuestionnaireResponses] resp 
        where  resp.QuestionID in (1600,1700,1717,1900)
        and    resp.AnswerText != ''
        and    resp.PolicyID = cnsp.PolicyID) as PolicyNumber
       ,MAX(cnsp.DateSubmittedNew) as DateSubmittedNew
       ,cnsp.ProviderName
       ,cnsp.ProviderCodeSwift
       ,case cnsp.OnPlatform when  0 then cnsp.OngoingServiceFee 
                             when  1 then (select top 1 (hsfod.firm - hsfod.discount) 
         from [prod_zurich_openwork_datawarehouse].[BSC].[sa_ows_BscSubmission] xx 
         join [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_SubmissionFeeOngoingDetails] hsfod on hsfod.SaleID = xx.SaleID
         where xx.BscSubmissionID = max(cnsp.BscSubmissionID)) 
                             end as OngoingServiceFee
       ,cnsp.AdviserUID
       ,cnsp.PersonID2
       ,cnsp.PolicyOwnerType
 from cte_non_submitted_policies cnsp
 where cnsp.OngoingServiceFee <> 0
 group by  cnsp.PolicyID
       ,cnsp.OnPlatform
       ,cnsp.ProviderName
       ,cnsp.ProviderCodeSwift
       ,cnsp.OngoingServiceFee
       ,cnsp.AdviserUID
       ,cnsp.PersonID2
       ,cnsp.PolicyOwnerType
       ;
       
-- Query to return BSC, Adviser & Openwork distribution 
INSERT INTO #BSCTABLE_REPORT 
      (PolicyID ,
       PolicyNumber ,
       ApplicationDate ,
       SubmissionDate,
       ProviderName,
       ProviderCodeSwift  ,
       ClientName ,
       BusinessUID ,
       FirmName  ,
       AdviserUID  ,
       AdviserName  ,
       AdviserPct  ,
       OpenworkPct  ,
       BscPct  ,
       DateCreated  )      
select bsct.PolicyID
      ,bsct.PolicyNumber
      ,poli.ApplicationDate
      ,bsct.DateSubmitted as SubmissionDate
      ,bsct.ProviderName
      ,bsct.ProviderCodeSwift
      ,  case bsct.PolicyOwnerType when 1 then pers.FirstName + ' ' + pers.LastName
                            when 2 then pers1.FirstName + ' ' + pers1.LastName
                            when 3 then pers.FirstName + ' ' + pers.LastName + ' & ' + pers1.FirstName + ' ' + pers1.LastName end as ClientName                        
      ,advi.BusinessUID -- for other details will need to join insight tables
      ,ISNULL(advi.BusinessTradingName,advi.BusinessCompanyName) FirmName
      ,bsct.AdviserUID
      ,advi.UserName as AdviserName
      ,CAST((100 - CAST((100 / ((bsct.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2))) * (au.upliftrate-20.0)/100 as DECIMAL (6,2)) as AdviserPct
      ,100 - CAST((100 / ((bsct.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2)) - CAST((100 - CAST((100 / ((bsct.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2))) * (au.upliftrate-20.0)/100 as DECIMAL (6,2)) AS OpenworkPct
      ,CAST((100 / ((bsct.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2)) as BscPct
      ,bsfi.DateCreated as DateCreated
from   #BSCTABLE bsct    
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Person] pers on bsct.PersonID = pers.PersonID 
JOIN [prod_zurich_openwork_datawarehouse].[BSC].[sa_ows_BscSubmissionFirm] bsfi on bsct.BscSubmissionID = bsfi.BscSubmissionID
JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_AgentUplifts] au on au.agentcode = bsfi.FirmUID
JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Policies] poli on poli.PolicyID = bsct.PolicyID
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[mi_insight_UserHierarchy] advi on advi.UserUID = bsct.AdviserUID
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Person] pers1       on pers1.PersonID = pers.PartnerPersonID
WHERE au.authorisedby is not null 
  AND au.status = 0
  AND bsct.OnGoingServiceFee <> 0
  AND au.productcode in ('OWGIA')
  AND au.DateInforce = (select max(au1.DateInforce)
                        from [dbo].[sa_swift_AgentUplifts] au1
                        WHERE au1.authorisedby is not null 
				        AND   au1.status = 0
                        AND   au1.productcode in ('OWGIA')
                         AND   au1.agentcode   = au.agentcode
                         AND   au1.DateInforce <= bsfi.PolicyApplicationDate
                         ) 
group by bsct.BscSubmissionID
      ,bsct.PolicyID
      ,bsct.PolicyNumber
      ,bsct.DateSubmitted
      ,bsct.ProviderName
      ,bsct.ProviderCodeSwift
      ,bsct.OnGoingServiceFee
      ,poli.ApplicationDate
      ,bsct.AdviserUID
      ,bsct.PersonID 
      ,bsct.PolicyOwnerType 
      ,pers.FirstName
      ,pers.LastName
      ,pers1.FirstName
      ,pers1.LastName
      ,advi.BusinessUID -- for other details will need to join insight tables
      ,advi.BusinessTradingName
      ,advi.BusinessCompanyName
      ,bsct.AdviserUID
      ,advi.UserName
      ,bsct.OngoingServiceFee
      ,au.upliftrate
      ,bsfi.DateCreated
 union 
 SELECT distinct subm.PolicyID  
     , (select max(resp.AnswerText) RespPolNum
        from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_QuestionnaireResponses] resp 
        where  resp.QuestionID in (1600,1700,1717,1900)
        and    resp.AnswerText != ''
        and    resp.PolicyID = pol.PolicyID) as PolicyNumber 
     ,  pol.ApplicationDate  as ApplicationDate
     ,  sale.DateSubmitted as SubmissionDate
     ,  prov.DisplayName as ProviderName
     ,  prov.ProviderCodeSwift
     ,  case pol.PolicyOwnerType when 1 then pers.FirstName + ' ' + pers.LastName
                            when 2 then pers1.FirstName + ' ' + pers1.LastName
                            when 3 then pers.FirstName + ' ' + pers.LastName + ' & ' + pers1.FirstName + ' ' + pers1.LastName end as ClientName                        
      ,advi.BusinessUID -- for other details will need to join insight tables
      ,ISNULL(advi.BusinessTradingName,advi.BusinessCompanyName) FirmName
      ,sale.AdviserUID
      ,advi.UserName as AdviserName
      ,CAST((100 - CAST((100 / ((subm.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2))) * (au.upliftrate-20.0)/100 as DECIMAL (6,2)) as AdviserPct
      ,100 - CAST((100 / ((subm.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2)) - CAST((100 - CAST((100 / ((subm.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2))) * (au.upliftrate-20.0)/100 as DECIMAL (6,2)) AS OpenworkPct
      ,CAST((100 / ((subm.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2)) as BscPct
      ,bsfi.DateCreated as DateCreated
FROM  [prod_zurich_openwork_datawarehouse].[BSC].[sa_ows_BscSubmission] bcsu
LEFT JOIN  [prod_zurich_openwork_datawarehouse].[BSC].[sa_ows_BscSubmissionFirm] bsfi on bcsu.BscSubmissionID = bsfi.BscSubmissionID
JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Sale] sale             on sale.SaleID         = bcsu.SaleId
JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_AgentUplifts] au      on au.agentcode         = bsfi.FirmUID
JOIN  [prod_zurich_openwork_datawarehouse].[Submission].[sa_ows_SubmittedProductCurrentOngoingServiceFee_SubmissionSnapshot] subm on subm.SaleID = sale.SaleID
JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Policies] pol           on pol.PolicyID         = subm.PolicyID
JOIN [prod_zurich_openwork_datawarehouse].[StaticData].[sa_ows_Provider] prov   on prov.InternalProviderID   = pol.InternalProviderID
JOIN [prod_zurich_openwork_datawarehouse].[StaticData].[sa_ows_Product] prod    on prod.InternalProductID    = pol.InternalProductID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Person] pers            on sale.PersonID            = pers.PersonID 
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[mi_insight_UserHierarchy] advi on advi.UserUID         = sale.AdviserUID
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Person] pers1       on pers1.PersonID           = pers.PartnerPersonID 
WHERE sale.DateSubmitted between @ReportStartDate and @ReportEndDate
  AND au.authorisedby is not null 
  AND au.status = 0
  AND au.productcode in ('OWGIA')
  AND au.DateInforce = (select max(au1.DateInforce)
                        from [dbo].[sa_swift_AgentUplifts] au1
                        WHERE au1.authorisedby is not null 
				        AND   au1.status = 0
                        AND   au1.productcode in ('OWGIA')
                         AND   au1.agentcode   = au.agentcode
                         AND   au1.DateInforce <= (select MAX(bsfi1.PolicyApplicationDate)
                                                   FROM   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_BscSubmissionFirm] bsfi1
                                                   WHERE  bcsu.BscSubmissionID = bsfi1.BscSubmissionID)
                         )
  AND (subm.OngoingServiceFee)   <> 0
  AND   prod.FeeApplies = 1
  AND   exists (select 1 
                from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] polm
                where  polm.PolicyRef = pol.PolicyID )
union /* Off Platform Products */
SELECT poli.PolicyID
      ,(select max(resp.AnswerText) RespPolNum
        from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_QuestionnaireResponses] resp 
        where  resp.QuestionID in (1600,1700,1717,1900)
        and    resp.AnswerText != ''
        and    resp.PolicyID = poli.PolicyID) as PolicyNumber
      ,poli.ApplicationDate  
      ,sale.DateSubmitted  
      ,prov.DisplayName
      ,prov.ProviderCodeSwift  
      ,case poli.PolicyOwnerType when 1 then pers.FirstName + ' ' + pers.LastName
                                 when 2 then pers1.FirstName + ' ' + pers1.LastName
                                 when 3 then pers.FirstName + ' ' + pers.LastName + ' & ' + pers1.FirstName + ' ' + pers1.LastName end as ClientName                        
      ,advi.BusinessUID -- for other details will need to join insight tables
      ,ISNULL(advi.BusinessTradingName,advi.BusinessCompanyName) FirmName
      ,sale.AdviserUID
      ,advi.UserName as AdviserName
      ,CAST((100 - CAST((100 / ((spcosfs.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2))) * (au.upliftrate-20.0)/100 as DECIMAL (6,2)) as AdviserPct
      ,100 - CAST((100 / ((spcosfs.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2)) - CAST((100 - CAST((100 / ((spcosfs.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2))) * (au.upliftrate-20.0)/100 as DECIMAL (6,2)) AS OpenworkPct
      ,CAST((100 / ((spcosfs.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2)) as BscPct
      ,spcosfs.CreatedDate as DateCreated
  FROM prod_zurich_openwork_datawarehouse.Submission.sa_ows_SubmittedProductCurrentOngoingServiceFee_SaveSnapshot spcosfs 
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Sale sale     on sale.PersonID          = spcosfs.PersonId
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Policies poli on poli.SaleID            = sale.SaleId
                                                                  and poli.InternalProductID = spcosfs.InternalProductID
                                                                  and poli.PolicyOwnerType   = spcosfs.OwnerId
  JOIN prod_zurich_openwork_datawarehouse.dbo.mi_insight_UserHierarchy advi on advi.UserUID = Sale.AdviserUID
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_swift_AgentUplifts au on au.agentcode      = advi.BusinessUID
  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_Provider prov   on prov.InternalProviderID = poli.InternalProviderID
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on spcosfs.PersonID = pers.PersonID 
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_ClientServiceLevel csle on csle.PersonID = pers.PersonID
  JOIN prod_zurich_openwork_datawarehouse.Proposition.sa_ows_ServiceLevel sele on sele.PropositionId = csle.ServiceLevelId
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_swift_S_POLMAI polm on polm.PolicyRef = poli.PolicyID 
  LEFT JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers1           on pers1.PersonID = pers.PartnerPersonID
  WHERE spcosfs.CreatedDate between @ReportStartDate and @ReportEndDate
  and   sele.BscApplies = 1
  and   sale.SaleStatusID = 2 -- Sumitted
  and   au.authorisedby is not null 
  AND   au.status = 0
  AND   spcosfs.OngoingServiceFee <> 0
  AND   au.productcode in ('OWGIA')
  AND   au.DateInforce = (select max(au1.DateInforce)
                          from [dbo].[sa_swift_AgentUplifts] au1
                          WHERE au1.authorisedby is not null 
				          AND   au1.status = 0
                          AND   au1.productcode in ('OWGIA')
                          AND   au1.agentcode   = au.agentcode
                          AND   au1.DateInforce <= spcosfs.CreatedDate
                         ) 
  AND   spcosfs.SubmittedProductCurrentOngoingServiceFeeSaveSnapshotID =
        (select max(spcosfs1.SubmittedProductCurrentOngoingServiceFeeSaveSnapshotID)
         from   prod_zurich_openwork_datawarehouse.Submission.sa_ows_SubmittedProductCurrentOngoingServiceFee_SaveSnapshot spcosfs1 
         where  spcosfs1.personid          = spcosfs.PersonID
         and    spcosfs1.InternalProductId = spcosfs.InternalProductId
         and    spcosfs1.Ownerid           = spcosfs.OwnerID)
union         
SELECT poli.PolicyID /* On Platform Products */
      ,(select max(resp.AnswerText) RespPolNum
        from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_QuestionnaireResponses] resp 
        where  resp.QuestionID in (1600,1700,1717,1900)
        and    resp.AnswerText != ''
        and    resp.PolicyID = poli.PolicyID) as PolicyNumber
      ,poli.ApplicationDate  
      ,sale.DateSubmitted  
      ,prov.DisplayName
      ,prov.ProviderCodeSwift  
      ,case poli.PolicyOwnerType when 1 then pers.FirstName + ' ' + pers.LastName
                                 when 2 then pers1.FirstName + ' ' + pers1.LastName
                                 when 3 then pers.FirstName + ' ' + pers.LastName + ' & ' + pers1.FirstName + ' ' + pers1.LastName end as ClientName                        
      ,advi.BusinessUID -- for other details will need to join insight tables
      ,ISNULL(advi.BusinessTradingName,advi.BusinessCompanyName) FirmName
      ,sale.AdviserUID
      ,advi.UserName as AdviserName
      ,CAST((100 - CAST((100 / ((spcosfs.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2))) * (au.upliftrate-20.0)/100 as DECIMAL (6,2)) as AdviserPct
      ,100 - CAST((100 / ((spcosfs.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2)) - CAST((100 - CAST((100 / ((spcosfs.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2))) * (au.upliftrate-20.0)/100 as DECIMAL (6,2)) AS OpenworkPct
      ,CAST((100 / ((spcosfs.OngoingServiceFee) / 0.12)) AS DECIMAL (6,2)) as BscPct
      ,spcosfs.CreatedDate as DateCreated
from   prod_zurich_openwork_datawarehouse.Submission.sa_ows_SubmittedProductCurrentOngoingServiceFee_SaveSnapshot spcosfs 
JOIN   prod_zurich_openwork_datawarehouse.dbo.sa_ows_Sale sale     on sale.PersonID                = spcosfs.PersonId
JOIN   prod_zurich_openwork_datawarehouse.dbo.sa_ows_Policies poli on poli.SaleID                  = sale.SaleId
                                                           --      and poli.PolicyOwnerType         = spcosfs.OwnerId
JOIN   prod_zurich_openwork_datawarehouse.StaticData.sa_ows_Product prod on prod.InternalProductID = poli.InternalProductID
JOIN prod_zurich_openwork_datawarehouse.dbo.mi_insight_UserHierarchy advi on advi.UserUID = Sale.AdviserUID
JOIN prod_zurich_openwork_datawarehouse.dbo.sa_swift_AgentUplifts au on au.agentcode      = advi.BusinessUID
JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_Provider prov   on prov.InternalProviderID = poli.InternalProviderID
JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on spcosfs.PersonID = pers.PersonID
JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_ClientServiceLevel csle on csle.PersonID = pers.PersonID
JOIN prod_zurich_openwork_datawarehouse.Proposition.sa_ows_ServiceLevel sele on sele.PropositionId = csle.ServiceLevelId
JOIN prod_zurich_openwork_datawarehouse.dbo.sa_swift_S_POLMAI polm on polm.PolicyRef = poli.PolicyID 
LEFT JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers1           on pers1.PersonID = pers.PartnerPersonID
WHERE spcosfs.CreatedDate between @ReportStartDate and @ReportEndDate
and   sele.BscApplies   = 1
and   sale.SaleStatusID = 2 -- Sumitted
and   au.authorisedby is not null 
AND   au.status = 0
AND   au.productcode in ('OWGIA')
AND   au.DateInforce = (select max(au1.DateInforce)
                        from [dbo].[sa_swift_AgentUplifts] au1
                        WHERE au1.authorisedby is not null 
				        AND   au1.status = 0
                        AND   au1.productcode in ('OWGIA')
                        AND   au1.agentcode   = au.agentcode
                        AND   au1.DateInforce <= spcosfs.CreatedDate
                       ) 
and    spcosfs.internalProductId = -2 -- All OnPlatform produts
and    spcosfs.OngoingServiceFee <> 0
and    prod.OnPlatform        = 1
AND    spcosfs.SubmittedProductCurrentOngoingServiceFeeSaveSnapshotID =
      (select max(spcosfs1.SubmittedProductCurrentOngoingServiceFeeSaveSnapshotID)
       from   prod_zurich_openwork_datawarehouse.Submission.sa_ows_SubmittedProductCurrentOngoingServiceFee_SaveSnapshot spcosfs1 
       where  spcosfs1.personid          = spcosfs.PersonID
       and    spcosfs1.InternalProductId = spcosfs.InternalProductId
       --and    spcosfs1.Ownerid           = spcosfs.OwnerID
       );
       
select * 
from   #BSCTABLE_REPORT bsre
where  DateCreated = (select MAX(DateCreated)
                      from   #BSCTABLE_REPORT bsre1
                      where  bsre1.PolicyID = bsre.PolicyID)      
order by DateCreated,PolicyID;




/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



