/**********************************************************************************************
Name	: [BI].[pr_093_EDIStatementTotals] 
Author	: A Yavuz
Date	: 24/08/2021

		This report is used by PSD to check EDI statement totals. The report owner is 
		Debbie Beattie, PSD Manager.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_093_EDIStatementTotals]

	@DateLoadedDte datetime,
	@StatementID int,
	@View	varchar(10)

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@StartDate				datetime,
			@EndDate				datetime

set	@ReportName			= 'EDI Statement Totals'
set @StoredProcName		= object_name(@@procid)
set @StartDate			= @DateLoadedDte
set @EndDate			= DATEADD(mm,1,@StartDate)-1

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select	Statement,
		FileDate,
		FileName,
		DateLoaded,
		Provider,
		PolicyCount,
		PaymentCount,
		TotalPayment,
		UnmatchedSuspenseCount,
		UnmatchedSuspenseAmount,
		MatchedSuspenseCount,
		MatchedSuspenseAmount
from	dbo.owhot_EDIStatementTotals
where	(@View = 'Date Loaded' 
and		DATEADD(dd,0,datediff(dd,0,DateLoaded)) between @StartDate and @EndDate)
or		(@View = 'Statement ID'
and		Statement = @StatementID)
order by Statement desc

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

