/**********************************************************************************************
Name	: [BI].[pr_097_finstats55]
Author	: A Yavuz
Date	: 24/08/2021

		On the 1st of the month there is an automated run of the Finstat Reports, which support the Financial Reporting Team in their monthly reporting.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_097_finstats55]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/
		Select 	isnull(left(convert(varchar(20),IRD, 112),4),'') as IRDYear,
		isnull(left(convert(varchar(20),IRD, 110),2),'') as IRDMonth,
		Provider,
		sh.description as CommissionShape,
		Product,
		SUM(FinStatTot1inPeriod) as FinStatTot1inPeriod
		,case when isnull(agt.Manager2Code,'111') = '1011671' and Product like '%Owl' then 'Owl' 
		      when isnull(agt.Manager2Code,'111') = '1011671' then 'Owl Panel' 
			  when agt.firm = '2016789' or agt.manager4code = '4019902' then 'Owl AR' else 'Openwork' end as AdviserType
from	owhot_FinanceFutureExpectations fe
		left outer join mstt_ProductHierarchy ph on fe.product = ph.productcode 
		left outer join msit_CodeCommissionShape sh  on sh.id = fe.shapeid
		left join mstt_policytransactions pt on pt.id = tranid
		left join mstt_agents agt on agt.code = pt.agentcode
where	basis = 'IT'
and		isnull(fe.IRD,'') <> ''
Group by	isnull(left(convert(varchar(20),IRD,112),4),''), 
			isnull(left(convert(varchar(20),IRD, 110),2),''), 
			Provider, 
			sh.description, 
			Product,
				case when isnull(agt.Manager2Code,'111') = '1011671' and Product like '%Owl' then 'Owl' 
		      when isnull(agt.Manager2Code,'111') = '1011671' then 'Owl Panel' 
			  when agt.firm = '2016789' or agt.manager4code = '4019902' then 'Owl AR' else 'Openwork' end

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
