/**********************************************************************************************
Name	: [BI].[pr_097_finstats55]
Author	: A Yavuz
Date	: 24/08/2021

		On the 1st of the month there is an automated run of the Finstat Reports, which support the Financial Reporting Team in their monthly reporting.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_098_OWLDeferredPayments]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select 
hp.productcode,
year(DateOfAdviserPayment) as Year,
month(dateofadviserpayment) as Month,
sum(case when hp.PaymentAmount > 0 then hp.PaymentAmount else 0 end) as TotalPositive,
sum(case when hp.PaymentAmount < 0 then hp.PaymentAmount else 0 end) as TotalNegative,
sum(hp.PaymentAmount) as NetAmount
from dbo.owoa_OwlHierarchyPayments hp
--left join mi_insight_userhierarchyAllusers uh on uh.useruid = roleadviseruid and latestrowind = 1
where paymentstage = 'Deferred'
Group by 
year(DateOfAdviserPayment),
month(dateofadviserpayment),
hp.productcode
order by year, month, productcode


/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_099_OWLUpfrontPayments]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_099_OWLUpfrontPayments]
Author	: A Yavuz
Date	: 24/08/2021

		On the 1st of the month there is an automated run of the Finstat Reports, which support the Financial Reporting Team in their monthly reporting.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_099_OWLUpfrontPayments]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select 
hp.productcode,
year(PaymentCollectedDate) as Year,
month(PaymentCollectedDate) as Month,
sum(case when hp.PaymentAmount > 0 then hp.PaymentAmount else 0 end) as TotalPositive,
sum(case when hp.PaymentAmount < 0 then hp.PaymentAmount else 0 end) as TotalNegative,
sum(hp.PaymentAmount) as NetAmount
from dbo.owoa_OwlHierarchyPayments hp
--left join mi_insight_userhierarchyAllusers uh on uh.useruid = roleadviseruid and latestrowind = 1
where paymentstage = 'Upfront'
Group by 
year(PaymentCollectedDate),
month(PaymentCollectedDate),
hp.productcode
Having year(PaymentCollectedDate) is not null
order by year, month, productcode


/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

