/**********************************************************************************************
Name	: [BI].[pr_100_IfrsFutureRenewals]
Author	: A Yavuz
Date	: 04/10/2021

		Throughout the year the Financial Reporting team may ask for updates to the IFRS 15 reports.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
06/10/2025	J Homer		1) Add in Firm UID to resuts as requested by Bella Fedai in Finance
						2) Correct Branding identification to correctly pick up all Owl AR
						   Firms as previous code only identified Kalon as an Owl AR
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_100_IfrsFutureRenewals]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

BEGIN TRY

/***************************************************************************************
		DECLARE VARIABLES
***************************************************************************************/
declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@EndDate				date

--			--Change the @Reportname param here to the name of your report
--set	@ReportName			= 'IFRSFutureRenewals - Milecross'
--set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


Set @EndDate = DATEADD(MONTH, DATEDIFF(MONTH, -1, GETDATE())-1, -1) --Last Day of previous month

Select
policyid,
amount,
comminitialperiod,
pt.WrittenDate,
pt.CreatedDate,
pt.CreateDateTime,
pt.AgentCode
into #TransType
from mstt_policytransactions pt 
where pt.transtype not in (117,39) and isnull(pt.CreateDateTime,pt.CreatedDate) < @EndDate
and id = (Select min(id) from mstt_policytransactions pt2 where pt2.PolicyID = pt.policyid and pt2.TransType not in (117,39))

Select 
Comp_Code,
Year(writtendate) as Year,
Month(writtendate) as Month,
sum(amount) as Premium,
count(policyid) as PolicyCount,
case when comp_code like '%Owl' then 'Owl'
	 when agt.manager2code = '1011671' and COMP_CODE not like '%Owl' then 'Owl Panel'
	 when agt.firm = '2016789' then 'Owl AR'
	 else 'Openwork' end ID --tt.CreatedDate

-- pol.CONT_NUM, pol.PolicyRef, tt.Amount,pol.CreateDate, tt.CreatedDate--,tt.CommInitialPeriod
from mstt_policies pol
join mstt_producthierarchy ph on ph.ProductCode = pol.ProductCode and ph.RDRType is null and ph.ProductGroupName != 'Mortgage'
join #transtype tt on tt.PolicyID = pol.POL_NUM
left join mstt_Agents agt on agt.code = isnull(tt.AgentCode,isnull(pol.SellingAgentCode,pol.ServicingAgentCode))
where writtendate <= @EndDate and dateadd(month,tt.CommInitialPeriod,createdate) > @EndDate --and tt.CreatedDate < @EndDate
--and COMP_CODE = 'Zurich owl' and Year(writtendate) = 2019 and month(writtendate) = 1
--and PolicyRef = 551347826
and COMP_CODE is not null


group by
Comp_Code,
Year(writtendate),
Month(writtendate),
case when comp_code like '%Owl' then 'Owl'
	 when agt.manager2code = '1011671' and COMP_CODE not like '%Owl' then 'Owl Panel'
	 when agt.firm = '2016789' then 'Owl AR'
	 else 'Openwork' end--, tt.CreatedDate
Order by Comp_Code,
Year(writtendate),
Month(writtendate)

drop table #transtype


/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
