/**********************************************************************************************
Name	: [BI].[pr_101_IfrsR12Renewals]
Author	: A Yavuz
Date	: 04/10/2021

		Throughout the year the Financial Reporting team may ask for updates to the IFRS 15 reports.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/09/2022	J Homer		Code to assign Brand updated to seperate Owl AR from Openwork
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_101_IfrsR12Renewals]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@EndDate				date

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select
pp.COMP_CODE,
Tranproduct,
ProviderRef,
CONVERT(DATE,pol.START_DATE,103) START_DATE,
sum(amount) as NetRenewals,
--case when pp.manager2code != '1011671' then 'Openwork' when pp.comp_code like '%owl' then 'Owl' else 'Owl Panel' end as Brand,
case when pp.manager2code != '1011671' then 
			CASE WHEN ((agt.Manager4Code in('4019902') OR agt.FranchiseCode = '2016789' OR agt.CODE = '2016789') AND pp.comp_code NOT LIKE '%owl') THEN 'Owl AR'
			ELSE 'Openwork' 
			END
	 when pp.comp_code like '%owl' then 'Owl' 
	 else 'Owl Panel' 
end AS Brand
--,ISNULL(isnull(pp.franchiseagentcode, pp.accessagentcode), pp.AGENT_CODE) FirmUID
--case when reasonforleaving = 'MCV' then 'MCV' else agt.agenttypedescription end as FirmType --OAL
--into #2016Renewals
from mstt_Paymentspending pp
join mstt_policies pol on pol.POL_NUM = pp.PolicyID
join mstt_producthierarchy ph on ph.productcode = pp.tranproduct and ph.rdrtype is null
left join mstt_agents agt on agt.code = isnull(pp.franchiseagentcode, pp.accessagentcode)
where commissiontype in (4,18,15)--(19,16,10)
 and createdatetime >= dateadd(year,-1,getdate())
--and CreateDateTime between '2022-01-01' and '2022-12-31'
--and createdatetime between '01-July-2021' and '30-Jun-2022'
--and ((agt.ReasonForLeaving = 'MCV' and pp.createdatetime > agt.dateleaving) or pp.AccessAgentCode is not null) -- OAL
group by 
pp.COMP_CODE,
Tranproduct,
ProviderRef,
pol.START_DATE,
case when pp.manager2code != '1011671' then 
			CASE WHEN ((agt.Manager4Code in('4019902') OR agt.FranchiseCode = '2016789' OR agt.CODE = '2016789') AND pp.comp_code NOT LIKE '%owl') THEN 'Owl AR'
			ELSE 'Openwork' 
			END
	 when pp.comp_code like '%owl' then 'Owl' 
	 else 'Owl Panel' 
end
--,isnull(isnull(pp.franchiseagentcode, pp.accessagentcode), pp.AGENT_CODE)

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

