Author	: A Yavuz
Date	: 04/10/2021

		Throughout the year the Financial Reporting team may ask for updates to the IFRS 15 reports.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_102_IfrsR12Trail]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@EndDate				date

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select
pp.COMP_CODE,
Tranproduct,
ProviderRef,
pol.START_DATE,
sum(amount) as NetTrail,
case when pp.manager2code = '1011671' then 'Owl' else 'Openwork' end
from mstt_Paymentspending pp
join mstt_policies pol on pol.POL_NUM = pp.PolicyID
join mstt_producthierarchy ph on ph.productcode = pp.tranproduct and ph.rdrtype is null
left join mstt_agents agt on agt.code = isnull(pp.franchiseagentcode, pp.accessagentcode)
where commissiontype in (19,16,10)
and createdatetime >= dateadd(year,-1,getdate())
group by 
pp.COMP_CODE,
Tranproduct,
ProviderRef,
pol.START_DATE,
case when pp.manager2code = '1011671' then 'Owl' else 'Openwork' end

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

