SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_103_RenewalAndTrailBreakdown]
Author	: A Yavuz
Date	: 04/10/2021

		Throughout the year the Financial Reporting team may ask for updates to the IFRS 15 reports.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_103_RenewalAndTrailBreakdown]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@EndDate				date

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Declare @Year int
Set @Year = YEAR(GETDATE())

Select
count(distinct case when pol.comp_code like '%Owl' then  pol.POL_NUM end) as NumberOfOwlPolicies,
count(distinct case when pol.comp_code not like '%Owl' and agt.manager2code = '1011671' and ph.ProductCategoryCode = 4 then  pol.POL_NUM end) as NumberOfOwlPanelPolicies,
count(distinct case when pol.comp_code not like '%Owl' and isnull(manager2code,'111') != '1011671' and ph.ProductCategoryCode = 4 then  pol.POL_NUM end) as NumberOfProtectionPolicies,
count(distinct case when ph.ProductCategoryCode = 1  then  pol.POL_NUM end) as NumberOfPreRDRWealthPolicies,
year(isnull(createdate,pol.PROP_DATE))  as PolicyYear
into #Policies
From mstt_policies pol
join mstt_producthierarchy ph on ph.productcode = pol.ProductCode
left join mstt_agents agt on agt.code = isnull(pol.sellingagentcode,pol.servicingagentcode)
where ph.RDRType is null and ph.ProductCategoryCode in (1,4)
--and year(isnull(createdate,pol.PROP_DATE))  < 2019
--and pol.CONT_NUM = '899506J'
Group by
year(isnull(createdate,pol.PROP_DATE)) 


Select year(createdatetime) as PaymentYear, 
year(isnull(createdate,pol.PROP_DATE)) as PolicyYear,
count(distinct case when pp.comp_code like '%Owl' then  pol.POL_NUM end) as NumberOfCasesOwl,
count(distinct case when pp.comp_code not like '%Owl' and pp.manager2code = '1011671' and ph.ProductCategoryCode = 4 then  pol.POL_NUM end) as NumberOfCasesOwlPanel,
count(distinct case when pp.comp_code not like '%Owl' and isnull(pp.manager2code,'111') != '1011671' and ph.ProductCategoryCode = 4 then  pol.POL_NUM end) as NumberOfCasesOW,
count(distinct case when ph.ProductCategoryCode = 1 and pp.CommissionType in (18,15,4) then  pol.POL_NUM end) as NumberOfCasesWealthRenewal,
count(distinct case when ph.ProductCategoryCode = 1 and pp.CommissionType in (19,16,10) then  pol.POL_NUM end) as NumberOfCasesWealthTrail,
sum( case when pp.comp_code like '%Owl' then  amount end) as RenewalAmountOwl,
sum( case when pp.comp_code not like '%Owl' and pp.manager2code = '1011671' and ph.ProductCategoryCode = 4 then  Amount end) as RenewalAmountOwlPanel,
sum( case when pp.comp_code not like '%Owl' and isnull(pp.manager2code,'111') != '1011671' and ph.ProductCategoryCode = 4 then  Amount end) as RenewalAmountOW,
sum( case when ph.ProductCategoryCode = 1 and pp.CommissionType in (18,15,4) then  Amount end) as RenewalAmountWealth,
sum( case when ph.ProductCategoryCode = 1 and pp.CommissionType in (19,16,10) then  Amount end) as TrailAmount,
poli.NumberOfPreRDRWealthPolicies,
poli.NumberOfProtectionPolicies,
poli.NumberOfOwlPolicies,
poli.NumberOfOwlPanelPolicies
from mstt_paymentspending pp
join mstt_policies pol on pol.POL_NUM = pp.PolicyID
join mstt_producthierarchy ph on ph.productcode = pp.TranProduct
join #Policies poli on poli.PolicyYear = year(isnull(createdate,pol.prop_date))
where 
ph.RDRType is null and ph.ProductCategoryCode in (1,4)
--and pol.CONT_NUM = '899506J'
and pp.CommissionType in (18,15,4,19,16,10)
and year(createdatetime) >= @Year
--and year(createdatetime) < 2019
group by year(createdatetime), year(isnull(createdate,pol.PROP_DATE)) ,
poli.NumberOfPreRDRWealthPolicies,
poli.NumberOfProtectionPolicies,
poli.NumberOfOwlPolicies,
poli.NumberOfOwlPanelPolicies

Drop table #Policies

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_104_IncorrectCases]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_104_IncorrectCases]
Author	: A Yavuz
Date	: 23/08/2021

			This weekly written report is run on a weekly basis to find the top 10 written cases
			accross Protection, Mortgage and Wealth. More info on this report is found here:
			G:\Finance and MI\MI & Reporting (NEW STRUCTURE)\Openwork Reporting\Weekly Top Written Report
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_104_IncorrectCases]

with recompile

AS 

set nocount on;

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@Countrows				int

set	@ReportName			= 'Incorrect Cases'
set @StoredProcName		= object_name(@@procid)
set @Countrows			= 0;


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

WITH APE_CHECK AS (
SELECT
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
WHERE
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
GROUP BY
po.policyref, po.cont_num, co.productcode
),

All_Cases_CTE AS (

SELECT
wr.AdviserName,
wr.FirmName,
wr.Adviser,
wr.Firm,
wr.Transactionid as [Transaction ID],
CONVERT(DATE,wr.Writtendate,103) AS Writtendate, CONVERT(DATE,wr.issueddate,103) AS [Issued Date],
wr.APE,
wr.Distributionallowance as [Distribution Allowance],  
wr.Margin, 
wr.NBcases, 
wr.Allcases AS [All Cases], 
wr.Frequency, 
wr.CaseID as [Case ID], 
wr.Policy as [Policy], 
wr.Productsubgroupname as [Product Sub Group Name], 
case when wr.productsubgroupname like '%Annuity' then 'Wealth' when ((left(wr.productcode,2) in ('OW','OZ') AND wr.productcode NOT IN ('OWADHOC','OWADVICE')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'Wealth' when wr.productgroupname in ('Pensions','Investment') then 'Wealth' else wr.productgroupname end as [Product Group Name],
wr.Provider,
wr.[Client Surname],
wr.[Mortgage Size]
---select top 100 * from mstt_Commissions
FROM
(SELECT  
ah.AgentDesc as AdviserName,
ah.FirmDescn as FirmName,
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate, min(pt.issueddate) as issueddate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
min((pt.mortgageamount) * (co.Agent_Perc/100)) as MortgageAmount,
round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) as distributionallowance, 
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2) as NBI, 
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) as Margin, 
max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases", 
max((co.agent_perc/100)) as "AllCases", min(pt.FrequencyDescription) as frequency, min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD,
cl.NAME [Client Surname],
CASE WHEN ph.productgroupname = 'Mortgage' THEN sum(pt.MortgageAmount) else null END as [Mortgage Size]

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  APE_CHECK c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.AGENT_CODE = ah.agentcode

WHERE 
co.agent_code not in ('10002','1011542','10004','1011623')
and cast(co.APE as int) > 999999
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)


GROUP BY
cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), ah.FirmDescn, ah.AgentDesc,cl.NAME, ph.ProductGroupName) wr

WHERE
wr.writtendate >= DATEADD(day,-7, GETDATE())
and (wr.caseid not in ('500020430','500020431') or wr.caseid is null)
and wr.ProductGroupName is not null
)

Select @Countrows / count([Case ID]) as [check] --If there are no rows returned, the report wont run due to divide by 0 error.
,* From All_Cases_CTE
group by
AdviserName,
FirmName,
Adviser,
Firm,
[Transaction ID],
[Issued Date],
APE,
[Distribution Allowance],
Margin,
NBCases,
[All Cases],
frequency,
[Case ID],
Policy,
[Product Sub Group Name],
[Product Group Name],
provider,
[Client Surname],
[Mortgage Size],
[writtendate]

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH


