/**********************************************************************************************
Name	: [BI].[pr_106_DeclinedEvents]
Author	: A Yavuz
Date	: 07/10/2021

		This report is used for Project Ringo. The recipients are the T&C Team.
			
AMENDMENT HISTORY
=================
Date		Author		Description
22/01/2024	Edd B		Changed Source table from [Events.sa_ows_Event] to [mi_concert_ows_Event] to include concert events.

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_106_DeclinedEvents]

        @AQMUID		        varchar(255) = 'View All',
        @FirmUID			varchar(255) = 'View All',
        @Year1				varchar(255) = 'View All',
        @Year2				varchar(255) = 'View All',
        @Year3				varchar(255) = 'View All',
        @Year4				varchar(255) = 'View All'

with recompile

AS 

set nocount on;

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@Countrows				int
			DECLARE			  @return_value					 int;
			DECLARE			  @lc_UserUid					 varchar(7);
			DECLARE			  @lc_UserName					 varchar(50);
			DECLARE			  @lc_UserJobTitleCodeHO		 int;
			DECLARE			  @lc_UserJobTitleCodePartner	 int;
			DECLARE			  @lc_UserJobTitleCodeSupervisor int;
			DECLARE			  @lc_UserJobTitleCodeBQM		 int;
			Declare			  @LC_SupervisorPermission		 int;

set	@ReportName			= 'Declined Events'
set @StoredProcName		= object_name(@@procid)

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

SELECT
even.PersonID
,even.DateDue
,year(even.DateDue) as EventDueYear
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
into #AdhocReviews
from mi_concert_ows_Event even -- Changed from Events.sa_ows_Event -- Edd B 01/2024
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8

select
even.PersonID
,even.DateDue
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
into #DeclinedEvents
from mi_concert_ows_Event even -- Changed from Events.sa_ows_Event -- Edd B 01/2024
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and TypeID = 2
and adh.PersonID is null

select
even.PersonID
,min(isnull(even.OneOffChangeToDateDue,even.DateDue)) as NextDueDate
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
into #ClientsDue
from mi_concert_ows_Event even -- Changed from Events.sa_ows_Event -- Edd B 01/2024
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where DateCompleted is null
and TypeID = 2 and isnull(IsComplete,0) = 0 and isnull(isdeleted,0) = 0 and isnull(iscancelled,0) = 0 --Updated 10.5.19 SI
Group by even.PersonID
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN
,pers.BusinessUid
,agt1.DESCN

Select
PersonID,
max(datedue) as LastDecline,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 14.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 14.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 14.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 14.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
into #ClientDeclines
From #DeclinedEvents de
join mi_insight_UserHierarchy uh on uh.UserUID = de.AdviserUID
where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID not in ('4021409','4005013')
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName

Select
cdec.PersonID,
cdec.BusinessUid
,cdec.FirmName
,cdec.AdviserUID
,cdec.AdviserName
,cdec.FirstName
,cdec.LastName,
AQMName,
BQMName
,cd.NextDueDate
,cdec.LastDecline
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end as 'ClientDeclinedCurrentYear'
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end as 'ClientDeclinedLastYear'
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end as 'ClientDeclined2YearsAgo'
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end as 'ClientDeclined3YearsAgo'
from #ClientDeclines cdec
join #ClientsDue cd on cd.PersonID = cdec.PersonID
where (cdec.BusinessUid = @FirmUID or @FirmUID = 'View All')
and	  (case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end = @Year1 or @Year1 = 'View All')
and	  (case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end = @Year2 or @Year2 = 'View All')
and	  (case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end = @Year3 or @Year3 = 'View All')
and	  (case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end = @Year4 or @Year4 = 'View All')

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH


