/**********************************************************************************************
Name	: [BI].[pr_108_FirmUpliftRate]
Author	: L Brigginshaw
Date	: 15/10/2021

		A report showing the uplift Rtes for all Openwork firms.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_108_FirmUpliftRate]

@FIRM	varchar (250) = 'View All'

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'Firm Uplift Rates'
set @StoredProcName		= object_name(@@procid)

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select 
AgentCode, Descn, case when ProductCode = 'LPP' then 'Term DMCP, LPP' 
					   when productcode = 'ZALP' then 'ZALP'
					   when ProductCode = 'IPP' then 'IPP'
					   when productcode = 'NWIDE' then 'Mortgages'
					   when productcode = 'UKPLC' then 'GI'
					   when ProductCode = 'OZISA' then 'COB' 
					   when ProductCode = 'ATP' then 'ATP' 
					   when ProductCode = 'A&P' then 'A&P' end as ProductCat, UpliftRate
from sa_swift_AgentUplifts au
join mstt_agents on code = AgentCode and CompetentStatusDescription = 'Active' and isnull(manager2code,'111') != '1011671'
where au.DateInForce = (Select max(au2.DateInForce)
						from sa_swift_AgentUplifts au2
						where au.AgentCode = au2.AgentCode
						and au2.ProductCode = au.productcode)
and ProductCode in ('LPP','ZALP','IPP','NWIDE','UKPLC','OZISA','ATP','A&P')
and (Descn = @FIRM or @FIRM = 'View All')

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

