/**********************************************************************************************
Name	: [BI].[pr_108_ServiceEvents]
Author	: A Yavuz
Date	: 07/10/2021

		This report is used for Project Ringo. The recipients are the T&C Team.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_108_ServiceEvents]

                @BusinessUID varchar(200),
                @AdviserUID  varchar(200) = null

with recompile

AS 

set nocount on;

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

DECLARE
				@ReportName					varchar(200),
				@StoredProcName				varchar(200),
				@StoredProcParams			varchar(4000),
				@ErrMsg						nvarchar(4000),
				@LastAuditID				int,
				@ErrNum						int,
				@ErrSev						int,
				@ErrLine					int,
				@Countrows					int
DECLARE			@return_value					 int;
DECLARE			@lc_UserUid						 varchar(7);
DECLARE			@lc_UserName					 varchar(50);
DECLARE			@lc_UserJobTitleCodeHO			 int;
DECLARE			@lc_UserJobTitleCodePartner	     int;
DECLARE			@lc_UserJobTitleCodeSupervisor	 int;
DECLARE			@lc_UserJobTitleCodeBQM			 int;
Declare			@LC_SupervisorPermission		 int;

set	@ReportName			= 'Service Events'
set @StoredProcName		= object_name(@@procid)
set @StoredProcParams	= '@BusinessUID = ' + isnull(@BusinessUID,'(None)') + ', @AdviserUID = ' + isnull(@AdviserUID,'(None)')

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

	SELECT 
		   miuh.FirmName as Firm
		  ,even.EventID
		  , miuh.AdviserUID as AdviserUID
		  , miuh.Adviser    as AdviserName
		  , Pers.FirstName + ' ' + Pers.LastName as ClientName
		  , evty.Name as EventType
		  , even.DateDue
		  , even.OneOffChangeToDateDue
		  , even.DateCompleted
		 , erst.EventReminderStatusText
		 , sele.Name as ServiceLevelName
		 , csle.ServiceLevelSigningDate
		 , repfrq.ValueName As ReportFrequency
		 , revfrq.ValueName As ReviewFrequency
	  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
	  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
	  JOIN prod_zurich_openwork_datawarehouse.dbo.mi_aqt_ReportingHierarchy miuh on miuh.AdviserUID = pers.AdviserUID
	  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_EventType evty on evty.EventTypeID = even.TypeID
	  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_EventReminderStatus erst on erst.EventReminderStatusID = even.EventReminderStatusID
	  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_ClientServiceLevel  csle on csle.PersonID = pers.PersonID
	  JOIN prod_zurich_openwork_datawarehouse.Proposition.sa_ows_ServiceLevel sele on sele.ServiceLevelID = csle.ServiceLevelId
	  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_InputValues repfrq on repfrq.InputID = sele.ReportFrequencyId
--	  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_InputValues revfrq on revfrq.InputID = sele.ReportFrequencyId	  
	  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_InputValues revfrq on revfrq.InputID = sele.ReviewFrequencyId	-- AG 13/08/2015
	  where even.TypeID in (1,2)
	  and   isnull(even.IsCancelled,0) = 0 --updated 17.2.20 SI
	  and   isnull(even.IsDeleted,0) = 0 --updated 17.2.20 SI
	  and   erst.EventReminderStatusID in (1,2,3)--,4)
	  and   miuh.BusinessUID = @BusinessUID
	  and   miuh.AdviserUID  = ISNULL(@AdviserUID,miuh.AdviserUID)
	  order by Firm;


/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

