with recompile

AS 

set nocount on;

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

DECLARE
				@ReportName					varchar(200),
				@StoredProcName				varchar(200),
				@StoredProcParams			varchar(4000),
				@ErrMsg						nvarchar(4000),
				@LastAuditID				int,
				@ErrNum						int,
				@ErrSev						int,
				@ErrLine					int,
				@Countrows					int
DECLARE			@return_value					 int;
DECLARE			@lc_UserUid						 varchar(7);
DECLARE			@lc_UserName					 varchar(50);
DECLARE			@lc_UserJobTitleCodeHO			 int;
DECLARE			@lc_UserJobTitleCodePartner	     int;
DECLARE			@lc_UserJobTitleCodeSupervisor	 int;
DECLARE			@lc_UserJobTitleCodeBQM			 int;
DECLARE			@LC_SupervisorPermission		 int;
set	@ReportName			= 'Adviser Panel'
set @StoredProcName		= object_name(@@procid)

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

	SELECT Distinct UH.UserUID
		, UH.UserName as Adviser
		, Code.[Code_Description] as Panel
		, UH.SupervisorUID
		, UH.SupervisorName as Sup
		, UH.BQMUID
		, UH.BQMName as QRM
		, UH.BQMUID2
		, UH.BQMName2
		, UH.AQMUID
		, UH.AQMName as SQRM
		, UH.BusinessUID
		, case   when UH.BusinessTradingName is NULL then UH.BusinessCompanyName 
										else UH.BusinessTradingName end as [Firm]

FROM  dbo.mi_insight_UserHierarchy  UH
 left join [dbo].[sa_insight_UserPosition]  UP on UP.UPS_UserID = UH.UserGUID
 left join [dbo].[sa_insight_CodeDescription] Code on Code.[Code_Code] = up.[UPS_Section] 
													and [Code_CodeType] = 53

 where UPS_JobTitle in (4,42) --advisers & Schedule e-sellers
and UPS_ContractStatus in (1) --under contract
and UPS_EmploymentStatus in (1,8) --Open or Re-Appointed
and UH.UserUID  not in ('4003930','4003931','4003932','4003921','4003924','4006614')
and UH.UserName not like ('%test %')
and UH.UserName not like ('%testuser%')
and UH.UserName not like ('% Test%')

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
