GO
/**********************************************************************************************
Name	: [BI].[pr_113_QualityResultsByAssessor]
Author	: Akin Yavuz
Date	: 20/10/2021
 			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_113_QualityResultsByAssessor]

@Startdate Date,
@Enddate Date,
@Product Varchar(100) = 'View All'

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Quality Results By Assessor'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

IF OBJECT_ID('tempdb..#AQT_OUTCOMES') IS NOT NULL
DROP TABLE #AQT_OUTCOMES;

CREATE TABLE #AQT_OUTCOMES 
      (
            Advice                    VARCHAR(100),
            CaseOutcome               VARCHAR(100),
            ProdShortName             VARCHAR(100),
			LOB						 VARCHAR(100),
            InitialStatus             VARCHAR(100),
           FinalStatus               VARCHAR(100),
           InitialWorkFlowStatus     VARCHAR(100),
            FinalWorkFlowStatus       VARCHAR(100),
			compfdate             VARCHAR(100),
            InitialCheckDate          DATETIME,
            FinalCheckDate            DATETIME,
		AssessorUID           VARCHAR(100),
		Assessor              VARCHAR(100),
		Num					  VARCHAR(100),
		Pass				  INT,
		Queried				  VARCHAR(100),
		PotUnsuit			  INT,
		Reject				  INT
      );
	  

insert into #AQT_OUTCOMES (Advice,CaseOutcome,ProdShortName,LOB,InitialStatus,InitialWorkFlowStatus,compfdate,InitialCheckDate
									,AssessorUID,Assessor,Num,Pass,Queried,PotUnsuit)
select saca.CASE_CaseReference
      ,cofs.CFS_Description
      ,prty.PROD_ShortName as ProdShortName
,CASE prty.PROD_ShortName 
            WHEN 'MORT' THEN 'MCOB'

            WHEN 'ICOB' THEN 'ICOB'
            WHEN 'WOL' THEN 'ICOB'
            WHEN 'WOLR' THEN 'ICOB'

            WHEN 'ONIV' THEN 'COBi'
            WHEN 'OIRP' THEN 'COBi'
            WHEN 'OFIN' THEN 'COBi'
            WHEN 'OFIR' THEN 'COBi'
            WHEN 'CINV' THEN 'COBi'
            WHEN 'IHT' THEN 'COBi'
            WHEN 'TIP' THEN 'COBi'
            WHEN 'TIPR' THEN 'COBi'

            WHEN 'EIS' THEN 'SpInv'
            WHEN 'EISR' THEN 'SpInv'
            WHEN 'VCT' THEN 'SpInv'
            WHEN 'VCTR' THEN 'SpInv'
            WHEN 'BPRL' THEN 'SpInv'
            WHEN 'BPRR' THEN 'SpInv'

            WHEN 'PENS' THEN 'COBp'
            WHEN 'PNRP' THEN 'COBp'
            WHEN 'PNSW' THEN 'COBp'
            WHEN 'METG' THEN 'COBp'
            WHEN 'SIPP' THEN 'COBp'

            WHEN 'ANNC' THEN 'RPB'
            WHEN 'ANNS' THEN 'RPB'
            WHEN 'DRAW' THEN 'RPB'
			WHEN 'DTOD' THEN 'RPB'

            ELSE 'Other' end as LOB      
      ,bqco.BQC_Description as outcome
      ,CaseStatus.Code_Description as WorkFlowStatus
		--,convert (varchar(10),buqu.BQ_CompletedDate,120) as compfdate
		,cast(buqu.BQ_CompletedDate as date) as compfdate
      ,buqu.BQ_CompletedDate
	  ,miuh.UserUID AS AssessorUID
      ,miuh.UserName AS Assessor
,1 as Num
,(case  bqco.BQC_Description when 'A1 Suitable and Complete' then			1
								when 'A2 Suitable and Acceptable' then		1
								when 'First time pass' then					1
								when 'First time pass with feedback' then	1
                                      else									0
									  end) as Pass 
,(case  bqco.BQC_Description when 'A3 Suitable but Defective' then			1
								when 'B Clarify' then						1
								when 'C Potentially Unsuitable' then		1
								when 'Unclear action required' then			1
								when 'Unsuitable advice' then				1
                                      else									0
									  end) as Queried 
,(case  bqco.BQC_Description when 'C Potentially Unsuitable' then 1
                                      else 0 end) as PotUnsuit 


FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --update 29/7/20 SH

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[mi_insight_UserHierarchy] miuh on miuh.UserGUID = buqu.BQ_CheckedBy
WHERE 
  
saca.CASE_SubmitDate >= '01-JAN-2013'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --update 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select min(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) ;                            

create index CTE_OUTCOME1 on #AQT_OUTCOMES (Advice,CaseOutcome,ProdShortName);


WITH CTE_OUTCOME
AS (select saca.CASE_CaseReference as Advice
      ,cofs.CFS_Description as CaseOutcome
      ,prty.PROD_ShortName  as ProdShortName    
      ,bqco.BQC_Description as FinalStatus
      ,CaseStatus.Code_Description as FinalWorkFlowStatus
      ,buqu.BQ_CompletedDate FinalCheckDate
	  ,CASE WHEN CaseStatus.Code_Description in ('Reject','Unsuitable advice') THEN 
								(case  bqco.BQC_Description when 'A3 Suitable but Defective' then 1
															when 'B Clarify' then 1
															when 'C Potentially Unsuitable' then 1
															when 'Unclear action required' then 1
															when 'Unsuitable advice' then 1
										          else 0 end)
                                     ELSE 0 END as Reject
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --update 29/7/20 SH
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
WHERE 
saca.CASE_SubmitDate >= '01-JAN-2013'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --update 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10,14)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) )
UPDATE #AQT_OUTCOMES                             
 set    
		FinalStatus             = CTE_OUTCOME.FinalStatus,
        FinalWorkFlowStatus     = CTE_OUTCOME.FinalWorkFlowStatus,
        FinalCheckDate          = CTE_OUTCOME.FinalCheckDate,
		Reject					= CTE_OUTCOME.Reject

FROM   #AQT_OUTCOMES aqou1
JOIN   CTE_OUTCOME on CTE_OUTCOME.Advice        = aqou1.Advice
                           and CTE_OUTCOME.CaseOutcome   = aqou1.CaseOutCome
                           and CTE_OUTCOME.ProdShortName = aqou1.ProdShortName;

select  
Assessor
,COUNT(Num) as Checked
,Sum(Pass) * 100 / count(Num) as [Pass Rate]
,sum(PotUnsuit) as [Potentially Unsuitable]
,sum(reject) as [Unsuitable Advice]
from #AQT_OUTCOMES
where compfdate between @startdate and @enddate
and (LOB = @product or @Product = 'View All')
group by Assessor


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
