/**********************************************************************************************
Name	: [BI].[pr_114_ChecklistQueries]
Author	: Akin Yavuz
Date	: 20/10/2021
 			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_114_ChecklistQueries]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'Checklist Queries'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

IF OBJECT_ID('tempdb..#AQT_OUTCOMES') IS NOT NULL
DROP TABLE #AQT_OUTCOMES;

CREATE TABLE #AQT_OUTCOMES 
      (
            Advice                                    VARCHAR(20),
            Product                                   VARCHAR(20),
            [Initial Workflow]                  VARCHAR(50),
            [Final Workflow]              VARCHAR(50),
            Submitted                           DATETIME,            
            [Initial Check]                     DATETIME,
            [Final Check]                       DATETIME,
			Adviser					VARCHAR(50),
			Assessor              VARCHAR(50),
            FailsPct                            float,
                  InitialCheckComplete          int,
                  InitialCheckAcceptable        int,
                  InitialCheckDefective         int,
                  InitialCheckSuitable          int,
                  InitialCheckClarify                 int,
                  InitialCheckPU                      int,
                  InitialCheckYes                      int,
                  InitialCheckNo                      int,
                  InitialCheckNA                      int,
                  InitialCheckPleaseSelect      int
       );



insert into #AQT_OUTCOMES 
(     Advice,
      Product,
      [Initial Workflow],
      Submitted,
      [Initial Check],
	  Adviser,
	  Assessor,
      FailsPct,
      InitialCheckComplete,
      InitialCheckAcceptable,
      InitialCheckDefective,
      InitialCheckSuitable,
      InitialCheckClarify,
      InitialCheckPU,
	  InitialCheckYes,
	  InitialCheckNo,
      InitialCheckNA,
      InitialCheckPleaseSelect
)
Select      Advice,
            Product,
            [Initial Workflow],
            Submitted,
            [Initial Check],
			Adviser,
			Assessor,
            case when Passes + Fails = 0 
                        then 0
                        else round((Fails / (Passes + Fails)),2) 
                  end as FailsPct,
            InitialCheckComplete,
            InitialCheckAcceptable,
            InitialCheckDefective,
            InitialCheckSuitable,
            InitialCheckClarify,
            InitialCheckPU,
			InitialCheckYes,
			InitialCheckNo,
            InitialCheckNA,
            InitialCheckPleaseSelect
from
(
select      saca.CASE_CaseReference as Advice,
            prty.PROD_ShortName as Product,
            CaseStatus.Code_Description as [Initial Workflow],
            saca.CASE_SubmitDate as Submitted,
            buqu.BQ_CompletedDate as [Initial Check],
			userd.USR_Name AS Adviser,
			miuh.UserName AS Assessor,
            sum(case when bqco.BQC_Description = '1 Complete' then 1 else 0 end) as InitialCheckComplete,
            sum(case when bqco.BQC_Description = '2 Acceptable' then 1 else 0 end) as InitialCheckAcceptable,
            sum(case when bqco.BQC_Description = '3 Defective' then 1 else 0 end) as InitialCheckDefective,
            sum(case when bqco.BQC_Description = 'A Suitable' then 1 else 0 end) as InitialCheckSuitable,
            sum(case when bqco.BQC_Description = 'B Clarify' then 1 else 0 end) as InitialCheckClarify,
            sum(case when bqco.BQC_Description = 'C Potentially Unsuitable' then 1 else 0 end) as InitialCheckPU,
			sum(case when bqco.BQC_Description = 'Yes' then 1 else 0 end) as InitialCheckYes,
			sum(case when bqco.BQC_Description = 'No' then 1 else 0 end) as InitialCheckNo,
            sum(case when bqco.BQC_Description = 'Not Applicable' then 1 else 0 end) as InitialCheckNA,   
            sum(case when bqco.BQC_Description = 'Please Select' then 1 else 0 end) as InitialCheckPleaseSelect,
            sum(case when bqco.BQC_Description in ('1 Complete','2 Acceptable','A Suitable','Yes') then convert(float,1) else convert(float,0) end) as Passes,
            sum(case when bqco.BQC_Description in ('3 Defective','B Clarify','C Potentially Unsuitable','No') then convert(float,1) else convert(float,0) end) as Fails
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
INNER JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_UserDetails] userd ON saca.CASE_AdviserID = userd.USR_ID 
--LEFT OUTER JOIN dbo.mi_insight_UserHierarchy ON userd.USR_ID = dbo.mi_insight_UserHierarchy.UserGUID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 9 and CaseStatus.Code_Code = buqu.BQ_Status   --JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceForm] cofo on cofo.CF_ID    = buqu.BQ_FormID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID   --       and buqp.BQP_FormSectionID  = cofs.CFS_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID  --    and bqre.BQR_Code in (400,752,753,755,756,757)
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID  -- and CFQ.CFQ_QuestionCode = 1648   --cofs.CFS_ID   = CFQ.CFQ_SectionID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID --and cofs.CFS_Description like 'Case Outcome%' 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType      
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[mi_insight_UserHierarchy] miuh on miuh.UserGUID = buqu.BQ_CheckedBy

WHERE 
saca.CASE_SubmitDate >= DATEADD(mm,-12,GETDATE())  
--saca.CASE_SubmitDate >= '01-JaN-2016'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and prty.PROD_ShortName  not like 'x%'
--and prty.PROD_ShortName  not like 'k%'
--and prty.PROD_ShortName  != 'OGS'
--and   cofs.CFS_Description like 'Case Outcome%'
--and   bqre.BQR_Code in (400,752,753,755,756,757)
and   CFQ.CFQ_QuestionCode between 2001 and 3000
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select min(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) )
--and saca.CASE_CaseReference = 'F00415922'
group by saca.CASE_CaseReference,
            prty.PROD_ShortName,
            CaseStatus.Code_Description,
            saca.CASE_SubmitDate,
            buqu.BQ_CompletedDate,
			userd.USR_Name,
			miuh.UserName
) a


create index CTE_OUTCOME1 on #AQT_OUTCOMES (Advice,Product);


WITH CTE_OUTCOME
AS (select saca.CASE_CaseReference as Advice
      ,prty.PROD_ShortName  as Product    
      ,CaseStatus.Code_Description as [Final Workflow]
      ,buqu.BQ_CompletedDate [Final Check]
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 9 and CaseStatus.Code_Code = buqu.BQ_Status --JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceForm] cofo on cofo.CF_ID    = buqu.BQ_FormID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID   --       and buqp.BQP_FormSectionID  = cofs.CFS_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID --    and bqre.BQR_Code in (400,752,753,755,756,757)
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID --and CFQ.CFQ_QuestionCode = 1648   --cofs.CFS_ID   = CFQ.CFQ_SectionID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID --and cofs.CFS_Description like 'Case Outcome%' 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
WHERE 
saca.CASE_SubmitDate >= DATEADD(mm,-12,GETDATE())  
--saca.CASE_SubmitDate >= '01-JaN-2016'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and prty.PROD_ShortName  not like 'x%'
--and prty.PROD_ShortName  not like 'k%'
--and prty.PROD_ShortName  != 'OGS'
--and   cofs.CFS_Description like 'Case Outcome%'
--and   bqre.BQR_Code in (400,752,753,755,756,757)
and   CFQ.CFQ_QuestionCode between 2001 and 3000
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10,14)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) )
--select * from CTE_OUTCOME;
UPDATE #AQT_OUTCOMES                             
 set
        [Final Workflow]     = CTE_OUTCOME.[Final Workflow],
        [Final Check]          = CTE_OUTCOME.[Final Check]
FROM   #AQT_OUTCOMES aqou1
JOIN   CTE_OUTCOME on CTE_OUTCOME.Advice        = aqou1.Advice
                           and CTE_OUTCOME.Product = aqou1.Product;

select
Advice,
Product,
Adviser,
Assessor,
FORMAT((FailsPct),'P2') as [Checklist Fails %]
from #AQT_OUTCOMES

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_115_QualityResultsByAssessorProductParam]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_115_QualityResultsByAssessorProductParam]
Author	: Akin Yavuz
Date	: 20/10/2021
 			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_115_QualityResultsByAssessorProductParam]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Quality Results By Assessor Product Param'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

IF OBJECT_ID('tempdb..#AQT_OUTCOMES') IS NOT NULL
DROP TABLE #AQT_OUTCOMES;

CREATE TABLE #AQT_OUTCOMES 
      (
            Advice                    VARCHAR(100),
            CaseOutcome               VARCHAR(100),
            ProdShortName             VARCHAR(100),
			LOB						 VARCHAR(100),
            InitialStatus             VARCHAR(100),
           FinalStatus               VARCHAR(100),
           InitialWorkFlowStatus     VARCHAR(100),
            FinalWorkFlowStatus       VARCHAR(100),
			compfdate             VARCHAR(100),
            InitialCheckDate          DATETIME,
            FinalCheckDate            DATETIME,
		AssessorUID           VARCHAR(100),
		Assessor              VARCHAR(100),
		Num					  VARCHAR(100),
		Pass				  INT,
		Queried				  VARCHAR(100),
		PotUnsuit			  INT,
		Reject				  INT
      );
	  

insert into #AQT_OUTCOMES (Advice,CaseOutcome,ProdShortName,LOB,InitialStatus,InitialWorkFlowStatus,compfdate,InitialCheckDate
									,AssessorUID,Assessor,Num,Pass,Queried,PotUnsuit)
select saca.CASE_CaseReference
      ,cofs.CFS_Description
      ,prty.PROD_ShortName as ProdShortName
,CASE prty.PROD_ShortName 
            WHEN 'MORT' THEN 'MCOB'

            WHEN 'ICOB' THEN 'ICOB'
            WHEN 'WOL' THEN 'ICOB'
            WHEN 'WOLR' THEN 'ICOB'

            WHEN 'ONIV' THEN 'COBi'
            WHEN 'OIRP' THEN 'COBi'
            WHEN 'OFIN' THEN 'COBi'
            WHEN 'OFIR' THEN 'COBi'
            WHEN 'CINV' THEN 'COBi'
            WHEN 'IHT' THEN 'COBi'
            WHEN 'TIP' THEN 'COBi'
            WHEN 'TIPR' THEN 'COBi'

            WHEN 'EIS' THEN 'SpInv'
            WHEN 'EISR' THEN 'SpInv'
            WHEN 'VCT' THEN 'SpInv'
            WHEN 'VCTR' THEN 'SpInv'
            WHEN 'BPRL' THEN 'SpInv'
            WHEN 'BPRR' THEN 'SpInv'

            WHEN 'PENS' THEN 'COBp'
            WHEN 'PNRP' THEN 'COBp'
            WHEN 'PNSW' THEN 'COBp'
            WHEN 'METG' THEN 'COBp'
            WHEN 'SIPP' THEN 'COBp'

            WHEN 'ANNC' THEN 'RPB'
            WHEN 'ANNS' THEN 'RPB'
            WHEN 'DRAW' THEN 'RPB'
			WHEN 'DTOD' THEN 'RPB'

            ELSE 'Other' end as LOB      
      ,bqco.BQC_Description as outcome
      ,CaseStatus.Code_Description as WorkFlowStatus
		--,convert (varchar(10),buqu.BQ_CompletedDate,120) as compfdate
		,cast(buqu.BQ_CompletedDate as date) as compfdate
      ,buqu.BQ_CompletedDate
	  ,miuh.UserUID AS AssessorUID
      ,miuh.UserName AS Assessor
,1 as Num
,(case  bqco.BQC_Description when 'A1 Suitable and Complete' then			1
								when 'A2 Suitable and Acceptable' then		1
								when 'First time pass' then					1
								when 'First time pass with feedback' then	1
                                      else									0
									  end) as Pass 
,(case  bqco.BQC_Description when 'A3 Suitable but Defective' then			1
								when 'B Clarify' then						1
								when 'C Potentially Unsuitable' then		1
								when 'Unclear action required' then			1
								when 'Unsuitable advice' then				1
                                      else									0
									  end) as Queried 
,(case  bqco.BQC_Description when 'C Potentially Unsuitable' then 1
                                      else 0 end) as PotUnsuit 


FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --update 29/7/20 SH

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[mi_insight_UserHierarchy] miuh on miuh.UserGUID = buqu.BQ_CheckedBy
WHERE 
  
saca.CASE_SubmitDate >= '01-JAN-2013'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --update 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select min(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) ;                            

create index CTE_OUTCOME1 on #AQT_OUTCOMES (Advice,CaseOutcome,ProdShortName);


WITH CTE_OUTCOME
AS (select saca.CASE_CaseReference as Advice
      ,cofs.CFS_Description as CaseOutcome
      ,prty.PROD_ShortName  as ProdShortName    
      ,bqco.BQC_Description as FinalStatus
      ,CaseStatus.Code_Description as FinalWorkFlowStatus
      ,buqu.BQ_CompletedDate FinalCheckDate
	  ,CASE WHEN CaseStatus.Code_Description in ('Reject','Unsuitable advice') THEN 
								(case  bqco.BQC_Description when 'A3 Suitable but Defective' then 1
															when 'B Clarify' then 1
															when 'C Potentially Unsuitable' then 1
															when 'Unclear action required' then 1
															when 'Unsuitable advice' then 1
										          else 0 end)
                                     ELSE 0 END as Reject
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --update 29/7/20 SH
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
WHERE 
saca.CASE_SubmitDate >= '01-JAN-2013'
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --update 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10,14)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) )
UPDATE #AQT_OUTCOMES                             
 set    
		FinalStatus             = CTE_OUTCOME.FinalStatus,
        FinalWorkFlowStatus     = CTE_OUTCOME.FinalWorkFlowStatus,
        FinalCheckDate          = CTE_OUTCOME.FinalCheckDate,
		Reject					= CTE_OUTCOME.Reject

FROM   #AQT_OUTCOMES aqou1
JOIN   CTE_OUTCOME on CTE_OUTCOME.Advice        = aqou1.Advice
                           and CTE_OUTCOME.CaseOutcome   = aqou1.CaseOutCome
                           and CTE_OUTCOME.ProdShortName = aqou1.ProdShortName;
select
'View All' as [LOB],
'View All' as [Label],
1 as		  [Sort]

union all

select 
DISTINCT [LOB],
[LOB] as [Label],
2 as	 [Sort]
from #AQT_OUTCOMES
order by sort, LOB asc

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_116_AQTDefinedBenefits]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
