/**********************************************************************************************
Name	: [BI].[pr_116_AQTDefinedBenefits]
Author	: Sam Campbell
Date	: 08/11/2021
 			
Stored procedure written for SSRS report.
Shows Servicing Events linked to clients that have a Defined Benefits transfer case in Swift (Product DBT and DCT manually entered to Swift)
If there is also a sales case for one of the listed products on the client's Portfolio, Servicing Events are returned where they exist.


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
28.01.2022	S Campbell	Removed 'DBT'& 'DCT' from where clause, AQT don't need to see Manual DB cases that have no
						subsequent sale
						Removed 'Status' Column
31.01.2022	S Campbell	Added Insight OGS case check details where available (Case Ref, outcome, last check started date)
11.02.2020	S Campbell	Added pre 01.10.2020 cases using set list of case id's from checking spreadsheets (this list shouldnt change, hence hard coded)
23.02.2022  S Campbell	Removed duplicates caused by QuestionResponse for AQT approval code being stored multiple times  (change join to QuestionResponses table)
25.02.2022	S Campbell	For cases from spreadsheets - added logic to find caseids where a Tax Wrapper has been entered into OWS (landed on different caseid in Swift)
05.04.2022	S Campbell	Use dbo.mi_concert_ows_Event
30.06.2022	S Campbell	Add further manual case ids, but now stored in an external table bi.ManualCaseids rather than hard coded in this proc
31.05.2024  K Garcia    New case references included for OAS and OAW product types
*********************************************************************************************************************************************************/
CREATE PROCEDURE [BI].[pr_116_AQTDefinedBenefits]


with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'AQT Defined Benefits / Servicing Events Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

-- Create temp table of Clients & Case details that have a Defined Benefits Fee account
drop table if exists #DBClients
select c.CLIENT_NUM, START_DATE, CONT_NUM, PolicyRef
into #DBClients
      from sa_swift_S_POLMAI p inner join sa_swift_S_CLIENT c on c.CLIENT_NUM = p.CLIENT_NUM
      where productcode IN ('DBT','DCT')
	  order by CLIENT_NUM


-- Create temp table of Insight case checks (OGS only) with Case Reference stripped of characters
drop table if exists #OGSChecks
SELECT case_id,case_casereference, SUBSTRING(CASE_CaseReference, PATINDEX('%[0-9]%', CASE_CaseReference), PATINDEX('%[0-9][^0-9]%', CASE_CaseReference + 't') - PATINDEX('%[0-9]%', 
                    CASE_CaseReference) + 1) AS Number
into #OGSChecks
from sa_insight_salescase
where (CASE_CaseReference like 'OGS%' 
or CASE_CaseReference like 'OAS%' 
or CASE_CaseReference like 'OAW%' )


--  Create temp table of TaxWrapper policies or caseids that don't exist on Swift (submission landed agains existing tax wrapper entered on OWS)
drop table if exists #taxwrappercaseids -- caseids where policies are added to existing case ids 
select cont_num,policyref 
into #taxwrappercaseids
from sa_swift_s_polmai
where cont_num in (
select TaxWrapperAccountNumber from sa_ows_Policies
where  PolicyID in -- Sales cases pre 01.10.2020 with no manual DB case to identify them
(select caseid from bi.manualcaseids) and TaxWrapperAccountNumber != ''  )



/*  Link to:
    1. Swift to find COBS Sale policies linked to clients who have a Defined Benefits Fee account
	2. OWS/Concert to find servicing events for DB transfer clients (Note currently Concert Events are taken from OWS - this 
	                                                                 will need to be updated when the Events merging work is complete)
*/

select convert(varchar,dbcl.START_DATE,103) as 'DB StartDate', convert(varchar,dbcl.PolicyRef) as 'DB CaseID', c.FIRSTNAMES as 'FirstName', c.name as 'Surname', 
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else convert(varchar(25),p.start_date,103) end as 'PolicyStartDate',  
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else convert(varchar(20),p.PolicyRef) end as 'CaseId', 
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else isnull(p.CONT_NUM,'N/A') end as 'PolicyNumber', 
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else case p.status 
     when 20 then 'Issued'
     when 19 then 'Written'
     else 'Unknown' end 
end as 'Status',
ev.sourcesystem,
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else plan_code end as 'PlanCode', 
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else p.ProductCode end as 'ProductCode', 
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else isnull(pt.AgentCode, 'Not found') end as 'AdviserUID', 
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else isnull(hier.UserName, 'Not found') end as 'Adviser Name',
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else isnull(hier.BusinessUID, 'Not found') end as 'Firm UID',
case when p.PolicyRef = dbcl.PolicyRef
then 'N/A'
else isnull(hier.BusinessCompanyName,'Not found') end as 'Firm Name',
isnull(convert(varchar,ev.eventid),'N/A') as 'EventId', isnull(et.name,'NA') as 'SE Type',  
isnull(convert(varchar(25),ev.DateDue,103),'N/A') as 'SE Due Date',
isnull(convert(varchar(25),ev.DateCompleted,103),'N/A') as 'SE Completed Date',
isnull(out.Description,'N/A') as 'SE Outcome',
isnull(qr.AnswerText, 'N/A') as 'AQT Approval Code',
isnull(saca.CASE_CaseReference,'') as 'Case Check ref.',
isnull(code.Code_Description,'') as 'Case Outcome',
isnull(convert(varchar(25),bq.bq_starteddate,103),'') as 'Check Started Date'
from  #DBClients dbcl
left outer join sa_swift_S_POLMAI p on dbcl.CLIENT_NUM = p.CLIENT_NUM 
inner join sa_swift_S_CLIENT c on c.CLIENT_NUM = p.CLIENT_NUM 
left join sa_ows_Policies pol on Pol.policyid = p.PolicyRef
left join sa_swift_policytransactions pt on pt.PolicyID = p.POL_NUM and TransactionNumber = 1 -- Proposal Slice to find Servicing Agent
left join sa_ows_Sale s on s.SaleID = pol.SaleID
left join dbo.mi_concert_ows_Event ev on ev.PersonID = s.PersonID and ev.datedue > p.START_DATE  -- Due date of event later than Sales case date
left join StaticData.sa_ows_EventType et on et.EventTypeID = ev.TypeID
left join #OGSChecks saca on  saca.Number = convert(varchar(10),ev.eventid) 
left join sa_Insight_CaseStatus cs on saca.CASE_ID = cs.CS_ParentID
left join sa_Insight_BusinessQuality bq on bq.BQ_ParentID = saca.CASE_ID and bq.BQ_StartedDate is not null
left join sa_Insight_CodeDescription code on code.code_code = bq.BQ_Status and Code_CodeType = 785
left join mi_insight_UserHierarchyAllUsers hier on hier.UserUID = pt.AgentCode and p.START_DATE between hier.EffectiveStartDate and hier.EffectiveEndDate
left join StaticData.sa_ows_EventOutcome out on out.EventOutcomeID = ev.Outcome
left join (select policyid, QuestionID,answertext, max(lastupdateddate) as 'Latest'
	       from sa_ows_HDRUI_QuestionnaireResponses
	       group by policyid, QuestionID, AnswerText) qr on qr.PolicyID = pol.PolicyID and QuestionID = 1201 --and DateLastUpdated = Latest -- Enter AQT Authorisation Code
where p.ProductCode in 
('OFXFIN','OZPENACC','OFJUSTGU','OFLVPRPA','LVPRPA','OWPENACC','OFZSIPP','ZSIPP')
and p.START_DATE >= dbcl.START_DATE 
and isnull(ev.TypeID,1) in (1,2,7,8) -- Only include Report/Review/AdHoc Report/AdHoc Review events
UNION ALL  --Add DB transfers pre 01.10.2020
select '**' as 'DB StartDate', '**' as 'DB CaseID', c.FIRSTNAMES , c.name , 
convert(varchar(25),p.start_date,103)  as 'PolicyStartDate',  
convert(varchar(20),p.PolicyRef)  as 'CaseId', 
isnull(p.CONT_NUM,'N/A')  as 'PolicyNumber', 
case p.status 
     when 20 then 'Issued'
     when 19 then 'Written'
     else 'Unknown' end as 'Status',
ev.sourcesystem,
plan_code  as 'PlanCode', 
p.ProductCode  as 'ProductCode', 
isnull(pt.AgentCode, 'Not found')  as 'AdviserUID', 
isnull(hier.UserName, 'Not found')  as 'Adviser Name',
isnull(hier.BusinessUID, 'Not found')  as 'Firm UID',
isnull(hier.BusinessCompanyName,'Not found')  as 'Firm Name',
isnull(convert(varchar,ev.eventid),'N/A') as 'EventId', 
isnull(et.name,'NA') as 'SE Type',  
isnull(convert(varchar(25),ev.DateDue,103),'N/A') as 'SE Due Date',
isnull(convert(varchar(25),ev.DateCompleted,103),'N/A') as 'SE Completed Date',
isnull(out.Description,'N/A') as 'SE Outcome',
isnull(qr.AnswerText, 'N/A') as 'AQT Approval Code',
isnull(saca.CASE_CaseReference,'') as 'Case Check ref.',
isnull(code.Code_Description,'') as 'Case Outcome',
isnull(convert(varchar(25),bq.bq_starteddate,103),'') as 'Check Started Date'
from  sa_swift_S_POLMAI p 
inner join sa_swift_S_CLIENT c on c.CLIENT_NUM = p.CLIENT_NUM 
left join sa_ows_Policies pol on Pol.policyid = p.PolicyRef
left join sa_swift_policytransactions pt on pt.PolicyID = p.POL_NUM and TransactionNumber = 1 -- Proposal Slice to find Servicing Agent
left join sa_ows_Sale s on s.SaleID = pol.SaleID
left join dbo.mi_concert_ows_Event ev on ev.PersonID = s.PersonID and ev.datedue > p.START_DATE  -- Due date of event later than Sales case date
left join StaticData.sa_ows_EventType et on et.EventTypeID = ev.TypeID
left join #OGSChecks saca on  saca.Number = convert(varchar(10),ev.eventid) 
left join sa_Insight_CaseStatus cs on saca.CASE_ID = cs.CS_ParentID
left join sa_Insight_BusinessQuality bq on bq.BQ_ParentID = saca.CASE_ID and bq.BQ_StartedDate is not null
left join sa_Insight_CodeDescription code on code.code_code = bq.BQ_Status and Code_CodeType = 785
left join mi_insight_UserHierarchyAllUsers hier on hier.UserUID = pt.AgentCode and p.START_DATE between hier.EffectiveStartDate and hier.EffectiveEndDate
left join StaticData.sa_ows_EventOutcome out on out.EventOutcomeID = ev.Outcome
left join (select policyid, QuestionID,answertext, max(lastupdateddate) as 'Latest'
	       from sa_ows_HDRUI_QuestionnaireResponses
	       group by policyid, QuestionID, AnswerText) qr on qr.PolicyID = pol.PolicyID and QuestionID = 1201 --and AnswerText like 'SB%' -- Enter AQT Authorisation Code
where 
(p.policyref in -- Sales cases pre 01.10.2020 with no manual DB case to identify them
  (select caseid from bi.ManualCaseIds)
   or p.policyref in (select policyref from #taxwrappercaseids)) -- CaseIds found via Tax Wrapper
and isnull(ev.TypeID,1) in (1,2,7,8) -- Only include Report/Review/AdHoc Report/AdHoc Review events
order by PolicyStartDate
--order by c.NAME, FIRSTNAMES, p.PolicyRef asc, convert(int,ev.EventID) asc




drop table #DBClients
drop table #OGSChecks
drop table #taxwrappercaseids

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_117_AgentChangeDefaultCommissionSplitOnly]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_117_AgentChangeDefaultCommissionSplitOnly] 
Author	: Akin Yavuz
Date	: 08/11/2021
 			
			  This report displays any policy on Swift where an agent change has been
			  implemented and the case has not been updated a new Active line to redirect the commission
			  for the new adviser.

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_117_AgentChangeDefaultCommissionSplitOnly]

			@OldAdviserUID			varchar (7),
			@NewAdviserUID			varchar (7),
			@NewFirmUID				varchar (7),
			@OldFirmUID				varchar (7)

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@PtlCode				varchar(255),
			@ReportFormat			varchar(200)

set	@ReportName			= 'Agent Change Default Comission Split Only'
set @StoredProcName		= object_name(@@procid);


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

with CTE_latestpayment AS(
Select 
PolicyID,
CreateDateTime,
CommissionTypeDesc,
TransactionID,
CaseID
from mstt_PaymentsPending pp
where TranProduct in (Select ProductCode from mstt_ProductHierarchy where RDRType is not null or ProductCode in ('ASP','FPP','INDPP','INDSTK','PPXFR','RTRCON','SECT32','EPP','GRPMP',
						   'GRPPP','GRPSTK','FPP-FAC','ZSIPP','PPP','SWGRPP','MLRP','MLIVPP','PRUTIP',
						   'HSIPP','INCOME','MGMA','PRUFUND')) 
and pp.CreateDateTime = (Select max(createdatetime) from mstt_PaymentsPending pp2
						 where pp2.CommissionType in (4,10) and pp2.PolicyID = pp.PolicyID)					
AND pp.AGENT_CODE IN (@NewAdviserUID,@OldAdviserUID)
)
				 
,CTE_DefaultCommisssionSplitOnly as(
select distinct  polm.CONT_NUM as 'PolicyNumber'
		,polm.PolicyRef as 'CaseID'
		,polm.COMP_CODE
		,polm.ProductCode
		,client.CLIENT_OF as 'ToAdviser'
		,tash.FranchiseAgentCode as 'ToFirm'
		,@OldAdviserUID as 'FromAdviser'
		,@OldFirmUID as 'FromFirm'
		,convert(varchar(10),polm.CreateDate,103) as 'CreatedDate'
		,pol.TransactionNumber as [Transaction number]
		,LP.CreateDateTime AS [Latest Payment Date]
		,'Default Commisssion Split Only' as Reason
from dbo.sa_swift_S_POLMAI polm
inner join dbo.sa_swift_PolicyTransactions pol on polm.POL_NUM = pol.PolicyID
inner join dbo.sa_swift_S_CLIENT client on client.CLIENT_NUM = polm.CLIENT_NUM
left join dbo.sa_swift_TransAgentSplitHierarchyHistory tash on tash.TransactionID = pol.ID and (tash.AgentCode = client.CLIENT_OF)
left join CTE_latestpayment LP on LP.CaseID = polm.PolicyRef
where pol.TransType = 117
and ((polm.ProductCode like 'OW%' or polm.ProductCode like 'OZ%' or polm.ProductCode like 'OF%') 
or   (polm.ProductCode in ('ASP','FPP','INDPP','INDSTK','PPXFR','RTRCON','SECT32','EPP','GRPMP',
						   'GRPPP','GRPSTK','FPP-FAC','ZSIPP','PPP','SWGRPP','MLRP','MLIVPP','PRUTIP',
						   'HSIPP','INCOME','MGMA','PRUFUND')))
and client.CLIENT_OF = @NewAdviserUID
and pol.TransactionNumber = (select max(pol1.transactionnumber)
							from dbo.sa_swift_PolicyTransactions pol1
							where pol.PolicyID = pol1.policyid)
and polm.STATUS = 20
)

,CTE_PolicyAdviserNotUpdated as(
SELECT distinct
polm.CONT_NUM as 'PolicyNumber'
		,polm.PolicyRef as 'CaseID'
		,polm.COMP_CODE
		,polm.ProductCode
		,client.CLIENT_OF as 'ToAdviser'
		,tash.FranchiseAgentCode as 'ToFirm'
		,pol.AgentCode as 'FromAdviser'
		,@OldFirmUID as 'FromFirm'
--		,pol.AgentCode as 'PolicyAdviser'
		,convert(varchar(10),polm.CreateDate,103) as 'CreatedDate'
		,pol.TransactionNumber
		,LP.CreateDateTime AS [Latest Payment Date]
		,'Policy Adviser Not Updated' as Reason
from dbo.sa_swift_S_POLMAI polm
join dbo.sa_swift_PolicyTransactions pol on polm.POL_NUM = pol.PolicyID
join dbo.sa_swift_S_CLIENT client on client.CLIENT_NUM = polm.CLIENT_NUM
join dbo.sa_swift_TransAgentSplitHierarchyHistory tash on tash.TransactionID = pol.ID and (tash.AgentCode = client.CLIENT_OF or tash.AgentCode = pol.AgentCode)
join sa_swift_S_AGTCOM agt on agt.TransactionID = pol.ID
left join CTE_latestpayment LP on LP.CaseID = polm.PolicyRef
where
 ((polm.ProductCode like 'OW%' or polm.ProductCode like 'OZ%' or polm.ProductCode like 'OF%') 
or   (polm.ProductCode in ('ASP','FPP','INDPP','INDSTK','PPXFR','RTRCON','SECT32','EPP','GRPMP',
						   'GRPPP','GRPSTK','FPP-FAC','ZSIPP','PPP','SWGRPP','MLRP','MLIVPP','PRUTIP',
						   'HSIPP','INCOME','MGMA','PRUFUND')))
and pol.AgentCode = @OldAdviserUID --old adviser--
and client.client_of = @NewAdviserUID -- new adviser --
and pol.TransactionNumber = (select max(pol1.transactionnumber)
							from dbo.sa_swift_PolicyTransactions pol1
							where pol.PolicyID = pol1.policyid)
and polm.STATUS = 20
and pol.Amount != 0.01
and agt.CommissionType = 10
and agt.AGENT_CODE not in (1011543,1011587)
)

,CTE_CaseNotUpdated as(
select distinct	 polm.CONT_NUM as 'PolicyNumber'
		,polm.PolicyRef as 'CaseID'
		,polm.COMP_CODE
		,polm.ProductCode
		,'N/A' as 'ToAdviser'
		,tash.FranchiseAgentCode as 'ToFirm'
		,agt.AGENT_CODE as 'FromAdviser'
		,@OldFirmUID as 'FromFirm'
--		,pol.AgentCode as 'PolicyAdviser'
		,convert(varchar(10),polm.CreateDate,103) as 'CreatedDate'
		,pol.TransactionNumber
		,LP.CreateDateTime AS [Latest Payment Date]
		,'Case Not Updated' as Reason
from dbo.sa_swift_S_POLMAI polm
join dbo.sa_swift_PolicyTransactions pol on polm.POL_NUM = pol.PolicyID
join dbo.sa_swift_S_CLIENT client on client.CLIENT_NUM = polm.CLIENT_NUM
join dbo.sa_swift_TransAgentSplitHierarchyHistory tash on tash.TransactionID = pol.ID and (tash.AgentCode = client.CLIENT_OF or tash.AgentCode = pol.AgentCode)
join sa_swift_S_AGTCOM agt on agt.TransactionID = pol.ID
left join CTE_latestpayment LP on LP.CaseID = polm.PolicyRef
where
 ((polm.ProductCode like 'OW%' or polm.ProductCode like 'OZ%' or polm.ProductCode like 'OF%') 
or   (polm.ProductCode in ('ASP','FPP','INDPP','INDSTK','PPXFR','RTRCON','SECT32','EPP','GRPMP',
						   'GRPPP','GRPSTK','FPP-FAC','ZSIPP','PPP','SWGRPP','MLRP','MLIVPP','PRUTIP',
						   'HSIPP','INCOME','MGMA','PRUFUND')))
and pol.TransactionNumber = (select max(pol1.transactionnumber)
							from dbo.sa_swift_PolicyTransactions pol1
							where pol.PolicyID = pol1.policyid)
and pol.Amount = 0.01 and agt.AGENT_CODE = @OldAdviserUID
and tash.FranchiseAgentCode != @NewFirmUID
)

,CTE_NegativePercentage as(
select distinct	 polm.CONT_NUM as 'PolicyNumber'
		,polm.PolicyRef as 'CaseID'
		,polm.COMP_CODE
		,polm.ProductCode
		,agt.AGENT_CODE as 'ToAdviser'
		,tash.FranchiseAgentCode as 'ToFirm'
		,'N/A' as 'FromAdviser'
		,@OldFirmUID as 'FromFirm'
--		,pol.AgentCode as 'PolicyAdviser'
		,convert(varchar(10),polm.CreateDate,103) as 'CreatedDate'
		,pol.TransactionNumber
		,LP.CreateDateTime AS [Latest Payment Date]
		,'Negative Percentage' as Reason
from dbo.sa_swift_S_POLMAI polm
join dbo.sa_swift_PolicyTransactions pol on polm.POL_NUM = pol.PolicyID
join dbo.sa_swift_S_CLIENT client on client.CLIENT_NUM = polm.CLIENT_NUM
join dbo.sa_swift_TransAgentSplitHierarchyHistory tash on tash.TransactionID = pol.ID and (tash.AgentCode = client.CLIENT_OF or tash.AgentCode = pol.AgentCode)
join sa_swift_S_AGTCOM agt on agt.TransactionID = pol.ID
left join CTE_latestpayment LP on LP.CaseID = polm.PolicyRef
where
 ((polm.ProductCode like 'OW%' or polm.ProductCode like 'OZ%' or polm.ProductCode like 'OF%') 
or   (polm.ProductCode in ('ASP','FPP','INDPP','INDSTK','PPXFR','RTRCON','SECT32','EPP','GRPMP',
						   'GRPPP','GRPSTK','FPP-FAC','ZSIPP','PPP','SWGRPP','MLRP','MLIVPP','PRUTIP',
						   'HSIPP','INCOME','MGMA','PRUFUND')))
and pol.TransactionNumber = (select max(pol1.transactionnumber)
							from dbo.sa_swift_PolicyTransactions pol1
							where pol.PolicyID = pol1.policyid)
and agt.AGENT_PERC < 0
and agt.AGENT_CODE in (@NewAdviserUID,@OldAdviserUID)
)

select * from CTE_DefaultCommisssionSplitOnly
union all
select * from CTE_PolicyAdviserNotUpdated
union all
select * from CTE_CaseNotUpdated
union all
select * from CTE_NegativePercentage

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_118_LandDTestSummary]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_118_LandDTestSummary]
Author	: Sam Campbell
Date	: 11/01/2022
 			
Stored procedure written for SSRS report.
Shows tests and the tracks in which they sit.  Also shows licences attached to tests as well as other test properties such as 
No. of questions, bank name, passmark etc


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_118_LandDTestSummary]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'L&D Test Summary Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

-- All 'main' tests, and their properties

drop table if exists #Tests
SELECT *
into #Tests
FROM sa_Insight_Test t
INNER JOIN sa_Insight_TestProperties tp ON t.TST_ID = tp.TP_TestID
left join sa_Insight_TandCTrackModule tm on tm.TCTM_LinkedID = t.TST_ID
left join sa_Insight_TandCTrack track on track.TCT_ID = tm.TCTM_TrackID
WHERE t.TST_VersionType = 2 -- Tests

-- All versions of tests and the CPD Hours applying to each version, for versions associated with 'main' tests
drop table if exists #Versions
SELECT *,
-- order the versions according to their version number
	row_number() over (
						partition by tv.TST_ParentID
						order by tv.TST_VersionNum DESC) AS RowNumber
into #Versions
FROM sa_Insight_Test tv
INNER JOIN sa_Insight_TestProperties tvp ON tv.TST_ID = tvp.TP_TestID -- get the properties for this test version
LEFT OUTER JOIN sa_Insight_CPDTypeProperties cpdtp ON tvp.TP_CPDTypeID  = cpdtp.CPDTP_CPDTypeID
WHERE tv.TST_VersionType = 3 -- Test Versions
AND tv.TST_ParentID in (SELECT tst_id from #Tests) -- Linked to a 'main' test



-- Final query:
SELECT isnull(t.TCT_Description, 'No Track') as 'Track Name', t.TP_Ref as 'Test Reference', v.TST_Description as 'Name', v.TP_QuestionLimit as 'No.of Questions', 
t.TP_PassMark as 'PassMark', t.TP_TimeLimit as 'Time Allowed', isnull(convert(varchar(10),CONVERT(int,CPDTP_AwardValue)),'N/A') as 'CPD Minutes', 
 lic.LIC_Code as 'Test Licence Code', lic.LIC_Description 'Test Licence', t.TCT_ID, isnull(t.tct_id,'9999A001-9999-9A99-99A9-A9F99999AA9A') as 'trackid'
FROM #Tests T
INNER JOIN #Versions v on t.tst_id = v.TST_ParentID AND v.RowNumber = 1
-- Join Tests to Licences
left join  (  -- done to remove duplicate link to 3
            select tl.TESL_TestID as 'TestID', tl.TESL_ParentID as 'ParentID', MAX(tl.TESL_UpdatedDate)as 'Newest'
            from sa_Insight_TestLink  tl
			group by tl.TESL_TestID, tl.TESL_ParentID
			) as NewestLink on  t.tst_id = NewestLink.TestID
left join sa_Insight_Licence lic on lic.LIC_ID = NewestLink.ParentID
where isnull(t.TCT_Description,'ZZ') not like 'XX%' -- Exclude tracks marked as obsolete
order by isnull(t.tct_description, 'XX') asc, t.TST_Description


drop table #Tests
drop table #Versions

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
