/**********************************************************************************************
Name	: [BI].[pr_119_TracksandLicences]
Author	: Sam Campbell
Date	: 12/01/2022
 			
Stored procedure written for SSRS report.
Shows Learning tracks with associated Qualifications and Licences
(DRILLDOWN REPORT FROM TEST SUMMARY REPORT pr_118_LandDTestSummary)

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_119_TracksandLicences]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'L&D Tracks & Licences Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

-- Track Details

select t.tct_id as 'tct_id', isnull(t.TCT_Description, 'No track') as 'Track Name',q.QUAL_Description as 'Qualification', lic2.LIC_Code as 'Track Licence Code', 
lic2.LIC_Description as 'Track Licence'
--,*
FROM sa_Insight_TandCTrack t  
--Join Tracks to Licences
left join 
           (  -- done to dedupe links between tracks and qualitications
            select tq.tttq_trackid as 'TrackId', tq.TTTQ_QualificationID, max(tq.tttq_startdate) as 'Newest'
            from sa_Insight_TandCTrackQualification  tq
			group by tq.TTTQ_TrackID, tq.TTTQ_QualificationID
			) as NewestLink on  NewestLink.TrackId = t.TCT_ID
left join sa_Insight_Qualification q on q.QUAL_ID = NewestLink.TTTQ_QualificationID
left join sa_Insight_LicenceLink liclink on liclink.LICL_ParentID = qual_id
left join sa_Insight_Licence lic2 on lic2.LIC_ID = liclink.LICL_LicenceID
where isnull(t.TCT_Description,'ZZ') not like 'XX%' -- Exclude tracks marked as obsolete
and t.tct_id is not null
and lic2.LIC_Code is not null -- exclude development tracks

union all -- add dummy row for tests that are no associated to a track

select '9999A001-9999-9A99-99A9-A9F99999AA9A','No Tracks Linked to test' as 'Track Name','' as 'Qualification', '' as 'Track Licence Code', 
'' as 'Track Licence'
order by [Track Name], lic2.LIC_Code




/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
