/****** Object:  StoredProcedure [BI].[pr_123_RecurringIncome2]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_123_RecurringIncome2] 
Author	: J Homer
Date	: 10/02/2022

Report for Corporate Finance to allow them to run a regular scan that shows Recurring Income by 
Firm.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
23/03/22	J Homer		Update scan to show ProductGroupName2 to allow Recurring Income to be
						split between Servicing Fee, Legacy and BSC
29/03/2022	J Homer		Add in Product Sub Group to show Provider
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_123_RecurringIncome2]

@StartDate as Date,
@EndDate as Date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			
set	@ReportName			= 'Recurring Income by Firm'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/
select 
Type
,Firm
,date
,Day
,Month
,Year
,SUM(APE) APE
,SUM(NewPolicies) NewPolicies
,SUM(DA) DA
,SUM(Margin) Margin
,ProductGroupname
,ProductGroupName2
,ProductSubGroup
,AdminMethod 
,Channel 
from [bi].[IssuedBusiness]
where Date between @Startdate AND @Enddate
and ProductGroupName = 'Recurring Income'
GROUP BY
Type
,Firm
,date
,Day
,Month
,Year
,ProductGroupname
,ProductGroupName2
,ProductSubGroup
,AdminMethod 
,Channel
ORDER BY DATE Desc


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



