/****** Object:  StoredProcedure [BI].[pr_124_OwlNewStarters]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_124_OwlNewStarters]
Author	: A Yavuz
Date	: 15/02/2022

Report to track a series of metrics for new Owl Advisers over their first 12 months.
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_124_OwlNewStarters]

@UserID varchar(50)

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int
		
set	@ReportName			= 'OWL New Starters'
set @StoredProcName		= object_name(@@procid)

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/
IF OBJECT_ID('tempdb..#AdviserTable') IS NOT NULL
DROP TABLE #AdviserTable;

WITH lic AS(

select 
CASE WHEN LEFT(TT.uid,2) = '00' THEN '00' + TT.uid
	 WHEN LEFT(TT.uid,1) = '0' THEN '000' + TT.uid
	 ELSE TT.uid
	 END as uid
,case when ah.AgentCategoryDescription = 'Administrator' then 'NASP'
	  when (TT.cob>0 and TT.mcob>0 and TT.icob >0) or (TT.cob>0 and TT.mcob>0) then 'CMCOB'
	  when (TT.cob>0 and TT.icob >0) or TT.cob>0 then 'COB'
	  when TT.ICOB_GI>0 then 'ICOB GI ONLY'
	  when (TT.mcob>0 and TT.icob >0) or TT.mcob>0 then 'MCOB'
	  when TT.ICOB_Owl >0 then 'ICOB_Owl'
	  else 'ICOB' end [business area]
, TT.CF30Status
from

(select uid 
,sum(case when (BusinessArea like 'cob%' AND CF30Status <> 'Not Set') then 1 else 0 end) COB
,sum(case when BusinessArea like 'mcob%' then 1 else 0 end) MCOB
,sum(case when BusinessArea like 'icob%' AND BusinessArea NOT LIKE '%Owl%' then 1 else 0 end) ICOB
,sum(case when BusinessArea like 'icob GI%' then 1 else 0 end) ICOB_GI
,sum(case when BusinessArea like '%Owl%' then 1 else 0 end) ICOB_Owl
,CF30Status

 from
	(select distinct case when UD.USR_ExternalID = '0072' then '1008203' when UD.USR_ExternalID = '1003604' then '1005181' when UD.USR_ExternalID = '1010321' then '1010897'
						  when UD.USR_ExternalID = '1010364' then '1010744' when UD.USR_ExternalID = '4001674' then '1011586' else UD.USR_ExternalID end UID 
					,CD.Code_Description BusinessArea, CD2.Code_Description AS CF30Status
					,UC.UC_Status Status 
					,Max(UC.UC_CompetencyLevel) Level
	from dbo.sa_insight_Licence L inner join
		dbo.sa_insight_UserLicence UL on L.LIC_ID = UL.ULIC_LicenceID right join
		dbo.sa_insight_Staff S inner join
		dbo.sa_insight_UserDetails UD on S.STAF_UserID = UD.USR_ID inner join
		dbo.sa_insight_UserCompetency UC on UD.USR_ID = UC.UC_OwnerID on UL.ULIC_UserID = UD.USR_ID left join
		dbo.sa_insight_CodeDescription CD on UC.UC_BusinessArea = CD.Code_Code and CD.Code_CodeType = 534 LEFT JOIN
		dbo.sa_insight_CodeDescription AS CD2 ON S.STAF_CustomerFunction = CD2.Code_Code AND CD2.Code_CodeType = 530
	where	UC_Status <> 1	and UC.UC_BusinessArea <=9
	group by UD.USR_ExternalID, UC.UC_Status, CD.Code_Description, CD2.Code_Description
	) T
							
group by uid, CF30Status) TT

left join dbo.cscv_AgentsHierarchy ah on ah.Agentcode = TT.UID
--------------
)
	

SELECT		ah.AgentCode [Adviser UID]
			,ltrim(rtrim(ah.AgentDesc)) [Adviser Name]
			,ah.CompetentStatusdescription [Swift Status]
			,CD.Code_Description [Insight Status]
			,case when (ah.asdcode) in ('4005013','4021409')  and ah.AgentTypeDescription = 'Principal' then 'Adviser'
				 when ah.AgentTypeDescription = 'Seller' then 'Adviser'
				 when ah.agenttype in (42,46) then 'Franchise'
				 else ah.AgentTypeDescription  end Type
			,CAST(ah.AgentStartDate AS Date) 'DOJ'	
			,CAST(ah.AgentLeftDate AS Date) 'DOL'
			,ag.ReasonforLeaving
			,ah.FirmCode 'Firm UID'
		   ,ltrim(rtrim(ah.FirmDescn)) [Firm Name]
		   ,ag3.descn SDC
		   ,Supervisorname [Supervisor Name]
		   ,ah.rsmname [RSM Name]
		   ,BQMName [QRM Name]
		   ,AQMName [AQM Name]
		   ,ah.ASDCode [ASD UID]
		   ,ah.ASDname [ASD Name]
		   ,OwlASMUID1
		   ,OwlASMName1
		   ,OwlASMUID2
		   ,OwlASMName2
		   ,OwlASMUID3
		   ,OwlASMName3
		   ,OwlASMUID4
		   ,OwlASMName4
		   ,OwlASMUID5
		   ,OwlASMName5
		   ,OwlASMUID6
		   ,OwlASMName6
		   ,OwlASMUID7
		   ,OwlASMName7
		   ,OwlASMUID8
		   ,OwlASMName8
		   ,OwlASMUID9
		   ,OwlASMName9
		   ,OwlASMUID10
		   ,OwlASMName10
		   ,CAST(cl.BIRTHDATE AS DATE) DOB
		   ,(datediff(d,cl.BIRTHDATE,GETDATE())/365)+1 Age_Next_Birthday
		   ,case when left(ag2.AgentCategoryDescription, 4) = 'NASP' and ah.AgentCategoryDescription = 'Administrator' then 'NASP' else null end [NASP Flag]
		   ,lic.[business area] 'Licensed As'
		   ,CF30Status [CF30 Status]
		   ,CASE WHEN (ah.ASDCode in('4019902') OR ah.FirmCode = '2016789') THEN 'Owl AR' WHEN ah.ASDCode in ('4005013','4021409') Then 'Owl'  ELSE 'Openwork' END AS Channel
		   ,isnull(ag.email,cl.EMAIL) Email
		   ,REPLACE(REPLACE(REPLACE(ltrim(rtrim(isnull(s_cl.CorrAddress1,ag.address1))), Char(9),''), Char(10),''), Char(13),'') [Address Line 1]
		   ,REPLACE(REPLACE(REPLACE(ltrim(rtrim(isnull(s_cl.CorrAddress2,ag.address2))), Char(9),''), Char(10),''), Char(13),'') [Address Line 2]
		   ,REPLACE(REPLACE(REPLACE(ltrim(rtrim(isnull(s_cl.CorrAddress3,ag.address3))), Char(9),''), Char(10),''), Char(13),'') [Address Line 3]
		   ,REPLACE(REPLACE(REPLACE(ltrim(rtrim(isnull(s_cl.CorrTown,ag.address4))), Char(9),''), Char(10),''), Char(13),'') [Address Line 4]
		   ,REPLACE(REPLACE(REPLACE(ltrim(rtrim(isnull(s_cl.CorrCounty,ag.address5))), Char(9),''), Char(10),''), Char(13),'') [Address Line 5]
		   ,REPLACE(REPLACE(REPLACE(ltrim(rtrim(isnull(s_cl.CorrPostcode,ag.postcode))), Char(9),''), Char(10),''), Char(13),'') Postcode
		   
		   ,REPLACE(REPLACE(REPLACE(isnull(isnull(isnull(ag.telephone,ins_con.cd_Telephone),cl.TEL_HOME),ins_con.CD_Mobile), Char(9),''), Char(10),''), Char(13),'') AS Telephone

		   ,ag2.telephone AS [Firm Telephone]
		   ,ins_con.CD_Mobile [Mobile Telephone]
		   ,case ag.LicenceNumber when 'Excluded' then null else ag.LicenceNumber end [Licence Number]
		   ,case ag2.LicenceNumber when 'Excluded' then null else ag2.LicenceNumber end [Firm Ref]
		   ,case ag.Salutation when 'Ocademy' then 'Yes' else 'No' end Ocademy
INTO #AdviserTable	           
FROM         dbo.mstt_Agents ag inner join dbo.cscv_AgentsHierarchy ah ON ag.CODE = ah.AgentCode
                      left join mstt_Agents ag2 ON ag.Firm = ag2.code
					  left join mstt_Agents ag3 on ag3.code = ag.Manager2Code
                      left join dbo.mstt_Clients cl ON ah.AgentCode = cl.AgentCode
					  left join mi_insight_UserHierarchyallusers uh on uh.useruid = ag.code and uh.latestrowind = 1
					  left join lic lic on lic.UID = ag.CODE

					  -- contact details - swift and insight
					  inner join dbo.msit_S_CLIENT s_cl on s_cl.CLIENT_NUM = cl.CLIENT_NUM
					  left join dbo.sa_insight_UserDetails in_UD on (CASE WHEN USR_externalid = '0102' THEN '0000102' 
																		  WHEN USR_externalid = '0132' THEN '0000132' 
																		  ELSE USR_externalid END)  = ag.code
					  left join dbo.sa_insight_Staff S on s.STAF_UserID = in_UD.USR_ID
					  left join dbo.sa_insight_ContactDetails ins_con ON  ins_con.CD_ParentID = S.STAF_ID
					  Left join dbo.sa_insight_CodeDescription CD on S.STAF_ContractStatus = CD.Code_Code and CD.Code_CodeType = 527
						
--manual exclusions
WHERE ah.AgentCode not in
(
'4002872','1001025','4003785','4007961','4007959','1011677','4007963','4009489','4009488','4009375','4010182','4010455',
'4010568','4010513','4010566','4010573','4010511','4010570','4011182','4006771','4011613','4011213','4012052','1011524',
'4012843','4012821','4012820','1005260','2001539','1011607','1011608','1011609','2001815','2004327','2005603','2005605',
'4007962','2005601','2005599','2007293','2007295','2007996','2008545','2008526','2008591','2008595','2008661','2008664',
'2008666','2008670','2000873','2009072','2000686','2009397','1002915','2010370','1003227','2011284','2011287','2011312',
'10003','4015635','4015829','2009397','4010475','1012060','1012059', '1004297'
)

AND
			(case when (RIGHT(ag.SupervisorTypeCode, 2) = 'NA' AND ag.givesAdvice = 'Y') OR
                      ah.AgentCode = '1005202' then 'N' else ag.GivesAdvice end = 'Y' OR
				case when left(ag2.AgentCategoryDescription, 4) = 'NASP' and ah.AgentCategoryDescription = 'Administrator' then 'NASP' else null end IS NOT NULL)
			and (ah.FirmTypeDescription not like 'Directly Authorised') 

Select 
[Adviser UID]
, [Adviser Name]
, DOJ
, DOL
, ReasonforLeaving
, [Swift Status]
, [QRM name]
, OwlASMUID1
, OwlASMName1
, SUM(CASE WHEN DATE BETWEEN DOJ and DATEADD (Year, 1, DOJ) THEN APE 
	ELSE 0 
  END) APE
, SUM(CASE WHEN DATE BETWEEN DOJ and DATEADD (Year, 1, DOJ) THEN NewPolicies 
	ELSE 0 
  END) NewPolicies
, SUM(CASE WHEN DATE BETWEEN DOJ and DATEADD (Year, 1, DOJ) THEN DA-Margin 
	ELSE 0 
  END) TotalCommission
  ,DATEDIFF(wk,max(DATE), Getdate())  as [Number of Weeks Inactive]
,UBD.PtlCode as PTLCode
from #AdviserTable at
Left Join [dbo].[WrittenBusiness] wb on wb.Adviser = at.[Adviser UID]
Left Join [staticdata].sa_ows_SCRTY_UserAndBusinessDetails UBD on OwlASMUID1 = UBD.AdviserUID
where at.Channel = 'Owl'
and at.DOJ >= '01 Jan 2020'
and 'Openwork\' + UBD.PtlCode = @UserID
GROUP BY
[Adviser UID]
, [Adviser Name]
, DOJ
, DOL
,ReasonforLeaving
, [Swift Status]
, [QRM name]
, OwlASMUID1
, OwlASMName1
,  at.Channel
,UBD.PtlCode
Order by [Swift Status] ASC, DOJ ASC, [Adviser UID] ASC


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_125_Submissions]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_125_Submissions]
Author	: J Homer
Date	: 25/02/2022

Report to track Owl Advice by Adviser..
			
AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
28/03/21	J Homer		Added Business UID, Date Sumbitted, Partner Name and Policy Type
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_125_Submissions]

@Startdate Date,
@EndDate Date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int
		
set	@ReportName			= 'Submissions'
set @StoredProcName		= object_name(@@procid)

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select uh.UserUID
, uh.Username
, uh.BusinessUID
, uh.UserEmploymentStatus
, CASE WHEN uh.UserJobTitleCodeSeller IS NOT NULL THEN
		CASE UserJobTitleCodeSeller WHEN 61 THEN 'Senior Protection Adviser'
		WHEN 62 THEN 'Mortgage Adviser'
		WHEN 63 THEN 'New Protection Adviser'
		ELSE 'Protection Adviser' 
		END
  ELSE NULL 
  END AS [Seller Type]
, pers.Firstname + ' ' + pers.Lastname [Client Name]
, CASE WHEN inp.ValueName = 'Joint' THEN part.Firstname + ' ' + part.Lastname 
	   ELSE ''
  END [Partner Name]
, s.SaleID AS Advice_ID
, CONVERT(DATE, s.DateSubmitted, 103) [Date Submitted]
, COUNT (DISTINCT po.PolicyID) [Policy ID Count]
, inp.ValueName [Policy Type]
from  sa_ows_sale s join
				[dbo].[sa_ows_Policies] po on s.SaleID = po.SaleID left join
				[dbo].[mi_insight_UserHierarchyAllUsers] uh on uh.UserUID = s.AdviserUID and uh.LatestRowInd = 1 Left join
				[dbo].[sa_ows_Person] pers on pers.PersonID = s.PersonID Left Join
				[dbo].[sa_ows_FactFindOverviewGeneral] ffog on ffog.saleid = s.SaleID Left Join
				[staticdata].[sa_ows_InputValues] inp on inp.InputID = ffog.CompletedFor Left Join
				[dbo].[sa_ows_person] part on part.personid = pers.partnerpersonid
where uh.UserJobTitleCodeSeller IN (52,61,62,63,64) -- OWl Adviser Job Title Codes
and s.DateSubmitted Between @StartDate AND @EndDate

GROUP BY uh.UserUID
, uh.Username
, uh.BusinessUID
, uh.UserEmploymentStatus
, CASE WHEN uh.UserJobTitleCodeSeller IS NOT NULL THEN
		CASE UserJobTitleCodeSeller WHEN 61 THEN 'Senior Protection Adviser'
		WHEN 62 THEN 'Mortgage Adviser'
		WHEN 63 THEN 'New Protection Adviser'
		ELSE 'Protection Adviser' 
		END
  ELSE NULL 
  END,
  pers.Firstname + ' ' + pers.Lastname
  , part.Firstname + ' ' + part.Lastname
  , s.SaleID
  , s.DateSubmitted
  , inp.ValueName
  Order by uh.UserUID asc
  , s.SaleID asc

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_126_NoSales12Months]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_126_NoSales12Months]
Author	: Sam Campbell
Date	: 01/03/2022
 			
Stored procedure written for SSRS report.
Shows Advisers who havent submitted any cases for 12 months (rolling) along with competencies held and last sale made date

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

********************************************************************************************************************************************/
CREATE PROCEDURE [BI].[pr_126_NoSales12Months]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
            @StartDate              datetime, 
            @EndDate                datetime,
		    @LastYear               datetime


set	@ReportName			= 'Adviser no Sales in last 12 months Report'
set @StoredProcName		= object_name(@@procid)
set @StartDate          = Convert(date, (DATEADD(year, -1, getdate()+1))) 
set @LastYear           = Convert(date, (DATEADD(year, -1, getdate()))) 
set @EndDate            = DATEADD(YEAR, 1, @LastYear)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

--**************************************************************************
-- Find all active sellers
--**************************************************************************

drop table if exists #CurrentSellers
 SELECT ud.USR_ID,  ud.USR_ExternalID as 'AdviserUID', ud.usr_name as 'Adviser Name', uh.BusinessUID as 'Firm ID', uh.BusinessCompanyName as 'Firm',
 uh.BQMName as 'QRM', isnull(uh.SupervisorName,'') as 'Supervisor', uh.AQMName as 'SQRM', up.UPS_JobTitle as 'Jobtitle'
 into #CurrentSellers
 FROM sa_Insight_Staff s
 inner join sa_Insight_UserDetails ud ON s.STAF_UserID = ud.USR_ID
 inner join sa_Insight_UserPosition up ON s.STAF_UserID = up.UPS_UserID 
 inner join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = ud.USR_ExternalID and up.UPS_DateFrom between uh.EffectiveStartDate and EffectiveEndDate
 and up.UPS_JobTitle in (4) -- Adviser/Seller
 and up.UPS_ContractStatus in (1) -- Currently under contract
 and up.UPS_DateTo is null  -- Current UserPosition



 --**************************************************************************
 -- Find date of last sale
 --**************************************************************************

  drop table if exists #LastSales
 select cs.AdviserUID, jobtitle, pmv.producttype, max(datesubmitted) as 'LatestSale' 
 into #LastSales
 from sa_ows_sale s inner join #CurrentSellers cs on cs.AdviserUID = s.AdviserUID
 inner join sa_ows_policies p on p.SaleID = s.SaleID
 inner join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
 group by cs.adviseruid, Jobtitle, pmv.producttype
 

 --**************************************************************************
 --  Find last sale detail
 --**************************************************************************

 drop table if exists #LastSalesDetails
 select distinct s.saleid, ls.LatestSale, ls.AdviserUID, pmv.ProductType
 into #LastSalesDetails
 from sa_ows_sale s 
 left join sa_ows_policies p on p.SaleID = s.SaleID
 left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
 inner join #LastSales ls on s.AdviserUID = ls.AdviserUID and s.datesubmitted = ls.LatestSale and ls.ProductType = pmv.ProductType
                                                  

 --  ***********************
 --  MAIN REPORT QUERY

 --  ***********************



 select aa.AdviserUID, aa.[Adviser Name],aa.[Firm ID] as 'FirmUID', aa.Firm, aa.QRM, aa.supervisor, aa.sqrm, 
 coalesce(case when lastsaledetails.ProductType = 'Mortgage' then 'MCOB'
	      when lastsaledetails.ProductType ='Investment' then 'COB (Inv)'
	      when lastsaledetails.ProductType ='Pension' then 'COB (Pen)'
	      when lastsaledetails.ProductType = 'Protection' and aa.jobtitle not in  
					             (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'ICOB' 
	      when lastsaledetails.ProductType = 'Protection' and aa.jobtitle in  
											             (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'OWL ICOB' 
	      end ,cdcomp.Code_Description) as 'Competency', 
cdcomplevel.Code_Description as 'CompetencyLevel',
case when UC_CompetencyLevel = 3
then convert(varchar,UC_DateAchieved,103)
else '' end as 'FC from',
 isnull(convert(varchar,lastsaledetails.LatestSale,103),'') as 'Date Last Sale Submitted',
 isnull(convert(varchar,lastsaledetails.SaleID),'') as 'Last SaleID submitted'
 from #CurrentSellers aa  
 left join sa_Insight_UserCompetency uc on uc.UC_OwnerID = aa.USR_ID and UC_BusinessArea in (1,2,3,9) and UC_Status = 0 -- COB, ICOB, MCOB, (ICOB GI only = 8 removed), OWL ICOB and competency is active
 inner join sa_Insight_CodeDescription cdcomp on cdcomp.Code_Code = uc.UC_BusinessArea and cdcomp.Code_CodeType = 960 -- Competency Name
 inner join sa_Insight_CodeDescription cdcomplevel on cdcomplevel.Code_Code = uc.UC_CompetencyLevel and cdcomplevel.Code_CodeType = 962 -- Competency Level
 left join sa_ows_sale s on s.AdviserUID = aa.[AdviserUID] and s.DateSubmitted between @StartDate and @EndDate
 left join #LastSalesDetails lastsaledetails on lastsaledetails.AdviserUID = aa.AdviserUID  
 and case when lastsaledetails.ProductType = 'Mortgage' then 'MCOB'
	 when lastsaledetails.ProductType ='Investment' then 'COB'
	 when lastsaledetails.ProductType ='Pension' then 'COB'
	 when lastsaledetails.ProductType = 'Protection' and aa.jobtitle not in  
					             (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'ICOB' 
	 when lastsaledetails.ProductType = 'Protection' and aa.jobtitle in  
											             (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'OWL ICOB' 
	 end = cdcomp.Code_Description 
 where s.SaleID is NULL -- No Sales Submitted in last 12 months
 and aa.[Adviser Name] not like 'OWS Test%'
 and aa.[Adviser Name] not like 'Concert Training%'
 and aa.[Adviser Name] not like 'JMD Test%'
 and aa.[Adviser Name] not like 'SharedTest%'
 and aa.[Adviser Name] not like 'OWS Fine Test%'
 order by AdviserUID, Competency

 drop table #CurrentSellers
 drop table #LastSales
 drop table #LastSalesDetails

/****************************************************************************


	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



