/**********************************************************************************************
Name	: [BI].[pr_127_OWSClientNationality] 
Author	: J Homer
Date	: 03/03/2022

Due to the outbreak of war in Ukraine, Russia and Ukraine are to be added to the Red List of countries.
The IT solution involves changes to OWS and will take some time to implement so, in the meantime, a
report is required to show clients who have a Nationality of Russian or Ukranian or are 
Domiciled/Resident in Russia or Ukraine so that the Financial Crime team can track these submissions

Report Owner - Alison Mayfield (Chief Financial Crime Officer)
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_127_OWSClientNationality] 

@Startdate Date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'OWS Client Nationality'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select pers.FirstName [First Name]
	   ,pers.LastName [Last Name]
	   ,pers.DateofBirth [Date of Birth]
	   ,CASE WHEN pers.PersonType = 1 THEN 'Client'
			 WHEN pers.PersonType = 2 THEN 'Partner'
		END [Person Type]
	   ,ISNULL(ISNULL(NationalityOther, iv.ValueName), '') Nationality
	   ,ISNULL(ISNULL(DomicileOther, iv2.Valuename), '') Domicile
	   ,ISNULL(ISNULL(ResidenceOther, iv3.Valuename), '') Residence
	   ,perstat.Description [Client Status]
	   ,pers.DateCreated [Date Created]
	   ,pers.LastUpdatedDate  [Date Last Updated]
FROM [dbo].[sa_ows_Person] pers LEFT JOIN
	 [dbo].[sa_ows_ClientDetailOverviewClientDetails] cd on cd.PersonID = pers.PersonID LEFT JOIN
	 [StaticData].[sa_ows_InputValues] iv on iv.InputID = cd.NationalityID LEFT JOIN
	 [StaticData].[sa_ows_InputValues] iv2 on iv2.InputID = cd.DomicileID LEFT JOIN
	 [StaticData].[sa_ows_InputValues] iv3 on iv3.InputID = cd.ResidenceID LEFT JOIN
	 [StaticData].[sa_ows_PersonStatus] perstat on perstat.PersonStatusID = pers.PersonStatus
where (Nationalityother like '%Russia%' OR NationalityOther like '%Ukrain%' OR NationalityOther LIKE '%Belarus%'
	or NationalityID in('5723', '10665') --5723 = Russian, 10665 = Ukrainian
	or DomicileID in('115', '10634') --115 = Russian Federation, 10634 = Ukraine
	or ResidenceID in ('115', '10634')
	or DomicileOther like 'Russia%' or DomicileOther Like 'Belarus%' or DomicileOther Like 'Ukrain%'
	or ResidenceOther like 'Russia%' or ResidenceOther Like 'Belarus%' or ResidenceOther Like 'Ukrain%')
	AND pers.FirstName NOT LIKE '%DO NOT USE%'
	AND (pers.DateCreated >= @StartDate or pers.LastUpdatedDate >=@StartDate)
Order By pers.DateCreated asc
,pers.LastUpdatedDate asc


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



