/**********************************************************************************************
Name	: [BI].[pr_128_FirmStaffPTLCodes] 
Author	: L Brigginshaw
Date	: 22/03/2022

Produce list of all firm staff and their PTL codes

Colette English
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
Create PROCEDURE [BI].[pr_128_FirmStaffPTLCodes] 

@FirmID int

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Firm Staff PTL Codes'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

SELECT DISTINCT 
UD.USR_ExternalID AS [Admin_UID],
UD.USR_Name AS [Admin_Name], 
IV1.ValueName as [Gender], 
CD8.Code_Description as [Role], 
CD6.Code_Description AS [User_Type], 
CD5.Code_Description AS [Admin_Employment_Status], 
CD7.Code_Description AS [Contract_Status], 
FIRMS.FirmCode, 
STAF_IRN,        
COALESCE(AG.DESCN, AG.TradingName,NULL) as [Firm_Name],
BUD.PtlCode

FROM dbo.sa_insight_UserDetails AS UD LEFT OUTER JOIN
dbo.sa_insight_Staff AS S ON UD.USR_ID = S.STAF_UserID LEFT OUTER JOIN
dbo.sa_insight_UserPosition AS UP ON UD.USR_ID = UP.UPS_UserID LEFT OUTER JOIN
dbo.f_Insight_GetFirmsOfAllUsers(GetDate()) AS FIRMS ON UP.UPS_ID = FIRMS.RoleGUID LEFT OUTER JOIN
dbo.sa_insight_CodeDescription AS CD5 ON S.STAF_EmploymentStatus = CD5.Code_Code AND CD5.Code_CodeType = 125 LEFT OUTER JOIN
dbo.sa_insight_CodeDescription AS CD6 ON UP.UPS_UserType = CD6.Code_Code AND CD6.Code_CodeType = 11 LEFT OUTER JOIN
dbo.sa_insight_CodeDescription AS CD7 ON S.STAF_ContractStatus = CD7.Code_Code AND CD7.Code_CodeType = 527 LEFT OUTER JOIN
dbo.sa_insight_CodeDescription AS CD8 ON UP.UPS_JobTitle = CD8.Code_Code AND CD8.Code_CodeType = 54 LEFT OUTER JOIN
dbo.mstt_Agents AG on FIRMS.FirmCode = AG.Code LEFT OUTER JOIN
dbo.sa_insight_ContactDetails CDT ON S.STAF_ID = CDT.CD_ParentID LEFT JOIN     
StaticData.sa_ows_InputValues IV1 on Iv1.InputID = S.STAF_Gender LEFT JOIN 
cscv_AgentsHierarchy AH on AH.AgentCode = UD.USR_ExternalID left join
[staticdata].sa_ows_SCRTY_UserAndBusinessDetails BUD on BUD.AdviserUID = UD.USR_ExternalID
					                     
WHERE
(S.STAF_ContractStatus <> '3') 
And (CD5.Code_Description in ('Open', 'Re-Appointed'))
and FIRMS.FirmCode = @FirmID

ORDER BY [Admin_UID]


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



