/**********************************************************************************************
Name	: [BI].[pr_129_DBClientCompletedEvent]
Author	: Akin Yavuz
Date	: 14.04.2022
 			
Stored procedure written for SSRS report.

*********************************************************************************************************************************************************/
CREATE PROCEDURE [BI].[pr_130_OWLHierarchyPaymentsReport]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'OWL Hierarchy Payments Report'
set @StoredProcName		= object_name(@@procid)

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select   a.*,
                          convert(decimal(6,2),(PositiveAmount / (PositiveAmount+abs(NegativeAmount))) * 100.0) as PercentagePositive
from
(
select StandingOrderDescription, 
                          PaymentCollectedDate,
                          sum(case when PaymentAmount >= 0.00 then PaymentAmount else 0.00 end) as PositiveAmount,
                          sum(case when PaymentAmount < 0.00 then PaymentAmount else 0.00 end) as NegativeAmount,
                          sum(case when CommissionTypeCode = 2 then PaymentAmount else 0.00 end) as Clawback,
                          sum(case when CommissionTypeCode = 17 then PaymentAmount else 0.00 end) as Adjustment,
                          sum(case when CommissionTypeCode = 1 and PaymentAmount < 0.00 then PaymentAmount else 0.00 end) as NegativeInitial,
                          sum(PaymentAmount) as NetAmount
from dbo.owoa_OwlHierarchyPayments
where PaymentStage = 'Upfront'
and year(PaymentCollectedDate) >= 2020
--and PaymentCollectedDate = '2020-05-08'
group by StandingOrderDescription, PaymentCollectedDate
) a
order by PaymentCollectedDate

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



